### 5. Running at Scale with Docker

To truly test a "distributed" system, we use Docker Compose to spin up Redis and multiple worker nodes.

**`docker-compose.yml`**
```yaml
version: '3.8'

services:
  redis:
    image: redis:7-alpine
    ports:
      - "6379:6379"

  api:
    build: .
    command: npm run start:producer
    ports:
      - "3000:3000"
    environment:
      - REDIS_HOST=redis
    depends_on:
      - redis

  worker:
    build: .
    command: npm run start:worker
    environment:
      - REDIS_HOST=redis
    depends_on:
      - redis
    # Scale this service to test distribution
    deploy:
      replicas: 3
```

---

### 6. Why This is Production Ready

1.  **At-Least-Once Delivery**: BullMQ uses Redis RPOPLPUSH (or Lua equivalent) patterns. If a worker picks up a job and immediately crashes, the job stays in the "active" list until a lock expires, after which it's moved back to "waiting" for another worker.
2.  **Concurrency Control**: Each worker instance can define how many parallel jobs it can handle, preventing CPU/Memory exhaustion.
3.  **Exponential Backoff**: This is critical for distributed systems to prevent "thundering herd" problems when an external API or database is down.
4.  **Priority Queuing**: We used a Sorted Set in Redis (via BullMQ) which ensures that jobs with a priority value of `1` are always picked up before jobs with `10`.
5.  **Delayed Jobs**: The system manages a "delayed" set and uses a timer to move jobs to the "waiting" list only when their time has come.

### 7. How to Test

1.  **Start the system**:
    ```bash
    docker-compose up --build --scale worker=3
    ```
2.  **Inject a High Priority Job**:
    ```bash
    curl -X POST http://localhost:3000/enqueue \
    -H "Content-Type: application/json" \
    -d '{"name":"email", "data":{"to":"user@example.com"}, "priority": 1}'
    ```
3.  **Inject a Scheduled Job (10s delay)**:
    ```bash
    curl -X POST http://localhost:3000/enqueue \
    -H "Content-Type: application/json" \
    -d '{"name":"cleanup", "data":{}, "delay": 10000}'
    ```

### Recommended Monitoring
For a production environment, you should also add **BullBoard**. It's a small UI dashboard that connects to your Redis instance and allows you to manually retry failed jobs or see the current queue backlog in real-time.

This is a sophisticated implementation of a **Double-Entry Financial Ledger**. In professional financial systems, we never use simple "balance" columns that are incremented/decremented. Instead, we use a ledger of immutable journal entries to ensure a perfect audit trail.

### Technical Stack Decisions

1.  **PostgreSQL**: The gold standard for financial data due to strict ACID compliance and powerful aggregation capabilities.
2.  **TypeScript & Node.js**: Provides type safety for complex financial calculations.
3.  **Prisma ORM**: Ensures type-safe database access and handles complex relations between transactions and entries.
4.  **Decimal.js**: Crucial for avoiding floating-point math errors (e.g., `0.1 + 0.2 !== 0.3`).
5.  **Double-Entry Pattern**: Every transaction must have at least one debit and one credit that sum to zero.

---

### 1. Database Schema (Prisma)

This schema implements a hierarchical Chart of Accounts and a robust Transaction/Journal Entry relationship.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum AccountType {
  ASSET
  LIABILITY
  EQUITY
  REVENUE
  EXPENSE
}

model Account {
  id          String         @id @default(uuid())
  code        String         @unique // e.g., "1000", "2100"
  name        String
  type        AccountType
  description String?
  entries     JournalEntry[]
  createdAt   DateTime       @default(now())
  updatedAt   DateTime       @updatedAt
}

model Transaction {
  id          String         @id @default(uuid())
  reference   String         @unique // External invoice/receipt ID
  description String
  postedAt    DateTime       @default(now())
  entries     JournalEntry[]
  metadata    Json?          // For custom tags, department IDs, etc.
}

model JournalEntry {
  id            String      @id @default(uuid())
  amount        Decimal     @db.Decimal(20, 4) // Stores the magnitude
  type          EntrySide   // DEBIT or CREDIT
  accountId     String
  account       Account     @relation(fields: [accountId], references: [id])
  transactionId String
  transaction   Transaction @relation(fields: [transactionId], references: [id])
}

enum EntrySide {
  DEBIT
  CREDIT
}
```

---

### 2. Core Ledger Service

This service handles the business logic, ensuring the "Golden Rule of Accounting": **Debits must equal Credits.**

```typescript
// src/services/LedgerService.ts
import { PrismaClient } from '@prisma/client';
import { Decimal } from 'decimal.js';

const prisma = new PrismaClient();

export interface TransactionInput {
  description: string;
  reference: string;
  entries: {
    accountId: string;
    amount: string; // Use string for precision during transport
    side: 'DEBIT' | 'CREDIT';
  }[];
  metadata?: any;
}

export class LedgerService {
  /**
   * Creates a transaction with multiple journal entries.
   * Uses a DB transaction to ensure atomicity.
   */
  async createTransaction(input: TransactionInput) {
    // 1. Validate Double-Entry Balance
    let totalDebit = new Decimal(0);
    let totalCredit = new Decimal(0);

    input.entries.forEach(e => {
      if (e.side === 'DEBIT') totalDebit = totalDebit.plus(e.amount);
      else totalCredit = totalCredit.plus(e.amount);
    });

    if (!totalDebit.equals(totalCredit)) {
      throw new Error(`Unbalanced Transaction: Debits (${totalDebit}) != Credits (${totalCredit})`);
    }

    // 2. Execute Atomic Database Operation
    return await prisma.$transaction(async (tx) => {
      const transaction = await tx.transaction.create({
        data: {
          description: input.description,
          reference: input.reference,
          metadata: input.metadata,
          entries: {
            create: input.entries.map(e => ({
              amount: new Decimal(e.amount),
              type: e.side,
              accountId: e.accountId
            }))
          }
        },
        include: { entries: true }
      });
      return transaction;
    });
  }

  /**
   * Complex Querying: Search transactions with dynamic filters
   */
  async queryTransactions(filters: {
    startDate?: Date;
    endDate?: Date;
    accountId?: string;
    minAmount?: number;
  }) {
    return await prisma.transaction.findMany({
      where: {
        postedAt: {
          gte: filters.startDate,
          lte: filters.endDate
        },
        entries: {
          some: {
            accountId: filters.accountId,
            amount: { gte: filters.minAmount }
          }
        }
      },
      include: {
        entries: { include: { account: true } }
      },
      orderBy: { postedAt: 'desc' }
    });
  }
}
```

---

### 3. Reporting Engine

Reporting in a ledger involves aggregating entries. To calculate a balance:
- Assets/Expenses: Balance = Debits - Credits
- Liabilities/Equity/Revenue: Balance = Credits - Debits

```typescript
// src/services/ReportingService.ts
import { PrismaClient } from '@prisma/client';
import { Decimal } from 'decimal.js';

const prisma = new PrismaClient();

export class ReportingService {
  /**
   * Generates a Trial Balance: The current balance of all accounts
   */
  async getTrialBalance() {
    const accounts = await prisma.account.findMany({
      include: { entries: true }
    });

    return accounts.map(account => {
      let balance = new Decimal(0);

      account.entries.forEach(entry => {
        if (entry.type === 'DEBIT') {
          balance = balance.plus(entry.amount);
        } else {
          balance = balance.minus(entry.amount);
        }
      });

      // Adjust sign based on account type normal balance
      const normalSide = ['ASSET', 'EXPENSE'].includes(account.type) ? 1 : -1;
      const finalBalance = balance.times(normalSide);

      return {
        accountCode: account.code,
        accountName: account.name,
        type: account.type,
        balance: finalBalance.toFixed(2)
      };
    });
  }

  /**
   * Advanced Reporting: Aggregated Monthly Cash Flow
   */
  async getMonthlyRevenue(year: number) {
    return await prisma.$queryRaw`
      SELECT 
        EXTRACT(MONTH FROM t."postedAt") as month,
        SUM(e.amount) as total
      FROM "Transaction" t
      JOIN "JournalEntry" e ON t.id = e."transactionId"
      JOIN "Account" a ON e."accountId" = a.id
      WHERE a.type = 'REVENUE' 
        AND EXTRACT(YEAR FROM t."postedAt") = ${year}
      GROUP BY month
      ORDER BY month ASC
    `;
  }
}
