### 4. Ledger Service (`src/services/ledger.ts`)

This service ensures the **Golden Rule of Accounting**: Debits must equal Credits.

```typescript
import { PrismaClient } from '@prisma/client';
import { Decimal } from 'decimal.js';

const prisma = new PrismaClient();

export interface EntryInput {
  accountId: string;
  amount: number | Decimal; // Positive for Debit, Negative for Credit
}

export class LedgerService {
  /**
   * Posts a multi-legged transaction to the ledger
   */
  async postTransaction(description: string, entries: EntryInput[], reference?: string) {
    // 1. Validate that the transaction balances to zero
    const sum = entries.reduce(
      (acc, entry) => acc.plus(new Decimal(entry.amount)),
      new Decimal(0)
    );

    if (!sum.isZero()) {
      throw new Error(`Transaction out of balance by ${sum.toString()}. Sum must be zero.`);
    }

    // 2. Execute within a DB Transaction for atomicity
    return await prisma.$transaction(async (tx) => {
      const transaction = await tx.transaction.create({
        data: {
          description,
          reference,
          entries: {
            create: entries.map(e => ({
              accountId: e.accountId,
              amount: new Decimal(e.amount)
            }))
          }
        },
        include: { entries: true }
      });

      return transaction;
    });
  }
}
```

