### 5. Reporting Service (`src/services/reports.ts`)

Demonstrates complex querying: calculating balances across time and categories.

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class ReportService {
  /**
   * Generates a Trial Balance (current balance of all accounts)
   */
  async getTrialBalance(asOf: Date = new Date()) {
    const report = await prisma.account.findMany({
      include: {
        journalEntries: {
          where: {
            transaction: {
              postedAt: { lte: asOf }
            }
          }
        }
      }
    });

    return report.map(account => {
      const balance = account.journalEntries.reduce(
        (sum, entry) => sum.plus(entry.amount),
        new Decimal(0)
      );

      return {
        accountName: account.name,
        accountType: account.type,
        balance: balance.toNumber()
      };
    });
  }

  /**
   * Complex Query: Search transactions with filters
   */
  async findTransactions(filters: {
    startDate?: Date,
    endDate?: Date,
    accountId?: string,
    minAmount?: number
  }) {
    return await prisma.transaction.findMany({
      where: {
        postedAt: {
          gte: filters.startDate,
          lte: filters.endDate
        },
        entries: {
          some: {
            accountId: filters.accountId,
            amount: filters.minAmount ? { gte: filters.minAmount } : undefined
          }
        }
      },
      include: {
        entries: {
          include: { account: true }
        }
      },
      orderBy: { postedAt: 'desc' }
    });
  }
}
```

