### 3. Core Ledger Service (`src/services/ledger.service.ts`)

This service handles the creation of transactions and ensures the "Zero-Sum" rule (Debits + Credits = 0).

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class LedgerService {
  /**
   * Records a double-entry transaction.
   * Total sum of entries must equal 0.
   */
  async createTransaction(description: string, entries: { accountId: string, amount: number }[]) {
    const totalSum = entries.reduce((acc, curr) => acc + curr.amount, 0);

    if (totalSum !== 0) {
      throw new Error("Transaction is not balanced. Debits must equal Credits.");
    }

    return await prisma.$transaction(async (tx) => {
      const transaction = await tx.transaction.create({
        data: {
          description,
          entries: {
            create: entries.map(e => ({
              amount: BigInt(e.amount),
              accountId: e.accountId
            }))
          }
        },
        include: { entries: true }
      });
      return transaction;
    });
  }

  async getAccountBalance(accountId: string) {
    const result = await prisma.journalEntry.aggregate({
      where: { accountId },
      _sum: { amount: true }
    });
    return result._sum.amount || BigInt(0);
  }
}
```

### 4. Complex Reporting Service (`src/services/report.service.ts`)

This shows how to perform complex aggregations, like a **Trial Balance** or **Income Statement**.

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class ReportService {
  /**
   * Generates a Trial Balance: The sum of all accounts.
   */
  async getTrialBalance() {
    const balances = await prisma.journalEntry.groupBy({
      by: ['accountId'],
      _sum: { amount: true },
    });

    const accounts = await prisma.account.findMany();

    return accounts.map(acc => ({
      accountName: acc.name,
      type: acc.type,
      balance: balances.find(b => b.accountId === acc.id)?._sum.amount?.toString() || "0"
    }));
  }

  /**
   * Generates an Income Statement (Profit & Loss) for a date range.
   */
  async getIncomeStatement(startDate: Date, endDate: Date) {
    const entries = await prisma.journalEntry.findMany({
      where: {
        transaction: {
          postedAt: { gte: startDate, lte: endDate }
        },
        account: {
          type: { in: ['REVENUE', 'EXPENSE'] }
        }
      },
      include: { account: true }
    });

    const report = entries.reduce((acc: any, entry) => {
      const type = entry.account.type;
      const amount = Number(entry.amount);
      acc[type] = (acc[type] || 0) + amount;
      return acc;
    }, {});

    return {
      revenue: report.REVENUE || 0,
      expenses: report.EXPENSE || 0,
      netIncome: (report.REVENUE || 0) + (report.EXPENSE || 0)
    };
  }
}
```

