### 3. Core Logic: The Feed & Social Graph
One of the hardest parts of a social backend is the **Feed Service**. We need to fetch posts from users that the current user follows, ordered by time.

#### `src/services/post.service.ts`
```typescript
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export const getFeed = async (userId: string, limit = 20, cursor?: string) => {
  // 1. Get IDs of people the user follows
  const following = await prisma.follows.findMany({
    where: { followerId: userId },
    select: { followingId: true }
  });

  const followingIds = following.map(f => f.followingId);
  // Include self in the feed
  followingIds.push(userId);

  // 2. Query posts from those users
  return prisma.post.findMany({
    where: { authorId: { in: followingIds } },
    take: limit,
    skip: cursor ? 1 : 0,
    cursor: cursor ? { id: cursor } : undefined,
    orderBy: { createdAt: 'desc' },
    include: {
      author: { select: { username: true } },
      _count: { select: { likes: true, comments: true } }
    }
  });
};
```

