### 4. API Implementation: Followers & Likes
We use a "toggle" pattern for follows and likes to simplify the frontend logic.

#### `src/controllers/social.controller.ts`
```typescript
import { Request, Response } from 'express';
import { prisma } from '../lib/prisma';

export const toggleFollow = async (req: Request, res: Response) => {
  const { targetUserId } = req.params;
  const currentUserId = req.user.id;

  if (targetUserId === currentUserId) return res.status(400).json({ error: "Cannot follow self" });

  const existing = await prisma.follows.findUnique({
    where: { followerId_followingId: { followerId: currentUserId, followingId: targetUserId } }
  });

  if (existing) {
    await prisma.follows.delete({
      where: { followerId_followingId: { followerId: currentUserId, followingId: targetUserId } }
    });
    return res.json({ message: "Unfollowed" });
  }

  await prisma.follows.create({
    data: { followerId: currentUserId, followingId: targetUserId }
  });
  res.json({ message: "Followed" });
};

export const toggleLike = async (req: Request, res: Response) => {
  const { postId } = req.params;
  const userId = req.user.id;

  const existing = await prisma.like.findUnique({
    where: { userId_postId: { userId, postId } }
  });

  if (existing) {
    await prisma.like.delete({ where: { userId_postId: { userId, postId } } });
    return res.json({ liked: false });
  }

  await prisma.like.create({ data: { userId, postId } });
  res.json({ liked: true });
};
```

