### 3. Core Implementation

#### `src/services/social.service.ts`
This service handles the business logic for the follower graph and feed generation.

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export const SocialService = {
  async followUser(followerId: string, followingId: string) {
    if (followerId === followingId) throw new Error("Cannot follow yourself");

    return prisma.follows.create({
      data: { followerId, followingId }
    });
  },

  async unfollowUser(followerId: string, followingId: string) {
    return prisma.follows.delete({
      where: {
        followerId_followingId: { followerId, followingId }
      }
    });
  },

  async getFeed(userId: string, limit = 20, cursor?: string) {
    // Get posts from people the user follows
    return prisma.post.findMany({
      where: {
        author: {
          followedBy: {
            some: { followerId: userId }
          }
        }
      },
      take: limit,
      skip: cursor ? 1 : 0,
      cursor: cursor ? { id: cursor } : undefined,
      orderBy: { createdAt: 'desc' },
      include: {
        author: { select: { username: true, id: true } },
        _count: { select: { likes: true, comments: true } }
      }
    });
  },

  async toggleLike(userId: string, postId: string) {
    const existing = await prisma.like.findUnique({
      where: { userId_postId: { userId, postId } }
    });

    if (existing) {
      return prisma.like.delete({ where: { userId_postId: { userId, postId } } });
    }
    return prisma.like.create({ data: { userId, postId } });
  }
};
```

#### `src/routes/post.routes.ts`
Fastify routes with Zod validation.

```typescript
import { FastifyInstance } from 'fastify';
import { z } from 'zod';
import { SocialService } from '../services/social.service';

export async function postRoutes(fastify: FastifyInstance) {

  // Create Post
  fastify.post('/posts', async (request, reply) => {
    const { content } = z.object({ content: z.string().max(280) }).parse(request.body);
    const userId = request.user.id; // Populated by Auth middleware

    const post = await fastify.prisma.post.create({
      data: { content, authorId: userId }
    });
    return post;
  });

  // Get News Feed
  fastify.get('/feed', async (request, reply) => {
    const { cursor } = z.object({ cursor: z.string().optional() }).parse(request.query);
    return SocialService.getFeed(request.user.id, 20, cursor);
  });

  // Like/Unlike a post
  fastify.post('/posts/:id/like', async (request, reply) => {
    const { id } = z.object({ id: z.string().uuid() }).parse(request.params);
    return SocialService.toggleLike(request.user.id, id);
  });

  // Follow a user
  fastify.post('/users/:id/follow', async (request, reply) => {
    const { id } = z.object({ id: z.string().uuid() }).parse(request.params);
    return SocialService.followUser(request.user.id, id);
  });
}
