### 2. Implementation: Core Logic

#### Follower Service (`src/services/follow.service.ts`)
This handles the logic for building the social graph.

```typescript
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export const followUser = async (followerId: string, followingId: string) => {
  if (followerId === followingId) throw new Error("Cannot follow yourself");

  return await prisma.follows.create({
    data: { followerId, followingId }
  });
};

export const getFeed = async (userId: string, cursor?: string) => {
  // Get IDs of people the user follows
  const following = await prisma.follows.findMany({
    where: { followerId: userId },
    select: { followingId: true }
  });

  const followingIds = following.map(f => f.followingId);
  // Include the user's own posts in the feed
  followingIds.push(userId);

  return await prisma.post.findMany({
    where: { authorId: { in: followingIds } },
    take: 10,
    skip: cursor ? 1 : 0,
    cursor: cursor ? { id: cursor } : undefined,
    orderBy: { createdAt: 'desc' },
    include: {
      author: { select: { username: true } },
      _count: { select: { likes: true, comments: true } }
    }
  });
};
```

#### Post Service (`src/services/post.service.ts`)
Handles post creation and "Liking" logic.

