### 2. Backend API (Express + TypeScript)
Here is the core logic for managing vehicles and their status.

```typescript
// server.ts
import express from 'express';
import { PrismaClient } from '@prisma/client';
import cors from 'cors';

const prisma = new PrismaClient();
const app = express();
app.use(cors());
app.use(express.json());

// GET: Fleet Overview Stats
app.get('/api/stats', async (req, res) => {
  const [vehicleCount, maintenanceCount, activeDrivers] = await Promise.all([
    prisma.vehicle.count(),
    prisma.maintenanceLog.count(),
    prisma.assignment.count({ where: { active: true } })
  ]);

  res.json({ vehicleCount, maintenanceCount, activeDrivers });
});

// GET: All Vehicles with their current driver
app.get('/api/vehicles', async (req, res) => {
  const vehicles = await prisma.vehicle.findMany({
    include: {
      assignments: {
        where: { active: true },
        include: { driver: true }
      }
    }
  });
  res.json(vehicles);
});

// POST: Log Maintenance
app.post('/api/maintenance', async (req, res) => {
  const { vehicleId, description, cost, odometer } = req.body;
  const log = await prisma.maintenanceLog.create({
    data: {
      vehicleId,
      description,
      cost,
      odometer,
      serviceDate: new Date(),
    }
  });

  // Automatically set vehicle to maintenance status
  await prisma.vehicle.update({
    where: { id: vehicleId },
    data: { status: 'MAINTENANCE' }
  });

  res.json(log);
});

app.listen(3000, () => console.log('Fleet API running on port 3000'));
```

