const prisma = new PrismaClient();

app.use(cors());
app.use(express.json());

// API Routes
app.get('/api/vehicles', async (req, res) => {
  const vehicles = await prisma.vehicle.findMany({ include: { assignments: { include: { driver: true } } } });
  res.json(vehicles);
});

app.post('/api/maintenance', async (req, res) => {
  const { vehicleId, description, cost } = req.body;
  const record = await prisma.maintenanceRecord.create({
    data: { vehicleId, description, cost: parseFloat(cost) }
  });
  res.json(record);
});

// Simulation: Move vehicles randomly every 3 seconds
setInterval(async () => {
  const vehicles = await prisma.vehicle.findMany({ where: { status: 'ACTIVE' } });
  for (const v of vehicles) {
    const newLat = v.lat + (Math.random() - 0.5) * 0.01;
    const newLng = v.lng + (Math.random() - 0.5) * 0.01;

    await prisma.vehicle.update({
      where: { id: v.id },
      data: { lat: newLat, lng: newLng }
    });

    io.emit('locationUpdate', { id: v.id, lat: newLat, lng: newLng });
  }
}, 3000);

server.listen(3001, () => console.log('Backend running on port 3001'));
```

