### 3. Server Actions (Backend Logic)
Handling the business logic for assignments and maintenance logs.

```tsx
// app/actions/fleet.ts
"use server"
import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";

export async function assignDriver(vehicleId: string, driverId: string) {
  try {
    // 1. Unassign current driver from this vehicle if exists
    // 2. Assign new driver
    await prisma.vehicle.update({
      where: { id: vehicleId },
      data: { driverId: driverId }
    });
    revalidatePath("/vehicles");
  } catch (error) {
    return { error: "Failed to assign driver" };
  }
}

export async function addMaintenanceRecord(formData: FormData) {
  const vehicleId = formData.get("vehicleId") as string;
  const cost = parseFloat(formData.get("cost") as string);

  await prisma.maintenanceLog.create({
    data: {
      vehicleId,
      serviceDate: new Date(formData.get("date") as string),
      description: formData.get("description") as string,
      cost,
      odometer: parseInt(formData.get("odometer") as string),
      technician: formData.get("technician") as string,
    }
  });

  // Update vehicle status if it was in maintenance
  await prisma.vehicle.update({
    where: { id: vehicleId },
    data: { status: 'ACTIVE' }
  });

  revalidatePath("/maintenance");
}
```

