### 3. Core Implementation: History & Playlist Services

#### Viewing History Controller (`src/controllers/history.controller.ts`)
This handles "Continue Watching" functionality.

```typescript
import { Request, Response } from 'express';
import { prisma } from '../utils/db';

export const updateHistory = async (req: Request, res: Response) => {
  const { videoId, position, completed } = req.body;
  const userId = req.user.id; // From Auth Middleware

  const history = await prisma.viewingHistory.upsert({
    where: {
      userId_videoId: { userId, videoId }
    },
    update: {
      lastPosition: position,
      completed: completed || false,
    },
    create: {
      userId,
      videoId,
      lastPosition: position,
    }
  });

  return res.json(history);
};

export const getHistory = async (req: Request, res: Response) => {
  const history = await prisma.viewingHistory.findMany({
    where: { userId: req.user.id },
    include: { video: true },
    orderBy: { updatedAt: 'desc' },
    take: 20
  });
  res.json(history);
};
```

#### Playlist Controller (`src/controllers/playlist.controller.ts`)

```typescript
import { Request, Response } from 'express';
import { prisma } from '../utils/db';

export const createPlaylist = async (req: Request, res: Response) => {
  const { name, description } = req.body;
  const playlist = await prisma.playlist.create({
    data: { name, description, userId: req.user.id }
  });
  res.status(201).json(playlist);
};

export const addVideoToPlaylist = async (req: Request, res: Response) => {
  const { playlistId, videoId } = req.params;

  // Get count to determine next 'order'
  const count = await prisma.playlistVideo.count({ where: { playlistId } });

  const entry = await prisma.playlistVideo.create({
    data: {
      playlistId,
      videoId,
      order: count + 1
    }
  });
  res.json(entry);
};
```

