### 2. Core Service Logic (`src/services/video.service.ts`)
Handling the business logic for updating history and managing playlists.

```typescript
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export class VideoService {
  // Update or create viewing history
  static async updateHistory(userId: string, videoId: string, progress: number) {
    return prisma.history.upsert({
      where: { userId_videoId: { userId, videoId } },
      update: { progress, watchedAt: new Date() },
      create: { userId, videoId, progress },
    });
  }

  // Get user's viewing history with metadata
  static async getUserHistory(userId: string, limit = 20) {
    return prisma.history.findMany({
      where: { userId },
      take: limit,
      orderBy: { watchedAt: 'desc' },
      include: { video: true }
    });
  }

  // Add video to playlist
  static async addVideoToPlaylist(playlistId: string, videoId: string) {
    const count = await prisma.playlistVideo.count({ where: { playlistId } });
    return prisma.playlistVideo.create({
      data: {
        playlistId,
        videoId,
        order: count + 1
      }
    });
  }
}
```

