### 2. Implementation: Viewing History Logic
The history module is critical for features like "Continue Watching." We use an `upsert` (Update or Insert) to keep the history clean.

```typescript
// src/history/history.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class HistoryService {
  constructor(private prisma: PrismaService) {}

  async trackView(userId: string, videoId: string, progressSeconds: number) {
    // 1. Record/Update History
    const history = await this.prisma.history.upsert({
      where: {
        userId_videoId: { userId, videoId },
      },
      update: {
        progressSeconds,
        watchedAt: new Date(),
      },
      create: {
        userId,
        videoId,
        progressSeconds,
      },
    });

    // 2. Increment Video View Count (Ideally debounced or via worker)
    await this.prisma.video.update({
      where: { id: videoId },
      data: { views: { increment: 1 } },
    });

    return history;
  }

  async getUserHistory(userId: string) {
    return this.prisma.history.findMany({
      where: { userId },
      include: { video: true },
      orderBy: { watchedAt: 'desc' },
      take: 50,
    });
  }
}
```

