### 3. Core Logic: Transaction Service

This is the most critical part of a marketplace. It handles the logic of purchasing a product.

```typescript
// src/services/transaction.service.ts
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export class TransactionService {
  static async createPurchase(buyerId: string, productId: string) {
    // We use a transaction to ensure atomicity
    return await prisma.$transaction(async (tx) => {
      // 1. Fetch product and lock the row for update to prevent race conditions
      const product = await tx.product.findUnique({
        where: { id: productId },
      });

      if (!product || product.stock <= 0) {
        throw new Error('Product unavailable or out of stock');
      }

      // 2. Create the transaction record
      const transaction = await tx.transaction.create({
        data: {
          buyerId,
          productId,
          amount: product.price,
          status: 'COMPLETED',
        },
      });

      // 3. Decrement product stock
      await tx.product.update({
        where: { id: productId },
        data: { stock: { decrement: 1 } },
      });

      return transaction;
    });
  }
}
```

