### 3. Core Logic: The Transaction Service

This is the most critical part: handling a purchase. We use a **Database Transaction** to ensure that we don't sell products that are out of stock.

```typescript
// src/services/transaction.service.ts
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export const createPurchase = async (buyerId: string, productId: string, quantity: number) => {
  return await prisma.$transaction(async (tx) => {
    // 1. Check stock and get product details
    const product = await tx.product.findUnique({
      where: { id: productId },
      lock: { mode: 'update' } // Row-level locking for concurrency
    });

    if (!product || product.stock < quantity) {
      throw new Error("Product unavailable or insufficient stock");
    }

    // 2. Update stock
    const updatedProduct = await tx.product.update({
      where: { id: productId },
      data: { stock: { decrement: quantity } }
    });

    // 3. Create transaction record
    const transaction = await tx.transaction.create({
      data: {
        buyerId,
        productId,
        sellerId: product.sellerId,
        quantity,
        totalPrice: product.price * quantity,
        status: 'COMPLETED'
      }
    });

    return transaction;
  });
};
```

