#### Transaction Controller (`src/controllers/transaction.controller.ts`)
This handles the logic for a purchase, ensuring stock integrity.

```typescript
import { Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';
import { TransactionSchema } from '../utils/schema';

const prisma = new PrismaClient();

export const createTransaction = async (req: Request, res: Response) => {
  const validated = TransactionSchema.parse(req.body);

  try {
    // Run as an atomic transaction
    const result = await prisma.$transaction(async (tx) => {
      const product = await tx.product.findUnique({
        where: { id: validated.productId }
      });

      if (!product || product.stock < validated.quantity) {
        throw new Error('Insufficient stock or product not found');
      }

      // 1. Decrement stock
      const updatedProduct = await tx.product.update({
        where: { id: validated.productId },
        data: { stock: { decrement: validated.quantity } }
      });

      // 2. Create record
      const transaction = await tx.transaction.create({
        data: {
          productId: validated.productId,
          buyerName: validated.buyerName,
          quantity: validated.quantity,
          totalAmount: Number(product.price) * validated.quantity,
        }
      });

      return transaction;
    });

    res.status(201).json(result);
  } catch (error: any) {
    res.status(400).json({ error: error.message });
  }
};
```

