### 3. Real-time Gateway (Socket.io)
This handles the "Live Map" feature for riders.

**Socket Handler (`src/sockets/ride.gateway.ts`):**
```typescript
import { Server } from 'socket.io';
import { updateDriverLocation } from '../services/location.service';

export const setupSocketHandlers = (io: Server) => {
  io.on('connection', (socket) => {

    // 1. Driver updates their location
    socket.on('driver:update_location', async (data: { driverId: string, lat: number, lng: number }) => {
      await updateDriverLocation(data.driverId, data.lat, data.lng);

      // Notify riders in a specific room (e.g., a "trip room")
      io.to(`trip_${data.driverId}`).emit('location_update', {
        lat: data.lat,
        lng: data.lng
      });
    });

    // 2. Rider joins a trip room to track their driver
    socket.on('trip:join', (tripId: string) => {
      socket.join(`trip_${tripId}`);
    });
  });
};
```

