### 4. Trip & Rating API (`src/routes/trip.routes.ts`)
Using Fastify to handle ride requests and history.

```typescript
import { FastifyInstance } from 'fastify';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export default async function tripRoutes(fastify: FastifyInstance) {

  // Request a Ride
  fastify.post('/trips/request', async (request, reply) => {
    const { riderId, pickup, destination } = request.body as any;
    const trip = await prisma.trip.create({
      data: {
        riderId,
        pickupLat: pickup.lat,
        pickupLng: pickup.lng,
        destinationLat: destination.lat,
        destinationLng: destination.lng,
      }
    });
    // In a real app, you'd trigger a "Find Driver" background job here
    return trip;
  });

  // Complete Trip & Save Rating
  fastify.post('/trips/:id/rate', async (request, reply) => {
    const { id } = request.params as { id: string };
    const { score, comment } = request.body as { score: number, comment: string };

    const rating = await prisma.$transaction(async (tx) => {
      const newRating = await tx.rating.create({
        data: { tripId: id, score, comment }
      });

      // Update Driver's average rating denormalized field
      const trip = await tx.trip.findUnique({ where: { id }, select: { driverId: true } });
      if (trip?.driverId) {
        const avg = await tx.rating.aggregate({
          where: { trip: { driverId: trip.driverId } },
          _avg: { score: true }
        });
        await tx.user.update({
          where: { id: trip.driverId },
          data: { rating: avg._avg.score || 5.0 }
        });
      }
      return newRating;
    });

    return rating;
  });

  // Trip History
  fastify.get('/trips/history/:userId', async (request) => {
    const { userId } = request.params as { userId: string };
    return prisma.trip.findMany({
      where: { OR: [{ riderId: userId }, { driverId: userId }] },
      include: { rating: true, driver: true, rider: true },
      orderBy: { createdAt: 'desc' }
    });
  });
}
```

