### 3. Real-Time Location Logic (Redis)
We use Redis **Geospatial indexes** (`GEOADD`) because they allow us to find drivers within a certain radius of a rider extremely quickly.

```typescript
// src/lib/redis.ts
import { createClient } from 'redis';

export const redis = createClient({ url: process.env.REDIS_URL });

export const updateDriverLocation = async (driverId: string, lat: number, lng: number) => {
  // Store location in a geospatial set named 'drivers'
  await redis.geoAdd('drivers', {
    longitude: lng,
    latitude: lat,
    member: driverId
  });
};

export const findNearbyDrivers = async (lat: number, lng: number, radiusKm: number) => {
  return await redis.geoSearch('drivers', { latitude: lat, longitude: lng }, { radius: radiusKm, unit: 'km' });
};
```

### 4. WebSocket Server (Socket.io)
This handles the "live" aspect: drivers streaming their coordinates and riders receiving them.

```typescript
// src/lib/socket.ts
import { Server } from 'socket.io';
import { updateDriverLocation } from './redis';

export const setupSocket = (server: any) => {
  const io = new Server(server, { cors: { origin: "*" } });

  io.on('connection', (socket) => {
    console.log('User connected:', socket.id);

    // Driver updates their location
    socket.on('update-location', async (data: { driverId: string, lat: number, lng: number }) => {
      await updateDriverLocation(data.driverId, data.lat, data.lng);

      // Notify riders tracking this specific driver
      socket.to(`trip-room-${data.driverId}`).emit('location-changed', data);
    });

    // Join a room for a specific trip to get live updates
    socket.on('join-trip', (tripId: string) => {
      socket.join(`trip-room-${tripId}`);
    });
  });

  return io;
};
```

