### 1. Database Schema (`prisma/schema.prisma`)
We define our core entities: Users (Drivers/Riders), Trips, and Ratings.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum UserRole {
  RIDER
  DRIVER
}

enum TripStatus {
  REQUESTED
  ACCEPTED
  IN_PROGRESS
  COMPLETED
  CANCELLED
}

model User {
  id            String   @id @default(uuid())
  email         String   @unique
  name          String
  role          UserRole
  tripsAsRider  Trip[]   @relation("RiderTrips")
  tripsAsDriver Trip[]   @relation("DriverTrips")
  ratingsGiven  Rating[] @relation("Giver")
  ratingsRecv   Rating[] @relation("Receiver")
  createdAt     DateTime @default(now())
}

model Trip {
  id             String     @id @default(uuid())
  riderId        String
  rider          User       @relation("RiderTrips", fields: [riderId], references: [id])
  driverId       String?
  driver         User?      @relation("DriverTrips", fields: [driverId], references: [id])
  status         TripStatus @default(REQUESTED)
  pickupCoords   String     // "lat,lng"
  dropoffCoords  String     // "lat,lng"
  ratings        Rating[]
  startTime      DateTime?
  endTime        DateTime?
  createdAt      DateTime   @default(now())
}

model Rating {
  id          String   @id @default(uuid())
  tripId      String
  trip        Trip     @relation(fields: [tripId], references: [id])
  score       Int      // 1-5
  comment     String?
  giverId     String
  giver       User     @relation("Giver", fields: [giverId], references: [id])
  receiverId  String
  receiver    User     @relation("Receiver", fields: [receiverId], references: [id])
}
```

