### 2. Location Management Service (`src/services/LocationService.ts`)
We use Redis `GEOADD` and `GEORADIUS` to handle driver locations efficiently.

```typescript
import Redis from 'ioredis';

const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

export class LocationService {
  private static GEO_KEY = 'driver_locations';

  // Update driver position in Redis
  static async updateDriverLocation(driverId: string, lat: number, lng: number) {
    await redis.geoadd(this.GEO_KEY, lng, lat, driverId);
  }

  // Find drivers within X kilometers
  static async findNearbyDrivers(lat: number, lng: number, radiusKm: number) {
    return await redis.georadius(this.GEO_KEY, lng, lat, radiusKm, 'km', 'WITHDIST');
  }

  static async removeDriver(driverId: string) {
    await redis.zrem(this.GEO_KEY, driverId);
  }
}
```

