### 3. Real-time Communication (`src/sockets/rideHandler.ts`)
This handles the WebSocket logic for real-time location pings and trip updates.

```typescript
import { Server, Socket } from 'socket.io';
import { LocationService } from '../services/LocationService';

export const setupRideHandlers = (io: Server, socket: Socket) => {
  // 1. Driver updates their location
  socket.on('update_location', async (data: { driverId: string, lat: number, lng: number }) => {
    await LocationService.updateDriverLocation(data.driverId, data.lat, data.lng);

    // Broadcast to riders tracking this specific driver
    io.to(`trip_tracking_${data.driverId}`).emit('location_changed', {
      lat: data.lat,
      lng: data.lng
    });
  });

  // 2. Rider joins a room to track a specific driver
  socket.on('join_tracking', (tripId: string) => {
    socket.join(`trip_tracking_${tripId}`);
  });
};
```

