### 4. Trip Controller (`src/controllers/TripController.ts`)
The REST API logic for requesting and completing rides.

```typescript
import { Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class TripController {
  static async requestRide(req: Request, res: Response) {
    const { riderId, pickup, dropoff } = req.body;

    const trip = await prisma.trip.create({
      data: {
        riderId,
        pickupCoords: pickup,
        dropoffCoords: dropoff,
        status: 'REQUESTED'
      }
    });

    // In a real app, you would trigger a "searchNearbyDrivers" 
    // background job here using LocationService
    res.status(201).json(trip);
  }

  static async completeTrip(req: Request, res: Response) {
    const { tripId } = req.params;

    const trip = await prisma.trip.update({
      where: { id: tripId },
      data: { 
        status: 'COMPLETED',
        endTime: new Date()
      }
    });

    res.json(trip);
  }

  static async getHistory(req: Request, res: Response) {
    const { userId } = req.params;
    const history = await prisma.trip.findMany({
      where: {
        OR: [{ riderId: userId }, { driverId: userId }]
      },
      include: { ratings: true },
      orderBy: { createdAt: 'desc' }
    });
    res.json(history);
  }
}
```

