### 5. Secure Data Ingestion (Mutation)

When creating data, we must ensure the `tenant_id` is stamped correctly.

```typescript
// app/actions/create-project.ts
"use server"
import { getTenantContext } from "@/lib/tenant-context";
import { revalidatePath } from "next/cache";

export async function createProject(formData: FormData) {
  const { db, tenantId } = await getTenantContext();
  const name = formData.get("name") as string;

  await db.project.create({
    data: {
      name,
      tenant_id: tenantId, // Enforce the current tenant ID
    },
  });

  revalidatePath("/dashboard/projects");
}
