### 2. The Database Schema (`prisma/schema.prisma`)

We define three core tables: `Account`, `Transaction`, and `JournalEntry`.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum AccountType {
  ASSET
  LIABILITY
  EQUITY
  REVENUE
  EXPENSE
}

model Account {
  id          String         @id @default(uuid())
  name        String         @unique
  type        AccountType
  code        String         @unique // e.g., "1000" for Cash
  entries     JournalEntry[]
  createdAt   DateTime       @default(now())
}

model Transaction {
  id          String         @id @default(uuid())
  description String
  reference   String?        // External invoice ID or check number
  date        DateTime       @default(now())
  entries     JournalEntry[]
  createdAt   DateTime       @default(now())
}

model JournalEntry {
  id            String      @id @default(uuid())
  amount        Decimal     @db.Decimal(19, 4) // Supports high precision
  transactionId String
  transaction   Transaction @relation(fields: [transactionId], references: [id])
  accountId     String
  account       Account     @relation(fields: [accountId], references: [id])

  // amount > 0 is Debit, amount < 0 is Credit (or vice versa depending on account type)
  // Standard practice: Assets/Expenses are positive for Debits.
}
```

### 3. Ledger Logic Service (`src/services/ledger.ts`)

This service ensures the **Golden Rule of Accounting**: $\sum Debits + \sum Credits = 0$.

```typescript
import { prisma } from "../lib/prisma";
import { Decimal } from "decimal.js";

export interface EntryInput {
  accountId: string;
  amount: number | Decimal; // Positive for Debit, Negative for Credit
}

export class LedgerService {
  static async createTransaction(description: string, entries: EntryInput[], reference?: string) {
    // 1. Validate Double-Entry: Sum of amounts must be zero
    const total = entries.reduce(
      (sum, entry) => sum.plus(new Decimal(entry.amount)),
      new Decimal(0)
    );

    if (!total.isZero()) {
      throw new Error(`Unbalanced transaction: Sum is ${total.toString()}, must be 0.`);
    }

    // 2. Execute within a database transaction (ACID)
    return await prisma.$transaction(async (tx) => {
      const transaction = await tx.transaction.create({
        data: {
          description,
          reference,
          entries: {
            create: entries.map((e) => ({
              amount: new Decimal(e.amount),
              accountId: e.accountId,
            })),
          },
        },
        include: { entries: true },
      });

      return transaction;
    });
  }
}
```

### 4. Complex Reporting (`src/services/reports.ts`)

Instead of fetching all rows and summing in JavaScript (slow), we use SQL to calculate balances.

```typescript
import { prisma } from "../lib/prisma";

export class ReportService {
  /**
   * Generates a Trial Balance (Current balance of all accounts)
   */
  static async getTrialBalance() {
    return await prisma.$queryRaw`
      SELECT 
        a.id, 
        a.name, 
        a.type,
        a.code,
        SUM(e.amount) as balance
      FROM "Account" a
      LEFT JOIN "JournalEntry" e ON a.id = e."accountId"
      GROUP BY a.id, a.name, a.type, a.code
      ORDER BY a.code ASC
    `;
  }

  /**
   * Generates a Balance Sheet
   */
  static async getBalanceSheet() {
    const balances: any[] = await this.getTrialBalance();

    return {
      assets: balances.filter(b => b.type === 'ASSET'),
      liabilities: balances.filter(b => b.type === 'LIABILITY'),
      equity: balances.filter(b => b.type === 'EQUITY'),
      totalAssets: balances.filter(b => b.type === 'ASSET').reduce((s, b) => s + Number(b.balance), 0),
      // ... further logic to ensure Assets = Liabilities + Equity
    };
  }
}
```

