### 2. The Search Engine Logic (`lib/products.ts`)

This is the "brain" of the application. It handles both the product retrieval and the **facet calculation** (counting how many items exist per brand/category given the current filters).

```typescript
import { prisma } from "./prisma";

export interface FilterParams {
  q?: string;
  category?: string;
  brand?: string;
  minPrice?: string;
  maxPrice?: string;
  sort?: string;
}

export async function getProducts(params: FilterParams) {
  const { q, category, brand, minPrice, maxPrice, sort } = params;

  // 1. Build the Where clause
  const where: any = {
    AND: [
      q ? { name: { contains: q, mode: 'insensitive' } } : {},
      category ? { category } : {},
      brand ? { brand: { in: brand.split(',') } } : {},
      {
        price: {
          gte: minPrice ? parseFloat(minPrice) : 0,
          lte: maxPrice ? parseFloat(maxPrice) : 1000000,
        },
      },
    ],
  };

  // 2. Determine Sorting
  const orderBy: any = {};
  if (sort === 'price_asc') orderBy.price = 'asc';
  else if (sort === 'price_desc') orderBy.price = 'desc';
  else orderBy.createdAt = 'desc';

  // 3. Execute queries in parallel
  const [products, brands, categories] = await Promise.all([
    prisma.product.findMany({ where, orderBy }),
    // Get unique brands and their counts for current search
    prisma.product.groupBy({
      by: ['brand'],
      where: { ...where, brand: undefined }, // Don't filter by brand for the brand list
      _count: true,
    }),
    prisma.product.groupBy({
      by: ['category'],
      where: { ...where, category: undefined },
      _count: true,
    }),
  ]);

  return { products, brands, categories };
}
```

