#### The Filtering Hook (`hooks/useProductFilters.ts`)
This is the "brain" of the application.

```typescript
import { useMemo } from 'react';
import { Product, FilterState } from '../types';

export const useProductFilters = (products: Product[], filters: FilterState) => {
  return useMemo(() => {
    let filtered = [...products];

    // 1. Search Text
    if (filters.search) {
      const query = filters.search.toLowerCase();
      filtered = filtered.filter(p => 
        p.name.toLowerCase().includes(query) || p.brand.toLowerCase().includes(query)
      );
    }

    // 2. Category Filter (OR logic within category)
    if (filters.categories.length > 0) {
      filtered = filtered.filter(p => filters.categories.includes(p.category));
    }

    // 3. Brand Filter (OR logic within category)
    if (filters.brands.length > 0) {
      filtered = filtered.filter(p => filters.brands.includes(p.brand));
    }

    // 4. Price Range Filter
    filtered = filtered.filter(p => 
      p.price >= filters.priceRange[0] && p.price <= filters.priceRange[1]
    );

    // 5. Sorting
    filtered.sort((a, b) => {
      if (filters.sortBy === 'price-low') return a.price - b.price;
      if (filters.sortBy === 'price-high') return b.price - a.price;
      if (filters.sortBy === 'rating') return b.rating - a.rating;
      return 0;
    });

    return filtered;
  }, [products, filters]);
};
```

