### 2. The Search & Filtering Logic
We need a function that handles the filtering logic. On a large scale, this runs on the database/search engine. For this example, we'll implement it as a server-side utility.

```typescript
// lib/search-service.ts
import { products } from './mock-data';

export async function getFilteredProducts(params: {
  q?: string;
  category?: string[];
  brand?: string[];
  minPrice?: number;
  maxPrice?: number;
  sort?: string;
}) {
  let filtered = [...products];

  // 1. Text Search
  if (params.q) {
    filtered = filtered.filter(p => 
      p.name.toLowerCase().includes(params.q!.toLowerCase())
    );
  }

  // 2. Category Filter (Multi-select)
  if (params.category?.length) {
    filtered = filtered.filter(p => params.category!.includes(p.category));
  }

  // 3. Brand Filter
  if (params.brand?.length) {
    filtered = filtered.filter(p => params.brand!.includes(p.brand));
  }

  // 4. Price Filter
  if (params.minPrice) filtered = filtered.filter(p => p.price >= params.minPrice!);
  if (params.maxPrice) filtered = filtered.filter(p => p.price <= params.maxPrice!);

  // 5. Generate Facet Counts (based on current search results)
  const facets: any = {
    categories: {},
    brands: {},
  };

  filtered.forEach(p => {
    facets.categories[p.category] = (facets.categories[p.category] || 0) + 1;
    facets.brands[p.brand] = (facets.brands[p.brand] || 0) + 1;
  });

  return { products: filtered, facets };
}
```

