### 3. The Filter Sidebar Component
This component interacts with the URL to update search parameters.

```tsx
// components/search/filter-sidebar.tsx
'use client';

import { useRouter, useSearchParams, usePathname } from 'next/navigation';
import { useCallback } from 'react';

export default function FilterSidebar({ facets }: { facets: any }) {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();

  const createQueryString = useCallback(
    (name: string, value: string) => {
      const params = new URLSearchParams(searchParams.toString());
      const currentValues = params.getAll(name);

      if (currentValues.includes(value)) {
        const updated = currentValues.filter(v => v !== value);
        params.delete(name);
        updated.forEach(v => params.append(name, v));
      } else {
        params.append(name, value);
      }
      return params.toString();
    },
    [searchParams]
  );

  return (
    <aside className="w-64 space-y-8 p-4 border-r">
      <div>
        <h3 className="font-bold mb-4">Categories</h3>
        {Object.entries(facets.categories).map(([category, count]) => (
          <label key={category} className="flex items-center space-x-2 mb-2 cursor-pointer">
            <input
              type="checkbox"
              checked={searchParams.getAll('category').includes(category)}
              onChange={() => router.push(`${pathname}?${createQueryString('category', category)}`)}
              className="rounded border-gray-300"
            />
            <span className="text-sm">{category} ({count as number})</span>
          </label>
        ))}
      </div>

      <div>
        <h3 className="font-bold mb-4">Brands</h3>
        {Object.entries(facets.brands).map(([brand, count]) => (
          <label key={brand} className="flex items-center space-x-2 mb-2 cursor-pointer">
            <input
              type="checkbox"
              checked={searchParams.getAll('brand').includes(brand)}
