### 3. The Ingestor Service (Go)
This service is designed to be "dumb and fast." Its only job is to move data from MQTT to Redis as quickly as possible.

```go
package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log"

	mqtt "github.com/eclipse/paho.mqtt.golang"
	"github.com/go-redis/redis/v8"
)

var rdb *redis.Client
var ctx = context.Background()

type SensorPayload struct {
	DeviceID string  `json:"device_id"`
	Metric   string  `json:"metric"`
	Value    float64 `json:"value"`
	TS       int64   `json:"ts"`
}

func main() {
	// Initialize Redis
	rdb = redis.NewClient(&redis.Options{Addr: "localhost:6379"})

	// Initialize MQTT
	opts := mqtt.NewClientOptions().AddBroker("tcp://localhost:1883")
	opts.SetClientID("ingestor_service")

	client := mqtt.NewClient(opts)
	if token := client.Connect(); token.Wait() && token.Error() != nil {
		panic(token.Error())
	}

	// Subscribe to all device telemetry
	client.Subscribe("devices/+/telemetry", 1, func(client mqtt.Client, msg mqtt.Message) {
		// Offload to a goroutine to keep the MQTT loop free
		go handleMessage(msg.Payload())
	})

	fmt.Println("Ingestor is running...")
	select {} // Keep alive
}

func handleMessage(payload []byte) {
	// 1. Basic validation
	var data SensorPayload
	if err := json.Unmarshal(payload, &data); err != nil {
		log.Printf("Invalid JSON: %v", err)
		return
	}

	// 2. Push to Redis Stream (The Buffer)
	err := rdb.XAdd(ctx, &redis.XAddArgs{
		Stream: "sensor_stream",
		Values: map[string]interface{}{
			"data": payload,
		},
	}).Err()

	if err != nil {
		log.Printf("Redis Error: %v", err)
	}
}
```

---

### 4. The Processor Service (Go)
This service reads from Redis in batches and writes to TimescaleDB. Using batches is critical for database performance.

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"time"

	"github.com/go-redis/redis/v8"
	_ "github.com/lib/pq"
)

func main() {
	db, _ := sql.Open("postgres", "postgres://user:pass@localhost:5432/iot?sslmode=disable")
	rdb := redis.NewClient(&redis.Options{Addr: "localhost:6379"})
	ctx := context.Background()

	for {
		// Read batch from Redis
		streams, _ := rdb.XRead(ctx, &redis.XReadArgs{
			Streams: []string{"sensor_stream", "0"},
			Count:   100,
			Block:   2 * time.Second,
		}).Result()

		if len(streams) == 0 { continue }

		// Begin DB Transaction
		tx, _ := db.Begin()
		stmt, _ := tx.Prepare("INSERT INTO sensor_data (time, device_id, metric_name, value) VALUES ($1, $2, $3, $4)")

		for _, row := range streams[0].Messages {
			var p SensorPayload
			json.Unmarshal([]byte(row.Values["data"].(string)), &p)

			// Use the provided timestamp or current time
			ts := time.Unix(p.TS, 0)
			stmt.Exec(ts, p.DeviceID, p.Metric, p.Value)

			// Acknowledge Redis (remove from stream)
			rdb.XDel(ctx, "sensor_stream", row.ID)
		}
		tx.Commit()
	}
}
```

