### 2. The Implementation (Go + Redis)

#### `internal/redis/leaderboard.go`
This is the core logic. We use `ZAdd` to update scores and `ZRevRank` to find positions.

```go
package redis

import (
	"context"
	"githubgo-redis/redis/v8"
)

type LeaderboardStore struct {
	client *redis.Client
	key    string
}

func NewLeaderboardStore(client *redis.Client) *LeaderboardStore {
	return &LeaderboardStore{
		client: client,
		key:    "game_leaderboard",
	}
}

// UpdateScore adds or updates a user's score. O(log(N))
func (s *LeaderboardStore) UpdateScore(ctx context.Context, userID string, score float64) error {
	return s.client.ZAdd(ctx, s.key, &redis.Z{
		Score:  score,
		Member: userID,
	}).Err()
}

// GetTopPlayers retrieves the top N players. O(log(N)+M)
func (s *LeaderboardStore) GetTopPlayers(ctx context.Context, limit int64) ([]redis.Z, error) {
	return s.client.ZRevRangeWithScores(ctx, s.key, 0, limit-1).Result()
}

// GetUserRank gets a user's rank and score.
func (s *LeaderboardStore) GetUserRank(ctx context.Context, userID string) (int64, float64, error) {
	pipe := s.client.Pipeline()
	rankCmd := pipe.ZRevRank(ctx, s.key, userID)
	scoreCmd := pipe.ZScore(ctx, s.key, userID)

	_, err := pipe.Exec(ctx)
	if err != nil {
		return 0, 0, err
	}

	return rankCmd.Val() + 1, scoreCmd.Val(), nil // +1 because Redis rank is 0-indexed
}
```

#### `main.go`
High-performance API using the **Fiber** framework (similar Express.js but for Go).

```go
package main

import (
	"log"
	"github.com/gofiber/fiber/v2"
	"github.com/go-redis/redis/v8"
	"leaderboard-api/internal/redis"
)

func main() {
	app := fiber.New()

	// Initialize Redis
	rdb := redis.NewClient(&redis.Options{
		Addr: "localhost:6379",
	})
	lb := redis.NewLeaderboardStore(rdb)

	// POST /score - Update user score
	app.Post("/score", func(c *fiber.Ctx) error {
		type Request struct {
			UserID string  `json:"user_id"`
			Score  float64 `json:"score"`
		}
		var req Request
		if err := c.BodyParser(&req); err != nil {
			return c.Status(400).SendString(err.Error())
		}

		err := lb.UpdateScore(c.Context(), req.UserID, req.Score)
		if err != nil {
			return c.Status(500).SendString(err.Error())
		}
		return c.SendStatus(204)
	})

	// GET /top - Get global top 10
	app.Get("/top", func(c *fiber.Ctx) error {
		top, err := lb.GetTopPlayers(c.Context(), 10)
		if err != nil {
			return c.Status(500).SendString(err.Error())
		}
		return c.JSON(top)
	})

	// GET /rank/:userID - Get specific user rank
	app.Get("/rank/:userID", func(c *fiber.Ctx) error {
		userID := c.Params("userID")
		rank, score, err := lb.GetUserRank(c.Context(), userID)
		if err != nil {
			return c.Status(404).SendString("User not found")
		}
		return c.JSON(fiber.Map{
			"user_id": userID,
			"rank":    rank,
			"score":   score,
		})
	})

	log.Fatal(app.Listen(":3000"))
}
```

