#### B. The Score Worker (`src/worker.ts`)
Decoupling the score update from the API request ensures that the API remains responsive.

```typescript
import { Worker } from 'bullmq';
import { redis } from './lib/redis';

const LEADERBOARD_KEY = 'game_leaderboard';

const worker = new Worker('score-updates', async (job) => {
  const { userId, score, username } = job.data;

  // ZADD updates the score if user exists, or creates it if not.
  // We use 'INCR' to add to existing score, or omit it to overwrite.
  await redis.zadd(LEADERBOARD_KEY, 'GT', score, userId);

  // Store metadata (username) in a separate Hash
  await redis.hset('user_metadata', userId, username);

  return { userId, score };
}, { connection: redis });

console.log('Worker started processing scores...');
```

#### C. The Main Server (`src/server.ts`)
This handles the API endpoints and the WebSocket connections.

```typescript
import Fastify from 'fastify';
import { Server } from 'socket.io';
import { Queue } from 'bullmq';
import { redis } from './lib/redis';

const app = Fastify();
const scoreQueue = new Queue('score-updates', { connection: redis });
const LEADERBOARD_KEY = 'game_leaderboard';

// 1. Submit Score Endpoint
app.post('/score', async (req, reply) => {
  const { userId, score, username } = req.body as any;

  // Add to queue for asynchronous processing
  await scoreQueue.add('update-score', { userId, score, username });

  return { status: 'queued' };
});

// 2. Get Leaderboard (Top 10)
app.get('/leaderboard', async () => {
  // ZREVRANGE gives us the highest scores first
  const rawRange = await redis.zrevrange(LEADERBOARD_KEY, 0, 9, 'WITHSCORES');

  // Format the response
  const leaders = [];
  for (let i = 0; i < rawRange.length; i += 2) {
    const userId = rawRange[i];
    const username = await redis.hget('user_metadata', userId);
    leaders.push({
      rank: Math.floor(i / 2) + 1,
      userId,
      username,
      score: rawRange[i + 1]
    });
  }
  return leaders;
});

// 3. Get User Rank (Specific User)
app.get('/rank/:userId', async (req) => {
  const { userId } = req.params as any;
  const rank = await redis.zrevrank(LEADERBOARD_KEY, userId);
  const score = await redis.zscore(LEADERBOARD_KEY, userId);

  return { 
    userId, 
    rank: rank !== null ? rank + 1 : null, 
    score: score || 0 
  };
});

// Real-time setup
const io = new Server(app.server, { cors: { origin: '*' } });

io.on('connection', (socket) => {
  console.log('User connected:', socket.id);

  // Optionally: Join user to a room based on their Rank Range
  // to push targeted updates
});

// Periodically broadcast Top 10 to everyone
setInterval(async () => {
    const top10 = await app.inject({ method: 'GET', url: '/leaderboard' });
    io.emit('leaderboard_update', top10.json());
}, 2000);

app.listen({ port: 3000 }, () => console.log('Server running on port 3000'));
```

