### 3. Core Promotion Engine Logic
This service handles the validation and calculation logic.

```typescript
// src/services/promotion.service.ts
import { PrismaClient, DiscountType } from '@prisma/client';
const prisma = new PrismaClient();

export class PromotionService {
  /**
   * Validates if a coupon can be applied to a specific cart
   */
  async validateAndCalculate(code: string, userId: string, orderAmount: number) {
    const coupon = await prisma.coupon.findUnique({
      where: { code: code.toUpperCase() }
    });

    if (!coupon || !coupon.isActive) throw new Error("Invalid coupon code.");

    // 1. Date Validation
    const now = new Date();
    if (now < coupon.startDate || (coupon.endDate && now > coupon.endDate)) {
      throw new Error("Coupon has expired.");
    }

    // 2. Minimum Spend Validation
    if (orderAmount < Number(coupon.minOrderValue)) {
      throw new Error(`Minimum spend of $${coupon.minOrderValue} required.`);
    }

    // 3. Global Usage Limit
    if (coupon.usageLimit && coupon.usageCount >= coupon.usageLimit) {
      throw new Error("Coupon usage limit reached.");
    }

    // 4. Per User Limit
    const userRedemptions = await prisma.redemption.count({
      where: { couponId: coupon.id, userId }
    });
    if (userRedemptions >= coupon.perUserLimit) {
      throw new Error("You have already used this coupon.");
    }

    // 5. Calculate Discount
    let discount = 0;
    if (coupon.discountType === DiscountType.PERCENTAGE) {
      discount = orderAmount * (Number(coupon.discountValue) / 100);
      if (coupon.maxDiscount && discount > Number(coupon.maxDiscount)) {
        discount = Number(coupon.maxDiscount);
      }
    } else {
      discount = Number(coupon.discountValue);
    }

    // Ensure discount doesn't exceed order amount
    return {
      couponId: coupon.id,
      discount: Math.min(discount, orderAmount),
      finalAmount: Math.max(0, orderAmount - discount)
    };
  }

  /**
   * Executes the redemption within a transaction to ensure atomicity
   */
  async redeem(code: string, userId: string, orderId: string, orderAmount: number) {
    return await prisma.$transaction(async (tx) => {
      // Re-validate inside transaction to prevent race conditions
      const result = await this.validateAndCalculate(code, userId, orderAmount);

      // 1. Increment usage count
      const updatedCoupon = await tx.coupon.update({
        where: { id: result.couponId },
        data: { usageCount: { increment: 1 } }
      });

      // Double check concurrency limit
      if (updatedCoupon.usageLimit && updatedCoupon.usageCount > updatedCoupon.usageLimit) {
        throw new Error("Coupon just reached its limit.");
      }

      // 2. Create redemption record
      return await tx.redemption.create({
        data: {
          couponId: result.couponId,
          userId,
          orderId,
          discountApplied: result.discount
        }
      });
    });
  }
}
```

