### 2. The Promotion Engine Logic

This is the core service. It handles validation and calculation.

```typescript
// promotion.service.ts
import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from './prisma.service';

interface Cart {
  items: { productId: string; price: number; quantity: number }[];
  userId: string;
}

@Injectable()
export class PromotionService {
  constructor(private prisma: PrismaService) {}

  async validateAndCalculate(code: string, cart: Cart) {
    const coupon = await this.prisma.coupon.findUnique({
      where: { code },
      include: { promotion: true },
    });

    if (!coupon || !coupon.promotion.isActive) {
      throw new BadRequestException('Invalid or inactive coupon.');
    }

    const { promotion } = coupon;
    const now = new Date();

    // 1. Basic Eligibility Checks
    if (now < promotion.startsAt || (promotion.endsAt && now > promotion.endsAt)) {
      throw new BadRequestException('Coupon has expired.');
    }

    if (promotion.usageLimit && promotion.usageCount >= promotion.usageLimit) {
      throw new BadRequestException('Coupon usage limit reached.');
    }

    // 2. Order Value Check
    const subtotal = cart.items.reduce((sum, item) => sum + item.price * item.quantity, 0);
    if (subtotal < Number(promotion.minOrderValue)) {
      throw new BadRequestException(`Minimum order value of ${promotion.minOrderValue} not met.`);
    }

    // 3. User Specific Limits
    const userRedemptions = await this.prisma.redemption.count({
      where: { couponId: coupon.id, userId: cart.userId },
    });

    if (userRedemptions >= coupon.maxUsagePerUser) {
      throw new BadRequestException('You have already used this coupon.');
    }

    // 4. Calculate Discount
    let discountAmount = 0;
    if (promotion.discountType === 'PERCENTAGE') {
      discountAmount = subtotal * (Number(promotion.discountValue) / 100);
      if (promotion.maxDiscount) {
        discountAmount = Math.min(discountAmount, Number(promotion.maxDiscount));
      }
    } else if (promotion.discountType === 'FIXED_AMOUNT') {
      discountAmount = Number(promotion.discountValue);
    }

    return {
      couponId: coupon.id,
      discountAmount: Math.min(discountAmount, subtotal), // Cannot discount more than total
      newTotal: subtotal - discountAmount,
    };
  }

  async redeem(code: string, orderId: string, userId: string, cart: Cart) {
    // We run the calculation again to ensure data hasn't changed
    const { couponId, discountAmount } = await this.validateAndCalculate(code, cart);

    // Use a Transaction to ensure atomicity
    return this.prisma.$transaction(async (tx) => {
      // 1. Create redemption record
      const redemption = await tx.redemption.create({
        data: {
          couponId,
          orderId,
          userId,
          amountSaved: discountAmount,
        },
      });

      // 2. Increment promotion usage
      const coupon = await tx.coupon.findUnique({ where: { id: couponId } });
      await tx.promotion.update({
        where: { id: coupon.promotionId },
        data: { usageCount: { increment: 1 } },
      });

      return redemption;
    });
  }
}
```

