### 2. The Promotion Engine Logic

The core logic resides in a `PromotionService`. It validates eligibility and calculates the actual discount.

```typescript
// src/services/promotion.service.ts

import { PrismaClient, Coupon, DiscountType } from '@prisma/client';
import { Decimal } from '@prisma/client/runtime/library';

const prisma = new PrismaClient();

interface CartItem {
  id: string;
  price: number;
  quantity: number;
  categoryId: string;
}

interface Cart {
  userId: string;
  items: CartItem[];
  subtotal: number;
}

export class PromotionService {
  /**
   * Validates if a coupon can be applied and calculates the discount
   */
  async validateAndCalculate(code: string, cart: Cart) {
    const coupon = await prisma.coupon.findUnique({
      where: { code: code.toUpperCase() },
    });

    if (!coupon || !coupon.isActive) {
      throw new Error('Coupon not found or inactive');
    }

    // 1. Basic Validity Checks
    const now = new Date();
    if (coupon.startDate > now || (coupon.endDate && coupon.endDate < now)) {
      throw new Error('Coupon is expired or not yet active');
    }

    if (coupon.maxUsage && coupon.usageCount >= coupon.maxUsage) {
      throw new Error('Coupon usage limit reached');
    }

    if (new Decimal(cart.subtotal).lt(coupon.minOrderAmount)) {
      throw new Error(`Minimum order amount of ${coupon.minOrderAmount} not met`);
    }

    // 2. User-specific limits
    const userRedemptions = await prisma.redemption.count({
      where: { couponId: coupon.id, userId: cart.userId },
    });

    if (userRedemptions >= coupon.perUserLimit) {
      throw new Error('You have already used this coupon the maximum number of times');
    }

    // 3. Calculate Discount
    const discountAmount = this.calculateDiscount(coupon, cart);

    return {
      couponId: coupon.id,
      code: coupon.code,
      discountAmount,
      finalTotal: Math.max(0, cart.subtotal - discountAmount),
    };
  }

  private calculateDiscount(coupon: Coupon, cart: Cart): number {
    let discount = 0;

    switch (coupon.discountType) {
      case DiscountType.FIXED_AMOUNT:
        discount = Number(coupon.discountValue);
        break;

      case DiscountType.PERCENTAGE:
        discount = (cart.subtotal * Number(coupon.discountValue)) / 100;
        if (coupon.maxDiscount) {
          discount = Math.min(discount, Number(coupon.maxDiscount));
        }
        break;

      case DiscountType.BOGO:
        // Logic: Find cheapest item in cart and make it free
        if (cart.items.length >= 2) {
          const prices = cart.items.map(i => i.price);
          discount = Math.min(...prices);
        }
        break;
    }

    return discount;
  }

  /**
   * Atomic redemption of a coupon
   */
  async redeem(code: string, cart: Cart, orderId: string) {
    return await prisma.$transaction(async (tx) => {
      // Re-validate inside transaction to prevent race conditions
      const validation = await this.validateAndCalculate(code, cart);

      // Increment usage
      const updatedCoupon = await tx.coupon.update({
        where: { id: validation.couponId },
        data: { usageCount: { increment: 1 } },
      });

      // Log redemption
      const redemption = await tx.redemption.create({
        data: {
          couponId: validation.couponId,
          userId: cart.userId,
          orderId: orderId,
          amountSaved: validation.discountAmount,
        },
      });

      return { redemption, updatedCoupon };
    });
  }
}
```

