### 2. The Core Matching Logic

The biggest challenge is: *Does the driver's route pass near the rider's pickup and drop-off points?*

We use PostGIS `ST_DWithin` to find points within a radius (e.g., 2km).

```typescript
// src/services/matching.service.ts

import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export const findMatchingTrips = async (params: {
  pickupLng: number;
  pickupLat: number;
  dropoffLng: number;
  dropoffLat: number;
  radiusMeters: number;
  startTime: Date;
  seatsNeeded: number;
}) => {
  // We use raw SQL because Prisma doesn't natively support all PostGIS functions yet
  return await prisma.$queryRaw`
    SELECT 
      t.id, 
      t."driverId", 
      t."departureTime", 
      t."availableSeats",
      ST_Distance(t."startLocation", ST_SetSRID(ST_MakePoint(${params.pickupLng}, ${params.pickupLat}), 4326)) as pickup_distance
    FROM "Trip" t
    WHERE 
      t."availableSeats" >= ${params.seatsNeeded}
      AND t."status" = 'SCHEDULED'
      -- Check if pickup is within radius
      AND ST_DWithin(t."startLocation", ST_SetSRID(ST_MakePoint(${params.pickupLng}, ${params.pickupLat}), 4326), ${params.radiusMeters})
      -- Check if dropoff is within radius
      AND ST_DWithin(t."endLocation", ST_SetSRID(ST_MakePoint(${params.dropoffLng}, ${params.dropoffLat}), 4326), ${params.radiusMeters})
      -- Time window: +/- 30 minutes
      AND t."departureTime" BETWEEN ${params.startTime}::timestamp - interval '30 minutes' 
                            AND ${params.startTime}::timestamp + interval '30 minutes'
    ORDER BY pickup_distance ASC
    LIMIT 10;
  `;
};
```

