### 3. Atomic Booking (Concurrency Control)

To prevent overbooking (two people grabbing the last seat simultaneously), we use a database transaction.

```typescript
// src/services/booking.service.ts

export const createBooking = async (tripId: string, riderId: string, seats: number) => {
  return await prisma.$transaction(async (tx) => {
    // 1. Lock the trip row for update to prevent concurrent modifications
    const trip = await tx.$queryRaw<any[]>`
      SELECT "availableSeats" FROM "Trip" 
      WHERE id = ${tripId} 
      FOR UPDATE
    `;

    if (!trip[0] || trip[0].availableSeats < seats) {
      throw new Error("Not enough seats available");
    }

    // 2. Create the booking
    const booking = await tx.booking.create({
      data: { tripId, riderId, seats, status: 'CONFIRMED' }
    });

    // 3. Decrement available seats
    await tx.trip.update({
      where: { id: tripId },
      data: { availableSeats: { decrement: seats } }
    });

    return booking;
  });
};
```

