### 2. The Matching Logic (Core Algorithm)

The "Search" functionality is the heart of the app. We need to find rides that match the rider's origin, destination, and schedule.

```typescript
// src/services/ride.service.ts
import { prisma } from "../lib/prisma";

export const searchRides = async (
  originLng: number,
  originLat: number,
  destLng: number,
  destLat: number,
  date: Date,
  radiusInMeters: number = 2000 // 2km default
) => {
  /**
   * We use raw SQL because Prisma doesn't natively support PostGIS functions yet.
   * ST_DWithin: Checks if points are within a specific distance.
   * 4326: The standard coordinate system (WGS 84).
   */
  const rides = await prisma.$queryRaw`
    SELECT 
      id, "driverId", "departureTime", "availableSeats", price,
      ST_X(origin::geometry) as lng, ST_Y(origin::geometry) as lat
    FROM "Ride"
    WHERE "availableSeats" > 0
    AND "departureTime" >= ${date}
    AND ST_DWithin(origin, ST_MakePoint(${originLng}, ${originLat})::geography, ${radiusInMeters})
    AND ST_DWithin(destination, ST_MakePoint(${destLng}, ${destLat})::geography, ${radiusInMeters})
    ORDER BY "departureTime" ASC
    LIMIT 50;
  `;

  return rides;
};
```

