    VALUES (
      gen_random_uuid(), 
      ${driverId}, 
      ST_SetSRID(ST_MakePoint(${origin.lng}, ${origin.lat}), 4326),
      ST_SetSRID(ST_MakePoint(${destination.lng}, ${destination.lat}), 4326),
      ${new Date(departureTime)}, 
      ${totalSeats}, 
      ${totalSeats}, 
      ${price}
    )
  `;

  res.status(201).json({ message: "Ride published successfully" });
};
