### 4. Booking a Seat (Concurrency Control)

We use a **Database Transaction** to ensure two riders don't book the last seat at the same time.

```typescript
// src/services/booking.service.ts
export const bookRide = async (rideId: string, riderId: string) => {
  return await prisma.$transaction(async (tx) => {
    // 1. Lock the ride row for update to prevent concurrent seat selection
    const ride = await tx.ride.findUnique({
      where: { id: rideId },
    });

    if (!ride || ride.availableSeats <= 0) {
      throw new Error("No seats available");
    }

    // 2. Decrement seat count
    await tx.ride.update({
      where: { id: rideId },
      data: { availableSeats: { decrement: 1 } },
    });

    // 3. Create booking
    return await tx.booking.create({
      data: {
        rideId,
        riderId,
        status: 'CONFIRMED'
      },
    });
  });
};
```

