### 3. The Matching Engine (Core Logic)
The most critical part is the `MatchingService`. It uses raw SQL to leverage PostGIS `ST_DWithin` for spatial efficiency.

```typescript
// src/matching/matching.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class MatchingService {
  constructor(private prisma: PrismaService) {}

  /**
   * Finds available trips for a specific ride request
   * Strategy: 
   * 1. Start point within 2km of driver's start
   * 2. End point within 2km of driver's end
   * 3. Time window matches
   * 4. Enough seats available
   */
  async findMatchesForRequest(requestId: string) {
    const request = await this.prisma.rideRequest.findUnique({
      where: { id: requestId },
    });

    if (!request) throw new Error('Request not found');

    // We use raw SQL because Prisma doesn't natively support PostGIS operators yet
    return this.prisma.$queryRaw`
      SELECT t.id, t."driverId", t."availableSeats", t."departureTime"
      FROM "Trip" t
      WHERE t."availableSeats" >= ${request.seatsNeeded}
      AND t."status" = 'PLANNED'
      -- Spatial: Driver start within 2000m of Rider pickup
      AND ST_DWithin(t."startLocation", 
                     (SELECT "pickupLocation" FROM "RideRequest" WHERE id = ${requestId}), 
                     2000)
      -- Spatial: Driver end within 2000m of Rider dropoff
      AND ST_DWithin(t."endLocation", 
                     (SELECT "dropoffLocation" FROM "RideRequest" WHERE id = ${requestId}), 
                     2000)
      -- Temporal: Trip departs between rider's window
      AND t."departureTime" BETWEEN ${request.earliestDeparture} AND ${request.latestDeparture}
      ORDER BY t."departureTime" ASC;
    `;
  }
}
```

