### 4. Handling Transactions (Booking)
When a match is found and a rider chooses a trip, we must use a database transaction to ensure seat availability doesn't result in "overbooking" due to race conditions.

```typescript
// src/trips/trips.service.ts
import { Injectable, BadRequestException } from '@nestjs/common';

@Injectable()
export class TripService {
  constructor(private prisma: PrismaService) {}

  async bookTrip(tripId: string, requestId: string) {
    return this.prisma.$transaction(async (tx) => {
      // 1. Lock the trip row for update to prevent concurrent booking issues
      const trip = await tx.$queryRaw<any[]>`
        SELECT * FROM "Trip" WHERE id = ${tripId} FOR UPDATE
      `.then(res => res[0]);

      const request = await tx.rideRequest.findUnique({
        where: { id: requestId }
      });

      if (trip.availableSeats < request.seatsNeeded) {
        throw new BadRequestException('Not enough seats available');
      }

      // 2. Create booking
      const booking = await tx.booking.create({
        data: { tripId, rideRequestId: requestId }
      });

      // 3. Decrement seats
      await tx.trip.update({
        where: { id: tripId },
        data: { availableSeats: { decrement: request.seatsNeeded } }
      });

      // 4. Update request status
      await tx.rideRequest.update({
        where: { id: requestId },
        data: { status: 'MATCHED' }
      });

      return booking;
    });
  }
}
```

