### 2. Backend Implementation (Express + Prisma)

This controller handles updating the ticket and **atomically** creating a status history record.

```typescript
// server/routes/tickets.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';

const prisma = new PrismaClient();
const router = Router();

// Update Ticket Status
router.patch('/:id/status', async (req, res) => {
  const { id } = req.params;
  const { status, userId } = req.body; // In production, get userId from Auth middleware

  try {
    const ticket = await prisma.ticket.findUnique({ where: { id } });
    if (!ticket) return res.status(404).json({ error: "Ticket not found" });

    // Use a Transaction to ensure both update and history are saved
    const updatedTicket = await prisma.$transaction(async (tx) => {
      const updated = await tx.ticket.update({
        where: { id },
        data: { status },
      });

      await tx.statusHistory.create({
        data: {
          ticketId: id,
          oldStatus: ticket.status,
          newStatus: status,
          changedBy: userId,
        },
      });

      return updated;
    });

    res.json(updatedTicket);
  } catch (error) {
    res.status(500).json({ error: "Failed to update ticket" });
  }
});

// Post a Comment
router.post('/:id/comments', async (req, res) => {
  const { id } = req.params;
  const { body, authorId } = req.body;

  const comment = await prisma.comment.create({
    data: {
      body,
      ticketId: id,
      authorId,
    },
    include: { author: true }
  });

  res.json(comment);
});

export default router;
```

