### 2. Core Logic: Server Actions (`lib/actions.ts`)

These functions handle the business logic and ensure the `StatusHistory` is updated whenever a ticket's status changes.

```typescript
"use server";

import { revalidatePath } from "next/cache";
import { prisma } from "@/lib/db"; // Standard Prisma client export
import { Status, Priority } from "@prisma/client";

export async function createTicket(formData: FormData) {
  const title = formData.get("title") as string;
  const description = formData.get("description") as string;
  const priority = formData.get("priority") as Priority;
  const email = formData.get("email") as string;

  const ticket = await prisma.ticket.create({
    data: {
      title,
      description,
      priority,
      creatorEmail: email,
    },
  });

  revalidatePath("/");
  return ticket;
}

export async function updateTicketStatus(
  ticketId: string, 
  newStatus: Status, 
  userEmail: string
) {
  const ticket = await prisma.ticket.findUnique({ where: { id: ticketId } });
  if (!ticket) throw new Error("Ticket not found");

  // Atomic transaction: Update ticket AND create history log
  await prisma.$transaction([
    prisma.ticket.update({
      where: { id: ticketId },
      data: { status: newStatus },
    }),
    prisma.statusHistory.create({
      data: {
        ticketId,
        oldStatus: ticket.status,
        newStatus,
        changedBy: userEmail,
      },
    }),
  ]);

  revalidatePath(`/tickets/${ticketId}`);
}

export async function addComment(ticketId: string, content: string, author: string) {
  await prisma.comment.create({
    data: {
      content,
      ticketId,
      author,
    },
  });
  revalidatePath(`/tickets/${ticketId}`);
}
```

