### 2. Backend Implementation (Express)

We will implement a controller that ensures status changes are logged atomically.

```typescript
// server/routes/tickets.ts
import express from 'express';
import { PrismaClient } from '@prisma/client';
import multer from 'multer';

const prisma = new PrismaClient();
const router = express.Router();
const upload = multer({ dest: 'uploads/' });

// Create Ticket
router.post('/', async (req, res) => {
  const { title, description, priority, creatorId } = req.body;
  const ticket = await prisma.ticket.create({
    data: { title, description, priority, creatorId },
  });
  res.json(ticket);
});

// Update Status (with History)
router.patch('/:id/status', async (req, res) => {
  const { id } = req.params;
  const { status, userId } = req.body;

  const oldTicket = await prisma.ticket.findUnique({ where: { id } });

  const [updatedTicket] = await prisma.$transaction([
    prisma.ticket.update({
      where: { id },
      data: { status },
    }),
    prisma.statusHistory.create({
      data: {
        ticketId: id,
        oldStatus: oldTicket!.status,
        newStatus: status,
        changedBy: userId,
      },
    }),
  ]);

  res.json(updatedTicket);
});

// Add Comment
router.post('/:id/comments', async (req, res) => {
  const { id } = req.params;
  const { content, authorId } = req.body;
  const comment = await prisma.comment.create({
    data: { content, ticketId: id, authorId },
    include: { author: true }
  });
  res.json(comment);
});

// Upload Attachment
router.post('/:id/attachments', upload.single('file'), async (req, res) => {
  const { id } = req.params;
  const attachment = await prisma.attachment.create({
    data: {
      filename: req.file!.originalname,
      url: `/uploads/${req.file!.filename}`,
      ticketId: id,
    },
  });
  res.json(attachment);
});

export default router;
```

