### 2. Core Notification Logic

The `NotificationService` is the heart of the application. It validates preferences and renders templates.

```typescript
// src/notifications/notifications.service.ts

import { Injectable, BadRequestException, Logger } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { Channel, DeliveryStatus } from '@prisma/client';
import { SendNotificationDto } from './dto/send-notification.dto';
import * as Mustache from 'mustache'; // For template parsing

@Injectable()
export class NotificationsService {
  private readonly logger = new Logger(NotificationsService.name);

  constructor(private prisma: PrismaService) {}

  async send(dto: SendNotificationDto) {
    const { userId, templateSlug, context } = dto;

    // 1. Fetch Template
    const template = await this.prisma.messageTemplate.findUnique({
      where: { slug: templateSlug },
    });
    if (!template) throw new BadRequestException('Template not found');

    // 2. Check User Preferences
    const preference = await this.prisma.userPreference.findUnique({
      where: {
        userId_channel_notificationType: {
          userId,
          channel: template.channel,
          notificationType: 'TRANSACTIONAL', // Or dynamic based on template
        },
      },
    });

    if (preference && !preference.enabled) {
      this.logger.log(`Notification suppressed for user ${userId} via ${template.channel}`);
      return { status: 'skipped', reason: 'User opted out' };
    }

    // 3. Render Content
    const renderedBody = Mustache.render(template.body, context);
    const renderedSubject = template.subject ? Mustache.render(template.subject, context) : null;

    // 4. Record Initial Log
    const log = await this.prisma.notificationLog.create({
      data: {
        userId,
        templateSlug,
        channel: template.channel,
        status: DeliveryStatus.PENDING,
        metadata: context,
      },
    });

    try {
      // 5. Dispatch to Provider (Abstracted)
      await this.dispatchToProvider(template.channel, {
        to: userId, // In production, look up user's email/phone
        subject: renderedSubject,
        body: renderedBody,
      });

      // 6. Update Log Success
      await this.prisma.notificationLog.update({
        where: { id: log.id },
        data: { status: DeliveryStatus.SENT },
      });

      return { success: true, logId: log.id };
    } catch (error) {
      // 7. Update Log Failure
      await this.prisma.notificationLog.update({
        where: { id: log.id },
        data: { 
          status: DeliveryStatus.FAILED, 
          errorMessage: error.message 
        },
      });
      throw error;
    }
  }

  private async dispatchToProvider(channel: Channel, payload: any) {
    // Integration logic for SendGrid, Twilio, or Firebase would go here
    this.logger.debug(`Sending ${channel} to ${payload.to}...`);
    // Simulated delay
    return new Promise((resolve) => setTimeout(resolve, 100));
  }
}
```

