### 3. Core Notification Logic

The `NotificationService` handles template rendering, preference checking, and logging.

```typescript
// src/services/NotificationService.ts

import { PrismaClient, Channel } from '@prisma/client';
import Handlebars from 'handlebars';

const prisma = new PrismaClient();

export class NotificationService {
  /**
   * Main entry point for sending a notification
   */
  static async send(userId: string, templateSlug: string, data: Record<string, any>) {
    // 1. Fetch Template
    const template = await prisma.notificationTemplate.findUnique({
      where: { slug: templateSlug }
    });

    if (!template) throw new Error("Template not found");

    // 2. Check User Preferences
    const prefs = await prisma.userPreference.findUnique({ where: { userId } });
    const isEnabled = this.checkPreference(prefs, template.channel);

    if (!isEnabled) {
      console.log(`User ${userId} has disabled ${template.channel} notifications.`);
      return;
    }

    // 3. Compile Template
    const renderedBody = Handlebars.compile(template.body)(data);
    const renderedSubject = template.subject 
      ? Handlebars.compile(template.subject)(data) 
      : undefined;

    // 4. Dispatch (Mocking the actual transport)
    try {
      await this.dispatchToProvider(template.channel, renderedBody, renderedSubject);

      // 5. Log Success
      await prisma.notificationLog.create({
        data: {
          userId,
          templateId: template.id,
          channel: template.channel,
          status: 'SENT',
          metadata: data
        }
      });
    } catch (error: any) {
      // 6. Log Failure
      await prisma.notificationLog.create({
        data: {
          userId,
          templateId: template.id,
          channel: template.channel,
          status: 'FAILED',
          errorMessage: error.message,
          metadata: data
        }
      });
    }
  }

  private static checkPreference(prefs: any, channel: Channel): boolean {
    if (!prefs) return true; // Default to on if no prefs set
    if (channel === 'EMAIL') return prefs.emailEnabled;
    if (channel === 'SMS') return prefs.smsEnabled;
    if (channel === 'PUSH') return prefs.pushEnabled;
    return false;
  }

  private static async dispatchToProvider(channel: Channel, body: string, subject?: string) {
    // Here you would integrate SendGrid, Twilio, etc.
    console.log(`[DISPATCHING ${channel}] Sub: ${subject} | Body: ${body}`);
    // Simulate API call
    return Promise.resolve();
  }
}
