### 4. API Layer

We expose endpoints to manage preferences, templates, and trigger sends.

```typescript
// src/index.ts

import express from 'express';
import { PrismaClient } from '@prisma/client';
import { NotificationService } from './services/NotificationService';
import { z } from 'zod';

const app = express();
const prisma = new PrismaClient();
app.use(express.json());

// --- Routes ---

// 1. Update User Preferences
app.put('/preferences/:userId', async (req, res) => {
  const schema = z.object({
    emailEnabled: z.boolean().optional(),
    smsEnabled: z.boolean().optional(),
    pushEnabled: z.boolean().optional(),
  });

  const data = schema.parse(req.body);
  const { userId } = req.params;

  const prefs = await prisma.userPreference.upsert({
    where: { userId },
    update: data,
    create: { userId, ...data },
  });

  res.json(prefs);
});

// 2. Create a Template
app.post('/templates', async (req, res) => {
  const schema = z.object({
    slug: z.string(),
    channel: z.enum(['EMAIL', 'SMS', 'PUSH']),
    subject: z.string().optional(),
    body: z.string(),
  });

  const template = await prisma.notificationTemplate.create({
    data: schema.parse(req.body)
  });

  res.status(201).json(template);
});

// 3. Trigger Notification
app.post('/send', async (req, res) => {
  const { userId, templateSlug, data } = req.body;

  // We don't 'await' this in a real production app. 
  // We would push this to a Background Queue (Redis/BullMQ).
  NotificationService.send(userId, templateSlug, data);

  res.status(202).json({ message: "Notification queued" });
});

// 4. Get History
app.get('/history/:userId', async (req, res) => {
  const logs = await prisma.notificationLog.findMany({
    where: { userId: req.params.userId },
    include: { template: true },
    orderBy: { sentAt: 'desc' }
  });
  res.json(logs);
});

app.listen(3000, () => console.log('Notification Service running on port 3000'));
```

