### 4. Implementation

#### Template Service
This handles the logic for parsing placeholders in templates.

```typescript
// src/templates/templates.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class TemplatesService {
  constructor(private prisma: PrismaService) {}

  async getTemplateBySlug(slug: string) {
    return this.prisma.template.findUnique({ where: { slug } });
  }

  // Simple interpolation: "Hello {{name}}" -> "Hello Alice"
  compile(content: string, variables: Record<string, any>): string {
    return content.replace(/\{\{(.*?)\}\}/g, (match, key) => {
      return variables[key.trim()] || match;
    });
  }
}
```

#### Notification Engine
This is the core logic that orchestrates the flow.

```typescript
// src/notifications/notifications.service.ts
import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { TemplatesService } from '../templates/templates.service';
import { Channel, DeliveryStatus } from '@prisma/client';

@Injectable()
export class NotificationsService {
  constructor(
    private prisma: PrismaService,
    private templateService: TemplatesService,
  ) {}

  async sendNotification(dto: {
    userId: string;
    templateSlug: string;
    channel: Channel;
    variables: Record<string, any>;
  }) {
    // 1. Check User Preferences
    const pref = await this.prisma.userPreference.findUnique({
      where: { userId_channel: { userId: dto.userId, channel: dto.channel } },
    });

    if (pref && !pref.isEnabled) {
      return { success: false, reason: 'User opted out' };
    }

    // 2. Get Template
    const template = await this.templateService.getTemplateBySlug(dto.templateSlug);
    if (!template) throw new BadRequestException('Template not found');

    // 3. Compile Content
    const finalContent = this.templateService.compile(template.content, dto.variables);

    // 4. Record History (Initial)
    const log = await this.prisma.notificationHistory.create({
      data: {
        userId: dto.userId,
        templateId: template.id,
        channel: dto.channel,
        status: DeliveryStatus.PENDING,
        metadata: { content: finalContent },
      },
    });

    try {
      // 5. Mock Delivery Logic
      // In production, call SendGrid, Twilio, or Firebase here
      await this.mockProviderDispatch(dto.channel, finalContent);

      // 6. Update History on Success
      return await this.prisma.notificationHistory.update({
        where: { id: log.id },
        data: { status: DeliveryStatus.SENT },
      });
    } catch (error) {
      // 7. Update History on Failure
      return await this.prisma.notificationHistory.update({
        where: { id: log.id },
        data: { status: DeliveryStatus.FAILED, errorMessage: error.message },
      });
    }
  }

  private async mockProviderDispatch(channel: Channel, content: string) {
    console.log(`Sending ${channel} with content: ${content}`);
    return Promise.resolve();
  }
}
```

