// src/preferences/preferences.controller.ts
@Controller('preferences')
export class PreferencesController {
  constructor(private prisma: PrismaService) {}

  @Patch(':userId')
  async updatePreference(
    @Param('userId') userId: string,
    @Body() dto: { channel: Channel; isEnabled: boolean },
  ) {
    return this.prisma.userPreference.upsert({
      where: { userId_channel: { userId, channel: dto.channel } },
      update: { isEnabled: dto.isEnabled },
      create: { userId, channel: dto.channel, isEnabled: dto.isEnabled },
    });
  }
}
