### 2. The Dynamic Renderer
This component takes a `Question` object and renders the appropriate UI element.

```tsx
// src/components/viewer/QuestionRenderer.tsx
import React from 'react';
import { UseFormRegister } from 'react-hook-form';
import { Question } from '../../types/form';

interface Props {
  question: Question;
  register: UseFormRegister<any>;
  error?: string;
}

export const QuestionRenderer: React.FC<Props> = ({ question, register, error }) => {
  const commonProps = {
    ...register(question.id, { required: question.required }),
    className: `w-full p-2 border rounded-md ${error ? 'border-red-500' : 'border-gray-300'}`,
    placeholder: question.placeholder,
  };

  return (
    <div className="mb-6">
      <label className="block text-sm font-medium text-gray-700 mb-1">
        {question.label} {question.required && <span className="text-red-500">*</span>}
      </label>

      {question.type === 'SHORT_TEXT' && <input type="text" {...commonProps} />}

      {question.type === 'LONG_TEXT' && <textarea rows={3} {...commonProps} />}

      {question.type === 'MULTIPLE_CHOICE' && (
        <div className="space-y-2">
          {question.options?.map((opt) => (
            <label key={opt} className="flex items-center space-x-2">
              <input type="radio" value={opt} {...register(question.id)} className="text-blue-600" />
              <span>{opt}</span>
            </label>
          ))}
        </div>
      )}

      {question.type === 'CHECKBOXES' && (
        <div className="space-y-2">
          {question.options?.map((opt) => (
            <label key={opt} className="flex items-center space-x-2">
              <input type="checkbox" value={opt} {...register(question.id)} />
              <span>{opt}</span>
            </label>
          ))}
        </div>
      )}

      {question.type === 'RATING' && (
        <select {...commonProps}>
          <option value="">Select a rating</option>
          {[1, 2, 3, 4, 5].map((n) => (
            <option key={n} value={n}>{n} Stars</option>
          ))}
        </select>
      )}

      {error && <p className="mt-1 text-xs text-red-500">{error}</p>}
    </div>
  );
};
