// src/components/builder/FormBuilder.tsx
import React, { useState } from 'react';
import { Plus, Trash2, Settings2 } from 'lucide-react';
import { FormSchema, Question, QuestionType } from '../../types/form';
import { v4 as uuidv4 } from 'uuid';

export const FormBuilder = () => {
  const [form, setForm] = useState<FormSchema>({
    id: uuidv4(),
    title: 'New Survey',
    description: '',
    questions: []
  });

  const addQuestion = (type: QuestionType) => {
    const newQuestion: Question = {
      id: uuidv4(),
      type,
      label: `Untitled ${type} Question`,
      required: false,
      options: type === 'MULTIPLE_CHOICE' || type === 'CHECKBOXES' ? ['Option 1'] : undefined
    };
    setForm({ ...form, questions: [...form.questions, newQuestion] });
  };

  const updateQuestion = (id: string, updates: Partial<Question>) => {
    setForm({
      ...form,
      questions: form.questions.map(q => q.id === id ? { ...q, ...updates } : q)
    });
  };

  const removeQuestion = (id: string) => {
    setForm({ ...form, questions: form.questions.filter(q => q.id !== id) });
  };

  return (
    <div className="max-w-4xl mx-auto p-8 bg-gray-50 min-h-screen">
      <div className="bg-white p-6 rounded-lg shadow-sm mb-8 border-t-8 border-indigo-600">
