          className="text-3xl font-bold w-full focus:outline-none border-b border-transparent focus:border-gray-200"
          value={form.title}
          onChange={(e) => setForm({...form, title: e.target.value})}
        />
        <input 
          className="text-gray-500 w-full mt-2 focus:outline-none"
          placeholder="Form description..."
          value={form.description}
          onChange={(e) => setForm({...form, description: e.target.value})}
        />
      </div>

      <div className="space-y-4">
        {form.questions.map((q, index) => (
          <div key={q.id} className="bg-white p-6 rounded-lg shadow-sm border border-gray-200 relative group">
            <div className="flex justify-between items-start mb-4">
              <input
                className="font-medium text-lg w-3/4 bg-gray-50 p-1 rounded"
                value={q.label}
                onChange={(e) => updateQuestion(q.id, { label: e.target.value })}
              />
              <button onClick={() => removeQuestion(q.id)} className="text-gray-400 hover:text-red-500">
                <Trash2 size={18} />
              </button>
            </div>

            {/* If Choice Type, show option editor */}
            {(q.type === 'MULTIPLE_CHOICE' || q.type === 'CHECKBOXES') && (
              <div className="ml-4 space-y-2">
                {q.options?.map((opt, i) => (
                  <input
                    key={i}
                    className="block text-sm border-b border-gray-100"
                    value={opt}
