### 1. The Database Schema (`prisma/schema.prisma`)

We use a relational structure but store "options" and "answer values" in flexible formats.

```prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model Form {
  id          String     @id @default(cuid())
  title       String
  description String?
  createdAt   DateTime   @default(now())
  updatedAt   DateTime   @updatedAt
  questions   Question[]
  submissions Submission[]
}

enum QuestionType {
  TEXT
  LONG_TEXT
  MULTIPLE_CHOICE
  CHECKBOX
  RATING
}

model Question {
  id          String       @id @default(cuid())
  formId      String
  form        Form         @relation(fields: [formId], onDelete: Cascade, references: id)
  type        QuestionType
  label       String
  placeholder String?
  required    Boolean      @default(false)
  order       Int          @default(0)

  // Stores options for Multiple Choice or Checkboxes: ["Red", "Blue", "Green"]
  options     Json?        

  answers     Answer[]
}

model Submission {
  id        String   @id @default(cuid())
  formId    String
  form      Form     @relation(fields: [formId], onDelete: Cascade, references: id)
  answers   Answer[]
  createdAt DateTime @default(now())
}

model Answer {
  id           String     @id @default(cuid())
  submissionId String
  submission   Submission @relation(fields: [submissionId], onDelete: Cascade, references: id)
  questionId   String
  question     Question   @relation(fields: [questionId], references: id)

  // Flexible value: can be a string, array of strings (checkboxes), or number (rating)
  value        Json
}
```

