                      </Button>
                    </div>
                  )}
                </div>
                <Button variant="ghost" size="icon" onClick={() => removeQuestion(q.id)}>
                  <Trash2 className="h-4 w-4 text-destructive" />
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      <div className="flex gap-4 justify-center border-t pt-8">
        <Button onClick={() => addQuestion('TEXT')} variant="outline">
