### 1. The Database Schema (Prisma)

The key here is the `config` field in `Question` and the `value` field in `Answer`.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum QuestionType {
  TEXT
  LONG_TEXT
  NUMBER
  SELECT
  MULTIPLE_CHOICE
  RATING
  DATE
}

model Survey {
  id          String       @id @default(cuid())
  title       String
  description String?
  published   Boolean      @default(false)
  questions   Question[]
  submissions Submission[]
  createdAt   DateTime     @default(now())
  updatedAt   DateTime     @updatedAt
}

model Question {
  id          String       @id @default(cuid())
  surveyId    String
  survey      Survey       @relation(fields: [surveyId], references: [id], onDelete: Cascade)
  type        QuestionType
  label       String
  placeholder String?
  required    Boolean      @default(false)
  order       Int
  // JSONB: Stores options for SELECT/MULTIPLE_CHOICE e.g., { options: ["Red", "Blue"] }
  config      Json?        
  answers     Answer[]

  @@index([surveyId])
}

model Submission {
  id        String   @id @default(cuid())
  surveyId  String
  survey    Survey   @relation(fields: [surveyId], references: [id], onDelete: Cascade)
  answers   Answer[]
  createdAt DateTime @default(now())
}

model Answer {
  id           String     @id @default(cuid())
  submissionId String
  submission   Submission @relation(fields: [submissionId], references: [id], onDelete: Cascade)
  questionId   String
  question     Question   @relation(fields: [questionId], references: [id])
  // JSONB: Stores strings, numbers, or arrays [ "Option A", "Option B" ]
  value        Json       

  @@index([submissionId])
  @@index([questionId])
}
```

