### 3. Dynamic Form Renderer (Submission Side)

This is where we convert the database rows into a functional React Hook Form.

```tsx
// components/renderer/SurveyForm.tsx
"use client";

import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { submitSurvey } from "@/actions/submit-survey";

export function SurveyForm({ survey }) {
  // 1. Dynamically build Zod Schema
  const schemaShape = {};
  survey.questions.forEach((q) => {
    let fieldSchema = z.any();
    if (q.required) {
      fieldSchema = z.union([
        z.string().min(1, "Required"),
        z.array(z.string()).min(1, "Select at least one"),
        z.number()
      ]);
    } else {
      fieldSchema = fieldSchema.optional();
    }
    schemaShape[q.id] = fieldSchema;
  });

  const dynamicSchema = z.object(schemaShape);

  const { register, handleSubmit, formState: { errors } } = useForm({
    resolver: zodResolver(dynamicSchema)
  });

  const onSubmit = async (data) => {
    await submitSurvey(survey.id, data);
    alert("Thank you for your response!");
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-8">
      {survey.questions.map((q) => (
        <div key={q.id} className="flex flex-col gap-2">
          <label className="font-semibold">{q.label}</label>

          {/* Render based on type */}
          {q.type === "TEXT" && (
            <input {...register(q.id)} className="border p-2 rounded" />
          )}

          {q.type === "SELECT" && (
            <select {...register(q.id)} className="border p-2 rounded">
              {q.config.options.map(opt => (
                <option key={opt} value={opt}>{opt}</option>
              ))}
            </select>
          )}

          {q.type === "RATING" && (
            <div className="flex gap-2">
               {[1,2,3,4,5].map(n => (
                 <label key={n}>
                   <input type="radio" value={n} {...register(q.id)} /> {n}
                 </label>
               ))}
            </div>
          )}

          {errors[q.id] && (
            <span className="text-red-500 text-sm">
              {errors[q.id]?.message as string}
            </span>
          )}
        </div>
      ))}
      <button type="submit" className="bg-black text-white px-4 py-2 rounded">
        Submit Response
      </button>
    </form>
  );
}
```

