### 4. Server Action (Handling variable responses)

Because we use `JSONB` for the `Answer.value`, we can save any data structure coming from the frontend without changing the database schema.

```tsx
// actions/submit-survey.ts
"use server";

import { db } from "@/lib/db";

export async function submitSurvey(surveyId: string, formData: Record<string, any>) {
  // Create the Submission record and all Answer records in one transaction
  await db.submission.create({
    data: {
      surveyId,
      answers: {
        create: Object.entries(formData).map(([questionId, value]) => ({
          questionId,
          value: value, // This is stored as JSONB
        })),
      },
    },
  });

  return { success: true };
}
```

