### 3. Workout Controller (`src/controllers/workout.controller.ts`)

This handles the core logic for logging sessions and calculating progress.

```typescript
import { Request, Response } from 'express';
import { prisma } from '../lib/prisma';
import { WorkoutSchema } from '../lib/validations';

export const createWorkout = async (req: Request, res: Response) => {
  try {
    const validatedData = WorkoutSchema.parse(req.body);
    const userId = (req as any).user.id;

    const workout = await prisma.workout.create({
      data: {
        name: validatedData.name,
        userId,
        date: validatedData.date ? new Date(validatedData.date) : new Date(),
        sets: {
          create: validatedData.sets,
        },
      },
      include: { sets: true },
    });

    res.status(201).json(workout);
  } catch (error) {
    res.status(400).json({ error: 'Invalid workout data' });
  }
};

export const getProgress = async (req: Request, res: Response) => {
  const { exerciseId } = req.params;
  const userId = (req as any).user.id;

  // Track Estimated 1 Rep Max over time for a specific exercise
  const history = await prisma.set.findMany({
    where: {
      exerciseId,
      workout: { userId },
    },
    include: { workout: true },
    orderBy: { workout: { date: 'asc' } },
  });

  // Business logic: Group sets by workout and find max volume or 1RM
  const progress = history.reduce((acc: any, set) => {
    const date = set.workout.date.toISOString().split('T')[0];
    const volume = (set.weight || 0) * (set.reps || 0);

    if (!acc[date] || acc[date] < volume) {
      acc[date] = volume;
    }
    return acc;
  }, {});

  res.json(progress);
};
```

