### 3. Core Implementation (TypeScript)

#### API Entry Point (`src/index.ts`)
We use Fastify with Zod for strict type checking on inputs.

```typescript
import Fastify from 'fastify';
import jwt from '@fastify/jwt';
import { serializerCompiler, validatorCompiler } from 'fastify-type-provider-zod';
import { workoutRoutes } from './routes/workouts';
import { exerciseRoutes } from './routes/exercises';
import { authRoutes } from './routes/auth';

const app = Fastify({ logger: true });

app.setValidatorCompiler(validatorCompiler);
app.setSerializerCompiler(serializerCompiler);

app.register(jwt, { secret: process.env.JWT_SECRET || 'super-secret-key' });

// Middleware to protect routes
app.decorate("authenticate", async (request, reply) => {
  try {
    await request.jwtVerify();
  } catch (err) {
    reply.send(err);
  }
});

app.register(authRoutes, { prefix: '/api/auth' });
app.register(exerciseRoutes, { prefix: '/api/exercises' });
app.register(workoutRoutes, { prefix: '/api/workouts' });

const start = async () => {
  try {
    await app.listen({ port: 3000 });
    console.log('Server running at http://localhost:3000');
  } catch (err) {
    app.log.error(err);
    process.exit(1);
  }
};

start();
```

#### Workout Logging Logic (`src/routes/workouts.ts`)
This handles creating a workout along with its associated sets in a single transaction.

```typescript
import { FastifyInstance } from 'fastify';
import { z } from 'zod';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export async function workoutRoutes(app: FastifyInstance) {
  app.addHook('onRequest', app.authenticate);

  // Log a new workout session
  app.post('/', async (req, res) => {
    const workoutSchema = z.object({
      name: z.string(),
      sets: z.array(z.object({
        exerciseId: z.string().uuid(),
        weight: z.number().optional(),
        reps: z.number().optional(),
        distance: z.number().optional(),
        duration: z.number().optional(),
        order: z.number()
      }))
    });

    const { name, sets } = workoutSchema.parse(req.body);
    const userId = (req.user as any).id;

    const workout = await prisma.workout.create({
      data: {
        name,
        userId,
        sets: {
          create: sets
        }
      },
      include: { sets: true }
    });

    return workout;
  });

  // Get progress/history for a specific exercise
  app.get('/progress/:exerciseId', async (req, res) => {
    const { exerciseId } = req.params as { exerciseId: string };
    const userId = (req.user as any).id;

    const history = await prisma.workoutSet.findMany({
      where: {
        exerciseId,
        workout: { userId }
      },
      include: { workout: true },
      orderBy: { workout: { createdAt: 'desc' } }
    });

    return history;
  });
}
```

#### Exercise Management (`src/routes/exercises.ts`)
This allows users to see system exercises and create their own custom ones.

```typescript
import { FastifyInstance } from 'fastify';
import { z } from 'zod';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export async function exerciseRoutes(app: FastifyInstance) {
  app.addHook('onRequest', app.authenticate);

  // Get all available exercises (System + My Custom)
  app.get('/', async (req) => {
    const userId = (req.user as any).id;
    return prisma.exercise.findMany({
      where: {
        OR: [
          { isCustom: false },
          { userId: userId }
        ]
      }
    });
  });

  // Create custom exercise
  app.post('/', async (req) => {
    const exerciseSchema = z.object({
      name: z.string(),
      category: z.string(),
      muscleGroup: z.string().optional()
    });

    const data = exerciseSchema.parse(req.body);
    const userId = (req.user as any).id;

    return prisma.exercise.create({
      data: {
        ...data,
        isCustom: true,
        userId
      }
    });
  });
}
```

