### 1. The Data Model (Prisma Schema)

This schema handles users, custom exercise definitions, and the hierarchical nature of a workout (Workout -> Exercise Log -> Sets).

```prisma
// prisma/schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model User {
  id        String     @id @default(uuid())
  email     String     @unique
  password  String
  name      String
  exercises Exercise[] // Custom exercises created by the user
  workouts  Workout[]
  createdAt DateTime   @default(now())
}

model Exercise {
  id          String       @id @default(uuid())
  name        String
  category    String       // e.g., "Strength", "Cardio", "Flexibility"
  equipment   String?      // e.g., "Dumbbell", "Barbell"
  description String?
  userId      String?      // Null means it's a "Global" exercise
  user        User?        @relation(fields: [userId], references: [id])
  logs        WorkoutLog[]
}

model Workout {
  id        String       @id @default(uuid())
  name      String       // e.g., "Leg Day"
  date      DateTime     @default(now())
  userId    String
  user      User         @relation(fields: [userId], references: [id])
  logs      WorkoutLog[]
}

model WorkoutLog {
  id         String   @id @default(uuid())
  workoutId  String
  exerciseId String
  workout    Workout  @relation(fields: [workoutId], references: [id], onDelete: Cascade)
  exercise   Exercise @relation(fields: [exerciseId], references: [id])
  sets       Set[]
}

model Set {
  id           String     @id @default(uuid())
  workoutLogId String
  reps         Int?
  weight       Float?     // Weight in kg/lbs
  distance     Float?     // For cardio
  duration     Int?       // In seconds
  rpe          Int?       // Rate of Perceived Exertion (1-10)
  workoutLog   WorkoutLog @relation(fields: [workoutLogId], references: [id], onDelete: Cascade)
}
```

