```typescript
// src/services/workout.service.ts
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export const createWorkout = async (userId: string, data: any) => {
  return await prisma.workout.create({
    data: {
      userId,
      name: data.name,
      logs: {
        create: data.exercises.map((ex: any) => ({
          exerciseId: ex.exerciseId,
          sets: {
            create: ex.sets.map((set: any) => ({
              reps: set.reps,
              weight: set.weight,
              rpe: set.rpe,
            })),
          },
        })),
      },
    },
    include: {
      logs: { include: { sets: true, exercise: true } },
    },
  });
};

export const getProgress = async (userId: string, exerciseId: string) => {
  // Get Max Weight over time for a specific exercise
  return await prisma.set.findMany({
    where: {
      workoutLog: {
        exerciseId,
        workout: { userId },
      },
    },
    select: {
      weight: true,
      workoutLog: {
        select: { workout: { select: { date: true } } },
      },
    },
    orderBy: { workoutLog: { workout: { date: 'asc' } } },
  });
};
```

