### 2. The Database Schema (Prisma)

This schema separates the **Content Shell** (metadata, settings) from the **Translations** (localized strings).

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Article {
  id           String               @id @default(cuid())
  slug         String               @unique
  createdAt    DateTime             @default(now())
  updatedAt    DateTime             @updatedAt
  published    Boolean              @default(false)

  // Relations
  translations ArticleTranslation[]
}

model ArticleTranslation {
  id          String   @id @default(cuid())
  articleId   String
  locale      String   // e.g., "en-US", "pt-BR", "fr-FR"
  title       String
  description String?
  content     String   @db.Text

  // Relations
  article     Article  @relation(fields: [articleId], references: [id], onDelete: Cascade)

  // Constraints: One translation per locale per article
  @@unique([articleId, locale])
  @@index([locale])
}
