### 3. Core Data Access Logic

We need a robust way to fetch content that handles **Regional Fallbacks**. If a user requests `pt-BR` but it doesn't exist, we might want to fall back to `pt` or our default `en-US`.

```typescript
// lib/content-service.ts
import { prisma } from "@/lib/db";

export async function getArticleBySlug(slug: string, locale: string) {
  // 1. Attempt to fetch with the specific locale
  let article = await prisma.article.findUnique({
    where: { slug },
    include: {
      translations: {
        where: { locale: locale }
      }
    }
  });

  // 2. Fallback Logic: If no translation found for requested locale
  if (!article || article.translations.length === 0) {
    const defaultLocale = "en-US";
    article = await prisma.article.findUnique({
      where: { slug },
      include: {
        translations: {
          where: { locale: defaultLocale }
        }
      }
    });
  }

  if (!article || article.translations.length === 0) return null;

  return {
    ...article,
    activeTranslation: article.translations[0],
  };
}
```

