To manage this, you would create a form that sends a nested payload to an API route:

```typescript
// app/api/articles/route.ts
export async function POST(req: Request) {
  const body = await req.json();
  const { slug, translations } = body; 
  // translations is an array: [{ locale: 'en-US', title: 'Hello' }, { locale: 'pt-BR', title: 'Olá' }]

  const article = await prisma.article.create({
    data: {
      slug,
      translations: {
        createMany: {
          data: translations
        }
      }
    }
  });

  return Response.json(article);
}
