### 1. The Database Schema (Prisma)

The core of a translation platform is the **Translatable Model Pattern**. Instead of adding columns like `title_en` and `title_fr`, we use a one-to-many relationship. This allows for infinite languages without changing the schema.

```prisma
// prisma/schema.prisma

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model Article {
  id        String   @id @default(cuid())
  slug      String   @unique
  published Boolean  @default(false)
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  // The relationship to translations
  translations ArticleTranslation[]

  @@index([slug])
}

model ArticleTranslation {
  id        String   @id @default(cuid())
  articleId String
  language  String   // e.g., "en", "pt"
  region    String?  // e.g., "US", "BR"

  title     String
  content   String   @db.Text

  article   Article  @relation(fields: [articleId], references: [id], onDelete: Cascade)

  // Ensure one translation per locale per article
  @@unique([articleId, language, region])
  @@index([language, region])
}
```

