### 2. The Content Fetching Logic (Backend)

When fetching content, we need a "Fallback Resolver." If a user requests `pt-BR` (Portuguese Brazil) but it doesn't exist, we should look for `pt` (Generic Portuguese) and then finally a default (e.g., `en`).

```typescript
// lib/db/articles.ts

import { prisma } from "./prisma";

export async function getArticleBySlug(slug: string, locale: string) {
  const [lang, region] = locale.split('-');

  const article = await prisma.article.findUnique({
    where: { slug },
    include: {
      translations: {
        where: {
          OR: [
            { language: lang, region: region || null }, // Perfect match
            { language: lang, region: null },           // Language match, no region
            { language: 'en' }                          // Global fallback
          ]
        }
      }
    }
  });

  if (!article) return null;

  // Logic to pick the best translation from the returned list
  const bestTranslation = 
    article.translations.find(t => t.language === lang && t.region === region) ||
    article.translations.find(t => t.language === lang) ||
    article.translations.find(t => t.language === 'en');

  return {
    ...article,
    translation: bestTranslation
  };
}
```

