### 2. The Dynamic Field Registry (`lib/job-definitions.ts`)

This is the "Source of Truth" for what fields appear for which industry.

```typescript
import { z } from "zod";

export const INDUSTRIES = ["tech", "healthcare", "finance"] as const;
export const ROLE_TYPES = ["full-time", "contract", "freelance"] as const;

export type Industry = (typeof INDUSTRIES)[number];
export type RoleType = (typeof ROLE_TYPES)[number];

export interface FieldDefinition {
  name: string;
  label: string;
  type: "text" | "number" | "boolean" | "select";
  options?: string[];
  placeholder?: string;
}

// Define specific fields for combinations
export const EXTRA_FIELDS: Record<Industry, FieldDefinition[]> = {
  tech: [
    { name: "techStack", label: "Primary Tech Stack", type: "text", placeholder: "React, Node, Postgres" },
    { name: "githubRequired", label: "GitHub Profile Required?", type: "boolean" },
    { name: "remoteLevel", label: "Remote Policy", type: "select", options: ["Full Remote", "Hybrid", "On-site"] }
  ],
  healthcare: [
    { name: "certification", label: "Medical Certification", type: "text" },
    { name: "shiftPattern", label: "Shift Pattern", type: "select", options: ["Day", "Night", "Rotating"] }
  ],
  finance: [
    { name: "regulatoryKnowledge", label: "Regulatory Compliance Exp.", type: "text" },
    { name: "clearanceLevel", label: "Clearance Level", type: "select", options: ["None", "Public Trust", "Top Secret"] }
  ]
};

// Validation Logic: Dynamically build Zod schema based on metadata
export function getMetadataSchema(industry: Industry) {
  const fields = EXTRA_FIELDS[industry] || [];
  const shape: any = {};

  fields.forEach(field => {
    if (field.type === "boolean") shape[field.name] = z.boolean().default(false);
    else shape[field.name] = z.string().min(1, `${field.label} is required`);
  });

  return z.object(shape);
}
```

