### 3. Dynamic Form Component (`components/JobForm.tsx`)

Using `react-hook-form` to handle the dynamic nature of the fields.

```tsx
"use client";

import { useForm } from "react-hook-form";
import { useState, useEffect } from "react";
import { INDUSTRIES, ROLE_TYPES, EXTRA_FIELDS, Industry } from "@/lib/job-definitions";

export default function JobForm() {
  const { register, handleSubmit, watch, setValue, unregister } = useForm();
  const selectedIndustry = watch("industry") as Industry;

  // Cleanup fields when industry changes
  useEffect(() => {
    return () => {
      const fields = EXTRA_FIELDS[selectedIndustry] || [];
      fields.forEach(f => unregister(`metadata.${f.name}`));
    };
  }, [selectedIndustry, unregister]);

  const onSubmit = async (data: any) => {
    const res = await fetch("/api/jobs", {
      method: "POST",
      body: JSON.stringify(data),
    });
    if (res.ok) alert("Job posted!");
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-6 max-w-2xl mx-auto p-6 bg-white rounded-xl shadow">
      <div className="grid grid-cols-2 gap-4">
        <div className="flex flex-col">
          <label className="text-sm font-medium">Job Title</label>
          <input {...register("title")} className="border p-2 rounded" placeholder="Senior Engineer" required />
        </div>
        <div className="flex flex-col">
          <label className="text-sm font-medium">Company</label>
          <input {...register("company")} className="border p-2 rounded" required />
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="flex flex-col">
          <label className="text-sm font-medium">Industry</label>
          <select {...register("industry")} className="border p-2 rounded">
            <option value="">Select Industry</option>
            {INDUSTRIES.map(i => <option key={i} value={i}>{i.toUpperCase()}</option>)}
          </select>
        </div>
        <div className="flex flex-col">
          <label className="text-sm font-medium">Role Type</label>
          <select {...register("roleType")} className="border p-2 rounded">
            {ROLE_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>
      </div>

      {/* DYNAMIC FIELDS SECTION */}
      {selectedIndustry && EXTRA_FIELDS[selectedIndustry] && (
        <div className="p-4 bg-slate-50 rounded-lg border border-slate-200">
          <h3 className="font-semibold mb-3 text-slate-700">Industry Specific Details</h3>
          <div className="grid grid-cols-1 gap-4">
            {EXTRA_FIELDS[selectedIndustry].map((field) => (
              <div key={field.name} className="flex flex-col">
                <label className="text-sm font-medium">{field.label}</label>

                {field.type === "text" && (
                  <input {...register(`metadata.${field.name}`)} placeholder={field.placeholder} className="border p-2 rounded bg-white" />
                )}

                {field.type === "select" && (
                  <select {...register(`metadata.${field.name}`)} className="border p-2 rounded bg-white">
                    {field.options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                  </select>
                )}

                {field.type === "boolean" && (
                  <input type="checkbox" {...register(`metadata.${field.name}`)} className="w-4 h-4" />
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      <button type="submit" className="w-full bg-blue-600 text-white py-3 rounded-lg font-bold hover:bg-blue-700 transition">
        Post Job Listing
      </button>
    </form>
  );
}
