### 4. API Route with Strict Validation (`app/api/jobs/route.ts`)

We validate the core fields, then dynamically select the sub-schema for the metadata.

```typescript
import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma"; // Standard prisma instance
import { getMetadataSchema, Industry } from "@/lib/job-definitions";
import { z } from "zod";

const CoreJobSchema = z.object({
  title: z.string().min(3),
  company: z.string().min(1),
  industry: z.string(),
  roleType: z.string(),
  description: z.string().optional().default(""),
  metadata: z.record(z.any())
});

export async function POST(req: Request) {
  try {
    const body = await req.json();

    // 1. Validate Core Fields
    const validatedCore = CoreJobSchema.parse(body);

    // 2. Validate Dynamic Metadata based on industry
    const metadataSchema = getMetadataSchema(validatedCore.industry as Industry);
    const validatedMetadata = metadataSchema.parse(body.metadata);

    // 3. Save to DB
    const job = await prisma.job.create({
      data: {
        ...validatedCore,
        metadata: validatedMetadata as any, // Cast for Prisma JSONB
      },
    });

    return NextResponse.json(job);
  } catch (error) {
    console.error(error);
    return NextResponse.json({ error: "Validation failed" }, { status: 400 });
  }
}

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const industry = searchParams.get("industry");

  const jobs = await prisma.job.findMany({
    where: industry ? { industry } : {},
    orderBy: { createdAt: "desc" }
  });

  return NextResponse.json(jobs);
}
```

