### 4. Logic: Event Registration (Stripe Integration)
This API route creates a checkout session for paid tickets.

```ts
// app/api/checkout/route.ts
import { stripe } from "@/lib/stripe";
import { createRouteHandlerClient } from "@supabase/auth-helpers-nextjs";
import { cookies } from "next/headers";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
  const { eventId, price, title } = await req.json();
  const supabase = createRouteHandlerClient({ cookies });
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) return new NextResponse("Unauthorized", { status: 401 });

  const session = await stripe.checkout.sessions.create({
    payment_method_types: ["card"],
    line_items: [
      {
        price_data: {
          currency: "usd",
          product_data: { name: title },
          unit_amount: Math.round(price * 100),
        },
        quantity: 1,
      },
    ],
    mode: "payment",
    success_url: `${process.env.NEXT_PUBLIC_URL}/events/${eventId}?success=true`,
    cancel_url: `${process.env.NEXT_PUBLIC_URL}/events/${eventId}?cancelled=true`,
    metadata: {
      userId: user.id,
      eventId: eventId,
    },
  });

  return NextResponse.json({ url: session.url });
}
```

