### 2. Server Actions (Backend Logic)
Next.js Server Actions allow us to handle data mutations securely without writing manual API endpoints.

```typescript
// lib/actions/event.actions.ts
"use server"

import { revalidatePath } from 'next/cache'
import { prisma } from '@/lib/db'
import { auth } from '@/auth' // Your NextAuth config

export async function createEvent(formData: any) {
  const session = await auth()
  if (!session?.user) throw new Error("Unauthorized")

  const event = await prisma.event.create({
    data: {
      ...formData,
      organizerId: session.user.id,
    }
  })

  revalidatePath('/dashboard')
  return event
}

export async function registerForEvent(eventId: string) {
  const session = await auth()
  if (!session?.user) throw new Error("Unauthorized")

  const event = await prisma.event.findUnique({ where: { id: eventId } })

  // Here you would typically integrate Stripe Checkout
  // This is a simplified direct registration for demo purposes
  const registration = await prisma.registration.create({
    data: {
      eventId,
      userId: session.user.id,
      totalAmount: event?.price || 0,
    }
  })

  revalidatePath(`/events/${eventId}`)
  return registration
}
```

