### 5. Stripe Webhook (Handling Successful Payments)
When the payment is confirmed, Stripe sends a POST request to our webhook to record the attendee data.

```typescript
// app/api/webhook/stripe/route.ts
import { NextResponse } from 'next/server'
import stripe from 'stripe'
import { prisma } from '@/lib/prisma'

export async function POST(request: Request) {
  const body = await request.text()
  const sig = request.headers.get('stripe-signature') as string
  let event

  try {
    event = stripe.webhooks.constructEvent(body, sig, process.env.STRIPE_WEBHOOK_SECRET!)
  } catch (err: any) {
    return NextResponse.json({ message: "Webhook Error", error: err.message }, { status: 400 })
  }

  const eventType = event.type

  if (eventType === 'checkout.session.completed') {
    const { id, amount_total, metadata } = event.data.object

    const newOrder = await prisma.order.create({
      data: {
        stripeId: id,
        eventId: metadata?.eventId || '',
        buyerId: metadata?.buyerId || '',
        totalAmount: (amount_total! / 100).toString(),
      },
    })

    return NextResponse.json({ message: 'OK', order: newOrder })
  }

  return new Response('', { status: 200 })
}
```

