### 3. API Implementation (Fastify + TypeScript)

#### Validation Schema (using Zod)
We define the shape of the data for creating a recipe.

```typescript
// src/schemas/recipe.schema.ts
import { z } from 'zod';

export const CreateRecipeSchema = z.object({
  title: z.string().min(3),
  description: z.string().optional(),
  servings: z.number().int().positive(),
  prepTime: z.number().optional(),
  cookTime: z.number().optional(),
  ingredients: z.array(z.object({
    name: z.string(),
    amount: z.number(),
    unit: z.string()
  })),
  instructions: z.array(z.object({
    stepNumber: z.number(),
    content: z.string()
  })),
  nutrition: z.object({
    calories: z.number(),
    protein: z.number().optional(),
    fat: z.number().optional(),
    carbs: z.number().optional(),
  }).optional(),
  parentRecipeId: z.string().uuid().optional(),
  variationNotes: z.string().optional(),
});

export type CreateRecipeInput = z.infer<typeof CreateRecipeSchema>;
```

#### The Recipe Service
This is where the complex database logic lives. We use a **Prisma Transaction** to ensure that if the ingredients fail to save, the recipe isn't created (Atomicity).

```typescript
// src/services/recipe.service.ts
import { PrismaClient } from '@prisma/client';
import { CreateRecipeInput } from '../schemas/recipe.schema';

const prisma = new PrismaClient();

export async function createRecipe(data: CreateRecipeInput, userId: string) {
  return await prisma.$transaction(async (tx) => {
    const recipe = await tx.recipe.create({
      data: {
        title: data.title,
        description: data.description,
        servings: data.servings,
        prepTime: data.prepTime,
        cookTime: data.cookTime,
        authorId: userId,
        parentRecipeId: data.parentRecipeId,
        variationNotes: data.variationNotes,

        // Nested Writes
        ingredients: {
          create: data.ingredients,
        },
        instructions: {
          create: data.instructions,
        },
        nutrition: data.nutrition ? {
          create: data.nutrition,
        } : undefined,
      },
      include: {
        ingredients: true,
        instructions: true,
        nutrition: true,
      },
    });
    return recipe;
  });
}

export async function getRecipeById(id: string) {
  return await prisma.recipe.findUnique({
    where: { id },
    include: {
      ingredients: true,
      instructions: true,
      nutrition: true,
      variations: true, // Fetch user-generated variations
    },
  });
}
```

#### The Controller/Routes
We link the HTTP request to our service.

```typescript
// src/routes/recipe.routes.ts
import { FastifyInstance } from 'fastify';
import { createRecipe, getRecipeById } from '../services/recipe.service';
import { CreateRecipeSchema } from '../schemas/recipe.schema';

export async function recipeRoutes(server: FastifyInstance) {

  // POST /api/recipes
  server.post('/', async (request, reply) => {
    // In a real app, userId comes from JWT
    const userId = "some-user-uuid"; 

    const validatedData = CreateRecipeSchema.parse(request.body);
    const recipe = await createRecipe(validatedData, userId);

    return reply.code(201).send(recipe);
  });

  // GET /api/recipes/:id
  server.get('/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    const recipe = await getRecipeById(id);

    if (!recipe) return reply.code(404).send({ message: "Recipe not found" });
    return recipe;
  });
}
```

