### 2. Core Service Logic (`recipe.service.ts`)

Creating a recipe requires a **Database Transaction** to ensure that the recipe, ingredients, instructions, and nutrition are all created together or not at all.

```typescript
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export class RecipeService {
  static async createRecipe(userId: string, data: any) {
    return await prisma.$transaction(async (tx) => {
      // 1. Create the base recipe
      const recipe = await tx.recipe.create({
        data: {
          title: data.title,
          description: data.description,
          authorId: userId,
          // 2. Create nested instructions
          instructions: {
            create: data.instructions.map((inst: any, index: number) => ({
              stepNumber: index + 1,
              content: inst,
            })),
          },
          // 3. Create nested nutrition
          nutrition: {
            create: data.nutrition, // { calories: 500, fat: 20, ... }
          },
        },
      });

      // 4. Handle ingredients (connect or create)
      for (const item of data.ingredients) {
        await tx.recipeIngredient.create({
          data: {
            recipeId: recipe.id,
            quantity: item.quantity,
            unit: item.unit,
            ingredient: {
              connectOrCreate: {
                where: { name: item.name.toLowerCase() },
                create: { name: item.name.toLowerCase() },
              },
            },
          },
        });
      }

      return recipe;
    });
  }

  static async addVariation(userId: string, recipeId: string, description: string) {
    return prisma.variation.create({
      data: {
        description,
        originalRecipeId: recipeId,
        authorId: userId,
      },
    });
  }
}
```

