### 3. The Recipe Service (`src/services/recipe.service.ts`)

This is where the business logic resides. Note the use of `$transaction`.

```typescript
import { PrismaClient } from '@prisma/client';
import { CreateRecipeInput } from '../schemas/recipe.schema';

const prisma = new PrismaClient();

export class RecipeService {
  static async createRecipe(data: CreateRecipeInput, userId: string) {
    return prisma.$transaction(async (tx) => {
      // 1. Create the base Recipe
      const recipe = await tx.recipe.create({
        data: {
          title: data.title,
          description: data.description,
          prepTime: data.prepTime,
          cookTime: data.cookTime,
          servings: data.servings,
          authorId: userId,
          // 2. Nested create for Instructions
          instructions: {
            create: data.instructions
          },
          // 3. Nested create for Ingredients
          ingredients: {
            create: data.ingredients
          },
          // 4. Nested create for Nutrition
          nutrition: data.nutrition ? {
            create: data.nutrition
          } : undefined
        },
        include: {
          ingredients: true,
          instructions: true,
          nutrition: true
        }
      });
      return recipe;
    });
  }

  static async getRecipeWithVariations(recipeId: string) {
    return prisma.recipe.findUnique({
      where: { id: recipeId },
      include: {
        ingredients: true,
        instructions: true,
        nutrition: true,
        variations: {
          include: { author: { select: { name: true } } }
        }
      }
    });
  }

  static async addVariation(recipeId: string, userId: string, note: string) {
    return prisma.variation.create({
      data: {
        recipeId,
        authorId: userId,
        note
      }
    });
  }
}
```

