### 1. Database Schema (PostgreSQL)

You need a database that supports vector operations to store document "embeddings."

```sql
-- Enable the pgvector extension
CREATE EXTENSION IF NOT EXISTS vector;

-- Documents table to track file metadata
CREATE TABLE documents (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    filename TEXT NOT NULL,
    s3_url TEXT NOT NULL,
    status TEXT DEFAULT 'processing', -- 'processing', 'completed', 'failed'
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Chunks table to store vector embeddings for search
CREATE TABLE document_chunks (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    document_id UUID REFERENCES documents(id) ON DELETE CASCADE,
    content TEXT NOT NULL,
    embedding VECTOR(1536), -- 1536 is the dimension for OpenAI text-embedding-3-small
    metadata JSONB
);

-- Create an HNSW index for fast vector similarity search
CREATE INDEX ON document_chunks USING hnsw (embedding vector_cosine_ops);
```

