### 2. Backend Implementation (Node.js + TypeScript)

This service handles file uploads, chunking, embedding generation, and retrieval.

**`src/services/ingestion.service.ts`**
```typescript
import { PDFLoader } from "langchain/document_loaders/web/pdf";
import { RecursiveCharacterTextSplitter } from "langchain/text_splitter";
import { OpenAIEmbeddings } from "@langchain/openai";
import { pool } from "../config/db";

export class IngestionService {
  private embeddings = new OpenAIEmbeddings({ modelName: "text-embedding-3-small" });

  async processDocument(docId: string, filePath: string) {
    // 1. Load PDF
    const loader = new PDFLoader(filePath);
    const docs = await loader.load();

    // 2. Split into manageable chunks
    const splitter = new RecursiveCharacterTextSplitter({
      chunkSize: 1000,
      chunkOverlap: 200,
    });
    const chunks = await splitter.splitDocuments(docs);

    // 3. Generate embeddings and store
    for (const chunk of chunks) {
      const embedding = await this.embeddings.embedQuery(chunk.pageContent);

      await pool.query(
        `INSERT INTO document_chunks (document_id, content, embedding) 
         VALUES ($1, $2, $3)`,
        [docId, chunk.pageContent, JSON.stringify(embedding)]
      );
    }

    await pool.query("UPDATE documents SET status = 'completed' WHERE id = $1", [docId]);
  }
}
```

**`src/services/search.service.ts`**
```typescript
import { OpenAI } from "openai";
import { pool } from "../config/db";

const openai = new OpenAI();

export class SearchService {
  async queryKnowledgeBase(userQuery: string) {
    // 1. Convert user query to embedding
    const response = await openai.embeddings.create({
      model: "text-embedding-3-small",
      input: userQuery,
    });
    const queryEmbedding = response.data[0].embedding;

    // 2. Perform Vector Search in PostgreSQL
    const { rows: contextChunks } = await pool.query(
      `SELECT content FROM document_chunks 
       ORDER BY embedding <=> $1::vector 
       LIMIT 5`,
      [JSON.stringify(queryEmbedding)]
    );

    const contextText = contextChunks.map(c => c.content).join("\n\n");

    // 3. Generate Answer using LLM
    const completion = await openai.chat.completions.create({
      model: "gpt-4o",
      messages: [
        { role: "system", content: "You are an enterprise assistant. Answer based ONLY on the provided context." },
        { role: "user", content: `Context: ${contextText} \n\n Question: ${userQuery}` }
      ],
    });

    return completion.choices[0].message.content;
  }
}
```

