### 2. The Logic: Availability Engine (`lib/booking-utils.ts`)

This utility calculates available time slots by comparing the resource's schedule against existing bookings.

```typescript
import { addMinutes, format, parse, startOfDay, isBefore, isAfter, isEqual } from "date-fns";

export function generateSlots(
  startTimeStr: string,
  endTimeStr: string,
  duration: number,
  date: Date,
  existingBookings: { startTime: Date; endTime: Date }[]
) {
  const slots = [];
  let current = parse(startTimeStr, "HH:mm", date);
  const end = parse(endTimeStr, "HH:mm", date);

  while (isBefore(current, end)) {
    const slotEnd = addMinutes(current, duration);

    // Check if slot overlaps with any existing booking
    const isOccupied = existingBookings.some((booking) => {
      return (
        (isAfter(slotEnd, booking.startTime) && isBefore(slotEnd, booking.endTime)) ||
        (isAfter(current, booking.startTime) && isBefore(current, booking.endTime)) ||
        (isEqual(current, booking.startTime))
      );
    });

    if (!isOccupied && !isBefore(slotEnd, end)) {
        // Only add if it fits in the window
    }

    slots.push({
      time: format(current, "HH:mm"),
      available: !isOccupied,
      start: new Date(current),
      end: slotEnd,
    });

    current = slotEnd;
  }

  return slots;
}
```

