### 3. API Route: Create Booking (`app/api/bookings/route.ts`)

This handles the reservation and prevents double-booking using a transaction.

```typescript
import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function POST(req: Request) {
  try {
    const { resourceId, startTime, endTime, customerName, customerEmail } = await req.json();

    // 1. Double-booking protection: Check if overlap exists in a transaction
    const booking = await prisma.$transaction(async (tx) => {
      const overlap = await tx.booking.findFirst({
        where: {
          resourceId,
          status: "CONFIRMED",
          OR: [
            {
              startTime: { lt: new Date(endTime) },
              endTime: { gt: new Date(startTime) },
            },
          ],
        },
      });

      if (overlap) {
        throw new Error("This time slot is no longer available.");
      }

      return await tx.booking.create({
        data: {
          resourceId,
          startTime: new Date(startTime),
          endTime: new Date(endTime),
          customerName,
          customerEmail,
        },
      });
    });

    return NextResponse.json(booking);
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 400 });
  }
}
```

