              disabled={!slot.available || loading}
              onClick={() => handleBook(slot)}
              className={slot.available ? "border-green-200 hover:bg-green-50" : "opacity-50 cursor-not-allowed"}
            >
              {slot.time}
            </Button>
          ))}
        </div>
      </div>
    </div>
  );
}
```

