### 2. Business Logic: Slot Generation
This utility handles the "heavy lifting" of calculating available time windows while excluding existing bookings.

```typescript
// lib/booking-utils.ts
import { addMinutes, format, isAfter, isBefore, parse, startOfDay } from "date-fns";

export function generateAvailableSlots(
  date: Date,
  duration: Int,
  workingHours: { start: string; end: string },
  existingBookings: { start: Date; end: Date }[]
) {
  const slots: Date[] = [];

  // Set start and end of the working day for the specific date
  const startAt = parse(workingHours.start, "HH:mm", date);
  const endAt = parse(workingHours.end, "HH:mm", date);

  let currentSlot = startAt;

  while (isBefore(addMinutes(currentSlot, duration), addMinutes(endAt, 1))) {
    const slotEnd = addMinutes(currentSlot, duration);

    // Check if slot is in the future
    const isFuture = isAfter(currentSlot, new Date());

    // Check if slot overlaps with any existing booking
    const isOverlapping = existingBookings.some(booking => {
      return (
        (currentSlot >= booking.start && currentSlot < booking.end) ||
        (slotEnd > booking.start && slotEnd <= booking.end)
      );
    });

    if (isFuture && !isOverlapping) {
      slots.push(new Date(currentSlot));
    }

    currentSlot = addMinutes(currentSlot, duration);
  }

  return slots;
}
```

