### 3. The Server Action (Booking Creation)
Next.js Server Actions provide a secure way to handle form submissions with built-in protection.

```typescript
// app/actions/bookings.ts
"use server";

import { db } from "@/lib/db";
import { z } from "zod";
import { revalidatePath } from "next/cache";

const BookingSchema = z.object({
  serviceId: z.string(),
  customerName: z.string().min(2),
  customerEmail: z.string().email(),
  startTime: z.string().datetime(),
});

export async function createBooking(formData: z.infer<typeof BookingSchema>) {
  const validated = BookingSchema.parse(formData);

  const service = await db.service.findUnique({
    where: { id: validated.serviceId }
  });

  if (!service) throw new Error("Service not found");

  const startTime = new Date(validated.startTime);
  const endTime = new Date(startTime.getTime() + service.duration * 60000);

  // Double-check availability on server-side to prevent race conditions
  const conflict = await db.booking.findFirst({
    where: {
      serviceId: validated.serviceId,
      status: "confirmed",
      OR: [
        { startTime: { lt: endTime, gte: startTime } },
        { endTime: { gt: startTime, lte: endTime } },
      ],
    },
  });

  if (conflict) {
    return { error: "This slot was just taken. Please pick another." };
  }

  await db.booking.create({
    data: {
      ...validated,
      startTime,
      endTime,
    },
  });

  revalidatePath("/bookings");
  return { success: true };
}
```

