### 3. Backend Implementation (Express + TypeScript)
The core logic resides in preventing double-bookings using a **Database Transaction**.

```typescript
// src/server.ts
import express from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';

const prisma = new PrismaClient();
const app = express();
app.use(express.json());

const BookingSchema = z.object({
  resourceId: z.string(),
  userEmail: z.string().email(),
  startTime: z.string().datetime(),
  endTime: z.string().datetime(),
});

app.post('/api/bookings', async (req, res) => {
  try {
    const { resourceId, userEmail, startTime, endTime } = BookingSchema.parse(req.body);

    // ATOMIC TRANSACTION: 
    // This ensures no two users can book the same slot simultaneously
    const result = await prisma.$transaction(async (tx) => {
      // 1. Check if the slot is already taken
      const existingBooking = await tx.booking.findFirst({
        where: {
          resourceId,
          status: 'CONFIRMED',
          OR: [
            { startTime: { lt: endTime }, endTime: { gt: startTime } }
          ]
        },
      });

      if (existingBooking) {
        throw new Error('This time slot is already reserved.');
      }

      // 2. Create the booking
      const booking = await tx.booking.create({
        data: { resourceId, userEmail, startTime, endTime },
      });

      return booking;
    });

    res.status(201).json(result);
  } catch (error: any) {
    res.status(400).json({ error: error.message });
  }
});

// Get available slots for a resource
app.get('/api/resources/:id/availability', async (req, res) => {
  const { id } = req.params;
  const slots = await prisma.slot.findMany({
    where: { resourceId: id, isBooked: false },
    orderBy: { startTime: 'asc' }
  });
  res.json(slots);
});

app.listen(3000, () => console.log('Booking Engine running on port 3000'));
```

