### 3. The Backend API (Fastify)
Fastify is chosen for its low overhead, crucial for high-throughput log ingestion.

```typescript
// api/src/index.ts
import Fastify from 'fastify';
import { PrismaClient } from '@prisma/client';
import cors from '@fastify/cors';

const prisma = new PrismaClient();
const server = Fastify({ logger: true });

server.register(cors);

// 1. Ingest Endpoint (POST /ingest)
server.post('/ingest', async (request, reply) => {
  const { level, service, message, metadata, traceId } = request.body as any;

  const log = await prisma.log.create({
    data: { level, service, message, metadata: metadata || {}, traceId }
  });

  return { status: 'ok', id: log.id };
});

// 2. Query Endpoint (GET /logs)
server.get('/logs', async (request, reply) => {
  const { service, level, search, limit = 50, offset = 0 } = request.query as any;

  const logs = await prisma.log.findMany({
    where: {
      service: service || undefined,
      level: level || undefined,
      message: search ? { contains: search, mode: 'insensitive' } : undefined,
    },
    orderBy: { timestamp: 'desc' },
    take: Number(limit),
    skip: Number(offset),
  });

  return logs;
});

// 3. Stats for Dashboard
server.get('/stats', async () => {
  const stats = await prisma.log.groupBy({
    by: ['level'],
    _count: { level: true },
  });
  return stats;
});

server.listen({ port: 3001, host: '0.0.0.0' });
```

