### 3. The Ingestion & Query API (api/src/server.ts)
Using Fastify for its low overhead and schema validation.

```typescript
import Fastify from 'fastify';
import { db } from './db';
import { logs } from './db/schema';
import { desc, eq, and, gte, lte } from 'drizzle-orm';

const app = Fastify({ logger: true });

// INGESTION ENDPOINT
// High-speed endpoint for applications to send logs
app.post('/ingest', async (request, reply) => {
  const body = request.body as any;

  // In production, you would push this to a Redis queue or Kafka 
  // to prevent DB bottlenecks during traffic spikes.
  const result = await db.insert(logs).values({
    level: body.level || 'info',
    service: body.service,
    message: body.message,
    metadata: body.metadata || {},
    traceId: body.traceId
  }).returning();

  return { success: true, id: result[0].id };
});

// QUERY ENDPOINT
app.get('/logs', async (request) => {
  const { service, level, start, end } = request.query as any;

  const filters = [];
  if (service) filters.push(eq(logs.service, service));
  if (level) filters.push(eq(logs.level, level));
  if (start) filters.push(gte(logs.timestamp, new Date(start)));
  if (end) filters.push(lte(logs.timestamp, new Date(end)));

  return await db.select()
    .from(logs)
    .where(and(...filters))
    .orderBy(desc(logs.timestamp))
    .limit(100);
});

app.listen({ port: 3000, host: '0.0.0.0' });
```

