│   │   ├── engine.ts     # The Recommendation Logic
│   │   └── tracker.ts    # Event Ingestion logic
│   ├── index.ts          # API Routes
│   └── seed.ts           # Sample Data
└── package.json
```

### 3. Database Schema (`prisma/schema.prisma`)
We need to track Users, Items (e.g., Movies, Products), and Interactions.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model User {
  id           String        @id @default(uuid())
  email        String        @unique
  interactions Interaction[]
}

model Item {
  id           String        @id @default(uuid())
  name         String
  category     String
  interactions Interaction[]
}

model Interaction {
  id        String   @id @default(uuid())
  userId    String
  itemId    String
  // Weight represents the strength of the action (e.g., View=1, Like=3, Purchase=5)
  weight    Int      @default(1)
  user      User     @relation(fields: [userId], references: [id])
  item      Item     @relation(fields: [itemId], references: [id])
  createdAt DateTime @default(now())

  @@unique([userId, itemId]) // Prevents duplicate tracking for the same item
}
```

### 4. The Recommendation Engine (`src/services/engine.ts`)
We use a **Collaborative Filtering** approach. To recommend items to User A:
1. Find items User A has interacted with.
2. Find "Similar Users" who interacted with those same items.
3. Find items those "Similar Users" liked that User A hasn't seen yet.
4. Rank those items by frequency and weight.

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class RecommendationEngine {
  /**
   * Get personalized recommendations for a specific user
   */
  static async getSuggestions(userId: string, limit: number = 5) {
    // 1. Get items the target user has already interacted with
    const userInteractions = await prisma.interaction.findMany({
      where: { userId },
      select: { itemId: true }
    });
    const viewedItemIds = userInteractions.map(i => i.itemId);

    // 2. Find "Similar Users" 
    // (Users who interacted with the same items)
    const similarUsers = await prisma.interaction.findMany({
      where: {
        itemId: { in: viewedItemIds },
        userId: { not: userId } // Don't include the user themselves
      },
      select: { userId: true }
    });
    const similarUserIds = [...new Set(similarUsers.map(u => u.userId))];

    // 3. Find items liked by those similar users that our target user hasn't seen
    const recommendations = await prisma.interaction.groupBy({
      by: ['itemId'],
      where: {
        userId: { in: similarUserIds },
        itemId: { notIn: viewedItemIds }
      },
      _sum: {
        weight: true // Items with higher engagement weight rank higher
      },
      orderBy: {
        _sum: {
          weight: 'desc'
        }
      },
      take: limit
    });

    // 4. Fetch the actual item details
    const recommendedItemIds = recommendations.map(r => r.itemId);
    return prisma.item.findMany({
      where: { id: { in: recommendedItemIds } }
    });
  }
}
```

### 5. Tracking Service (`src/services/tracker.ts`)
This ingests user behavior.

```typescript
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export const trackInteraction = async (userId: string, itemId: string, type: 'VIEW' | 'LIKE' | 'PURCHASE') => {
  const weights = { VIEW: 1, LIKE: 3, PURCHASE: 5 };

  return prisma.interaction.upsert({
    where: {
      userId_itemId: { userId, itemId }
    },
    update: {
      weight: weights[type] // Update if they upgrade from view to purchase
    },
    create: {
      userId,
      itemId,
      weight: weights[type]
    }
  });
};
```

### 6. API Layer (`src/index.ts`)

```typescript
import express from 'express';
import { trackInteraction } from './services/tracker';
import { RecommendationEngine } from './services/engine';

const app = express();
app.use(express.json());

// Record an action
app.post('/events', async (req, res) => {
  const { userId, itemId, action } = req.body;
  await trackInteraction(userId, itemId, action);
  res.status(202).send({ status: 'tracked' });
});

// Get personalized recommendations
app.get('/recommendations/:userId', async (req, res) => {
  const { userId } = req.params;
  const suggestions = await RecommendationEngine.getSuggestions(userId);
  res.json(suggestions);
});

app.listen(3000, () => console.log('Recommendation Engine running on port 3000'));
```

### 7. Technical Decisions & Production Considerations

1.  **Why Collaborative Filtering?**
    *   It doesn't require "knowing" what the items are (content-agnostic). If User A and B both bought a hammer, and User B buys a drill, User A might need a drill too.
2.  **Weights (The "Secret Sauce"):**
    *   Not all actions are equal. A "Purchase" is a much stronger signal of interest than a "View". We use a weighting system to ensure high-intent actions drive the recommendations.
3.  **Scalability (Performance):**
    *   **The Problem:** Calculating recommendations on the fly (Real-time) gets slow as the `Interaction` table grows to millions of rows.
    *   **The Solution:** In a massive production environment, you would use a **Vector Database** (like Pinecone or Milvus) or run a cron job to pre-calculate recommendations and store them in **Redis**.
4.  **Cold Start Problem:**
    *   New users have no history. For them, the engine should fall back to "Global Trends" (e.g., `orderBy: { interactions: { _count: 'desc' } }`).
5.  **Data Consistency:**
    *   We use `upsert` in the tracker to ensure we don't have duplicate records for the same User-Item pair, which would skew the math.

