### 3. Core Implementation

#### Authentication Middleware (`src/middleware/auth.ts`)
This protects routes and extracts the user ID from the JWT header.

```typescript
import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

export const authenticate = (req: Request, res: Response, next: NextFunction) => {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) return res.status(401).json({ error: 'Unauthorized' });

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as { userId: string };
    (req as any).userId = decoded.userId;
    next();
  } catch (err) {
    res.status(401).json({ error: 'Invalid token' });
  }
};
```

#### User Controller (`src/controllers/userController.ts`)
This handles updating profiles and preferences simultaneously with a transaction.

```typescript
import { Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export const getProfile = async (req: any, res: Response) => {
  const user = await prisma.user.findUnique({
    where: { id: req.userId },
    include: { profile: true, preference: true }
  });
  res.json(user);
};

export const updatePreferences = async (req: any, res: Response) => {
  const { theme, notificationsOn, language } = req.body;

  try {
    const updated = await prisma.preference.upsert({
      where: { userId: req.userId },
      update: { theme, notificationsOn, language },
      create: { userId: req.userId, theme, notificationsOn, language }
    });

    // Log the activity
    await prisma.activity.create({
      data: {
        userId: req.userId,
        action: 'UPDATE_PREFERENCES',
        metadata: { theme, language }
      }
    });

    res.json(updated);
  } catch (error) {
    res.status(500).json({ error: 'Failed to update preferences' });
  }
};

export const getActivityHistory = async (req: any, res: Response) => {
  const activities = await prisma.activity.findMany({
    where: { userId: req.userId },
    orderBy: { createdAt: 'desc' },
    take: 20 // Pagination
  });
  res.json(activities);
};
```

