// Validation schema for updating preferences
const preferenceSchema = z.object({
  theme: z.enum(['light', 'dark', 'system']).optional(),
  notificationsEnabled: z.boolean().optional(),
  language: z.string().min(2).max(5).optional(),
});

export const getMyData = async (req: Request, res: Response) => {
  try {
    const userId = req.user.id; // Populated by auth middleware
    const user = await UserService.getUserFullProfile(userId);

    // Log that user viewed their profile
    await UserService.logActivity(userId, 'VIEW_PROFILE');

    res.json(user);
  } catch (error) {
    res.status(500).json({ error: 'Internal Server Error' });
  }
};

export const patchPreferences = async (req: Request, res: Response) => {
  try {
    const userId = req.user.id;
    const validatedData = preferenceSchema.parse(req.body);

    const updated = await UserService.updatePreferences(userId, validatedData);

    await UserService.logActivity(userId, 'UPDATE_PREFERENCES', validatedData);

    res.json(updated);
  } catch (error) {
    if (error instanceof z.ZodError) {
      return res.status(400).json({ errors: error.errors });
    }
    res.status(500).json({ error: 'Internal Server Error' });
  }
};
