### 3. The Catalog Service (`src/services/catalog.service.ts`)

This service handles the recursive logic for categories and product management.

```typescript
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export class CatalogService {
  // Fetch all categories as a nested tree
  async getCategoryTree() {
    const allCategories = await prisma.category.findMany();

    const buildTree = (parentId: string | null = null): any[] => {
      return allCategories
        .filter(c => c.parentId === parentId)
        .map(c => ({
          ...c,
          children: buildTree(c.id)
        }));
    };

    return buildTree(null);
  }

  async createProduct(data: any) {
    return prisma.product.create({
      data,
      include: { category: true }
    });
  }

  // Advanced: Query products by dynamic attributes
  async findProductsByAttribute(key: string, value: any) {
    return prisma.product.findMany({
      where: {
        attributes: {
          path: [key],
          equals: value
        }
      }
    });
  }
}
```

