// Products
router.get('/products', async (req, res) => {
  const { categoryId, attr_key, attr_val } = req.query;

  let where: any = {};
  if (categoryId) where.categoryId = categoryId;

  // Logic to filter by JSONB attributes
  if (attr_key && attr_val) {
    where.attributes = { path: [attr_key as string], equals: attr_val };
  }

  const products = await prisma.product.findMany({ where });
  res.json(products);
});

router.post('/products', async (req, res) => {
  try {
    const validated = CreateProductSchema.parse(req.body);
    const product = await service.createProduct(validated);
    res.status(201).json(product);
  } catch (error: any) {
    res.status(400).json({ error: error.message });
  }
});

export default router;
