#### `src/components/Calculator.tsx`
Handles the math logic and the "Server Name" input.

```tsx
import React, { useState } from 'react';
import { HistoryItem } from '../types';
import { Terminal, Server, Equal, Delete, RotateCcw } from 'lucide-react';

interface Props {
  onCalculate: (item: HistoryItem) => void;
}

const Calculator: React.FC<Props> = ({ onCalculate }) => {
  const [display, setDisplay] = useState('0');
  const [serverName, setServerName] = useState('Default-Server');
  const [expression, setExpression] = useState('');

  const handleNumber = (num: string) => {
    setDisplay(prev => (prev === '0' ? num : prev + num));
  };

  const handleOperator = (op: string) => {
    setExpression(prev => display + ' ' + op + ' ');
    setDisplay('0');
  };

  const calculate = () => {
    try {
      const fullExpression = expression + display;
      // Using Function constructor for a simple, safer alternative to eval() in this demo context
      const result = new Function(`return ${fullExpression.replace(/[^-()\d/*+.]/g, '')}`)();

      const newItem: HistoryItem = {
        id: Date.now().toString(),
        timestamp: new Date().toISOString(),
        expression: fullExpression,
        result: Number(result.toFixed(4)).toString(),
        serverName: serverName || 'General'
      };

      onCalculate(newItem);
      setDisplay(newItem.result);
      setExpression('');
    } catch (error) {
      setDisplay('Error');
      setTimeout(() => setDisplay('0'), 1500);
    }
  };

  const clear = () => {
    setDisplay('0');
    setExpression('');
  };

  return (
    <div className="bg-slate-800 rounded-3xl shadow-2xl border border-slate-700 overflow-hidden">
      {/* Server Name Tagging */}
      <div className="bg-slate-700/50 p-4 border-b border-slate-600 flex items-center gap-3">
        <Server className="w-4 h-4 text-indigo-400" />
        <input 
          type="text" 
          value={serverName}
          onChange={(e) => setServerName(e.target.value)}
          placeholder="Server/Context Name..."
          className="bg-transparent text-sm focus:outline-none w-full text-indigo-200 placeholder:text-slate-500"
        />
      </div>

      {/* Screen */}
      <div className="p-6 text-right">
        <div className="h-6 text-slate-500 text-sm font-mono mb-1">{expression}</div>
        <div className="text-5xl font-light tracking-tighter truncate">{display}</div>
      </div>

      {/* Buttons */}
      <div className="grid grid-cols-4 gap-px bg-slate-700">
        {['AC', '/', '*', 'DEL', '7', '8', '9', '-', '4', '5', '6', '+', '1', '2', '3', '=', '0', '.'].map((btn) => (
          <button
            key={btn}
            onClick={() => {
              if (btn === 'AC') clear();
              else if (btn === 'DEL') setDisplay(d => d.length > 1 ? d.slice(0, -1) : '0');
              else if (btn === '=') calculate();
              else if (['+', '-', '*', '/'].includes(btn)) handleOperator(btn);
              else handleNumber(btn);
            }}
            className={`
              p-6 text-xl font-medium transition-all active:scale-95
              ${btn === '=' ? 'bg-indigo-600 hover:bg-indigo-500 col-span-1' : 'bg-slate-800 hover:bg-slate-750'}
              ${['/', '*', '-', '+', 'AC', 'DEL'].includes(btn) ? 'text-indigo-400' : 'text-slate-200'}
              ${btn === '0' ? 'col-span-1' : ''}
            `}
          >
            {btn === 'DEL' ? <Delete className="mx-auto" /> : btn}
          </button>
        ))}
      </div>
    </div>
  );
};

export default Calculator;
```

