```jsx
import React, { useState, useEffect, useRef } from 'react';
import { evaluate } from 'mathjs';
import { 
  History, 
  Trash2, 
  Server, 
  Delete, 
  RotateCcw, 
  Save,
  CheckCircle2
} from 'lucide-react';

const App = () => {
  const [display, setDisplay] = useState('');
  const [serverName, setServerName] = useState('Default-Server');
  const [history, setHistory] = useState([]);
  const [showHistory, setShowHistory] = useState(false);
  const [isCopied, setIsCopied] = useState(false);
  const scrollRef = useRef(null);

  // Load history from LocalStorage on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('calc_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  // Save history to LocalStorage whenever it changes
  useEffect(() => {
    localStorage.setItem('calc_history', JSON.stringify(history));
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history]);

  const handleKeyPress = (value) => {
    if (display.length > 20) return;
    setDisplay(prev => prev + value);
  };

  const clearDisplay = () => setDisplay('');

  const backspace = () => setDisplay(prev => prev.slice(0, -1));

  const calculateResult = () => {
    try {
      if (!display) return;

      // Evaluate using mathjs for safety and precision
      const result = evaluate(display).toString();

      const newEntry = {
        id: Date.now(),
        expression: display,
        result: result,
        serverName: serverName,
        timestamp: new Date().toLocaleTimeString(),
      };

      setHistory([newEntry, ...history]);
      setDisplay(result);
    } catch (error) {
      setDisplay('Error');
      setTimeout(() => setDisplay(''), 1500);
    }
  };

  const clearHistory = () => {
    if (window.confirm('Clear all calculation history?')) {
      setHistory([]);
    }
  };

  const copyToClipboard = (text) => {
    navigator.clipboard.writeText(text);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex items-center justify-center p-4 font-sans">
      <div className="w-full max-w-4xl grid grid-cols-1 md:grid-cols-12 gap-6 bg-slate-900 p-6 rounded-3xl shadow-2xl border border-slate-800">

        {/* Left Side: Calculator Panel */}
        <div className="md:col-span-7 space-y-4">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center gap-2 bg-slate-800 px-3 py-1.5 rounded-full border border-slate-700">
              <Server size={14} className="text-blue-400" />
              <input 
                value={serverName}
                onChange={(e) => setServerName(e.target.value)}
                className="bg-transparent border-none outline-none text-xs font-mono w-32 focus:ring-0"
                placeholder="Server Name..."
              />
            </div>
            <button 
              onClick={() => setShowHistory(!showHistory)}
              className="md:hidden p-2 hover:bg-slate-800 rounded-full transition-colors"
            >
              <History size={20} />
            </button>
          </div>

          {/* Screen */}
          <div className="bg-slate-950 p-6 rounded-2xl border border-slate-800 text-right h-32 flex flex-col justify-end overflow-hidden">
            <div className="text-slate-500 text-sm font-mono mb-1 truncate">
              {serverName}
            </div>
            <div className="text-4xl font-light tracking-wider truncate">
              {display || '0'}
            </div>
          </div>

          {/* Keypad */}
          <div className="grid grid-cols-4 gap-3">
            {[
              { label: 'AC', action: clearDisplay, color: 'text-red-400' },
              { label: <Delete size={20} />, action: backspace, color: 'text-blue-400' },
              { label: '%', action: () => handleKeyPress('%'), color: 'text-blue-400' },
              { label: '/', action: () => handleKeyPress('/'), color: 'text-blue-400' },
              { label: '7', action: () => handleKeyPress('7') },
              { label: '8', action: () => handleKeyPress('8') },
              { label: '9', action: () => handleKeyPress('9') },
              { label: '*', action: () => handleKeyPress('*'), color: 'text-blue-400' },
              { label: '4', action: () => handleKeyPress('4') },
              { label: '5', action: () => handleKeyPress('5') },
              { label: '6', action: () => handleKeyPress('6') },
              { label: '-', action: () => handleKeyPress('-'), color: 'text-blue-400' },
              { label: '1', action: () => handleKeyPress('1') },
              { label: '2', action: () => handleKeyPress('2') },
              { label: '3', action: () => handleKeyPress('3') },
              { label: '+', action: () => handleKeyPress('+'), color: 'text-blue-400' },
              { label: <RotateCcw size={20} />, action: () => setDisplay('') },
              { label: '0', action: () => handleKeyPress('0') },
              { label: '.', action: () => handleKeyPress('.') },
              { label: '=', action: calculateResult, color: 'bg-blue-600 hover:bg-blue-500 text-white rounded-xl' },
            ].map((btn, idx) => (
              <button
                key={idx}
                onClick={btn.action}
