#### Calculator Logic & UI (`src/components/Calculator.jsx`)
This component handles the mathematical operations and the "Server Name" context.

```jsx
import React, { useState, useEffect } from 'react';
import { Trash2, Server, History as HistoryIcon, X } from 'lucide-react';

const Calculator = () => {
  const [display, setDisplay] = useState('');
  const [result, setResult] = useState('');
  const [serverName, setServerName] = useState('Default-Server');
  const [history, setHistory] = useState([]);
  const [showHistory, setShowHistory] = useState(false);

  // Load history from localStorage on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('calc_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  // Save history to localStorage whenever it changes
  useEffect(() => {
    localStorage.setItem('calc_history', JSON.stringify(history));
  }, [history]);

  const handleNumber = (num) => setDisplay(prev => prev + num);

  const handleOperator = (op) => {
    if (display === '' && op !== '-') return;
    const lastChar = display.slice(-1);
    if (['+', '-', '*', '/'].includes(lastChar)) {
      setDisplay(display.slice(0, -1) + op);
    } else {
      setDisplay(display + op);
    }
  };

  const calculate = () => {
    try {
      // Use Function instead of eval for a bit more security in this context
      const evaluated = new Function(`return ${display}`)();
      const finalResult = Number.isInteger(evaluated) ? evaluated : evaluated.toFixed(4);

      const newEntry = {
        id: Date.now(),
        expression: display,
        result: finalResult,
        serverName: serverName,
        timestamp: new Date().toLocaleTimeString()
      };

      setResult(finalResult);
      setHistory([newEntry, ...history]);
      setDisplay(finalResult.toString());
    } catch (error) {
      setResult('Error');
    }
  };

  const clear = () => {
    setDisplay('');
    setResult('');
  };

  const deleteHistoryItem = (id) => {
    setHistory(history.filter(item => item.id !== id));
  };

  return (
    <div className="flex flex-col md:flex-row h-screen bg-slate-900 text-white font-sans p-4 gap-4">
      {/* Main Calculator */}
      <div className="flex-1 flex flex-col items-center justify-center">
        <div className="w-full max-w-md bg-slate-800 rounded-3xl p-6 shadow-2xl border border-slate-700">

          {/* Server Context Input */}
          <div className="flex items-center gap-2 mb-4 bg-slate-700/50 p-2 rounded-lg">
            <Server size={18} className="text-blue-400" />
            <input 
              type="text" 
              value={serverName}
              onChange={(e) => setServerName(e.target.value)}
              className="bg-transparent border-none outline-none text-sm w-full font-mono text-blue-200"
              placeholder="Enter Server/Context Name..."
            />
          </div>

          {/* Display */}
          <div className="bg-slate-900 rounded-2xl p-6 mb-6 text-right min-h-[120px] flex flex-col justify-end overflow-hidden">
            <div className="text-slate-400 text-sm mb-1 font-mono h-6">{display || '0'}</div>
            <div className="text-4xl font-bold truncate">{result || display || '0'}</div>
          </div>

          {/* Keypad */}
          <div className="grid grid-cols-4 gap-3">
            {['C', '/', '*', 'DEL', '7', '8', '9', '-', '4', '5', '6', '+', '1', '2', '3', '=', '0', '.'].map((btn) => (
              <button
                key={btn}
                onClick={() => {
                  if (btn === 'C') clear();
                  else if (btn === '=') calculate();
                  else if (btn === 'DEL') setDisplay(display.slice(0, -1));
                  else if (['+', '-', '*', '/'].includes(btn)) handleOperator(btn);
                  else handleNumber(btn);
                }}
                className={`
                  h-14 rounded-2xl text-xl font-semibold transition-all active:scale-95
                  ${btn === '=' ? 'bg-blue-600 hover:bg-blue-500 col-span-1' : 
                    ['+', '-', '*', '/', 'DEL', 'C'].includes(btn) ? 'bg-slate-700 hover:bg-slate-600 text-blue-400' : 
                    'bg-slate-800 border border-slate-700 hover:bg-slate-700'}
                  ${btn === '0' ? 'col-span-1' : ''}
                `}
              >
                {btn}
              </button>
            ))}
            <button 
              onClick={() => setShowHistory(!showHistory)}
              className="h-14 rounded-2xl bg-slate-700 hover:bg-slate-600 flex items-center justify-center md:hidden"
            >
              <HistoryIcon size={20} />
            </button>
          </div>
        </div>
      </div>

      {/* History Sidebar */}
      <div className={`
        fixed inset-0 md:relative md:inset-auto z-50 md:z-0
        ${showHistory ? 'translate-x-0' : 'translate-x-full md:translate-x-0'}
        transition-transform duration-300 ease-in-out
        w-full md:w-80 bg-slate-800 md:rounded-3xl border-l border-slate-700 p-6 flex flex-col
      `}>
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <HistoryIcon size={20} /> History
          </h2>
          <button onClick={() => setShowHistory(false)} className="md:hidden">
            <X size={24} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
          {history.length === 0 && (
            <p className="text-slate-500 text-center mt-10">No calculations yet</p>
          )}
          {history.map((item) => (
            <div key={item.id} className="bg-slate-900/50 p-4 rounded-xl border border-slate-700 group relative">
              <div className="flex justify-between items-start mb-1">
                <span className="text-[10px] uppercase tracking-wider text-blue-400 font-bold">
                  {item.serverName}
                </span>
                <button 
                  onClick={() => deleteHistoryItem(item.id)}
                  className="text-slate-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <Trash2 size={14} />
                </button>
              </div>
              <div className="text-slate-400 text-xs font-mono">{item.expression} =</div>
              <div className="text-lg font-bold text-white">{item.result}</div>
              <div className="text-[10px] text-slate-500 mt-2">{item.timestamp}</div>
            </div>
          ))}
        </div>

        {history.length > 0 && (
          <button 
            onClick={() => setHistory([])}
            className="mt-4 w-full py-2 text-sm text-slate-400 hover:text-red-400 transition-colors flex items-center justify-center gap-2"
          >
            <Trash2 size={16} /> Clear All
          </button>
        )}
      </div>
    </div>
  );
};

export default Calculator;
```

### 3. Key Technical Decisions

1.  **Context Mapping**: Every calculation is stored as an object. By adding `serverName` to each history entry, the user can switch contexts (e.g., "Web-Server-A" vs "DB-Cluster-1") and know exactly what those calculations were for.
2.  **LocalStorage Persistence**: I used a `useEffect` hook to synchronize the state with `localStorage`. This ensures that even if the user refreshes the page or closes the browser, their calculation history and current server name are preserved.
3.  **Security**: Instead of using raw `eval()`, I used a `new Function()` constructor. In a high-security production environment, I would swap this for a math library like `mathjs`, but for a standard calculator utility, this provides a balance of flexibility and performance.
4.  **Responsive UX**: The history sidebar is visible on desktops but converts into a slide-over drawer on mobile devices, ensuring the calculator remains usable on all screen sizes.
5.  **Neumorphic/Dark Mode Design**: The UI uses a deep slate palette (`slate-900`) which reduces eye strain and looks professional for technical users (DevOps, Engineers).

