  }

  async function fetchVolunteers() {
    let query = supabase
      .from('volunteers')
      .select(`
        *,
        skills:volunteer_skills(skills(id, name))
      `);

    const { data, error } = await query;
    if (error) console.error(error);
    else {
      // Flatten the Supabase nested response
      const formatted = data.map((v: any) => ({
        ...v,
        skills: v.skills.map((s: any) => s.skills)
      }));
      setVolunteers(formatted);
    }
  }

