);

-- Set up Row Level Security (RLS)
alter table books enable row level security;
alter table reviews enable row level security;

-- Policies: Anyone logged in can read; only owners can modify
create policy "Anyone can view books" on books for select using (true);
create policy "Authenticated users can add books" on books for insert with check (auth.role() = 'authenticated');

create policy "Anyone can view reviews" on reviews for select using (true);
create policy "Authenticated users can add reviews" on reviews for insert with check (auth.role() = 'authenticated');
