import React, { useState } from 'react';
import { supabase } from '../lib/supabase';

export default function ReviewSection({ bookId, initialReviews }) {
  const [reviews, setReviews] = useState(initialReviews || []);
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState('');

  const submitReview = async (e) => {
    e.preventDefault();
    const { data: { user } } = await supabase.auth.getUser();

    const { data, error } = await supabase
      .from('reviews')
      .insert([{ book_id: bookId, rating, comment, user_id: user.id }])
      .select();

    if (!error) {
      setReviews([...reviews, data[0]]);
      setComment('');
    }
  };

  return (
    <div className="border-t pt-4">
      <h3 className="font-semibold mb-2 text-gray-800">Reviews ({reviews.length})</h3>

      <div className="space-y-3 mb-6">
        {reviews.map((r, i) => (
          <div key={i} className="bg-gray-50 p-3 rounded text-sm">
            <div className="text-yellow-500 font-bold">{'★'.repeat(r.rating)}</div>
            <p className="text-gray-700">{r.comment}</p>
          </div>
        ))}
      </div>

      <form onSubmit={submitReview} className="flex flex-col gap-2">
        <div className="flex gap-2 items-center">
          <select 
            value={rating} 
            onChange={(e) => setRating(e.target.value)}
            className="border p-1 rounded"
          >
            {[5,4,3,2,1].map(n => <option key={n} value={n}>{n} Stars</option>)}
          </select>
          <input 
            type="text" 
            placeholder="Write a review..." 
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            className="flex-1 border p-1 rounded px-3"
            required
          />
          <button className="bg-gray-800 text-white px-4 py-1 rounded hover:bg-black">Post</button>
        </div>
      </form>
    </div>
  );
}
