### 2. Database Schema
We will define two main models: `Book` and `Review`.

Create the file `prisma/schema.prisma`:

```prisma
// prisma/schema.prisma
datasource db {
  provider = "sqlite"
  url      = "file:./dev.db"
}

generator client {
  provider = "prisma-client-js"
}

model Book {
  id          String   @id @default(cuid())
  title       String
  author      String
  description String?
  coverUrl    String?
  dateRead    DateTime @default(now())
  reviews     Review[]
}

model Review {
  id        String   @id @default(cuid())
  userName  String
  rating    Int
  content   String
  createdAt DateTime @default(now())
  bookId    String
  book      Book     @relation(fields: [bookId], references: [id], onDelete: Cascade)
}
```

Initialize the database:
```bash
npx prisma db push
```

### 3. Database Client
Create a singleton for the Prisma client to prevent multiple instances during development.

```typescript
// lib/db.ts
import { PrismaClient } from "@prisma/client";

const globalForPrisma = global as unknown as { prisma: PrismaClient };

export const prisma = globalForPrisma.prisma || new PrismaClient();

if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = prisma;
```

### 4. Server Actions
We'll use Next.js Server Actions to handle form submissions directly without creating manual API routes.

```typescript
// lib/actions.ts
"use server";

import { prisma } from "@/lib/db";
import { revalidatePath } from "next/cache";

export async function addBook(formData: FormData) {
  const title = formData.get("title") as string;
  const author = formData.get("author") as string;
  const coverUrl = formData.get("coverUrl") as string;

  await prisma.book.create({
    data: { title, author, coverUrl },
  });

  revalidatePath("/");
}

export async function addReview(bookId: string, formData: FormData) {
  const userName = formData.get("userName") as string;
  const rating = parseInt(formData.get("rating") as string);
  const content = formData.get("content") as string;

  await prisma.review.create({
    data: { bookId, userName, rating, content },
  });

  revalidatePath(`/book/${bookId}`);
}
```

