              {[5,4,3,2,1].map(n => <option key={n} value={n}>{n} Stars</option>)}
            </select>
          </div>
          <textarea name="content" placeholder="What did you think?" className="border p-2 rounded w-full h-24" required />
          <button type="submit" className="bg-slate-800 text-white px-6 py-2 rounded hover:bg-slate-900 transition-colors">Post Review</button>
        </form>
      </section>

      <section className="space-y-6">
        <h3 className="text-2xl font-bold">Reviews</h3>
        {book.reviews.map(review => (
          <div key={review.id} className="border-b pb-6">
            <div className="flex items-center gap-2 mb-2">
              <div className="bg-indigo-100 p-1 rounded-full"><User size={16} className="text-indigo-600" /></div>
              <span className="font-bold text-slate-800">{review.userName}</span>
              <div className="flex ml-auto text-amber-500">
                {Array.from({ length: review.rating }).map((_, i) => <Star key={i} size={14} fill="currentColor" />)}
              </div>
            </div>
            <p className="text-slate-600 italic">"{review.content}"</p>
          </div>
        ))}
      </section>
    </div>
  );
}
```

### 6. Technical Decisions Explained

1.  **Next.js Server Actions**: This eliminates the need for `useEffect`, `useState`, or manual `fetch` calls to handle forms. When a user submits a review, the server processes it and calls `revalidatePath`, which triggers an instant UI update with the new data.
2.  **SQLite + Prisma**: For a small application like a book club, a full PostgreSQL/MySQL setup is overkill. SQLite is a local file, making it extremely fast and easy to back up. Prisma provides type-safety, so you'll get autocomplete for your book and review properties.
3.  **Tailwind CSS**: Used for a clean, modern aesthetic. I chose a serif font for headings to give it a "literary" feel and used a warm slate color palette.
4.  **No Auth (Simplicity)**: To keep this "simple" as requested, I used a `userName` field in the review form. In a larger production app, you would wrap this with **NextAuth.js** to ensure only invited members can post.

