This script handles the API, authentication, and moderation.

```javascript
const express = require('express');
const { PrismaClient } = require('@prisma/client');
const cors = require('cors');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcryptjs');

const prisma = new PrismaClient();
const app = express();
app.use(cors());
app.use(express.json());

const JWT_SECRET = 'your-super-secret-key'; // In production, use process.env.JWT_SECRET
const ADMIN_PASSWORD_HASH = bcrypt.hashSync('admin123', 10); // Change this!

// Public: Get approved messages
app.get('/api/messages', async (req, res) => {
  const messages = await prisma.message.findMany({
    where: { status: 'APPROVED' },
    orderBy: { createdAt: 'desc' }
  });
  res.json(messages);
});

// Public: Post a new message
app.post('/api/messages', async (req, res) => {
  const { name, content } = req.body;
  const newMessage = await prisma.message.create({
    data: { name, content, status: 'PENDING' }
  });
  res.json({ message: "Submitted for moderation!", data: newMessage });
});

// Admin Login
app.post('/api/admin/login', (req, res) => {
  const { password } = req.body;
  if (bcrypt.compareSync(password, ADMIN_PASSWORD_HASH)) {
    const token = jwt.sign({ role: 'admin' }, JWT_SECRET);
    return res.json({ token });
  }
  res.status(401).json({ error: 'Invalid password' });
});

// Middleware to protect admin routes
const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  try {
    jwt.verify(token, JWT_SECRET);
    next();
  } catch (e) { res.status(401).json({ error: 'Invalid token' }); }
};

// Admin: Get all messages (for moderation)
app.get('/api/admin/messages', authenticate, async (req, res) => {
  const messages = await prisma.message.findMany({ orderBy: { createdAt: 'desc' } });
  res.json(messages);
});

// Admin: Update status (Approve)
app.patch('/api/admin/messages/:id', authenticate, async (req, res) => {
  const { status } = req.body;
  const updated = await prisma.message.update({
    where: { id: parseInt(req.params.id) },
    data: { status }
  });
  res.json(updated);
});

// Admin: Delete message
app.delete('/api/admin/messages/:id', authenticate, async (req, res) => {
  await prisma.message.delete({ where: { id: parseInt(req.params.id) } });
  res.json({ success: true });
});

app.listen(5000, () => console.log('Server running on http://localhost:5000'));
```

