import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { CheckCircle, Trash2, Lock } from 'lucide-react';

const API_URL = 'http://localhost:5000/api';

export default function App() {
  const [isAdmin, setIsAdmin] = useState(!!localStorage.getItem('token'));
  const [messages, setMessages] = useState([]);
  const [form, setForm] = useState({ name: '', content: '' });

  useEffect(() => {
    fetchMessages();
  }, [isAdmin]);

  const fetchMessages = async () => {
    const endpoint = isAdmin ? `${API_URL}/admin/messages` : `${API_URL}/messages`;
    const headers = isAdmin ? { Authorization: `Bearer ${localStorage.getItem('token')}` } : {};
    const res = await axios.get(endpoint, { headers });
    setMessages(res.data);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    await axios.post(`${API_URL}/messages`, form);
    alert("Message sent! It will appear once approved.");
    setForm({ name: '', content: '' });
  };

  const moderate = async (id, status) => {
    await axios.patch(`${API_URL}/admin/messages/${id}`, { status }, {
      headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
    });
    fetchMessages();
  };

  const deleteMsg = async (id) => {
    await axios.delete(`${API_URL}/admin/messages/${id}`, {
      headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
    });
    fetchMessages();
  };

  const handleLogin = async () => {
    const password = prompt("Enter admin password:");
    try {
      const res = await axios.post(`${API_URL}/admin/login`, { password });
      localStorage.setItem('token', res.data.token);
      setIsAdmin(true);
    } catch (e) { alert("Wrong password"); }
  };

  return (
    <div className="min-h-screen bg-gray-50 p-8 font-sans">
      <div className="max-w-2xl mx-auto">
        <header className="flex justify-between items-center mb-12">
          <h1 className="text-4xl font-bold text-gray-800">Digital Guestbook</h1>
          <button onClick={isAdmin ? () => {localStorage.clear(); setIsAdmin(false)} : handleLogin} 
                  className="text-gray-500 hover:text-gray-800 flex items-center gap-2">
            <Lock size={16} /> {isAdmin ? 'Logout' : 'Admin'}
          </button>
        </header>

        {!isAdmin && (
          <form onSubmit={handleSubmit} className="bg-white p-6 rounded-xl shadow-sm mb-12 border border-gray-100">
            <h2 className="text-xl font-semibold mb-4 text-gray-700">Leave a Message</h2>
            <input required placeholder="Your Name" className="w-full mb-3 p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                   value={form.name} onChange={e => setForm({...form, name: e.target.value})} />
            <textarea required placeholder="Write something nice..." className="w-full mb-3 p-3 border rounded-lg h-32 focus:ring-2 focus:ring-blue-500 outline-none"
                      value={form.content} onChange={e => setForm({...form, content: e.target.value})} />
            <button className="w-full bg-blue-600 text-white py-3 rounded-lg font-medium hover:bg-blue-700 transition">Post Message</button>
          </form>
        )}

        <div className="space-y-6">
          {messages.map(msg => (
            <div key={msg.id} className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 relative">
              <div className="flex justify-between items-start">
                <div>
                  <h3 className="font-bold text-gray-800">{msg.name}</h3>
                  <p className="text-gray-600 mt-2">{msg.content}</p>
                  <span className="text-xs text-gray-400 mt-4 block">{new Date(msg.createdAt).toLocaleDateString()}</span>
                </div>
                {isAdmin && (
                  <div className="flex gap-2">
