```tsx
'use client';
import { useState } from 'react';
import { supabase } from '@/lib/supabase';

export default function RSVPModal({ eventId, onClose, onSuccess }: any) {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // 1. Double check capacity (Production-ready check)
    const { data: event } = await supabase
      .from('events')
      .select('capacity, rsvps(id)')
      .eq('id', eventId)
      .single();

    if (event && event.rsvps.length >= event.capacity) {
      alert("Sorry, this event just filled up!");
      onClose();
      return;
    }

    // 2. Insert RSVP
    const { error } = await supabase
      .from('rsvps')
      .insert([{ event_id: eventId, user_name: name, user_email: email }]);

    if (error) {
      if (error.code === '23505') alert("You've already RSVP'd for this event!");
      else alert("Something went wrong.");
    } else {
      alert("Success! You're on the list.");
      onSuccess();
    }
    setIsSubmitting(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-xl p-8 max-w-md w-full relative">
        <h2 className="text-2xl font-bold mb-4">Complete your RSVP</h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1">Full Name</label>
            <input 
              required
              className="w-full border p-2 rounded-lg"
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Email Address</label>
            <input 
              required
              type="email"
              className="w-full border p-2 rounded-lg"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <div className="flex gap-3 pt-4">
            <button 
              type="button" 
              onClick={onClose}
              className="flex-1 px-4 py-2 border rounded-lg hover:bg-slate-50"
            >
              Cancel
            </button>
            <button 
              disabled={isSubmitting}
              className="flex-1 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
            >
              {isSubmitting ? 'Processing...' : 'Confirm RSVP'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
