### 3. Server Actions (The Logic)

Create a file `app/actions.ts` to handle data mutations.

```typescript
"use server";

import { prisma } from "@/lib/db";
import { revalidatePath } from "next/cache";
import { z } from "zod";

const RsvpSchema = z.object({
  email: z.string().email(),
  name: z.string().min(2),
  eventId: z.string(),
});

export async function createRsvp(formData: FormData) {
  const validatedFields = RsvpSchema.safeParse({
    email: formData.get("email"),
    name: formData.get("name"),
    eventId: formData.get("eventId"),
  });

  if (!validatedFields.success) return { error: "Invalid fields" };

  const { email, name, eventId } = validatedFields.data;

  try {
    // Use a transaction to ensure capacity isn't exceeded by simultaneous requests
    const result = await prisma.$transaction(async (tx) => {
      const event = await tx.event.findUnique({
        where: { id: eventId },
        include: { _count: { select: { rsvps: true } } },
      });

      if (!event) throw new Error("Event not found");
      if (event._count.rsvps >= event.capacity) throw new Error("Event is full");

      return await tx.rsvp.create({
        data: { email, name, eventId },
      });
    });

    revalidatePath("/");
    return { success: true };
  } catch (error: any) {
    return { error: error.message || "Failed to RSVP" };
  }
}

export async function createEvent(formData: FormData) {
  const title = formData.get("title") as string;
  const capacity = parseInt(formData.get("capacity") as string);
  const date = formData.get("date") as string;
  const location = formData.get("location") as string;
  const description = formData.get("description") as string;

  await prisma.event.create({
    data: { title, capacity, date: new Date(date), location, description },
  });

  revalidatePath("/");
}
```

