#### `app/actions.ts` (Server Action for RSVP)
Handling the logic on the server ensures database integrity.

```typescript
'use server'

import { supabase } from '@/lib/supabase';
import { revalidatePath } from 'next/cache';

export async function submitRSVP(formData: FormData) {
  const eventId = formData.get('eventId') as string;
  const name = formData.get('name') as string;
  const email = formData.get('email') as string;

  // 1. Check current capacity
  const { count, error: countError } = await supabase
    .from('rsvps')
    .select('*', { count: 'exact', head: true })
    .eq('event_id', eventId);

  const { data: event } = await supabase
    .from('events')
    .select('max_capacity')
    .eq('id', eventId)
    .single();

  if (event && count !== null && count >= event.max_capacity) {
    return { error: "Sorry, this event is full!" };
  }

  // 2. Insert RSVP
  const { error } = await supabase
    .from('rsvps')
    .insert([{ event_id: eventId, user_name: name, user_email: email }]);

  if (error) {
    if (error.code === '23505') return { error: "You've already registered for this event." };
    return { error: "Something went wrong. Please try again." };
  }

  revalidatePath('/');
  return { success: true };
}
```

