### 2. The Application Logic

We'll create a main `App.jsx` that handles the business logic, including the streak algorithm.

```jsx
// src/App.jsx
import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Flame, CheckCircle2, Circle, Calendar as CalendarIcon } from 'lucide-react';
import { format, subDays, isSameDay, startOfToday, parseISO } from 'date-fns';

const HabitTracker = () => {
  const [habits, setHabits] = useState(() => {
    const saved = localStorage.getItem('habits');
    return saved ? JSON.parse(saved) : [];
  });
  const [newHabitName, setNewHabitName] = useState('');

  // Persist to LocalStorage whenever habits change
  useEffect(() => {
    localStorage.setItem('habits', JSON.stringify(habits));
  }, [habits]);

  const addHabit = (e) => {
    e.preventDefault();
    if (!newHabitName.trim()) return;

    const newHabit = {
      id: crypto.randomUUID(),
      name: newHabitName,
      createdAt: new Date().toISOString(),
      completedDates: [] // Array of ISO strings
    };

    setHabits([...habits, newHabit]);
    setNewHabitName('');
  };

  const deleteHabit = (id) => {
    setHabits(habits.filter(h => h.id !== id));
  };

  const toggleHabit = (habitId) => {
    const today = startOfToday().toISOString();

    setHabits(habits.map(habit => {
      if (habit.id === habitId) {
        const isCompletedToday = habit.completedDates.includes(today);
        return {
          ...habit,
          completedDates: isCompletedToday
            ? habit.completedDates.filter(d => d !== today)
            : [...habit.completedDates, today]
        };
      }
      return habit;
    }));
  };

  const calculateStreak = (completedDates) => {
    if (completedDates.length === 0) return 0;

    const sortedDates = [...completedDates]
      .map(d => parseISO(d))
      .sort((a, b) => b - a);

    let streak = 0;
    let currentDate = startOfToday();

    // If not completed today, check if it was completed yesterday to maintain streak
    const completedToday = isSameDay(sortedDates[0], currentDate);
    if (!completedToday) {
      currentDate = subDays(currentDate, 1);
    }

    for (let i = 0; i < sortedDates.length; i++) {
      if (isSameDay(sortedDates[i], currentDate)) {
        streak++;
        currentDate = subDays(currentDate, 1);
      } else if (sortedDates[i] < currentDate) {
        break;
      }
    }
    return streak;
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-8 font-sans text-slate-900">
      <div className="max-w-2xl mx-auto">
        <header className="mb-8">
          <h1 className="text-3xl font-bold text-indigo-600 mb-2">Daily Habits</h1>
          <p className="text-slate-500">{format(new Date(), 'eeee, MMMM do')}</p>
        </header>

        {/* Add Habit Form */}
        <form onSubmit={addHabit} className="flex gap-2 mb-8">
          <input
            type="text"
            value={newHabitName}
            onChange={(e) => setNewHabitName(e.target.value)}
            placeholder="Enter a new habit..."
            className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-white shadow-sm transition-all"
          />
          <button
            type="submit"
            className="bg-indigo-600 hover:bg-indigo-700 text-white p-3 rounded-xl transition-colors shadow-lg shadow-indigo-200"
          >
            <Plus size={24} />
          </button>
        </form>

        {/* Habits List */}
        <div className="space-y-4">
          {habits.length === 0 && (
            <div className="text-center py-12 border-2 border-dashed border-slate-200 rounded-2xl">
              <p className="text-slate-400">No habits tracked yet. Start small!</p>
            </div>
          )}

          {habits.map((habit) => {
            const streak = calculateStreak(habit.completedDates);
            const isCompletedToday = habit.completedDates.includes(startOfToday().toISOString());

            return (
              <div 
                key={habit.id}
                className="group bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between hover:shadow-md transition-shadow"
              >
                <div className="flex items-center gap-4">
                  <button
                    onClick={() => toggleHabit(habit.id)}
                    className={`transition-all duration-200 ${
                      isCompletedToday ? 'text-emerald-500' : 'text-slate-300 hover:text-indigo-400'
                    }`}
                  >
                    {isCompletedToday ? <CheckCircle2 size={32} /> : <Circle size={32} />}
                  </button>

                  <div>
                    <h3 className={`font-semibold text-lg ${isCompletedToday ? 'line-through text-slate-400' : 'text-slate-700'}`}>
                      {habit.name}
                    </h3>
                    <div className="flex items-center gap-3 text-sm">
                      <div className="flex items-center gap-1 text-orange-500 font-medium">
                        <Flame size={16} fill="currentColor" />
                        <span>{streak} day streak</span>
                      </div>
                      <div className="text-slate-400 flex items-center gap-1">
                        <CalendarIcon size={14} />
                        <span>{habit.completedDates.length} total</span>
                      </div>
                    </div>
                  </div>
                </div>

                <button
                  onClick={() => deleteHabit(habit.id)}
                  className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            );
          })}
        </div>

        {/* Mini Stats Footer */}
        {habits.length > 0 && (
          <footer className="mt-12 pt-6 border-t border-slate-200">
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-indigo-50 p-4 rounded-xl">
                <p className="text-indigo-600 text-sm font-semibold uppercase tracking-wider">Active Habits</p>
                <p className="text-2xl font-bold text-indigo-900">{habits.length}</p>
              </div>
              <div className="bg-emerald-50 p-4 rounded-xl">
                <p className="text-emerald-600 text-sm font-semibold uppercase tracking-wider">Today's Progress</p>
                <p className="text-2xl font-bold text-emerald-900">
                  {Math.round((habits.filter(h => h.completedDates.includes(startOfToday().toISOString())).length / habits.length) * 100)}%
                </p>
              </div>
            </div>
          </footer>
        )}
      </div>
    </div>
  );
};

export default HabitTracker;
```

### 3. Technical Decisions Explained

#### **Streak Calculation Algorithm**
The `calculateStreak` function is the brain of the app. 
- It sorts completion dates in descending order.
- It checks if the most recent completion was "today" or "yesterday". If not, the streak is broken (0).
- It iterates backward through the dates. If a date is exactly one day before the current check-date, the streak increments. If there's a gap, the loop breaks. This ensures accurate tracking even if the user hasn't checked in *yet* today but did yesterday.

#### **Data Structure**
I chose to store `completedDates` as an array of ISO strings (`YYYY-MM-DD...`).
- **Why?** It's serializable for `localStorage`.
- **Why not a Boolean?** A boolean only tracks today. By storing specific dates, we can calculate history, generate heatmaps, and determine streaks accurately across months.

#### **Local-First Pattern**
The state is initialized via a functional initializer in `useState`:
```javascript
const [habits, setHabits] = useState(() => {
  const saved = localStorage.getItem('habits');
  return saved ? JSON.parse(saved) : [];
});
```
This prevents the "flicker" of empty content on page load and ensures the UI is always in sync with the user's stored data.

#### **Styling (Tailwind CSS)**
- **Modern Aesthetic**: Used `slate-50` background with `indigo` accents for a professional, clean productivity feel.
- **Micro-interactions**: Added `group-hover` effects to show the delete button only when focusing on a habit, reducing visual clutter.
- **Accessibility**: Used semantic `button` and `form` elements to ensure the app is usable via keyboard.

