## 3. Core Logic: Streak Calculation
Create `lib/streak-utils.ts` to handle the business logic.

```typescript
import { differenceInDays, parseISO, startOfDay } from 'date-fns';

export function calculateStreak(logs: { completed_at: string }[]) {
  if (logs.length === 0) return { currentStreak: 0, longestStreak: 0 };

  const dates = logs
    .map(log => startOfDay(parseISO(log.completed_at)).getTime())
    .sort((a, b) => b - a);

  let currentStreak = 0;
  const today = startOfDay(new Date()).getTime();
  const yesterday = today - 86400000;

  // Check if user completed habit today or yesterday to continue current streak
  if (dates[0] === today || dates[0] === yesterday) {
    currentStreak = 1;
    for (let i = 0; i < dates.length - 1; i++) {
      if (dates[i] - dates[i + 1] === 86400000) {
        currentStreak++;
      } else {
        break;
      }
    }
  }

  // Calculate longest streak
  let longestStreak = 0;
  let tempStreak = 1;
  const sortedAsc = [...dates].sort((a, b) => a - b);

  for (let i = 0; i < sortedAsc.length; i++) {
    if (sortedAsc[i + 1] - sortedAsc[i] === 86400000) {
      tempStreak++;
    } else {
      longestStreak = Math.max(longestStreak, tempStreak);
      tempStreak = 1;
    }
  }

  return { currentStreak, longestStreak: Math.max(longestStreak, tempStreak) };
}
```

