## 5. Main Dashboard Component
This component displays habits and handles the "check off" action with optimistic updates.

```tsx
// components/HabitList.tsx
'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';
import { calculateStreak } from '@/lib/streak-utils';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { CheckCircle2, Circle, Flame, Trophy } from 'lucide-react';
import { format } from 'date-fns';

export default function HabitList() {
  const queryClient = useQueryClient();
  const today = format(new Date(), 'yyyy-MM-dd');

  const { data: habits, isLoading } = useQuery({
    queryKey: ['habits'],
    queryFn: async () => {
      const { data } = await supabase
        .from('habits')
        .select(`*, habit_logs(completed_at)`);
      return data || [];
    }
  });

  const toggleHabit = useMutation({
    mutationFn: async ({ habitId, completed }: { habitId: string, completed: boolean }) => {
      if (completed) {
        await supabase.from('habit_logs').delete().match({ habit_id: habitId, completed_at: today });
      } else {
        const { data: { user } } = await supabase.auth.getUser();
        await supabase.from('habit_logs').insert({ habit_id: habitId, user_id: user?.id, completed_at: today });
      }
    },
    onSettled: () => queryClient.invalidateQueries({ queryKey: ['habits'] }),
  });

  if (isLoading) return <div className="p-8 text-center">Loading habits...</div>;

  return (
    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
      {habits?.map((habit) => {
        const { currentStreak, longestStreak } = calculateStreak(habit.habit_logs);
        const isCompletedToday = habit.habit_logs.some((l: any) => l.completed_at === today);

        return (
          <Card key={habit.id} className="relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full" style={{ backgroundColor: habit.color }} />
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-lg font-bold">{habit.name}</CardTitle>
              <button 
                onClick={() => toggleHabit.mutate({ habitId: habit.id, completed: isCompletedToday })}
                className="transition-transform active:scale-90"
              >
                {isCompletedToday ? (
                  <CheckCircle2 className="w-8 h-8 text-green-500 fill-green-50" />
                ) : (
                  <Circle className="w-8 h-8 text-gray-300" />
                )}
              </button>
            </CardHeader>
            <CardContent>
              <div className="flex gap-4 text-sm text-muted-foreground">
                <div className="flex items-center gap-1">
                  <Flame className="w-4 h-4 text-orange-500" />
                  <span>{currentStreak} day streak</span>
                </div>
                <div className="flex items-center gap-1">
                  <Trophy className="w-4 h-4 text-yellow-500" />
                  <span>Best: {longestStreak}</span>
                </div>
              </div>
            </CardContent>
          </Card>
        );
      })}
    </div>
  );
}
```

