#### `src/utils/habitUtils.ts`
The "brain" of the app. It calculates streaks by looking at the completion history.
```typescript
import { format, subDays, isSameDay, parseISO } from 'date-fns';

export const TODAY = format(new Date(), 'yyyy-MM-dd');

export function calculateStats(completedDates: string[]): { currentStreak: number; total: number } {
  if (completedDates.length === 0) return { currentStreak: 0, total: 0 };

  const sortedDates = [...completedDates].sort((a, b) => b.localeCompare(a));
  let streak = 0;
  let checkDate = new Date(); // Start checking from today

  // If not completed today, check if it was completed yesterday to keep streak alive
  const completedToday = sortedDates.includes(TODAY);
  if (!completedToday) {
    checkDate = subDays(checkDate, 1);
  }

  for (let i = 0; i < 365; i++) {
    const dateStr = format(checkDate, 'yyyy-MM-dd');
    if (sortedDates.includes(dateStr)) {
      streak++;
      checkDate = subDays(checkDate, 1);
    } else {
      break;
    }
  }

  return {
    currentStreak: streak,
    total: completedDates.length,
  };
}
```

