```tsx
// components/SearchFilters.tsx
"use client";

import { useRouter, useSearchParams } from "next/navigation";
import { useTransition } from "react";

export default function SearchFilters({ categories }: { categories: any[] }) {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [isPending, startTransition] = useTransition();

  function handleFilter(term: string, type: 'q' | 'category') {
    const params = new URLSearchParams(searchParams);
    if (term) {
      params.set(type, term);
    } else {
      params.delete(type);
    }

    startTransition(() => {
      router.push(`/?${params.toString()}`);
    });
  }

  return (
    <div className="flex flex-col md:flex-row gap-4 mb-8">
      <div className="flex-1">
        <input
          type="text"
          placeholder="Search businesses..."
          defaultValue={searchParams.get('q') || ''}
          onChange={(e) => handleFilter(e.target.value, 'q')}
          className="w-full p-3 border rounded-lg shadow-sm focus:ring-2 focus:ring-blue-500 outline-none"
        />
      </div>
      <select
        defaultValue={searchParams.get('category') || ''}
        onChange={(e) => handleFilter(e.target.value, 'category')}
        className="p-3 border rounded-lg shadow-sm bg-white"
      >
        <option value="">All Categories</option>
        {categories.map((cat) => (
          <option key={cat.id} value={cat.slug}>{cat.name}</option>
        ))}
      </select>
      {isPending && <span className="animate-pulse text-sm text-gray-400">Updating...</span>}
    </div>
  );
}
```

