#### app/page.tsx
This is the main Server Component. It fetches data directly from Supabase based on the URL search params.

```tsx
import { supabase } from "@/lib/supabase";
import FilterBar from "@/components/FilterBar";
import BusinessCard from "@/components/BusinessCard";

interface PageProps {
  searchParams: {
    category?: string;
    search?: string;
  };
}

export default async function DirectoryPage({ searchParams }: PageProps) {
  const { category, search } = searchParams;

  // Build Query
  let query = supabase
    .from("businesses")
    .select("*")
    .order("created_at", { ascending: false });

  if (category && category !== "All") {
    query = query.eq("category", category);
  }

  if (search) {
    query = query.or(`name.ilike.%${search}%,description.ilike.%${search}%`);
  }

  const { data: businesses, error } = await query;

  return (
    <main className="min-h-screen bg-gray-50/50">
      <div className="max-w-7xl mx-auto px-4 py-12">
        <header className="text-center mb-12">
          <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight sm:text-5xl mb-4">
            Local Business Directory
          </h1>
          <p className="text-lg text-gray-600">
            Discover the best spots in your neighborhood.
          </p>
        </header>

        <FilterBar />

        {error ? (
          <div className="text-center py-20 text-red-500">Error loading businesses.</div>
        ) : businesses && businesses.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {businesses.map((business) => (
              <BusinessCard key={business.id} business={business} />
            ))}
          </div>
        ) : (
          <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-gray-200">
            <h3 className="text-xl font-medium text-gray-900">No businesses found</h3>
            <p className="text-gray-500">Try adjusting your search or filters.</p>
          </div>
        )}
      </div>
    </main>
  );
}
```

### 4. Technical Decisions

1.  **Server-Side Rendering (SSR)**: By using `searchParams` in a Server Component, the business list is generated on the server. This is great for SEO (search engines can index the filtered results) and performance (less JavaScript sent to the client).
2.  **URL as State**: Instead of using `useState` for search and filters, we use the URL (`?category=Cafe&search=coffee`). This makes the application "stateless" on the frontend, allowing users to refresh the page or share a specific filtered view with others.
3.  **Supabase `ilike`**: Using PostgreSQL's `ilike` (case-insensitive search) provides a simple but effective way to handle search without needing a complex search engine like Algolia for small to medium-sized directories.
4.  **Tailwind & Lucide**: Provides a modern, clean UI with consistent iconography and rapid styling.

