```jsx
'use client';
import { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { ShoppingCart, Plus, Minus } from 'lucide-react';

export default function CustomerMenu() {
  const [products, setProducts] = useState([]);
  const [cart, setCart] = useState({});
  const [customerName, setCustomerName] = useState('');

  useEffect(() => {
    fetchProducts();
  }, []);

  async function fetchProducts() {
    const { data } = await supabase.from('products').select('*');
    setProducts(data);
  }

  const addToCart = (product) => {
    setCart(prev => ({
      ...prev,
      [product.id]: { ...product, qty: (prev[product.id]?.qty || 0) + 1 }
    }));
  };

  const submitOrder = async () => {
    if (!customerName || Object.keys(cart).length === 0) return alert("Add items and name!");

    const total = Object.values(cart).reduce((acc, item) => acc + (item.price * item.qty), 0);

    const { data: order, error } = await supabase
      .from('orders')
      .insert([{ customer_name: customerName, total_price: total }])
      .select()
      .single();

    if (order) {
      const items = Object.values(cart).map(item => ({
        order_id: order.id,
        product_id: item.id,
        quantity: item.qty,
        price_at_time: item.price
      }));
      await supabase.from('order_items').insert(items);
      alert("Order placed successfully!");
      setCart({});
      setCustomerName('');
    }
  };

  return (
    <div className="max-w-md mx-auto p-4 pb-24">
      <h1 className="text-3xl font-bold mb-6">Our Menu</h1>
      <input 
        className="w-full border p-2 mb-4 rounded" 
        placeholder="Your Name / Table #" 
        value={customerName}
        onChange={(e) => setCustomerName(e.target.value)}
      />

      <div className="space-y-4">
        {products.map(product => (
          <div key={product.id} className="flex justify-between items-center p-4 border rounded-lg shadow-sm">
            <div>
              <h3 className="font-semibold">{product.name}</h3>
              <p className="text-gray-600">${product.price}</p>
            </div>
            <button 
              onClick={() => addToCart(product)}
              className="bg-orange-500 text-white p-2 rounded-full"
            >
              <Plus size={20} />
            </button>
          </div>
        ))}
      </div>

      {Object.keys(cart).length > 0 && (
        <div className="fixed bottom-0 left-0 right-0 bg-white border-t p-4 shadow-lg">
          <button 
            onClick={submitOrder}
            className="w-full bg-green-600 text-white py-3 rounded-xl font-bold flex justify-center items-center gap-2"
          >
            <ShoppingCart size={20} /> Place Order (${Object.values(cart).reduce((acc, i) => acc + (i.price * i.qty), 0).toFixed(2)})
          </button>
        </div>
      )}
    </div>
  );
}
