### 5. The Admin Dashboard (`app/admin/page.js`)
This is the real-time screen for the restaurant staff.

```jsx
'use client';
import { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';

export default function AdminDashboard() {
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    fetchOrders();

    // REAL-TIME SUBSCRIPTION
    const channel = supabase
      .channel('realtime-orders')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'orders' }, (payload) => {
        setOrders(prev => [payload.new, ...prev]);
        new Audio('/notification.mp3').play().catch(e => console.log("Audio play blocked"));
      })
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'orders' }, (payload) => {
        setOrders(prev => prev.map(o => o.id === payload.new.id ? payload.new : o));
      })
      .subscribe();

    return () => supabase.removeChannel(channel);
  }, []);

  async function fetchOrders() {
    const { data } = await supabase
      .from('orders')
      .select('*, order_items(quantity, products(name))')
      .order('created_at', { ascending: false });
    setOrders(data || []);
  }

  async function updateStatus(id, status) {
    await supabase.from('orders').update({ status }).eq('id', id);
  }

  return (
    <div className="p-8 bg-gray-50 min-h-screen">
      <h1 className="text-4xl font-bold mb-8">Live Orders</h1>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {orders.map(order => (
          <div key={order.id} className={`p-6 rounded-xl shadow-md border-t-4 ${
            order.status === 'pending' ? 'border-red-500 bg-white' : 
            order.status === 'preparing' ? 'border-yellow-500 bg-white' : 'border-green-500 bg-gray-100'
          }`}>
            <div className="flex justify-between items-start mb-4">
              <h2 className="text-xl font-bold">{order.customer_name}</h2>
              <span className="text-sm text-gray-500">{new Date(order.created_at).toLocaleTimeString()}</span>
            </div>

            <div className="mb-4">
              {order.order_items?.map((item, idx) => (
                <div key={idx} className="flex justify-between">
                  <span>{item.products?.name} x {item.quantity}</span>
                </div>
              ))}
            </div>

            <div className="flex gap-2">
              <button 
                onClick={() => updateStatus(order.id, 'preparing')}
                className="flex-1 bg-yellow-500 text-white py-2 rounded text-sm font-semibold"
              >
                Prepare
              </button>
              <button 
                onClick={() => updateStatus(order.id, 'ready')}
                className="flex-1 bg-green-500 text-white py-2 rounded text-sm font-semibold"
              >
                Ready
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
```

### Key Technical Decisions

1.  **Supabase Realtime**: Instead of polling the database every 10 seconds (which wastes battery and server resources), we use WebSockets. When a customer inserts a row into the `orders` table, Supabase broadcasts that event to the Admin dashboard instantly.
2.  **Relational Integrity**: By using an `orders` table and an `order_items` table, you can store historical prices. If you change the price of a burger tomorrow, the orders from today still show the price they were sold at.
3.  **Tailwind CSS**: Used for a "Mobile First" approach for customers (ordering on phones) and a "Dashboard" approach for the admin.
4.  **Optimistic UI (Potential Upgrade)**: For a production app, you might want to add items to the admin state before the database confirms to make the UI feel instantaneous.

### How to Deploy
1.  **Supabase**: Create a free project at [supabase.com](https://supabase.com).
2.  **Environment Variables**: Add `NEXT_PUBLIC_SUPABASE_URL` and `NEXT_PUBLIC_SUPABASE_ANON_KEY` to your Vercel/environment settings.
3.  **Images**: I recommend using a service like Cloudinary or Supabase Storage to handle menu item images.
4.  **Security**: In a real production environment, you must enable **RLS (Row Level Security)** in Supabase to ensure customers can only place orders and not delete them. (Example: `CREATE POLICY "Enable insert for everyone" ON orders FOR INSERT WITH CHECK (true);`)

