"use client";
import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';

export default function AdminDashboard() {
  const [orders, setOrders] = useState<any[]>([]);

  useEffect(() => {
    fetchOrders();

    // REAL-TIME SUBSCRIPTION
    const channel = supabase
      .channel('realtime-orders')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'orders' }, () => {
        fetchOrders(); // Refresh list when any order changes
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  const fetchOrders = async () => {
    const { data } = await supabase
      .from('orders')
      .select('*, order_items(*, products(name))')
      .order('created_at', { ascending: false });
    setOrders(data || []);
  };

  const updateStatus = async (id: string, status: string) => {
    await supabase.from('orders').update({ status }).eq('id', id);
  };

  return (
    <div className="p-8 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Live Kitchen Orders</h1>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {orders.map(order => (
          <div key={order.id} className={`p-6 rounded-xl shadow-md border-t-4 bg-white ${
            order.status === 'pending' ? 'border-red-500' : 'border-blue-500'
          }`}>
            <div className="flex justify-between mb-4">
              <span className="font-bold text-lg">Table {order.table_number}</span>
              <span className="uppercase text-xs font-bold px-2 py-1 rounded bg-gray-100">
                {order.status}
              </span>
            </div>

            <div className="space-y-2 mb-6">
