#### `app/dashboard/student/quiz/[id]/page.tsx` (Student View)
Logic for taking the quiz and calculating the score.

```tsx
'use client';
import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';

export default function TakeQuiz({ params }: { params: { id: string } }) {
  const [quiz, setQuiz] = useState<any>(null);
  const [questions, setQuestions] = useState<any[]>([]);
  const [answers, setAnswers] = useState<Record<number, number>>({});
  const [submitted, setSubmitted] = useState(false);
  const [score, setScore] = useState(0);

  useEffect(() => {
    const fetchData = async () => {
      const { data: qz } = await supabase.from('quizzes').select('*').eq('id', params.id).single();
      const { data: qs } = await supabase.from('questions').select('*').eq('quiz_id', params.id);
      setQuiz(qz);
      setQuestions(qs || []);
    };
    fetchData();
  }, [params.id]);

  const handleSubmit = async () => {
    let correctCount = 0;
    questions.forEach((q, idx) => {
      if (q.options[answers[idx]]?.isCorrect) {
        correctCount++;
      }
    });

    const finalScore = Math.round((correctCount / questions.length) * 100);
    setScore(finalScore);
    setSubmitted(true);

    // Save submission to DB
    const { data: userData } = await supabase.auth.getUser();
    await supabase.from('submissions').insert({
      quiz_id: params.id,
      student_id: userData.user?.id,
      score: finalScore
    });
  };

  if (submitted) return (
    <div className="text-center p-10">
      <h2 className="text-4xl font-bold">Quiz Complete!</h2>
      <p className="text-2xl mt-4">Your Score: {score}%</p>
    </div>
  );

  return (
    <div className="max-w-xl mx-auto p-6">
      <h1 className="text-2xl font-bold mb-6">{quiz?.title}</h1>
      {questions.map((q, qIdx) => (
        <div key={q.id} className="mb-8">
          <p className="font-medium mb-3">{qIdx + 1}. {q.question_text}</p>
          <div className="space-y-2">
            {q.options.map((opt: any, oIdx: number) => (
              <label key={oIdx} className="flex items-center p-3 border rounded cursor-pointer hover:bg-gray-50">
                <input
                  type="radio"
                  name={`q-${qIdx}`}
                  className="mr-3"
                  onChange={() => setAnswers({ ...answers, [qIdx]: oIdx })}
                />
                {opt.text}
              </label>
            ))}
          </div>
        </div>
      ))}
      <button 
        onClick={handleSubmit}
        className="w-full bg-green-600 text-white py-3 rounded-lg"
      >
        Submit Answers
      </button>
    </div>
  );
}
```

