'use client'
import { useState } from 'react'
import { supabase } from '@/lib/supabase'
import { useRouter } from 'next/navigation'

export default function QuizClient({ quiz, questions, userId }: any) {
  const [answers, setAnswers] = useState<Record<number, number>>({})
  const [submitted, setSubmitted] = useState(false)
  const router = useRouter()

  const handleSubmit = async () => {
    let score = 0
    questions.forEach((q: any, index: number) => {
      if (answers[index] === q.correct_answer_index) score++
    })

    const { error } = await supabase.from('submissions').insert({
      quiz_id: quiz.id,
      student_id: userId,
      score: score,
      total_questions: questions.length
    })

    if (!error) setSubmitted(true)
  }

  if (submitted) {
    return (
      <div className="max-w-md mx-auto mt-10 p-6 bg-white rounded-xl shadow-md text-center">
        <h2 className="text-2xl font-bold mb-4">Quiz Completed!</h2>
        <p className="text-xl">Your Score: {Object.values(answers).filter((a, i) => a === questions[i].correct_answer_index).length} / {questions.length}</p>
        <button onClick={() => router.push('/dashboard')} className="mt-4 bg-blue-500 text-white px-4 py-2 rounded">Back to Dashboard</button>
      </div>
    )
  }

  return (
    <div className="max-w-2xl mx-auto p-4">
      <h1 className="text-3xl font-bold mb-6">{quiz.title}</h1>
      {questions.map((q: any, qIdx: number) => (
