              <option key={oIdx} value={oIdx}>Correct: Option {oIdx + 1}</option>
            ))}
          </select>
        </div>
      ))}

      <div className="flex gap-4 mt-6">
        <button onClick={addQuestion} className="bg-gray-200 px-4 py-2 rounded">Add Question</button>
        <button onClick={handleSave} className="bg-blue-600 text-white px-4 py-2 rounded">Save Quiz</button>
      </div>
    </div>
  )
}
```

