#### E. Taking a Quiz (`src/pages/TakeQuiz.jsx`)
The student interface for answering questions.

```jsx
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import toast from 'react-hot-toast';

export default function TakeQuiz() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [quiz, setQuiz] = useState(null);
  const [questions, setQuestions] = useState([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState({});
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    fetchQuizData();
  }, [id]);

  async function fetchQuizData() {
    const { data: quizData } = await supabase.from('quizzes').select('*').eq('id', id).single();
    const { data: quesData } = await supabase.from('questions').select('*').eq('quiz_id', id);
    setQuiz(quizData);
    setQuestions(quesData);
  }

  const handleAnswer = (option) => {
    setAnswers({ ...answers, [questions[currentIdx].id]: option });
  };

  const submitQuiz = async () => {
    let score = 0;
    questions.forEach(q => {
      if (answers[q.id] === q.correct_answer) score++;
    });

    const { data: { user } } = await supabase.auth.getUser();
    await supabase.from('submissions').insert([{
      quiz_id: id,
      student_id: user.id,
      score: score
    }]);

    setSubmitted(true);
    toast.success(`Quiz complete! Score: ${score}/${questions.length}`);
  };

  if (!quiz || questions.length === 0) return <div>Loading questions...</div>;
  if (submitted) return <div className="text-center py-20"><h2 className="text-2xl">Thank you for submitting!</h2><button onClick={() => navigate('/')} className="mt-4 text-indigo-600 underline">Back Home</button></div>;

  const q = questions[currentIdx];

  return (
    <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow-lg">
      <div className="mb-8">
        <span className="text-sm text-gray-500">Question {currentIdx + 1} of {questions.length}</span>
        <h2 className="text-2xl font-bold mt-2">{q.question_text}</h2>
      </div>

      <div className="space-y-3">
        {q.options.map((opt, i) => (
          <button
            key={i}
            onClick={() => handleAnswer(opt)}
            className={`w-full text-left p-4 rounded-xl border transition ${
              answers[q.id] === opt ? 'bg-indigo-100 border-indigo-500' : 'hover:bg-gray-50'
            }`}
          >
            {opt}
          </button>
        ))}
      </div>

      <div className="mt-8 flex justify-between">
        <button 
          disabled={currentIdx === 0}
          onClick={() => setCurrentIdx(prev => prev - 1)}
          className="px-6 py-2 border rounded-lg disabled:opacity-30"
        >
          Previous
        </button>
        {currentIdx === questions.length - 1 ? (
          <button onClick={submitQuiz} className="px-6 py-2 bg-green-600 text-white rounded-lg">Finish Quiz</button>
        ) : (
          <button onClick={() => setCurrentIdx(prev => prev + 1)} className="px-6 py-2 bg-indigo-600 text-white rounded-lg">Next</button>
        )}
      </div>
    </div>
  );
}
```

### 3. Key Technical Decisions

1.  **JSONB for Options**: In the `questions` table, I used `JSONB` for the options array. This allows flexibility (different question types later) while keeping the database schema simple.
2.  **Conditional Rendering by Role**: The `App.jsx` checks the user profile role immediately after login to redirect them to the correct dashboard.
3.  **Supabase Auth + Profiles**: Supabase manages the `auth.users` table. I created a secondary `profiles` table to store application-specific data like "Role", which is a standard pattern for multi-tenant apps.
4.  **State Management**: For a simple app, React's `useState` and `useEffect` are sufficient. For a larger production app, I would recommend adding **TanStack Query** (React Query) to handle caching and server-state synchronization.

