### 3. Key Feature: The Upload Component
Handling images is the hardest part. Here is a production-ready component for uploading to Supabase Storage.

**`components/UploadPost.tsx`**
```tsx
'use client'
import { useState } from 'react'
import { createClientComponentClient } from '@supabase/auth-helpers-nextjs'
import { Camera, Loader2 } from 'lucide-react'

export default function UploadPost({ onComplete }: { onComplete: () => void }) {
  const [uploading, setUploading] = useState(false)
  const [caption, setCaption] = useState('')
  const supabase = createClientComponentClient()

  async function uploadPost(event: any) {
    try {
      setUploading(true)
      const file = event.target.files[0]
      if (!file) return

      // 1. Upload image to Storage
      const fileExt = file.name.split('.').pop()
      const fileName = `${Math.random()}.${fileExt}`
      const { error: uploadError, data } = await supabase.storage
        .from('posts')
        .upload(fileName, file)

      if (uploadError) throw uploadError

      // 2. Create Database record
      const { data: { user } } = await supabase.auth.getUser()
      const { error: dbError } = await supabase.from('posts').insert({
        user_id: user?.id,
        image_url: data.path,
        caption: caption
      })

      if (dbError) throw dbError

      setCaption('')
      onComplete()
    } catch (error) {
      alert('Error uploading post!')
    } finally {
      setUploading(false)
    }
  }

  return (
    <div className="p-4 border-b bg-white sticky top-0 z-10">
      <div className="max-w-md mx-auto flex flex-col gap-4">
        <input 
          type="text" 
          placeholder="Write a caption..." 
          className="w-full p-2 border rounded-md"
          value={caption}
          onChange={(e) => setCaption(e.target.value)}
        />
        <label className="flex items-center justify-center gap-2 bg-blue-600 text-white p-2 rounded-md cursor-pointer hover:bg-blue-700 transition">
          {uploading ? <Loader2 className="animate-spin" /> : <Camera size={20} />}
          {uploading ? 'Posting...' : 'Share a Photo'}
          <input type="file" hidden accept="image/*" onChange={uploadPost} disabled={uploading} />
        </label>
      </div>
    </div>
  )
}
