export default function PostCard({ post }) {
  const [comments, setComments] = useState([]);
  const [newComment, setNewComment] = useState('');

  useEffect(() => {
    fetchComments();
  }, []);

  async function fetchComments() {
    const { data } = await supabase
      .from('comments')
      .select('*, profiles(username)')
      .eq('post_id', post.id)
      .order('created_at', { ascending: true });
    setComments(data || []);
  }

  async function handleAddComment(e) {
    e.preventDefault();
    const { data: { user } } = await supabase.auth.getUser();

    await supabase.from('comments').insert([
      { post_id: post.id, user_id: user.id, content: newComment }
    ]);

    setNewComment('');
    fetchComments();
  }

  return (
    <div className="bg-white border rounded-lg mb-8 overflow-hidden">
      {/* Header */}
      <div className="p-4 flex items-center gap-3">
        <div className="w-8 h-8 bg-gradient-to-tr from-yellow-400 to-purple-600 rounded-full" />
        <span className="font-semibold text-sm">{post.profiles?.username || 'Community Member'}</span>
      </div>

      {/* Image */}
      <img src={post.image_url} alt="Post content" className="w-full object-cover max-h-[600px]" />

      {/* Actions */}
      <div className="p-4">
        <div className="flex gap-4 mb-3">
          <Heart className="cursor-pointer hover:text-red-500 transition" size={24} />
          <MessageCircle size={24} />
        </div>

        <p className="text-sm mb-2">
          <span className="font-semibold mr-2">{post.profiles?.username}</span>
          {post.caption}
        </p>

        {/* Comments List */}
        <div className="space-y-1 mb-4">
          {comments.map(c => (
            <div key={c.id} className="text-sm">
              <span className="font-semibold mr-2">{c.profiles?.username}</span>
              {c.content}
            </div>
          ))}
        </div>

        {/* Comment Input */}
        <form onSubmit={handleAddComment} className="border-t pt-3 flex">
          <input
            type="text"
            placeholder="Add a comment..."
            className="flex-1 text-sm outline-none"
            value={newComment}
            onChange={(e) => setNewComment(e.target.value)}
          />
          <button className="text-blue-500 font-semibold text-sm disabled:opacity-50" disabled={!newComment}>
            Post
          </button>
        </form>
      </div>
    </div>
  );
}
