Supabase is chosen because it provides Authentication, a PostgreSQL database, and Image Storage out of the box, which are the three pillars of an Instagram-like app.

### 1. Prerequisites
- Create a [Supabase](https://supabase.com/) account.
- Create a new project.
- Run the following SQL in your Supabase SQL Editor to set up the tables:

```sql
-- Create a table for user profiles
create table profiles (
  id uuid references auth.users on delete cascade not null primary key,
  username text unique not null,
  avatar_url text,
  full_name text
);

-- Create a table for posts
create table posts (
  id uuid default gen_random_uuid() primary key,
  user_id uuid references profiles(id) on delete cascade not null,
  image_url text not null,
  caption text,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- Create a table for comments
create table comments (
  id uuid default gen_random_uuid() primary key,
  post_id uuid references posts(id) on delete cascade not null,
  user_id uuid references profiles(id) on delete cascade not null,
  content text not null,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- Set up Row Level Security (RLS)
alter table profiles enable row level security;
alter table posts enable row level security;
alter table comments enable row level security;

-- Policies: Authenticated users can read everything, but only owners can insert/delete
create policy "Public profiles are viewable by everyone." on profiles for select using (true);
create policy "Users can update own profile." on profiles for update using (auth.uid() = id);

create policy "Posts are viewable by everyone." on posts for select using (true);
create policy "Users can insert their own posts." on posts for insert with check (auth.uid() = user_id);

create policy "Comments are viewable by everyone." on comments for select using (true);
create policy "Users can post comments." on comments for insert with check (auth.uid() = user_id);
```

