### 6. Upload Functionality
`components/UploadButton.tsx`
Handles image selection, Supabase Storage upload, and DB entry.

```tsx
'use client';
import { useState } from 'react';
import { PlusSquare, Loader2 } from 'lucide-react';
import { createClientComponentClient } from '@supabase/auth-helpers-nextjs';
import { useRouter } from 'next/navigation';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";

export default function UploadButton() {
  const [loading, setLoading] = useState(false);
  const [caption, setCaption] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const supabase = createClientComponentClient();
  const router = useRouter();

  const handleUpload = async () => {
    if (!file) return;
    setLoading(true);

    try {
      // 1. Upload Image to Supabase Storage
      const fileExt = file.name.split('.').pop();
      const fileName = `${Math.random()}.${fileExt}`;
      const { data: storageData, error: storageError } = await supabase.storage
        .from('post-images')
        .upload(fileName, file);

      if (storageError) throw storageError;

      // 2. Get Public URL
      const { data: { publicUrl } } = supabase.storage
        .from('post-images')
        .getPublicUrl(fileName);

      // 3. Save to Database
      const { data: { user } } = await supabase.auth.getUser();
      const { error: dbError } = await supabase
        .from('posts')
        .insert({
          user_id: user?.id,
          image_url: publicUrl,
          caption: caption
        });

      if (dbError) throw dbError;

      router.refresh();
      setFile(null);
      setCaption('');
    } catch (e) {
      alert('Error uploading');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t p-3 flex justify-center">
      <Dialog>
        <DialogTrigger>
          <PlusSquare className="w-8 h-8 cursor-pointer hover:scale-110 transition" />
        </DialogTrigger>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Create New Post</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <input 
              type="file" 
              accept="image/*" 
              onChange={(e) => setFile(e.target.files?.[0] || null)}
              className="block w-full text-sm"
            />
            <textarea 
              placeholder="Write a caption..."
              className="w-full p-2 border rounded-md"
              value={caption}
              onChange={(e) => setCaption(e.target.value)}
            />
            <button 
              onClick={handleUpload}
              disabled={loading || !file}
              className="w-full bg-blue-500 text-white py-2 rounded-md font-bold disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin mx-auto" /> : 'Share'}
            </button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}
```

### Key Technical Decisions

1.  **Private Access (Middleware):**
    I recommend adding a `middleware.ts` file to check if a user is authenticated. If not, redirect them to a `/login` page. This ensures the community remains private.
2.  **Supabase Storage:**
    Images are stored in a dedicated Supabase bucket. In the Supabase dashboard, you'll need to create a bucket named `post-images` and set it to "Public" (so users can see images via URL).
3.  **Responsive Design:**
    The feed is constrained to `max-w-md` (mobile width) to mimic the native Instagram experience on both desktop and mobile.
4.  **Optimistic UI (Next Step):**
    For a production app, I would use **React Query** to update the feed instantly when a user likes or comments, without waiting for the server response.

### How to Launch

1.  **Storage Setup:** Go to Supabase > Storage > Create Bucket "post-images". Set public access.
2.  **Auth Setup:** Enable Email/Password or Google Auth in Supabase dashboard.
3.  **Deploy:** Push to GitHub and connect to **Vercel**. It will automatically detect Next.js and deploy.

