### 2. The Backend API (Node.js)

We'll use Express to handle the logic and Resend for emails.

**`server/server.js`**
```javascript
import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import { Resend } from 'resend';
import { createClient } from '@supabase/supabase-js';

dotenv.config();

const app = express();
app.use(cors());
app.use(express.json());

const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_ANON_KEY);
const resend = new Resend(process.env.RESEND_API_KEY);

// Get all orders
app.get('/api/orders', async (req, res) => {
  const { data, error } = await supabase.from('orders').select('*').order('created_at', { ascending: false });
  if (error) return res.status(400).json(error);
  res.json(data);
});

// Create new order
app.post('/api/orders', async (req, res) => {
  const { data, error } = await supabase.from('orders').insert([req.body]).select();
  if (error) return res.status(400).json(error);
  res.json(data[0]);
});

// Send Follow-up Email
app.post('/api/send-followup', async (req, res) => {
  const { email, customerName, productName } = req.body;

  try {
    const data = await resend.emails.send({
      from: 'Orders <onboarding@resend.dev>', // Use your verified domain in production
      to: [email],
      subject: `How is your ${productName}?`,
      html: `<strong>Hi ${customerName},</strong><p>Thank you for your recent purchase of ${productName}. We hope you're loving it! If you have a moment, we'd love to hear your feedback.</p>`
    });
    res.json({ success: true, data });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

const PORT = 3001;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

