#### The Follow-up Email Action (`app/actions/send-followup.ts`)
This server-side function handles the logic of sending the email and updating the database.

```typescript
"use server"

import { Resend } from 'resend';
import { createClient } from '@/utils/supabase/server';

const resend = new Resend(process.env.RESEND_API_KEY);

export async function sendFollowUpEmail(orderId: string, customerEmail: string, customerName: string) {
  try {
    const { data, error } = await resend.emails.send({
      from: 'Business Name <updates@yourdomain.com>',
      to: customerEmail,
      subject: 'How was your order?',
      html: `<strong>Hi ${customerName},</strong><p>Thank you for your recent order. We'd love to hear your feedback!</p>`
    });

    if (error) throw error;

    // Update database so we don't send it twice
    const supabase = createClient();
    await supabase
      .from('orders')
      .update({ follow_up_sent: true })
      .eq('id', orderId);

    return { success: true };
  } catch (error) {
    return { success: false, error: error.message };
  }
}
```

