#### B. Follow-up Email API (`app/api/send-followup/route.ts`)
This route handles sending the email and updating the database.

```typescript
import { Resend } from 'resend';
import { supabase } from '@/lib/supabase';
import { NextResponse } from 'next/server';

const resend = new Resend(process.env.RESEND_API_KEY);

export async function POST(req: Request) {
  const { orderId, customerEmail, customerName } = await req.json();

  try {
    const data = await resend.emails.send({
      from: 'Business Name <onboarding@resend.dev>', // Use your verified domain in production
      to: [customerEmail],
      subject: 'How was your order?',
      html: `<p>Hi ${customerName},</p><p>Thank you for your recent order! We'd love to hear your feedback.</p>`,
    });

    // Update the database to mark follow-up as sent
    await supabase
      .from('orders')
      .update({ follow_up_sent: true })
      .eq('id', orderId);

    return NextResponse.json(data);
  } catch (error) {
    return NextResponse.json({ error }, { status: 500 });
  }
}
```

