```jsx
"use client";
import React, { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { Plus, Calendar, User, CheckCircle2, Clock, AlertCircle } from 'lucide-react';
import { format, isPast, isToday } from 'date-fns';

export default function TaskDashboard() {
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [newTask, setNewTask] = useState({ title: '', description: '', due_date: '', assignee: '', status: 'todo' });

  useEffect(() => {
    fetchTasks();
  }, []);

  async function fetchTasks() {
    const { data, error } = await supabase
      .from('tasks')
      .select('*')
      .order('due_date', { ascending: true });

    if (error) console.error('Error:', error);
    else setTasks(data);
    setLoading(false);
  }

  async function createTask(e) {
    e.preventDefault();
    const { data, error } = await supabase.from('tasks').insert([newTask]).select();
    if (!error) {
      setTasks([...tasks, ...data]);
      setShowModal(false);
      setNewTask({ title: '', description: '', due_date: '', assignee: '', status: 'todo' });
    }
  }

  async function updateStatus(id, newStatus) {
    const { error } = await supabase.from('tasks').update({ status: newStatus }).eq('id', id);
    if (!error) {
      setTasks(tasks.map(t => t.id === id ? { ...t, status: newStatus } : t));
    }
  }

  const getDeadlineStyle = (date) => {
    if (!date) return "text-slate-500";
    const d = new Date(date);
    if (isPast(d) && !isToday(d)) return "text-red-500 font-bold";
    if (isToday(d)) return "text-orange-500 font-bold";
    return "text-blue-500";
  };

  const Column = ({ title, status }) => (
    <div className="flex-1 min-w-[300px] bg-gray-50 rounded-lg p-4">
      <h2 className="text-sm font-semibold uppercase tracking-wider text-gray-500 mb-4 flex items-center justify-between">
        {title}
        <span className="bg-gray-200 text-gray-700 px-2 py-0.5 rounded-full text-xs">
          {tasks.filter(t => t.status === status).length}
        </span>
      </h2>
      <div className="space-y-3">
        {tasks.filter(t => t.status === status).map(task => (
          <div key={task.id} className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-shadow">
            <h3 className="font-bold text-gray-800 mb-1">{task.title}</h3>
            <p className="text-sm text-gray-600 mb-3">{task.description}</p>

            <div className="flex items-center gap-3 text-xs mb-4">
              <div className={`flex items-center gap-1 ${getDeadlineStyle(task.due_date)}`}>
                <Clock size={14} />
                {task.due_date ? format(new Date(task.due_date), 'MMM do') : 'No date'}
              </div>
              <div className="flex items-center gap-1 text-gray-500">
                <User size={14} />
                {task.assignee || 'Unassigned'}
              </div>
            </div>

            <div className="flex gap-2">
              {status !== 'todo' && (
                <button onClick={() => updateStatus(task.id, 'todo')} className="text-[10px] bg-gray-100 px-2 py-1 rounded">To Do</button>
              )}
              {status !== 'in-progress' && (
                <button onClick={() => updateStatus(task.id, 'in-progress')} className="text-[10px] bg-blue-50 text-blue-600 px-2 py-1 rounded">In Progress</button>
              )}
              {status !== 'done' && (
                <button onClick={() => updateStatus(task.id, 'done')} className="text-[10px] bg-green-50 text-green-600 px-2 py-1 rounded flex items-center gap-1">
                  <CheckCircle2 size={10} /> Complete
                </button>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-white p-8">
      <header className="max-w-7xl mx-auto mb-10 flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 italic tracking-tight">TEAMFLOW</h1>
          <p className="text-gray-500">Track tasks and impending deadlines.</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-all"
        >
          <Plus size={20} /> New Task
        </button>
      </header>

      <main className="max-w-7xl mx-auto flex gap-6 overflow-x-auto pb-6">
        <Column title="To Do" status="todo" />
        <Column title="In Progress" status="in-progress" />
        <Column title="Completed" status="done" />
      </main>

      {/* Basic Modal for New Task */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-2xl p-6 max-w-md w-full shadow-2xl">
            <h2 className="text-xl font-bold mb-4">Create New Task</h2>
            <form onSubmit={createTask} className="space-y-4">
              <input 
                required
                className="w-full border p-2 rounded-lg focus:ring-2 ring-indigo-500 outline-none"
                placeholder="Task Title"
                value={newTask.title}
                onChange={e => setNewTask({...newTask, title: e.target.value})}
              />
              <textarea 
                className="w-full border p-2 rounded-lg h-24 focus:ring-2 ring-indigo-500 outline-none"
                placeholder="Description"
                value={newTask.description}
                onChange={e => setNewTask({...newTask, description: e.target.value})}
