                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-2 border rounded-lg">Cancel</button>
                <button type="submit" className="flex-1 py-2 bg-indigo-600 text-white rounded-lg">Save Task</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
```

