### 3. The Redis Core logic (`redis-logic.ts`)
This Lua script is the heart of the system. It runs inside Redis to ensure maximum speed and atomicity.

```typescript
import Redis from 'ioredis';

const redis = new Redis(process.env.REDIS_URL);

/**
 * LUA script for atomic "Check then Increment"
 * KEYS[1] = usage_key (usage:tenant_id)
 * ARGS[1] = limit_key (limit:tenant_id)
 * ARGS[2] = increment_amount
 */
const METER_SCRIPT = `
  local current_usage = tonumber(redis.call('GET', KEYS[1]) or "0")
  local limit = tonumber(redis.call('GET', ARGS[1]) or "0")
  local increment = tonumber(ARGS[2])

  if limit > 0 and (current_usage + increment) > limit then
    return -1 -- Over limit
  else
    local new_usage = redis.call('INCRBY', KEYS[1], increment)
    return new_usage
  end
`;

redis.defineCommand('meterUsage', {
  numberOfKeys: 1,
  lua: METER_SCRIPT,
});

export default redis;
```

---

### 4. High-Performance Middleware (`app.ts`)

```typescript
import Fastify from 'fastify';
import redis from './redis-logic';
import { PrismaClient } from '@prisma/client';

const fastify = Fastify();
const prisma = new PrismaClient();

// In a real app, you'd cache limits in Redis with an expiration
// or sync them when a Tenant's limit is updated in the DB.
async function getTenantLimit(tenantId: string): Promise<number> {
  const cachedLimit = await redis.get(`limit:${tenantId}`);
  if (cachedLimit) return parseInt(cachedLimit);

  const tenant = await prisma.tenant.findUnique({ where: { id: tenantId } });
  const limit = tenant?.creditLimit || 0;

  // Cache for 1 hour
  await redis.set(`limit:${tenantId}`, limit, 'EX', 3600);
  return limit;
}

fastify.addHook('preHandler', async (request, reply) => {
  const tenantId = request.headers['x-tenant-id'] as string;

  if (!tenantId) {
    return reply.status(401).send({ error: 'Missing Tenant ID' });
  }

  // 1. Get/Cache limit
  await getTenantLimit(tenantId);

  // 2. Atomic Credit Check & Increment
  // We use the custom Lua command defined earlier
  const result = await (redis as any).meterUsage(
    `usage:${tenantId}`, // KEYS[1]
    `limit:${tenantId}`, // ARGS[1]
    1                    // ARGS[2] (increment by 1 call)
  );

  if (result === -1) {
    return reply.status(429).send({
      error: 'Credit limit exceeded',
      suggestion: 'Upgrade your plan'
    });
  }

  // Inject usage into request for logging/headers
  request.headers['x-current-usage'] = result.toString();
});

fastify.get('/api/resource', async () => {
  return { data: "Success", message: "This call was metered." };
});

fastify.listen({ port: 3000 });
```

