### 3. The Implementation (Node.js + Fastify + Redis)

We'll use **TypeScript** and **IoRedis**.

#### `src/services/meter.service.ts`

```typescript
import Redis from 'ioredis';
import fs from 'fs';
import path from 'path';

const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');
const luaScript = fs.readFileSync(path.join(__dirname, '../lua/increment_and_check.lua'), 'utf8');

// Define the custom command
redis.defineCommand('incrementUsage', {
  numberOfKeys: 2,
  lua: luaScript,
});

export class MeteringService {
  /**
   * Performs sub-second credit check and increment
   * @returns { success: boolean, currentUsage: number }
   */
  async recordUsage(tenantId: string, amount: number = 1) {
    const usageKey = `usage:${tenantId}`;
    const limitKey = `limit:${tenantId}`;

    // Executing the Lua script atomically
    // @ts-ignore (custom command)
    const result = await redis.incrementUsage(usageKey, limitKey, amount);

    if (result === -1) {
      return { success: false, currentUsage: null, error: 'LIMIT_EXCEEDED' };
    }

    // Add to a "dirty" set so we know which tenants to sync to Postgres later
    await redis.sadd('tenants_to_sync', tenantId);

    return { success: true, currentUsage: result };
  }

  async getLimitStatus(tenantId: string) {
    const [usage, limit] = await redis.mget(`usage:${tenantId}`, `limit:${tenantId}`);
    return {
      usage: parseInt(usage || '0'),
      limit: parseInt(limit || '0'),
      remaining: Math.max(0, parseInt(limit || '0') - parseInt(usage || '0'))
    };
  }
}
```

#### `src/server.ts` (The API)

```typescript
import Fastify from 'fastify';
import { MeteringService } from './services/meter.service';

const fastify = Fastify({ logger: true });
const meter = new MeteringService();

// Pre-flight Credit Check (Sub-millisecond)
fastify.get('/check/:tenantId', async (request, reply) => {
  const { tenantId } = request.params as { tenantId: string };
  const status = await meter.getLimitStatus(tenantId);

  if (status.usage >= status.limit && status.limit !== 0) {
    return reply.status(403).send({ allowed: false, ...status });
  }
  return { allowed: true, ...status };
});

// Increment Usage (The "Metering" call)
fastify.post('/increment', async (request, reply) => {
  const { tenantId, amount } = request.body as { tenantId: string, amount: number };

  const result = await meter.recordUsage(tenantId, amount);

  if (!result.success) {
    return reply.status(429).send({ error: 'Quota Exceeded' });
  }

  return { status: 'recorded', currentUsage: result.currentUsage };
});

fastify.listen({ port: 3000 });
```

