### 1. The Database Schema (Prisma)

This schema uses `JSONB` for `extraFields` to handle the requirement of adding new licensing fields (like "Podcast RSS Rights" vs "Movie Theatrical Window") without migrations.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum ContentType {
  MOVIE
  PODCAST
  SERIES
}

model Category {
  id        String     @id @default(cuid())
  name      String
  parentId  String?
  parent    Category?  @relation("SubCategories", fields: [parentId], references: [id])
  children  Category[] @relation("SubCategories")
  content   Content[]
  createdAt DateTime   @default(now())
}

model Content {
  id          String       @id @default(cuid())
  title       String
  type        ContentType
  categoryId  String
  category    Category     @relation(fields: [categoryId], references: [id])
  licenses    License[]
  createdAt   DateTime     @default(now())
}

model License {
  id             String   @id @default(cuid())
  contentId      String
  content        Content  @relation(fields: [contentId], references: [id])
  regionCode     String   // ISO 3166-1 alpha-2 (e.g., "US", "GB")
  isAvailable    Boolean  @default(true)
  expiresAt      DateTime?

  // Dynamic fields for different content types
  // e.g., { "theatricalWindowDays": 45 } for Movies
  // e.g., { "explicitContent": true } for Podcasts
  metadata       Json     @default("{}") 

  @@unique([contentId, regionCode])
}
```

