### 2. The Backend Logic (Server Actions)

We need a service to fetch the category tree and validate regional access.

```typescript
// lib/actions/streaming.ts
"use server"

import { prisma } from "@/lib/prisma";
import { ContentType } from "@prisma/client";

// Fetch full category tree recursively
export async function getCategoryTree() {
  return await prisma.category.findMany({
    where: { parentId: null },
    include: {
      children: {
        include: {
          children: true // You can extend this for deeper initial loads
        }
      }
    }
  });
}

// Logic to check if content is available in a specific region
export async function getContentByRegion(region: string, categoryId?: string) {
  return await prisma.content.findMany({
    where: {
      categoryId: categoryId,
      licenses: {
        some: {
          regionCode: region,
          isAvailable: true,
          OR: [
            { expiresAt: null },
            { expiresAt: { gt: new Date() } }
          ]
        }
      }
    },
    include: {
      licenses: {
        where: { regionCode: region }
      }
    }
  });
}

// Add content with dynamic licensing
export async function createContentWithLicense(data: {
  title: string;
  type: ContentType;
  categoryId: string;
  region: string;
  metadata: any; // Dynamic fields based on type
}) {
  return await prisma.content.create({
    data: {
      title: data.title,
      type: data.type,
      categoryId: data.categoryId,
      licenses: {
        create: {
          regionCode: data.region,
          metadata: data.metadata
        }
      }
    }
  });
}
```

