### 1. Database Schema (Prisma)

The key to this architecture is the `JSONB` type for `licensingFields` and `metadata`. This allows us to add fields for Podcasts (e.g., `rss_feed`) or Movies (e.g., `theatrical_window`) without running migrations every time.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum MediaType {
  MOVIE
  EPISODE
  PODCAST
  LIVESTREAM
}

model Category {
  id        String     @id @default(uuid())
  name      String
  slug      String     @unique
  parentId  String?
  parent    Category?  @relation("CategoryToCategory", fields: [parentId], references: [id])
  children  Category[] @relation("CategoryToCategory")
  media     Media[]
  createdAt DateTime   @default(now())
}

model Media {
  id              String    @id @default(uuid())
  title           String
  type            MediaType
  categoryId      String
  category        Category  @relation(fields: [categoryId], references: [id])

  // Dynamic metadata (e.g., duration, director, host)
  metadata        Json      @default("{}")

  licenses        License[]
  createdAt       DateTime  @default(now())
}

model License {
  id             String   @id @default(uuid())
  mediaId        String
  media          Media    @relation(fields: [mediaId], references: [id])

  regionCode     String   // e.g., "US", "GB", "FR"
  isAvailable    Boolean  @default(true)

  // Dynamic licensing constraints
  // e.g., { "max_resolution": "4K", "expires_at": "2025-01-01", "podcast_exclusive": true }
