### 2. Implementation: Recursive Category Service

To handle "Infinite Nested Categories," we use a service that can fetch a category and all its descendants.

```typescript
// src/services/category.service.ts
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class CategoryService {
  /**
   * Returns a category and all its children recursively
   */
  async getCategoryTree(slug: string) {
    // We use a raw query for recursive CTE (Common Table Expression) 
    // to handle infinite nesting efficiently in one trip to the DB.
    const categories = await prisma.$queryRaw`
      WITH RECURSIVE CategoryTree AS (
        SELECT id, name, "parentId", slug 
        FROM "Category" 
        WHERE slug = ${slug}
        UNION ALL
        SELECT c.id, c.name, c."parentId", c.slug
        FROM "Category" c
        INNER JOIN CategoryTree ct ON c."parentId" = ct.id
      )
      SELECT * FROM CategoryTree;
    `;
    return categories;
  }
}
```

