// src/services/media.service.ts
import { PrismaClient, MediaType } from '@prisma/client';

const prisma = new PrismaClient();

export class MediaService {
  async getAvailableMedia(region: string, categoryId: string) {
    return prisma.media.findMany({
      where: {
        categoryId,
        licenses: {
          some: {
            regionCode: region,
            isAvailable: true,
            startsAt: { lte: new Date() },
            OR: [
              { endsAt: null },
              { endsAt: { gte: new Date() } }
            ]
          }
        }
      },
      include: {
        licenses: {
          where: { regionCode: region }
        }
      }
    });
  }

  /**
   * Example of handling dynamic fields for new content types
   */
  async createMediaWithDynamicLicensing(data: {
    title: string;
    type: MediaType;
    region: string;
    category: string;
    rules: Record<string, any>; // Dynamic fields
  }) {
    return prisma.media.create({
      data: {
        title: data.title,
        type: data.type,
        category: { connect: { id: data.category } },
        licenses: {
          create: {
            regionCode: data.region,
            licensingRules: data.rules // Stores arbitrary fields like "allow_download" or "podcast_tier"
          }
        }
      }
