### 4. API Layer (Fastify Route)

This route demonstrates how to resolve the user's region (via header or IP) and serve the filtered content.

```typescript
// src/routes/media.ts
import { FastifyInstance } from 'fastify';
import { MediaService } from '../services/media.service';

const mediaService = new MediaService();

export async function mediaRoutes(fastify: FastifyInstance) {
  fastify.get('/content/:categoryId', async (request, reply) => {
    // 1. Detect region (usually from CloudFront-Viewer-Country or GeoIP)
    const region = (request.headers['x-region'] as string) || 'US';
    const { categoryId } = request.params as { categoryId: string };

    // 2. Fetch media filtered by licensing
    const content = await mediaService.getAvailableMedia(region, categoryId);

    // 3. Post-process dynamic rules
    const processedContent = content.map(item => {
      const activeLicense = item.licenses[0];
      return {
        ...item,
        // UI can adapt based on dynamic fields
        canDownload: activeLicense.licensingRules['allow_offline'] ?? false,
        bitrateLimit: activeLicense.licensingRules['max_bitrate'] || 'auto'
      };
    });

    return processedContent;
  });
}
```

