### 1. The Database Schema (Prisma)

This schema handles the hierarchical categories, the core content, and the regional licensing rules.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Category {
  id        String   @id @default(uuid())
  name      String
  slug      String   @unique
  // Materialized path: e.g., "movies.sci-fi.cyberpunk"
  path      String   @unique @index 
  parentId  String?
  parent    Category?  @relation("CategoryToCategory", fields: [parentId], references: [id])
  children  Category[] @relation("CategoryToCategory")
  contents  Content[]

  createdAt DateTime @default(now())
}

enum ContentType {
  MOVIE
  PODCAST
  SERIES
}

model Content {
  id          String      @id @default(uuid())
  title       String
  type        ContentType
  categoryId  String
  category    Category    @relation(fields: [categoryId], references: [id])

  // Extensible metadata (JSONB)
  // Store fields like { "duration": 120, "director": "..." } for Movies
  // or { "host": "...", "episodeCount": 10 } for Podcasts
  metadata    Json        @default("{}")

  licenses    License[]
  createdAt   DateTime    @default(now())
}

model License {
  id             String   @id @default(uuid())
  contentId      String
  content        Content  @relation(fields: [contentId], references: [id])

  regionCode     String   // ISO 3166-1 alpha-2 (e.g., "US", "GB")
  isAvailable    Boolean  @default(true)

  // Extensible licensing rules (JSONB)
  // Store fields like { "requiresPremium": true, "offlineDownload": false }
  licensingTerms Json     @default("{}")

  startsAt       DateTime @default(now())
  expiresAt      DateTime?

  @@unique([contentId, regionCode])
}
```

