### 2. Implementation: The Content Service

This service handles the creation of content with dynamic metadata.

```typescript
// src/content/content.service.ts
import { Injectable, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../prisma.service';
import { CreateContentDto } from './dto/create-content.dto';

@Injectable()
export class ContentService {
  constructor(private prisma: PrismaService) {}

  async createContent(dto: CreateContentDto) {
    // Validates that the category exists
    const category = await this.prisma.category.findUnique({
      where: { id: dto.categoryId }
    });
    if (!category) throw new NotFoundException('Category not found');

    return this.prisma.content.create({
      data: {
        title: dto.title,
        type: dto.type,
        categoryId: dto.categoryId,
        metadata: dto.metadata, // JSONB handles the flexibility
      },
    });
  }

  async getContentForRegion(contentId: string, region: string) {
    const content = await this.prisma.content.findUnique({
      where: { id: contentId },
      include: {
        licenses: {
          where: {
            regionCode: region,
            isAvailable: true,
            startsAt: { lte: new Date() },
            OR: [
              { expiresAt: null },
              { expiresAt: { gte: new Date() } }
            ]
          }
        }
      }
    });

    if (!content || content.licenses.length === 0) {
      throw new NotFoundException('Content not available in your region');
    }

    return content;
  }
}
```

