### 3. Implementation: Nested Category Logic

To handle infinite nesting, we use the `path` field. If "Sci-Fi" (ID: 1) is a child of "Movies" (ID: 0), its path is `0.1`.

```typescript
// src/category/category.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma.service';

@Injectable()
export class CategoryService {
  constructor(private prisma: PrismaService) {}

  async createCategory(name: string, parentId?: string) {
    let path = '';
    const slug = name.toLowerCase().replace(/ /g, '-');

    if (parentId) {
      const parent = await this.prisma.category.findUnique({ where: { id: parentId } });
      path = `${parent.path}.${slug}`;
    } else {
      path = slug;
    }

    return this.prisma.category.create({
      data: { name, slug, path, parentId }
    });
  }

  // Find all subcategories of a specific category (infinite depth)
  async getSubtree(parentPath: string) {
    return this.prisma.category.findMany({
      where: {
        path: {
          startsWith: parentPath
        }
      },
      orderBy: { path: 'asc' }
    });
  }
}
```

