### 4. Advanced Regional Licensing Guard

You can protect your streaming routes using a Guard that checks the user's IP (mapped to region) against the database.

```typescript
// src/auth/guards/regional.guard.ts
import { Injectable, CanActivate, ExecutionContext, ForbiddenException } from '@nestjs/common';
import { ContentService } from '../../content/content.service';

@Injectable()
export class RegionalGuard implements CanActivate {
  constructor(private contentService: ContentService) {}

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const request = context.switchToHttp().getRequest();
    const contentId = request.params.id;
    const userRegion = request.headers['x-user-region']; // In production, resolve from IP

    try {
      const content = await this.contentService.getContentForRegion(contentId, userRegion);

      // Check for specific license fields added later
      const license = content.licenses[0];
      const terms = license.licensingTerms as any;

      if (terms.requiresPremium && !request.user.isPremium) {
        throw new ForbiddenException('This content requires a premium subscription in your region');
      }

      return true;
    } catch (e) {
      throw new ForbiddenException('Content unavailable in your region');
    }
  }
}
```

