### 3. Backend Implementation (Node.js + TypeScript)

We'll use Fastify for high-performance JSON delivery.

```typescript
// server/index.ts
import Fastify from 'fastify';
import pg from 'pg';

const pool = new pg.Pool({ connectionString: process.env.DATABASE_URL });
const app = Fastify();

interface QueryParams {
  lat: number;
  lng: number;
  interests: string; // Comma separated
}

app.get('/api/events', async (request, reply) => {
  const { lat, lng, interests } = request.query as QueryParams;
  const interestArray = interests ? interests.split(',') : [];

  const query = `
    SELECT 
      id, name, check_ins, tags,
      ST_Distance(location, ST_SetSRID(ST_Point($2, $1), 4326)::geography) as dist,
      (
        (1 / (1 + (ST_Distance(location, ST_SetSRID(ST_Point($2, $1), 4326)::geography) / 2000))) * 0.5 +
        (LEAST(check_ins, 500) / 500.0) * 0.2 +
        (CASE 
            WHEN ARRAY_LENGTH($3::text[], 1) > 0 
            THEN (cardinality(ARRAY(SELECT UNNEST(tags) INTERSECT SELECT UNNEST($3::text[])))::float / ARRAY_LENGTH($3::text[], 1))
            ELSE 0 
         END) * 0.3
      ) as score
    FROM events
    WHERE ST_DWithin(location, ST_SetSRID(ST_Point($2, $1), 4326)::geography, 20000)
    ORDER BY score DESC
    LIMIT 20;
  `;

  const result = await pool.query(query, [lat, lng, interestArray]);
  return result.rows;
});

app.listen({ port: 3001 });
```

