### 2. Implementation: The Fan-out Service

This service handles the logic of receiving a "Post" event and triggering the massive fan-out.

```typescript
// fanout-worker.ts
import Redis from 'ioredis';

const redis = new Redis({ cluster: true }); // Use Redis Cluster for scale
const SUB_BATCH_SIZE = 5000;

async function handlePost(postId: string, authorId: string) {
  const startTime = Date.now();

  // 1. Fetch Follower IDs in chunks to avoid blocking the Event Loop
  // In a real system, you'd fetch only 'Active' followers from a Redis Set
  const followersKey = `followers:${authorId}`;

  // Use a stream or pipeline to get followers
  let cursor = '0';
  do {
    const [nextCursor, followers] = await redis.sscan(followersKey, cursor, 'COUNT', SUB_BATCH_SIZE);
    cursor = nextCursor;

    // 2. Publish to Redis Pub/Sub
    // All WebSocket nodes are listening to this 'notifications' channel
    const payload = JSON.stringify({
      postId,
      authorId,
      timestamp: startTime,
      recipients: followers // Send chunk of IDs to all nodes
    });

    redis.publish('global-notifications', payload);
  } while (cursor !== '0');

  console.log(`Fan-out initiated in ${Date.now() - startTime}ms`);
}
```

