### 3. Implementation: The WebSocket Server

This server runs on multiple nodes. It maintains active connections and listens for the "broadcast" signal.

```typescript
// socket-server.ts
import { Server } from 'socket.io';
import { createAdapter } from '@socket.io/redis-adapter';
import Redis from 'ioredis';

const pubClient = new Redis();
const subClient = pubClient.duplicate();
const io = new Server(3000, {
  adapter: createAdapter(pubClient, subClient),
  transports: ['websocket'] // Force WebSockets for speed
});

// local map for O(1) lookup: userId -> SocketId
const localConnections = new Map<string, string>();

io.on('connection', (socket) => {
  const userId = socket.handshake.query.userId as string;
  if (userId) {
    localConnections.set(userId, socket.id);
  }

  socket.on('disconnect', () => {
    localConnections.delete(userId);
  });
});

// Listen for the fan-out signal from the Fan-out Worker
subClient.subscribe('global-notifications', (err) => {
  if (err) console.error("Failed to subscribe");
});

subClient.on('message', (channel, message) => {
  if (channel === 'global-notifications') {
    const { postId, recipients, authorId } = JSON.parse(message);

    // CRITICAL OPTIMIZATION:
    // Only iterate through recipients that are ACTUALLY on THIS specific node
    for (const userId of recipients) {
      const socketId = localConnections.get(userId);
      if (socketId) {
        io.to(socketId).emit('new_post', {
          postId,
          authorId,
          text: "New post from someone you follow!"
        });
      }
    }
  }
});
```

