### 2. Implementation: The Notification Service (Node.js + Redis)

#### A. The WebSocket Server (Scale-out Ready)
This server manages the real-time connections and listens to a Redis Pub/Sub channel for its specific node.

```typescript
// server.ts
import { createServer } from "http";
import { Server } from "socket.io";
import { createAdapter } from "@socket.io/redis-adapter";
import { Redis } from "ioredis";

const pubClient = new Redis(process.env.REDIS_URL);
const subClient = pubClient.duplicate();

const io = new Server(3000, {
  adapter: createAdapter(pubClient, subClient)
});

io.on("connection", (socket) => {
  const userId = socket.handshake.auth.userId;
  if (!userId) return socket.disconnect();

  // Mark user as active in Redis with a TTL (Heartbeat)
  pubClient.set(`active_user:${userId}`, "node_1", "EX", 300);

  socket.join(`user_${userId}`);

  socket.on("disconnect", () => {
    pubClient.del(`active_user:${userId}`);
  });
});
```

#### B. The Fan-out Orchestrator
When a celebrity posts, this service triggers the distributed fan-out.

```typescript
// orchestrator.ts
import Redis from "ioredis";
const redis = new Redis();

async function triggerPostNotification(authorId: string, postData: any) {
  const start = Date.now();

  // 1. Get the follower count/list (In production, use SSCAN for memory efficiency)
  const followerKey = `followers:${authorId}`;

  // 2. Partition 5M followers into chunks of 10k
  // We use Redis Lua scripts to fetch and push to streams for atomic speed
  const batchSize = 10000;
  let cursor = "0";

  do {
    // Fetch a batch of followers
    const [nextCursor, followers] = await redis.sscan(followerKey, cursor, "COUNT", batchSize);
    cursor = nextCursor;

    // Push batch to a high-speed worker queue (Redis Stream)
    await redis.xadd("notification_stream", "*", 
      "data", JSON.stringify(postData), 
      "targets", JSON.stringify(followers)
    );
  } while (cursor !== "0");

  console.log(`Fan-out orchestrated in ${Date.now() - start}ms`);
}
```

#### C. The High-Speed Worker
This worker checks who is actually online and pushes to the WebSocket adapter.

```typescript
// worker.ts
import Redis from "ioredis";
const redis = new Redis();
const pubClient = new Redis(); // For Socket.io adapter

async function processStream() {
  while (true) {
    // Read from the stream (Blocking)
    const results = await redis.xread("BLOCK", 0, "STREAMS", "notification_stream", "$");

    for (const [stream, messages] of results) {
      for (const [id, fields] of messages) {
        const payload = JSON.parse(fields[1]);
        const targets = JSON.parse(fields[3]);

        // PIpeline Redis calls to check who is active
        const pipeline = redis.pipeline();
        targets.forEach((uid: string) => pipeline.get(`active_user:${uid}`));
        const activeStatuses = await pipeline.exec();

        // Only send to users who are currently connected
        targets.forEach((uid: string, index: number) => {
          if (activeStatuses[index][1]) {
            // Push to the Redis Adapter (Broadcasting to specific rooms)
            pubClient.publish("socket.io#emitter", JSON.stringify({
              type: "broadcast",
              data: { room: `user_${uid}`, event: "new_post", args: [payload] }
            }));
          }
        });

        await redis.xdel("notification_stream", id);
      }
    }
  }
}
```

