io.on("connection", (socket) => {
  const userId = socket.handshake.query.userId;
  if (userId) {
    localActiveUsers.set(userId, socket);
    // Add to a global Redis Set of "Online Users"
    pubClient.sadd("online_users", userId);
  }

  socket.on("disconnect", () => {
    localActiveUsers.delete(userId);
    pubClient.srem("online_users", userId);
  });
});

