### 2. The Backend Implementation (Go)

The backend provides a single high-performance endpoint `/calculate-price`.

#### `backend/main.go`
```go
package main

import (
	"context"
	"encoding/json"
	"log"
	"net/http"
	"strconv"

	"github.com/go-redis/redis/v8"
	"github.com/gorilla/mux"
)

var ctx = context.Background()
var rdb *redis.Client

type PricingRequest struct {
	UserID    string  `json:"user_id"`
	ProductID string  `json:"product_id"`
	Region    string  `json:"region"` // e.g., "US-EAST-1"
	BasePrice float64 `json:"base_price"`
}

type PricingResponse struct {
	FinalPrice float64           `json:"final_price"`
	Discounts  map[string]float64 `json:"discounts_applied"`
	LatencyMs  int64             `json:"latency_ns"`
}

func main() {
	// Initialize Redis
	rdb = redis.NewClient(&redis.Options{
		Addr: "localhost:6379",
	})

	r := mux.NewRouter()
	r.HandleFunc("/calculate-price", CalculatePriceHandler).Methods("POST")

	log.Println("Pricing Engine running on :8080")
	log.Fatal(http.ListenAndServe(":8080", r))
}

func CalculatePriceHandler(w http.ResponseWriter, r *http.Request) {
	var req PricingRequest
	json.NewDecoder(r.Body).Decode(&req)

	// 1. Fetch data concurrently from Redis (O(1) lookups)
	// User History: Total spend in last 12 months (Pre-aggregated)
	historyStr, _ := rdb.Get(ctx, "user:history:"+req.UserID).Result()
	history, _ := strconv.ParseFloat(historyStr, 64)

	// Stock Levels: Current stock count
	stockStr, _ := rdb.Get(ctx, "stock:"+req.ProductID).Result()
	stock, _ := strconv.ParseInt(stockStr, 10, 64)

	// Geographic Demand: Scale of 1-10 (calculated via recent hits in region)
	demandStr, _ := rdb.Get(ctx, "demand:"+req.Region+":"+req.ProductID).Result()
	demand, _ := strconv.ParseFloat(demandStr, 64)

	// 2. Pricing Algorithm Logic
	finalPrice, breakdowns := calculateDynamicPrice(req.BasePrice, history, stock, demand)

	// 3. Update Demand (Asynchronous/Non-blocking)
	go rdb.Incr(ctx, "demand:"+req.Region+":"+req.ProductID)

	res := PricingResponse{
		FinalPrice: finalPrice,
		Discounts:  breakdowns,
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(res)
}

func calculateDynamicPrice(base float64, history float64, stock int64, demand float64) (float64, map[string]float64) {
	discounts := make(map[string]float64)
	price := base

	// Factor 1: Loyalty Discount (Max 10%)
	// If user spent > $1000 in 12 months
	if history > 1000 {
		d := base * 0.10
		discounts["loyalty"] = d
		price -= d
	}

	// Factor 2: Stock Surplus (Max 15%)
	// If stock > 500 units, clear inventory
	if stock > 500 {
		d := base * 0.15
		discounts["surplus_stock"] = d
		price -= d
	}

	// Factor 3: Geographic Demand Premium (Adds up to 20%)
	// If demand score > 500 hits/hour
	if demand > 500 {
		p := base * 0.20
		discounts["high_demand_surge"] = -p // Negative discount = price increase
		price += p
	}

	return price, discounts
}
```

