### 1. The Pricing Engine (Core Logic)

Create a standalone, testable utility for the calculation.

```typescript
// lib/pricing-engine.ts

export interface PricingContext {
  basePrice: number;
  userTotalSpend12m: number;
  stockLevel: number;
  regionalDemandFactor: number; // 1.0 is neutral, >1.0 is high demand
}

export function calculateDynamicPrice(context: PricingContext) {
  const { basePrice, userTotalSpend12m, stockLevel, regionalDemandFactor } = context;

  // 1. Loyalty Discount (Max 15%)
  // Logic: 1% discount for every $1000 spent, capped at 15%
  const loyaltyDiscountPercent = Math.min((userTotalSpend12m / 1000) * 0.01, 0.15);

  // 2. Inventory Adjustment
  // Logic: If stock is low (< 20), increase price. If stock is high (> 500), decrease price.
  let stockAdjustment = 1.0;
  if (stockLevel < 20) stockAdjustment = 1.2;      // 20% surge
  else if (stockLevel > 500) stockAdjustment = 0.9; // 10% clearance

  // 3. Demand Multiplier
  // Logic: Direct multiplier from regional trends (e.g., ZIP code heatmaps)
  const demandAdjustment = regionalDemandFactor;

  // Final Calculation
  const discountedBase = basePrice * (1 - loyaltyDiscountPercent);
  const finalPrice = discountedBase * stockAdjustment * demandAdjustment;

  return {
    finalPrice: Math.round(finalPrice * 100) / 100,
    adjustments: {
      loyaltyDiscount: loyaltyDiscountPercent,
      stockImpact: stockAdjustment,
      demandImpact: demandAdjustment
    }
  };
}
```

