### 2. High-Performance API (Next.js Edge Route)

Using Edge Runtime ensures sub-50ms execution. We assume Redis stores the heavy data.

```typescript
// app/api/get-price/route.ts
import { NextRequest, NextResponse } from 'next/server';
import { calculateDynamicPrice } from '@/lib/pricing-engine';
import { Redis } from '@upstash/redis';

const redis = Redis.fromEnv(); // Fast Redis Connection

export const runtime = 'edge'; // Minimize Latency

export async function GET(req: NextRequest) {
  const { searchParams } = new URL(req.url);
  const userId = searchParams.get('userId');
  const productId = searchParams.get('productId');
  const zipCode = searchParams.get('zipCode');

  if (!userId || !productId) {
    return NextResponse.json({ error: 'Missing parameters' }, { status: 400 });
  }

  // Parallel fetching from Redis (O(1) lookups)
  const [userSpend, stock, demand] = await Promise.all([
    redis.get<number>(`user:${userId}:spend_12m`) ?? 0,
    redis.get<number>(`product:${productId}:stock`) ?? 100,
    redis.get<number>(`demand:${zipCode}`) ?? 1.0,
  ]);

  // Base price would typically come from a cache or fast DB
  const basePrice = 299.99; 

  const result = calculateDynamicPrice({
    basePrice,
    userTotalSpend12m: Number(userSpend),
    stockLevel: Number(stock),
    regionalDemandFactor: Number(demand),
  });

  return NextResponse.json({
    productId,
    originalPrice: basePrice,
    ...result
  });
}
