### 2. Implementation: The Go Backend

We use Go because its goroutines handle massive concurrency with minimal memory overhead.

#### `main.go`
```go
package main

import (
	"context"
	"fmt"
	"math/rand"
	"net/http"
	"strconv"

	"github.com/go-redis/redis/v8"
	"github.com/labstack/echo/v4"
)

var (
	ctx         = context.Background()
	rdb         = redis.NewClient(&redis.Options{Addr: "localhost:6379"})
	numShards   = 10 // Increase based on load
	itemName    = "black_friday_ps5"
	luaScript   = `
		local current = redis.call("GET", KEYS[1])
		if not current or tonumber(current) < tonumber(ARGV[1]) then
			return -1
		else
			return redis.call("DECRBY", KEYS[1], ARGV[1])
		end
	`
)

func main() {
	e := echo.New()

	// Purchase Endpoint
	e.POST("/purchase", func(c echo.Context) error {
		// 1. Pick a random shard to spread the 100k/s load
		shardID := rand.Intn(numShards)
		key := fmt.Sprintf("stock:%s:%d", itemName, shardID)

		// 2. Execute Atomic Lua Script
		res, err := rdb.Eval(ctx, luaScript, []string{key}, 1).Result()
		if err != nil {
			return c.JSON(http.StatusInternalServerError, "Server Error")
		}

		remaining := res.(int64)
		if remaining < 0 {
			return c.JSON(http.StatusConflict, "Out of Stock")
		}

		// 3. Queue the success for DB persistence (Asynchronous)
		// In a real app, push to Kafka or Redis Stream
		rdb.XAdd(ctx, &redis.XAddArgs{
			Stream: "orders_stream",
			Values: map[string]interface{}{"item": itemName, "count": 1},
		})

		return c.JSON(http.StatusOK, "Success")
	})

	e.Logger.Fatal(e.Start(":8080"))
}
```

