### 2. Backend Logic (Node.js & Express)

We'll implement a service layer to handle stock movements, ensuring that moving stock between global warehouses is a single atomic transaction.

```typescript
// src/services/inventory.service.ts
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class InventoryService {
  /**
   * Transfers stock between warehouses safely
   */
  async transferStock(
    skuId: string, 
    fromWarehouseId: string, 
    toWarehouseId: string, 
    amount: number
  ) {
    return await prisma.$transaction(async (tx) => {
      // 1. Decrement from source
      const source = await tx.inventory.update({
        where: { skuId_warehouseId: { skuId, warehouseId: fromWarehouseId } },
        data: { quantity: { decrement: amount } }
      });

      if (source.quantity < 0) {
        throw new Error("Insufficient stock in source warehouse");
      }

      // 2. Increment at destination
      return await tx.inventory.upsert({
        where: { skuId_warehouseId: { skuId, warehouseId: toWarehouseId } },
        update: { quantity: { increment: amount } },
        create: {
          skuId,
          warehouseId: toWarehouseId,
          quantity: amount
        }
      });
    });
  }

  /**
   * Get global stock level for a product
   */
  async getGlobalProductStock(productId: string) {
    return await prisma.sku.findMany({
      where: { productId },
      include: {
        inventory: {
          include: { warehouse: true }
        }
      }
    });
  }
}
```

