### 1. The Data Architecture (Prisma Schema)

This schema handles the parent Product, the specific SKU Variants, Warehouses, and the stock levels linking them. It also includes an `InventoryLog` for a full audit trail.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Product {
  id          String   @id @default(cuid())
  name        String
  description String?
  category    String
  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt
  variants    Variant[]
}

model Variant {
  id          String   @id @default(cuid())
  sku         String   @unique
  productId   String
  product     Product  @relation(fields: [productId], references: [id])
  attributes  Json     // e.g., { "color": "Blue", "size": "XL" }
  price       Decimal  @db.Decimal(10, 2)
  stockLevels Stock[]
  logs        InventoryLog[]
}

model Warehouse {
  id        String   @id @default(cuid())
  name      String
  location  String   // e.g., "Berlin, DE"
  timezone  String   @default("UTC")
  stock     Stock[]
}

model Stock {
  id          String    @id @default(cuid())
  variantId   String
  warehouseId String
  quantity    Int       @default(0)
  variant     Variant   @relation(fields: [variantId], references: [id])
  warehouse   Warehouse @relation(fields: [warehouseId], references: [id])

  @@unique([variantId, warehouseId]) // Ensures one record per variant per warehouse
}

model InventoryLog {
  id              String   @id @default(cuid())
  variantId       String
  variant         Variant  @relation(fields: [variantId], references: [id])
  fromWarehouseId String?
  toWarehouseId   String?
  quantityChange  Int
  type            String   // "ADJUSTMENT", "TRANSFER", "SALE", "RESTOCK"
  reason          String?
  createdAt       DateTime @default(now())
}
```

