### 2. The Backend Logic (NestJS Service)

We need atomic transactions to ensure that when we move stock between warehouses, the data remains consistent.

```typescript
// inventory.service.ts
import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from './prisma.service';

@Injectable()
export class InventoryService {
  constructor(private prisma: PrismaService) {}

  /**
   * Transfer stock between warehouses with Transaction atomicity
   */
  async transferStock(
    variantId: string,
    fromWarehouseId: string,
    toWarehouseId: string,
    quantity: number
  ) {
    return this.prisma.$transaction(async (tx) => {
      // 1. Check & Decrement source stock
      const sourceStock = await tx.stock.update({
        where: { variantId_warehouseId: { variantId, warehouseId: fromWarehouseId } },
        data: { quantity: { decrement: quantity } },
      });

      if (sourceStock.quantity < 0) {
        throw new BadRequestException('Insufficient stock in source warehouse');
      }

      // 2. Increment destination stock (upsert if record doesn't exist)
      await tx.stock.upsert({
        where: { variantId_warehouseId: { variantId, warehouseId: toWarehouseId } },
        update: { quantity: { increment: quantity } },
        create: { variantId, warehouseId: toWarehouseId, quantity },
      });

      // 3. Create Audit Log
      await tx.inventoryLog.create({
        data: {
          variantId,
          fromWarehouseId,
          toWarehouseId,
          quantityChange: quantity,
          type: 'TRANSFER',
        },
      });

      return { success: true };
    });
  }
}
```

