### 4. The Tenant Onboarding Service (`src/services/TenantService.ts`)
This service handles the transaction. It creates the company and maps the default templates to the new `companyId`.

```typescript
import { PrismaClient } from '@prisma/client';
import { DEFAULT_CATEGORIES } from '../config/templates';

const prisma = new PrismaClient();

export class TenantService {
  /**
   * Registers a new company and seeds initial data.
   * Uses a transaction to ensure data integrity.
   */
  static async registerCompany(data: { name: string; slug: string; adminEmail: string }) {
    return await prisma.$transaction(async (tx) => {
      // 1. Create the Company
      const company = await tx.company.create({
        data: {
          name: data.name,
          slug: data.slug,
        },
      });

      // 2. Create the Admin User
      await tx.user.create({
        data: {
          email: data.adminEmail,
          companyId: company.id,
        },
      });

      // 3. Seed Default Categories
      // We map our templates to include the newly created companyId
      const categoriesToCreate = DEFAULT_CATEGORIES.map((cat) => ({
        ...cat,
        companyId: company.id,
      }));

      await tx.category.createMany({
        data: categoriesToCreate,
      });

      return {
        company,
        categoriesCreated: categoriesToCreate.length,
      };
    });
  }
}
```

