### 3. The Onboarding Service (`src/services/OnboardingService.ts`)
This service handles the business logic. We use a **Prisma Transaction** to ensure that if seeding categories fails, the company record is rolled back (Atomicity).

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

// Default templates to seed for every new company
const DEFAULT_CATEGORIES = [
  { name: 'General', type: 'Administrative' },
  { name: 'Sales Pipeline', type: 'Revenue' },
  { name: 'Customer Support', type: 'Operations' },
  { name: 'Product Roadmap', type: 'Engineering' },
];

export class OnboardingService {
  /**
   * Provisions a new tenant:
   * 1. Creates the Company
   * 2. Seeds default category templates
   * 3. (Optional) Executes raw SQL for specific optimization
   */
  static async provisionCompany(name: string, slug: string) {
    return await prisma.$transaction(async (tx) => {
      // 1. Create the Company
      const company = await tx.company.create({
        data: { name, slug },
      });

      // 2. Seed default categories specific to this company
      const seedData = DEFAULT_CATEGORIES.map((cat) => ({
        ...cat,
        companyId: company.id,
      }));

      await tx.category.createMany({
        data: seedData,
      });

      /**
       * 3. Dynamic Indexing (Advanced Use Case)
       * In most shared-DB SaaS apps, indexes are static. However, if you use 
       * PostgreSQL Partitioning or need to refresh concurrent stats for 
       * the new tenant's ID range, you can run raw SQL here.
       */
      // Example: tx.$executeRaw`ANALYZE "Category";` 

      return company;
    });
  }
}
