### 2. The Tenant Service (`src/services/tenant.service.ts`)

This service handles the business logic for creating the company, ensuring indexes, and seeding data.

```typescript
import { PrismaClient, Company, Category } from '@prisma/client';

const prisma = new PrismaClient();

// Default templates to be seeded for every new company
const DEFAULT_CATEGORIES = [
  { name: 'Marketing', type: 'EXPENSE' },
  { name: 'Sales', type: 'EXPENSE' },
  { name: 'Consulting', type: 'INCOME' },
  { name: 'Software Subscription', type: 'EXPENSE' },
];

export class TenantService {
  /**
   * Registers a new tenant, sets up indexes, and seeds data.
   */
  static async registerCompany(name: string, slug: string): Promise<Company> {
    return prisma.$transaction(async (tx) => {
      // 1. Create the Company record
      const company = await tx.company.create({
        data: { name, slug },
      });

      // 2. Programmatically ensure indexes (Safety Layer)
      // While Prisma handles indexes via migration, in dynamic systems 
      // you might want to ensure specific Gin or BTree indexes exist.
      await tx.$executeRawUnsafe(`
        CREATE INDEX IF NOT EXISTS "idx_categories_company_name" 
        ON "Category" ("companyId", "name");
      `);

      // 3. Seed default category templates specific to this Company ID
      const seedData = DEFAULT_CATEGORIES.map((cat) => ({
        ...cat,
        companyId: company.id,
        isDefault: true,
      }));

      await tx.category.createMany({
        data: seedData,
      });

      return company;
    });
  }
}
```

