This exposes the functionality via an HTTP endpoint.

```typescript
import { Request, Response } from 'express';
import { TenantService } from '../services/tenant.service';

export const signup = async (req: Request, res: Response) => {
  try {
    const { companyName, companySlug } = req.body;

    if (!companyName || !companySlug) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    const company = await TenantService.registerCompany(companyName, companySlug);

    return res.status(201).json({
      message: 'Company registered and environment initialized.',
      company,
    });
  } catch (error: any) {
    console.error('Signup Error:', error);

    if (error.code === 'P2002') {
      return res.status(409).json({ error: 'Company slug or name already exists' });
    }

    return res.status(500).json({ error: 'Internal Server Error' });
  }
};
