### 3. Backend Strategy (NestJS + Prisma)

In a production app, we need a "Tenant Context" that flows through the system.

#### A. The Tenant Interceptor
This middleware extracts the `tenantId` from the JWT and injects it into the database transaction.

```typescript
// tenant.interceptor.ts
import { Injectable, NestInterceptor, ExecutionContext, CallHandler } from '@nestjs/common';
import { PrismaService } from './prisma.service';

@Injectable()
export class TenantInterceptor implements NestInterceptor {
  constructor(private prisma: PrismaService) {}

  async intercept(context: ExecutionContext, next: CallHandler) {
    const request = context.switchToHttp().getRequest();
    const tenantId = request.user.tenantId; // Set by AuthGuard from JWT

    // We use a transaction to set the local session variable in Postgres
    // This variable exists ONLY for the duration of this specific connection
    return this.prisma.$transaction(async (tx) => {
      await tx.$executeRawUnsafe(`SET LOCAL app.current_tenant_id = '${tenantId}'`);
      return next.handle();
    });
  }
}
```

#### B. The Global Prisma Service
To ensure no query ever bypasses RLS, we wrap our database calls.

```typescript
// prisma.service.ts
import { Injectable, OnModuleInit } from '@nestjs/common';
import { PrismaClient } from '@prisma/client';

@Injectable()
export class PrismaService extends PrismaClient implements OnModuleInit {
  async onModuleInit() {
    await this.$connect();
  }

  // Helper to ensure every query runs within a "Tenant-Aware" transaction
  async tenantQuery(tenantId: string, callback: (tx: any) => Promise<any>) {
    return this.$transaction(async (tx) => {
      await tx.$executeRawUnsafe(`SET LOCAL app.current_tenant_id = '${tenantId}'`);
      return callback(tx);
    });
  }
}
```

