### 4. Usage in a Controller
Notice that the developer **does not** need to manually filter by `tenant_id`. The database does it automatically.

```typescript
@Controller('orders')
@UseGuards(JwtAuthGuard)
export class OrderController {
  constructor(private prisma: PrismaService) {}

  @Get()
  async getMyOrders(@Request() req) {
    // Even if I try to find ALL orders, 
    // Postgres will ONLY return orders for req.user.tenantId
    return this.prisma.tenantQuery(req.user.tenantId, (tx) => {
      return tx.order.findMany(); 
    });
  }

  @Post()
  async createOrder(@Request() req, @Body() data) {
    return this.prisma.tenantQuery(req.user.tenantId, (tx) => {
      return tx.order.create({
        data: {
          ...data,
          tenant_id: req.user.tenantId // Must match RLS 'WITH CHECK'
        }
      });
    });
  }
}
```

