### 3. The Database Client Utility

We create a helper that wraps the database connection and injects the current user's `organizationId` from the auth session into the Postgres transaction.

```typescript
// src/lib/db.ts
import { drizzle } from "drizzle-orm/postgres-js";
import postgres from "postgres";
import { auth } from "@clerk/nextjs/server";

const queryClient = postgres(process.env.DATABASE_URL!);
export const db = drizzle(queryClient);

/**
 * Returns a database instance restricted to the current tenant.
 */
export async function getTenantDb() {
  const { orgId } = auth();

  if (!orgId) {
    throw new Error("Unauthorized: No organization context found.");
  }

  // We use a transaction to set a local variable for this specific request
  return db.transaction(async (tx) => {
    // Set the tenant ID in the session
    await tx.execute(
      sql`SELECT set_config('app.current_tenant_id', ${orgId}, true)`
    );
    return tx;
  });
}
```

