### 2. The Rate Limiter Logic (`src/limiter.js`)

This uses the **Token Bucket** algorithm. Each tenant has a "bucket" of tokens that refills over time.

```javascript
const Redis = require('ioredis');
const fs = require('fs');
const path = require('path');

const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

// Lua script for atomic Rate Limiting
// Returns 1 if allowed, 0 if throttled
const rateLimitScript = `
local bucketKey = KEYS[1]
local limit = tonumber(ARGV[1])
local refillRate = tonumber(ARGV[2])
local now = tonumber(ARGV[3])

local bucket = redis.call('hmget', bucketKey, 'tokens', 'lastRefill')
local tokens = tonumber(bucket[1]) or limit
local lastRefill = tonumber(bucket[2]) or now

-- Refill tokens based on time passed
local elapsed = math.max(0, now - lastRefill)
local refill = math.floor(elapsed * refillRate)
tokens = math.min(limit, tokens + refill)

if tokens >= 1 then
    redis.call('hmset', bucketKey, 'tokens', tokens - 1, 'lastRefill', now)
    return 1
else
    return 0
end
`;

async function isAllowed(tenantId, tier = 'standard') {
  // Define limits per tier
  const tiers = {
    free: { limit: 10, refillRate: 1 },       // 10 burst, 1 req/sec refill
    standard: { limit: 100, refillRate: 10 }, // 100 burst, 10 req/sec refill
    enterprise: { limit: 1000, refillRate: 100 }
  };

  const { limit, refillRate } = tiers[tier];
  const key = `ratelimit:tenant:${tenantId}`;
  const now = Math.floor(Date.now() / 1000);

  const result = await redis.eval(rateLimitScript, 1, key, limit, refillRate, now);
  return result === 1;
}

module.exports = { isAllowed };
```

---

### 3. Middleware Integration (`src/middleware.js`)

This middleware identifies the tenant and blocks them if they exceed their quota.

```javascript
const { isAllowed } = require('./limiter');

const tenantGuard = async (req, res, next) => {
  const tenantId = req.headers['x-tenant-id'];
  const tenantTier = req.headers['x-tenant-tier'] || 'standard';

  if (!tenantId) {
    return res.status(400).json({ error: 'Missing X-Tenant-ID header' });
  }

  try {
    const allowed = await isAllowed(tenantId, tenantTier);

    if (!allowed) {
      console.warn(`Tenant ${tenantId} is being throttled.`);
      return res.status(429).json({
        error: 'Too Many Requests',
        message: 'Your tenant has exceeded its rate limit. Please try again later.'
      });
    }

    next();
  } catch (err) {
    console.error('Rate limiter error:', err);
    next(); // Fail open in production to not block traffic if Redis is down
  }
};

module.exports = tenantGuard;
```

