### 4. Fair Background Worker (`src/worker.js`)

If a tenant triggers a massive batch process, we use BullMQ's **`groupKey`**. This ensures the worker picks up jobs round-robin style across tenants rather than finishing one tenant's huge backlog first.

```javascript
const { Queue, Worker } = require('bullmq');
const Redis = require('ioredis');

const connection = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

// 1. Create the Queue
const heavyTaskQueue = new Queue('heavy-tasks', { connection });

// 2. The Worker with Concurrency
const worker = new Worker('heavy-tasks', async (job) => {
  console.log(`Processing job ${job.id} for Tenant ${job.data.tenantId}`);
  // Simulate heavy work
  await new Promise(res => setTimeout(res, 500));
}, { 
  connection,
  concurrency: 5 // Process 5 jobs at once
});

// 3. Logic to add jobs fairly
async function addJob(tenantId, data) {
  await heavyTaskQueue.add('process-data', data, {
    // BullMQ Pro feature: groupKey ensures fair distribution
    // For standard BullMQ, we can use separate queues or manual prioritization
    jobId: `${tenantId}:${Date.now()}`, 
    removeOnComplete: true
  });
}

module.exports = { addJob };
