### 2. The Rate Limiter Middleware (`middleware/throttler.js`)

```javascript
const Redis = require('ioredis');
const fs = require('fs');
const path = require('path');

const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');
const luaScript = fs.readFileSync(path.join(__dirname, 'rate_limiter.lua'), 'utf8');

// Pre-load script into Redis for performance
let scriptSha;
async function loadScript() {
    scriptSha = await redis.script('load', luaScript);
}
loadScript();

const TENANT_CONFIGS = {
    'standard': { limit: 100, window: 60 }, // 100 rpm
    'premium': { limit: 1000, window: 60 }, // 1000 rpm
    'free': { limit: 10, window: 60 }        // 10 rpm
};

const multiTenantThrottler = async (req, res, next) => {
    const tenantId = req.header('x-tenant-id');
    const tier = req.header('x-tenant-tier') || 'free';

    if (!tenantId) {
        return res.status(400).json({ error: 'Missing x-tenant-id header' });
    }

    const config = TENANT_CONFIGS[tier] || TENANT_CONFIGS.free;
    const key = `ratelimit:${tenantId}`;

    try {
        // Execute the atomic Lua script
        const result = await redis.evalsha(scriptSha, 1, key, config.limit, config.window);

        if (result === -1) {
            console.warn(`[Throttler] Tenant ${tenantId} exceeded quota.`);
            return res.status(429).json({
                error: 'Too Many Requests',
                message: 'Your tenant has exceeded its allocated capacity. Please upgrade for higher limits.',
                retryAfter: config.window
            });
        }

        // Set standard Rate-Limit headers
        res.setHeader('X-RateLimit-Limit', config.limit);
        res.setHeader('X-RateLimit-Remaining', result);

        next();
    } catch (err) {
        // Fail Open: If Redis fails, let the request through but log it
        // This prevents the throttler from becoming a Single Point of Failure
        console.error('Rate Limiter Error:', err);
        next();
    }
};

module.exports = multiTenantThrottler;
```

