### 1. The Database Schema (Prisma)

We use a "Summary" pattern to keep queries fast.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Organization {
  id             String         @id @default(uuid())
  name           String
  stripeCustomerId String?      @unique
  usageRecords   UsageRecord[]
  usageSummaries DailyUsageSummary[]
}

// Audit log of every single usage event
model UsageRecord {
  id             String   @id @default(uuid())
  organizationId String
  metric         String   // e.g., "email_sent", "gb_stored"
  units          Int
  idempotencyKey String   @unique // To prevent double counting
  createdAt      DateTime @default(now())

  organization   Organization @relation(fields: [organizationId], references: [id])
  @@index([organizationId, createdAt])
}

// Optimized table for invoicing
model DailyUsageSummary {
  id             String   @id @default(uuid())
  organizationId String
  date           DateTime // Normalized to midnight
  metric         String
  totalUnits     Int      @default(0)

  organization   Organization @relation(fields: [organizationId], references: [id])
  @@unique([organizationId, date, metric])
}
