### 2. The Usage Service

This service handles recording units. It uses an **Atomic Upsert** to update the daily summary at the same time it records the event.

```typescript
// src/services/usage.service.ts
import { PrismaClient } from '@prisma/client';
import { startOfDay } from 'date-fns';

const prisma = new PrismaClient();

export class UsageService {
  /**
   * Records usage of a specific metric.
   * Uses a transaction to ensure the audit log and summary stay in sync.
   */
  async recordUsage(params: {
    orgId: string;
    metric: string;
    units: number;
    idempotencyKey: string;
  }) {
    const { orgId, metric, units, idempotencyKey } = params;
    const today = startOfDay(new Date());

    try {
      return await prisma.$transaction(async (tx) => {
        // 1. Create the immutable audit log (fails if idempotencyKey exists)
        const record = await tx.usageRecord.create({
          data: {
            organizationId: orgId,
            metric,
            units,
            idempotencyKey,
          },
        });

        // 2. Update the daily aggregate (The "Read Model")
        await tx.dailyUsageSummary.upsert({
          where: {
            organizationId_date_metric: {
              organizationId: orgId,
              date: today,
              metric,
            },
          },
          update: {
            totalUnits: { increment: units },
          },
          create: {
            organizationId: orgId,
            date: today,
            metric,
            totalUnits: units,
          },
        });

        return record;
      });
    } catch (error: any) {
      if (error.code === 'P2002') {
        console.warn(`Duplicate usage event ignored: ${idempotencyKey}`);
        return null;
      }
      throw error;
    }
  }
}
```

