### 3. Monthly Invoicing Logic

At the end of the month, we need to calculate the total usage and push it to a billing provider like Stripe.

```typescript
// src/services/billing.service.ts
import { PrismaClient } from '@prisma/client';
import Stripe from 'stripe';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, { apiVersion: '2023-10-16' });
const prisma = new PrismaClient();

export class BillingService {
  /**
   * Sums up usage for a billing period and syncs to Stripe
   */
  async syncMonthlyUsageToStripe(orgId: string, startDate: Date, endDate: Date) {
    const organization = await prisma.organization.findUnique({ where: { id: orgId } });
    if (!organization?.stripeCustomerId) throw new Error("No Stripe ID found");

    // Aggregate usage from our DailySummaries (much faster than raw records)
    const usageItems = await prisma.dailyUsageSummary.groupBy({
      by: ['metric'],
      where: {
        organizationId: orgId,
        date: {
          gte: startDate,
          lte: endDate,
        },
      },
      _sum: {
        totalUnits: true,
      },
    });

    for (const item of usageItems) {
      const totalUnits = item._sum.totalUnits || 0;

      // Report to Stripe Metered Billing
      // The 'subscription_item_id' should be stored in your DB during checkout
      await stripe.subscriptionItems.createUsageRecord(
        'si_12345...', // You'd retrieve this from your DB
        {
          quantity: totalUnits,
          timestamp: Math.floor(Date.now() / 1000),
          action: 'set', // 'set' replaces previous value for this period
        }
      );
    }
  }
}
```

