### 2. The Billing Service (`BillingService.ts`)

This service handles recording usage and rolling up data.

```typescript
import { PrismaClient, UsageType } from '@prisma/client';

const prisma = new PrismaClient();

export class BillingService {
  /**
   * Tracks a usage event. Uses a transaction to ensure the raw event 
   * and the daily aggregate are updated atomically.
   */
  async trackUsage(params: {
    customerId: string;
    type: UsageType;
    units: number;
    idempotencyKey: string;
  }) {
    const { customerId, type, units, idempotencyKey } = params;

    // Use UTC midnight for the daily aggregate
    const today = new Date();
    today.setUTCHours(0, 0, 0, 0);

    try {
      return await prisma.$transaction(async (tx) => {
        // 1. Create the raw event (will fail if idempotencyKey exists)
        const event = await tx.usageEvent.create({
          data: {
            customerId,
            type,
            units,
            idempotencyKey,
          },
        });

        // 2. Upsert the daily aggregate
        await tx.dailyUsageMetric.upsert({
          where: {
            customerId_date_type: {
              customerId,
              date: today,
              type,
            },
          },
          update: {
            totalUnits: { increment: units },
          },
          create: {
            customerId,
            date: today,
            type,
            totalUnits: units,
          },
        });

        return event;
      });
    } catch (error: any) {
      if (error.code === 'P2002') {
        console.warn(`Duplicate event ignored: ${idempotencyKey}`);
        return null; // Idempotency hit
      }
      throw error;
    }
  }

  /**
   * Calculates total usage for a billing period
   */
  async getMonthlyUsage(customerId: string, year: number, month: number) {
    const startOfMonth = new Date(Date.UTC(year, month - 1, 1));
    const endOfMonth = new Date(Date.UTC(year, month, 0, 23, 59, 59));

    const metrics = await prisma.dailyUsageMetric.groupBy({
      by: ['type'],
      where: {
        customerId,
        date: {
          gte: startOfMonth,
          lte: endOfMonth,
        },
      },
      _sum: {
        totalUnits: true,
      },
    });

    return metrics.map((m) => ({
      type: m.type,
      total: m._sum.totalUnits || 0,
    }));
  }
}
```

