### 4. Tiered Pricing Calculator

When it's time to generate an invoice, you need to apply costs to those units.

```typescript
const PRICING_CONFIG = {
  EMAIL_SENT: [
    { upTo: 1000, pricePerUnit: 0 },       // Free tier
    { upTo: 10000, pricePerUnit: 0.01 },   // $0.01 per email
    { upTo: Infinity, pricePerUnit: 0.005 } // Bulk discount
  ],
  FILE_STORAGE_GB: [
    { upTo: Infinity, pricePerUnit: 0.05 }  // $0.05 per GB
  ]
};

function calculateCost(type: UsageType, totalUnits: number): number {
  const tiers = PRICING_CONFIG[type];
  let remaining = totalUnits;
  let totalCost = 0;
  let previousLimit = 0;

  for (const tier of tiers) {
    const tierSize = tier.upTo - previousLimit;
    const unitsInTier = Math.min(remaining, tierSize);

    totalCost += unitsInTier * tier.pricePerUnit;
    remaining -= unitsInTier;
    previousLimit = tier.upTo;

    if (remaining <= 0) break;
  }

  return totalCost;
}
```

