### 2. The Core Service

This service handles recording usage and syncing it with Stripe.

```typescript
// src/services/billing.service.ts
import { PrismaClient } from '@prisma/client';
import Stripe from 'stripe';

const prisma = new PrismaClient();
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, { apiVersion: '2023-10-16' });

export class BillingService {
  /**
   * Records a usage event and pushes to Stripe
   */
  async recordUsage(params: {
    customerId: string;
    type: 'email_sent' | 'file_storage_gb';
    amount: number;
    idempotencyKey: string;
  }) {
    const { customerId, type, amount, idempotencyKey } = params;

    return await prisma.$transaction(async (tx) => {
      // 1. Check if event already exists (Idempotency)
      const existing = await tx.usageEvent.findUnique({
        where: { idempotencyKey }
      });
      if (existing) return existing;

      // 2. Fetch customer to get Stripe ID
      const customer = await tx.customer.findUniqueOrThrow({
        where: { id: customerId }
      });

      // 3. Record in DB (Audit Trail)
      const event = await tx.usageEvent.create({
        data: { customerId, type, amount, idempotencyKey }
      });

      // 4. Update Daily Summary (Aggregated View)
      const today = new Date();
      today.setUTCHours(0, 0, 0, 0);

      await tx.dailyUsageSummary.upsert({
        where: {
          customerId_date_type: { customerId, date: today, type }
        },
        update: { totalUnits: { increment: amount } },
        create: { customerId, date: today, type, totalUnits: amount }
      });

      // 5. Sync to Stripe Metered Billing
      // Note: In Stripe, you must create a 'Meter' for 'email_sent' beforehand
      await stripe.billing.meterEvents.create({
        event_name: type,
        payload: {
          value: amount.toString(),
          stripe_customer_id: customer.stripeCustomerId,
        },
      });

      return event;
    });
  }

  /**
   * Retrieves usage for a customer dashboard
   */
  async getUsageReport(customerId: string, days = 30) {
    return prisma.dailyUsageSummary.findMany({
      where: {
        customerId,
        date: { gte: new Date(Date.now() - days * 24 * 60 * 60 * 1000) }
      },
      orderBy: { date: 'desc' }
    });
  }
}
```

