### 3. Core Implementation (Backend)

#### The Data Access Layer
The magic happens in the query. By injecting `new Date()` into the query, the database handles the "automatic" transition.

```typescript
// src/services/post.service.ts
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export const PostService = {
  /**
   * Public API: Only fetches posts that are NOT drafts 
   * and whose publishedAt date is in the past.
   */
  async getPublicPosts() {
    const now = new Date();

    return prisma.post.findMany({
      where: {
        isDraft: false,
        publishedAt: {
          lte: now, // "Less than or equal to" now
        },
      },
      orderBy: {
        publishedAt: 'desc',
      },
    });
  },

  /**
   * Admin API: Fetches everything regardless of date.
   */
  async getAllPostsForAdmin() {
    return prisma.post.findMany({
      orderBy: { createdAt: 'desc' },
    });
  },

  async createPost(data: { title: string; content: string; publishedAt: Date; isDraft?: boolean }) {
    return prisma.post.create({ data });
  }
};
```

