### 1. The Database Schema (Prisma)

This schema supports a base content object linked to many translations.

```prisma
// prisma/schema.prisma

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model Content {
  id           String               @id @default(cuid())
  createdAt    DateTime             @default(now())
  updatedAt    DateTime             @updatedAt
  status       String               @default("DRAFT") // DRAFT, PUBLISHED
  translations ContentTranslation[]
}

model ContentTranslation {
  id          String   @id @default(cuid())
  contentId   String
  content     Content  @relation(fields: [contentId], references: [id], onDelete: Cascade)

  // The locale (e.g., 'en', 'en-US', 'fr')
  locale      String

  // Localized Fields
  title       String
  slug        String
  body        String   @db.Text
  seoTitle    String?
  seoDesc     String?

  @@unique([contentId, locale]) // Only one translation per language per content
  @@unique([slug, locale])      // Slugs must be unique within a language
  @@index([locale])
}
```

