### 3. Data Access Layer (Server Actions)

We need a way to fetch content based on the locale, including a fallback mechanism.

```typescript
// lib/content-service.ts
import { prisma } from './prisma';

export async function getContentBySlug(slug: string, locale: string) {
  // 1. Try to find the exact locale (e.g., en-GB)
  let translation = await prisma.contentTranslation.findFirst({
    where: { slug, locale },
    include: { content: true }
  });

  // 2. Fallback: If not found, try the base language (e.g., 'en' if searching for 'en-US')
  if (!translation && locale.includes('-')) {
    const baseLang = locale.split('-')[0];
    translation = await prisma.contentTranslation.findFirst({
      where: { 
        content: { translations: { some: { slug } } },
        locale: { startsWith: baseLang }
      },
      include: { content: true }
    });
  }

  return translation;
}
```

