### 1. The Database Schema

The core logic separates "Content" (the container) from "Translation" (the localized data). We use a combination of `languageCode` (ISO 639-1) and `regionCode` (ISO 3166-1) to handle variations like `en-US` vs `en-GB`.

```prisma
// prisma/schema.prisma

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model Content {
  id           String        @id @default(cuid())
  slug         String        @unique // Global unique identifier (e.g., "summer-sale-2024")
  contentType  String        // "article", "page", "product"
  createdAt    DateTime      @default(now())
  updatedAt    DateTime      @updatedAt
  translations Translation[]

  @@index([slug])
}

model Translation {
  id           String   @id @default(cuid())
  contentId    String
  content      Content  @relation(fields: [contentId], references: [id], onDelete: Cascade)

  // Localization fields
  languageCode String   // e.g., "en", "fr"
  regionCode   String?  // e.g., "US", "GB", "CA"

  // Localized Data
  title        String
  body         Json     // Using JSONB for flexible rich-text or block structures
  isPublished  Boolean  @default(false)

  createdAt    DateTime @default(now())
  updatedAt    DateTime @updatedAt

  // Constraints: One translation per language/region per content item
  @@unique([contentId, languageCode, regionCode])
  @@index([languageCode, regionCode])
}
```

