### 2. The Data Access Layer (with Fallback Logic)

In production, you often want a "fallback" mechanism. If `en-GB` doesn't exist, show `en`. If `en` doesn't exist, show the default site language.

```typescript
// lib/content-service.ts
import { prisma } from "./prisma";

export async function getContentBySlug(slug: string, locale: string) {
  // Split locale like "en-US" into language "en" and region "US"
  const [lang, region] = locale.split("-");

  const content = await prisma.content.findUnique({
    where: { slug },
    include: {
      translations: {
        where: {
          OR: [
            // Exact match: en-US
            { languageCode: lang, regionCode: region || null },
            // Language match: en
            { languageCode: lang, regionCode: null },
            // Global Fallback: en (no region)
            { languageCode: "en", regionCode: null }
          ]
        },
        orderBy: [
          { regionCode: 'desc' }, // Regions first
          { languageCode: 'desc' }
        ],
        take: 1
      }
    }
  });

  return {
    id: content?.id,
    slug: content?.slug,
    translation: content?.translations[0] || null
  };
}
```

