### 3. API Routes for Content Management

This handles creating a piece of content with its first translation.

```typescript
// app/api/content/route.ts
import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { z } from "zod";

const createContentSchema = z.object({
  slug: z.string().min(3),
  contentType: z.string(),
  translation: z.object({
    languageCode: z.string().length(2),
    regionCode: z.string().length(2).optional().nullable(),
    title: z.string(),
    body: z.any(),
  })
});

export async function POST(req: Request) {
  try {
    const body = await req.json();
    const data = createContentSchema.parse(body);

    const result = await prisma.content.create({
      data: {
        slug: data.slug,
        contentType: data.contentType,
        translations: {
          create: {
            languageCode: data.translation.languageCode,
            regionCode: data.translation.regionCode,
            title: data.translation.title,
            body: data.translation.body,
            isPublished: true
          }
        }
      }
    });

    return NextResponse.json(result);
  } catch (error) {
    return NextResponse.json({ error: "Validation failed" }, { status: 400 });
  }
}
```

