## 1. Database Schema (Prisma)

The core challenge is organizing data so that "Global" properties (like an ID or an image URL) are stored once, while "Local" properties (like titles and body text) are stored per language.

```prisma
// prisma/schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Language {
  code         String        @id // e.g., "en-US", "fr-FR", "es"
  name         String        // e.g., "English (US)"
  isDefault    Boolean       @default(false)
  translations ContentTranslation[]
}

model Content {
  id           String        @id @default(uuid())
  slug         String        @unique // URL identifier: "how-to-build-apps"
  authorId     String
  createdAt    DateTime      @default(now())
  updatedAt    DateTime      @updatedAt
  status       String        @default("DRAFT") // DRAFT, PUBLISHED

  // Relations
  translations ContentTranslation[]
}

model ContentTranslation {
  id          String   @id @default(uuid())
  title       String
  body        String   @db.Text
  summary     String?  @db.Text

  // Localization link
  locale      String
  language    Language @relation(fields: [locale], references: [code])

  // Content link
  contentId   String
  content     Content  @relation(fields: [contentId], references: [id], onDelete: Cascade)

  @@unique([contentId, locale]) // Prevents duplicate translations for one language
}
```

