## 2. Backend Implementation (NestJS)

We need a service that can fetch content for a specific locale, with a **fallback mechanism** (if Spanish isn't available, show English).

### Content Service
```typescript
// src/content/content.service.ts
import { Injectable, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../prisma.service';

@Injectable()
export class ContentService {
  constructor(private prisma: PrismaService) {}

  async getPublishedContent(slug: string, locale: string = 'en-US') {
    const content = await this.prisma.content.findUnique({
      where: { slug },
      include: {
        translations: {
          where: { locale: locale }
        }
      }
    });

    if (!content) throw new NotFoundException('Content not found');

    // Fallback Logic: If requested locale doesn't exist, get the default
    if (content.translations.length === 0) {
      const fallback = await this.prisma.contentTranslation.findFirst({
        where: { 
          contentId: content.id,
          language: { isDefault: true } 
        }
      });
      return { ...content, translation: fallback };
    }

    return { ...content, translation: content.translations[0] };
  }

  async upsertTranslation(contentId: string, locale: string, data: any) {
    return this.prisma.contentTranslation.upsert({
      where: {
        contentId_locale: { contentId, locale }
      },
      update: data,
      create: { ...data, contentId, locale }
    });
  }
}
```

