  id           String             @id @default(uuid())
  title        String
  instructions String[] // Array of steps
  authorId     String
  author       User               @relation("UserRecipes", fields: [authorId], references: [id])
  ingredients  RecipeIngredient[]
  nutrition    Nutrition?
  variations   Variation[]
  createdAt    DateTime           @default(now())
}

model Ingredient {
  id      String             @id @default(uuid())
  name    String             @unique
  recipes RecipeIngredient[]
}

model RecipeIngredient {
  recipeId     String
  ingredientId String
  amount       String // e.g., "200g" or "2 cups"
  recipe       Recipe     @relation(fields: [recipeId], references: [id])
  ingredient   Ingredient @relation(fields: [ingredientId], references: [id])

  @@id([recipeId, ingredientId])
}

model Nutrition {
  id       String @id @default(uuid())
  recipeId String @unique
  recipe   Recipe @relation(fields: [recipeId], references: [id])
  calories Float
  protein  Float
  fat      Float
  carbs    Float
}

model Variation {
  id           String   @id @default(uuid())
  originalId   String
  authorId     String
  description  String // What was changed?
  instructions String[] // New steps
  recipe       Recipe   @relation(fields: [originalId], references: [id])
  author       User     @relation(fields: [authorId], references: [id])
  createdAt    DateTime @default(now())
}
