### 4. The Recipe Service (`src/services/recipe.service.ts`)

This is where the heavy lifting happens, including the search logic.

```typescript
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export class RecipeService {
  static async createRecipe(data: any) {
    return prisma.$transaction(async (tx) => {
      // 1. Create the recipe
      const recipe = await tx.recipe.create({
        data: {
          title: data.title,
          authorId: data.authorId,
          instructions: data.instructions,
          nutrition: { create: data.nutrition },
        },
      });

      // 2. Handle Ingredients (upserting them if they don't exist)
      for (const ing of data.ingredients) {
        const ingredient = await tx.ingredient.upsert({
          where: { name: ing.name.toLowerCase() },
          update: {},
          create: { name: ing.name.toLowerCase() },
        });

        await tx.recipeIngredient.create({
          data: {
            recipeId: recipe.id,
            ingredientId: ingredient.id,
            amount: ing.amount,
          },
        });
      }

      return recipe;
    });
  }

  static async searchRecipes(filters: { username?: string; ingredient?: string }) {
    return prisma.recipe.findMany({
      where: {
        AND: [
          filters.username ? {
            author: { username: { contains: filters.username, mode: 'insensitive' } }
          } : {},
          filters.ingredient ? {
            ingredients: {
              some: {
                ingredient: { name: { contains: filters.ingredient.toLowerCase() } }
              }
            }
          } : {}
        ]
      },
      include: {
        author: { select: { username: true } },
        ingredients: { include: { ingredient: true } },
        nutrition: true,
        variations: true
      }
    });
  }

  static async addVariation(recipeId: string, data: any) {
    return prisma.variation.create({
      data: {
        originalId: recipeId,
        authorId: data.authorId,
        description: data.description,
        instructions: data.instructions
      }
    });
  }
}
```

