```typescript
import { PrismaClient } from '@prisma/client';
import { CreateRecipeInput } from '../schema/recipe.schema';

const prisma = new PrismaClient();

export const RecipeService = {
  async createRecipe(data: CreateRecipeInput) {
    return prisma.recipe.create({
      data: {
        title: data.title,
        description: data.description,
        authorId: data.authorId,
        parentRecipeId: data.parentRecipeId,
        nutrition: { create: data.nutrition },
        ingredients: { create: data.ingredients },
        instructions: { create: data.instructions },
      },
      include: { nutrition: true, ingredients: true, instructions: true }
    });
  },

  async searchRecipes(query: { username?: string; ingredient?: string }) {
    return prisma.recipe.findMany({
      where: {
        AND: [
          query.username ? {
            author: { username: { contains: query.username, mode: 'insensitive' } }
          } : {},
          query.ingredient ? {
            ingredients: { some: { name: { contains: query.ingredient, mode: 'insensitive' } } }
          } : {}
        ]
      },
      include: {
        author: { select: { username: true } },
        ingredients: true,
        nutrition: true
      }
    });
  },

  async getRecipeDetails(id: string) {
    return prisma.recipe.findUnique({
      where: { id },
      include: {
        ingredients: true,
        instructions: { orderBy: { stepNumber: 'asc' } },
        nutrition: true,
        variations: true, // Show all user-generated variations
        parentRecipe: true // Show the original source if it is a variation
      }
    });
  }
};
```

