### 3. Database Schema (PostgreSQL + pgvector)

Using `pgvector` allows us to keep document metadata and vector embeddings in the same ACID-compliant database, simplifying backups and consistency.

```sql
-- Enable the vector extension
CREATE EXTENSION IF NOT EXISTS vector;

-- Documents Metadata table
CREATE TABLE documents (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    title TEXT NOT NULL,
    file_key TEXT NOT NULL, -- S3 Path
    mime_type TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    metadata JSONB -- Store tags, department, author
);

-- Document Chunks table for semantic search
CREATE TABLE document_chunks (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    document_id UUID REFERENCES documents(id) ON DELETE CASCADE,
    content TEXT NOT NULL,
    embedding vector(1536), -- 1536 for OpenAI ada-002
    page_number INTEGER
);

-- Index for fast retrieval
CREATE INDEX ON document_chunks USING ivfflat (embedding vector_cosine_ops) WITH (lists = 100);
```

