### 3. Content Processing Strategy
To support multiple types, we implement a `ContentProcessor`.

```typescript
// src/storage/processors/processor.strategy.ts

export interface ContentProcessor {
  extractText(buffer: Buffer): Promise<string>;
}

// PDF Processor
import * as pdf from 'pdf-parse';
export class PdfProcessor implements ContentProcessor {
  async extractText(buffer: Buffer): Promise<string> {
    const data = await pdf(buffer);
    return data.text;
  }
}

// Text/Markdown Processor
export class TextProcessor implements ContentProcessor {
  async extractText(buffer: Buffer): Promise<string> {
    return buffer.toString('utf-8');
  }
}
```

