### 5. Document Service (The Orchestrator)
This service coordinates file processing, storage, and database indexing.

```typescript
// src/documents/documents.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { StorageService } from '../storage/storage.service';
import { PdfProcessor, TextProcessor } from '../storage/processors/processor.strategy';

@Injectable()
export class DocumentsService {
  constructor(
    private prisma: PrismaService,
    private storage: StorageService
  ) {}

  async createDocument(file: Express.Multer.File, metadata: any) {
    const { originalname, buffer, mimetype } = file;

    // 1. Determine processor
    const processor = mimetype === 'application/pdf' ? new PdfProcessor() : new TextProcessor();

    // 2. Extract text for the search index
    const extractedText = await processor.extractText(buffer);

    // 3. Upload to S3
    const fileKey = `docs/${Date.now()}-${originalname}`;
    await this.storage.uploadFile(fileKey, buffer, mimetype);

    // 4. Save to DB within a transaction
    return this.prisma.$transaction(async (tx) => {
      const doc = await tx.document.create({
        data: {
          title: metadata.title || originalname,
          contentType: this.mapMimetype(mimetype),
          tags: metadata.tags || [],
          versions: {
            create: {
              versionNum: 1,
              fileKey: fileKey,
              fileSize: file.size,
              textContent: extractedText
            }
          }
        }
      });
      return doc;
    });
  }

  async search(query: string) {
    // Advanced: Using PostgreSQL Full Text Search
    return this.prisma.$queryRaw`
      SELECT d.*, ts_rank(d."searchVector", plainto_tsquery('english', ${query})) as rank
      FROM "Document" d
      JOIN "DocumentVersion" dv ON dv."documentId" = d.id
      WHERE d."searchVector" @@ plainto_tsquery('english', ${query})
         OR dv."textContent" ILIKE ${'%' + query + '%'}
      ORDER BY rank DESC;
    `;
  }

  private mapMimetype(mime: string) {
    if (mime === 'application/pdf') return 'PDF';
    if (mime === 'text/markdown') return 'MARKDOWN';
    return 'TEXT';
  }
}
```

