### 6. The API Controller
Standard REST endpoints for the document lifecycle.

```typescript
// src/documents/documents.controller.ts
import { Controller, Post, Get, Query, UploadedFile, UseInterceptors, Body } from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { DocumentsService } from './documents.service';

@Controller('documents')
export class DocumentsController {
  constructor(private readonly docsService: DocumentsService) {}

  @Post('upload')
  @UseInterceptors(FileInterceptor('file'))
  async uploadFile(
    @UploadedFile() file: Express.Multer.File,
    @Body() body: { title: string; tags: string }
  ) {
    const tags = body.tags ? body.tags.split(',') : [];
    return this.docsService.createDocument(file, { ...body, tags });
  }

  @Get('search')
  async search(@Query('q') query: string) {
    return this.docsService.search(query);
  }
}
```

