### 2. Backend API (Node.js)

We'll create a single endpoint that accepts `lat` and `lng` and returns both events and users within the 15-mile radius.

**Note:** PostGIS uses meters. 15 miles ≈ **24,140 meters**.

```javascript
// server.js
const express = require('express');
const { Pool } = require('pg');
const cors = require('cors');

const app = express();
const pool = new Pool({
  connectionString: process.env.DATABASE_URL, // e.g., postgres://user:pass@localhost:5432/mydb
});

app.use(cors());
app.use(express.json());

const RADIUS_IN_METERS = 15 * 1609.34; // 15 miles to meters

app.get('/api/search', async (req, res) => {
  const { lat, lng } = req.query;

  if (!lat || !lng) {
    return res.status(400).json({ error: "Missing coordinates" });
  }

  try {
    // ST_DWithin is highly optimized for spatial indexes
    // ST_MakePoint(lng, lat) - Note: Longitude comes first in PostGIS!

    const eventsQuery = `
      SELECT id, title, description, event_date,
             ST_Distance(location, ST_MakePoint($1, $2)::geography) / 1609.34 as distance_miles
      FROM events
      WHERE ST_DWithin(location, ST_MakePoint($1, $2)::geography, $3)
      ORDER BY distance_miles ASC;
    `;

    const usersQuery = `
      SELECT id, name,
             ST_Distance(location, ST_MakePoint($1, $2)::geography) / 1609.34 as distance_miles
      FROM users
      WHERE ST_DWithin(location, ST_MakePoint($1, $2)::geography, $3)
      AND ST_Distance(location, ST_MakePoint($1, $2)::geography) > 0 -- Exclude self
      ORDER BY distance_miles ASC;
    `;

    const [events, users] = await Promise.all([
      pool.query(eventsQuery, [lng, lat, RADIUS_IN_METERS]),
      pool.query(usersQuery, [lng, lat, RADIUS_IN_METERS])
    ]);

    res.json({
      events: events.rows,
      users: users.rows
    });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: "Internal server error" });
  }
});

app.listen(3001, () => console.log('Server running on port 3001'));
```

