### 2. The Backend Search Logic

We'll create a single API endpoint that accepts `lat` and `lng` and returns both users and events. We use `ST_DWithin` for the search, which is highly optimized for spatial indexes.

```typescript
// app/api/search/route.ts
import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const lat = parseFloat(searchParams.get('lat') || '');
  const lng = parseFloat(searchParams.get('lng') || '');
  const radiusInMiles = 15;
  const metersPerMile = 1609.34;
  const radiusInMeters = radiusInMiles * metersPerMile;

  if (isNaN(lat) || isNaN(lng)) {
    return NextResponse.json({ error: 'Invalid coordinates' }, { status: 400 });
  }

  try {
    // We use raw queries because Prisma doesn't natively support PostGIS functions yet
    // ST_DWithin uses the spatial index for O(log n) performance
    // ST_DistanceSphere calculates accurate distance in meters for the UI

    const nearbyEvents = await prisma.$queryRaw`
      SELECT id, title, description, date,
      ST_Distance(location, ST_SetSRID(ST_MakePoint(${lng}, ${lat}), 4326)::geography) / 1609.34 as distance
      FROM "Event"
      WHERE ST_DWithin(location, ST_SetSRID(ST_MakePoint(${lng}, ${lat}), 4326)::geography, ${radiusInMeters})
      ORDER BY distance ASC
    `;

    const nearbyUsers = await prisma.$queryRaw`
      SELECT id, name, image,
      ST_Distance(location, ST_SetSRID(ST_MakePoint(${lng}, ${lat}), 4326)::geography) / 1609.34 as distance
      FROM "User"
      WHERE ST_DWithin(location, ST_SetSRID(ST_MakePoint(${lng}, ${lat}), 4326)::geography, ${radiusInMeters})
      ORDER BY distance ASC
    `;

    return NextResponse.json({ events: nearbyEvents, users: nearbyUsers });
  } catch (error) {
    console.error('Search error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}
```

