## 3. The Backend (Express.js)

The logic relies on `ST_DWithin`, which checks if a point is within a specific distance of another.

**Note:** 15 miles ≈ 24,140 meters.

```javascript
// server.js
const express = require('express');
const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();
const app = express();

const RADIUS_METERS = 15 * 1609.34; // 15 miles to meters

app.get('/api/search', async (req, res) => {
  const { lat, lng, type } = req.query;

  if (!lat || !lng) {
    return res.status(400).json({ error: "Latitude and longitude are required" });
  }

  try {
    const latitude = parseFloat(lat);
    const longitude = parseFloat(lng);

    // Use Raw SQL for PostGIS functionality
    // ST_DWithin is highly optimized for spatial indices
    const results = type === 'events' 
      ? await prisma.$queryRaw`
          SELECT id, title, description, date, 
          ST_X(location::geometry) as lng, ST_Y(location::geometry) as lat
          FROM "Event"
          WHERE ST_DWithin(
            location, 
            ST_MakePoint(${longitude}, ${latitude})::geography, 
            ${RADIUS_METERS}
          )
          ORDER BY ST_Distance(location, ST_MakePoint(${longitude}, ${latitude})::geography) ASC;
        `
      : await prisma.$queryRaw`
          SELECT id, name, 
          ST_X(location::geometry) as lng, ST_Y(location::geometry) as lat
          FROM "User"
          WHERE ST_DWithin(
            location, 
            ST_MakePoint(${longitude}, ${latitude})::geography, 
            ${RADIUS_METERS}
          )
          ORDER BY ST_Distance(location, ST_MakePoint(${longitude}, ${latitude})::geography) ASC;
        `;

    res.json(results);
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: "Internal Server Error" });
  }
});

app.listen(3001, () => console.log('API running on port 3001'));
