### 1. Database Schema & Triggers (SQL)

Run this in your database to handle the heavy lifting. This ensures the background sync is handled at the data layer, making it impossible for the count to get out of sync.

```sql
-- 1. Create the profiles table
create table profiles (
  id uuid references auth.users not null primary key,
  username text unique,
  follower_count int default 0
);

-- 2. Create the follows table
create table follows (
  id bigint generated boolean identity primary key,
  follower_id uuid references profiles(id) on delete cascade,
  following_id uuid references profiles(id) on delete cascade,
  unique(follower_id, following_id)
);

-- 3. Create a function to update the count
create or replace function handle_follow_change()
returns trigger as $$
begin
  if (TG_OP = 'INSERT') then
    update profiles
    set follower_count = follower_count + 1
    where id = NEW.following_id;
  elsif (TG_OP = 'DELETE') then
    update profiles
    set follower_count = follower_count - 1
    where id = OLD.following_id;
  end if;
  return null;
end;
$$ language plpgsql;

-- 4. Create the trigger
create trigger on_follow_change
after insert or delete on follows
for each row execute function handle_follow_change();
```

