### 2. Frontend: Real-time Hook

This React hook subscribes to the specific user's profile and updates the UI the moment the database trigger fires.

```typescript
// hooks/useFollowerCount.ts
import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';

export function useFollowerCount(userId: string, initialCount: number) {
  const [count, setCount] = useState(initialCount);

  useEffect(() => {
    // 1. Subscribe to changes on the 'profiles' table for this specific user
    const channel = supabase
      .channel(`profile_updates_${userId}`)
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'profiles',
          filter: `id=eq.${userId}`,
        },
        (payload) => {
          // 2. Update the state with the new count from the DB trigger
          setCount(payload.new.follower_count);
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [userId]);

  return count;
}
```

