### 2. The Background Worker (Server-side)

First, install dependencies: `npm install express socket.io bullmq ioredis prisma @prisma/client`

#### `server/src/queue.js` (The Producer)
We use BullMQ to ensure that even if the server restarts, follow requests aren't lost.

```javascript
const { Queue } = require('bullmq');
const Redis = require('ioredis');

const connection = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

// Create the queue for follow operations
const followQueue = new Queue('follow-updates', { connection });

async function addFollowJob(userId, targetId, action) {
  await followQueue.add('update-count', { userId, targetId, action }, {
    attempts: 3,
    backoff: { type: 'exponential', delay: 1000 }
  });
}

module.exports = { addFollowJob, connection };
```

#### `server/src/worker.js` (The Consumer)
The worker handles the heavy lifting and then tells the Socket server to notify clients.

```javascript
const { Worker } = require('bullmq');
const { PrismaClient } = require('@prisma/client');
const { connection } = require('./queue');

const prisma = new PrismaClient();

const worker = new Worker('follow-updates', async (job) => {
  const { targetId, action } = job.data;

  // 1. Atomic Database Update
  // We use "increment" to prevent race conditions
  const updatedUser = await prisma.user.update({
    where: { id: targetId },
    data: {
      followerCount: {
        [action === 'follow' ? 'increment' : 'decrement']: 1
      }
    }
  });

  // 2. Return data for the socket trigger
  return { targetId, newCount: updatedUser.followerCount };
}, { connection });

module.exports = worker;
```

