### 1. The Database Schema (`schema.prisma`)

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Order {
  id           String      @id @default(uuid())
  createdAt    DateTime    @default(now())
  items        OrderItem[]
  refunds      Refund[]
  status       String      // e.g., "COMPLETED", "REFUNDED"
}

model ProductVariant {
  id        String      @id @default(uuid())
  sku       String      @unique
  name      String
  inventory Inventory[]
  orderItems OrderItem[]
}

model Warehouse {
  id        String      @id @default(uuid())
  name      String
  location  String
  inventory Inventory[]
}

model Inventory {
  id               String         @id @default(uuid())
  productVariantId String
  warehouseId      String
  quantity         Int
  variant          ProductVariant @relation(fields: [productVariantId], references: [id])
  warehouse        Warehouse      @relation(fields: [warehouseId], references: [id])

  @@unique([productVariantId, warehouseId])
}

model OrderItem {
  id               String         @id @default(uuid())
  orderId          String
  productVariantId String
  warehouseId      String         // Track which warehouse fulfilled this
  quantity         Int
  order            Order          @relation(fields: [orderId], references: [id])
  variant          ProductVariant @relation(fields: [productVariantId], references: [id])
}

model Refund {
  id        String   @id @default(uuid())
  orderId   String
  reason    String
  createdAt DateTime @default(now())
  order     Order    @relation(fields: [orderId], references: [id])
}
```

