### 2. The Refund Service (`refund.service.ts`)

This service contains the core business logic.

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class RefundService {
  private readonly REFUND_WINDOW_DAYS = 30;

  async processRefund(orderId: string, reason: string) {
    return await prisma.$transaction(async (tx) => {
      // 1. Fetch Order and items
      const order = await tx.order.findUnique({
        where: { id: orderId },
        include: { items: true },
      });

      if (!order) throw new Error('Order not found');

      // 2. Verify 30-day window
      const now = new Date();
      const orderDate = new Date(order.createdAt);
      const diffInDays = (now.getTime() - orderDate.getTime()) / (1000 * 3600 * 24);

      if (diffInDays > this.REFUND_WINDOW_DAYS) {
        throw new Error(`Refund window expired. Order was placed ${Math.floor(diffInDays)} days ago.`);
      }

      // 3. Prevent double refunds
      const existingRefund = await tx.refund.findFirst({ where: { orderId } });
      if (existingRefund) throw new Error('Order already refunded');

      // 4. Update Stock for each item in the order
      for (const item of order.items) {
        await tx.inventory.update({
          where: {
            productVariantId_warehouseId: {
              productVariantId: item.productVariantId,
              warehouseId: item.warehouseId,
            },
          },
          data: {
            quantity: {
              increment: item.quantity,
            },
          },
        });
      }

      // 5. Create Refund Record
      const refund = await tx.refund.create({
        data: {
          orderId,
          reason,
        },
      });

      // 6. Update Order Status
      await tx.order.update({
        where: { id: orderId },
        data: { status: 'REFUNDED' },
      });

      return refund;
    });
  }
}
```

