### 2. The Refund Service

This service contains the core business logic. It validates the 30-day window and performs the atomic update across all locations.

```typescript
// src/services/refund.service.ts

import { PrismaClient } from '@prisma/client';
import { differenceInDays } from 'date-fns';

const prisma = new PrismaClient();

export class RefundService {
  /**
   * Processes a refund for a specific order item.
   * Updates stock across ALL warehouses that stock this variant.
   */
  static async processRefund(orderItemId: string) {
    return await prisma.$transaction(async (tx) => {
      // 1. Fetch Order Item and parent Order
      const orderItem = await tx.orderItem.findUnique({
        where: { id: orderItemId },
        include: { order: true },
      });

      if (!orderItem) throw new Error('Order item not found');
      if (orderItem.refunded) throw new Error('Item already refunded');

      // 2. Verify 30-day window
      const daysSincePurchase = differenceInDays(new Date(), orderItem.order.createdAt);
      if (daysSincePurchase > 30) {
        throw new Error(`Refund window expired. Days elapsed: ${daysSincePurchase}`);
      }

      // 3. Update Order Item status
      await tx.orderItem.update({
        where: { id: orderItemId },
        data: { refunded: true },
      });

      // 4. Update Stock Level across ALL warehouse locations
      // Business Logic: If we "restock" a refund, we usually return it to a 
      // specific warehouse. However, based on requirements to update "all locations",
      // we will increment the stock for this variant in every warehouse it exists in.
      const inventoryRecords = await tx.inventory.findMany({
        where: { productVariantId: orderItem.productVariantId }
      });

      if (inventoryRecords.length === 0) {
        throw new Error('No inventory records found for this variant');
      }

      // Increment stock in every location
      const updates = inventoryRecords.map((record) =>
        tx.inventory.update({
          where: { id: record.id },
          data: {
            stockLevel: {
              increment: orderItem.quantity,
            },
          },
        })
      );

      await Promise.all(updates);

      return {
        success: true,
        message: 'Refund processed and stock updated across all locations',
        refundedQuantity: orderItem.quantity,
        locationsUpdated: inventoryRecords.length
      };
    });
  }
}
```

