### 2. The Refund Service

This service contains the core business logic. It checks the 30-day window and uses a **Database Transaction** to ensure data integrity.

```typescript
// src/services/refund.service.ts
import { PrismaClient } from '@prisma/client';
import { differenceInDays } from 'date-fns';

const prisma = new PrismaClient();

export class RefundService {
  /**
   * Processes a refund and restores stock levels
   */
  async processRefund(orderId: string, reason: string) {
    return await prisma.$transaction(async (tx) => {
      // 1. Fetch the order and its items
      const order = await tx.order.findUnique({
        where: { id: orderId },
        include: { items: true },
      });

      if (!order) {
        throw new Error('Order not found');
      }

      // 2. Verify 30-day window
      const daysSincePurchase = differenceInDays(new Date(), order.createdAt);
      if (daysSincePurchase > 30) {
        throw new Error(`Refund window expired. Order was placed ${daysSincePurchase} days ago.`);
      }

      // 3. Create the refund record
      const refund = await tx.refund.create({
        data: {
          orderId: order.id,
          reason,
        },
      });

      // 4. Update Stock Levels
      // Logic: For every item in the order, increment the stock in ALL warehouses 
      // OR a specific default warehouse. Here we increment across all warehouses 
      // that already stock this variant to maintain distribution.
      for (const item of order.items) {
        const inventories = await tx.inventory.findMany({
          where: { variantId: item.variantId }
        });

        if (inventories.length === 0) {
          // If no inventory record exists, handle logic to assign to a default warehouse
          throw new Error(`No warehouse location found for variant ${item.variantId}`);
        }

        // Strategy: We return the quantity to the "Primary" warehouse 
        // (the first one found in this example)
        const targetWarehouseId = inventories[0].warehouseId;

        await tx.inventory.update({
          where: {
            variantId_warehouseId: {
              variantId: item.variantId,
              warehouseId: targetWarehouseId,
            },
          },
          data: {
            quantity: { increment: item.quantity },
          },
        });
      }

      // 5. Update Order Status
      await tx.order.update({
        where: { id: orderId },
        data: { status: 'REFUNDED' },
      });

      return refund;
    });
  }
}
```

