### 3. Atomic Inventory Service (`src/lib/redis.ts`)
We use a Lua script to ensure that "Check Stock" and "Decrement Stock" happen as a single atomic operation in Redis.

```typescript
import Redis from 'ioredis';

export const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

/**
 * Lua Script:
 * 1. Get current stock
 * 2. If stock >= requested amount, decrement and return 1
 * 3. Else return 0
 */
const reserveStockScript = `
  local currentStock = tonumber(redis.call('get', KEYS[1]) or "0")
  local requestAmount = tonumber(ARGV[1])
  if currentStock >= requestAmount then
    redis.call('decrby', KEYS[1], requestAmount)
    return 1
  else
    return 0
  end
`;

redis.defineCommand('reserveStock', {
  numberOfKeys: 1,
  lua: reserveStockScript,
});

// Type definition for the custom command
declare module 'ioredis' {
  interface Redis {
    reserveStock(key: string, amount: number): Promise<number>;
  }
}
```

### 4. The Checkout Logic (`src/services/checkout.ts`)
This is the core "Saga" logic: Reserve -> Pay -> (Commit or Rollback).

```typescript
import { redis } from '../lib/redis';
import { prisma } from '../lib/db';

export async function processCheckout(productId: string, sku: string, amount: number) {
  const stockKey = `stock:${sku}`;

  // 1. ATOMIC RESERVATION (Redis)
  const isReserved = await redis.reserveStock(stockKey, amount);

  if (isReserved === 0) {
    throw new Error('OUT_OF_STOCK');
  }

  try {
    // 2. SIMULATE PAYMENT
    // In a real app, this calls Stripe/PayPal
    await simulatePayment();

    // 3. SUCCESS: Create Order & Sync DB (Async)
    const order = await prisma.order.create({
      data: {
        productId,
        amount: 100.00, // Example
        status: 'COMPLETED'
      }
    });

    // Note: In production, we'd use a Message Queue (BullMQ) 
    // to update Postgres stock to match Redis eventually.
    return order;

  } catch (error) {
    // 4. INSTANT ROLLBACK (Redis)
    // If payment fails, put the stock back immediately
    await redis.incrby(stockKey, amount);

    console.error(`Payment failed, stock restored for ${sku}`);
    throw new Error('PAYMENT_FAILED');
  }
}

async function simulatePayment() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      // Simulate 10% failure rate
      Math.random() > 0.1 ? resolve(true) : reject(new Error('Bank Declined'));
    }, 200);
  });
}
```

