### 3. The Redis Logic (Lua Scripting)

The secret to high concurrency is performing the "Check Stock" and "Decrement Stock" as a single atomic unit.

```typescript
// src/lib/redis.ts
import Redis from 'ioredis';

export const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

/**
 * LUA script to ensure atomicity.
 * KEYS[1]: product stock key
 * ARGV[1]: quantity to decrement
 * Returns 1 if success, 0 if insufficient stock.
 */
const decrementStockLua = `
  local currentStock = redis.call("GET", KEYS[1])
  if currentStock == false then
    return -1
  end
  if tonumber(currentStock) >= tonumber(ARGV[1]) then
    return redis.call("DECRBY", KEYS[1], ARGV[1])
  else
    return -2
  end
`;

export async function tryReserveStock(sku: string, qty: number): Promise<boolean> {
  const key = `stock:${sku}`;
  const result = await redis.eval(decrementStockLua, 1, key, qty);
  // result >= 0 means success (returns remaining stock)
  return (result as number) >= 0;
}

export async function releaseStock(sku: string, qty: number) {
  const key = `stock:${sku}`;
  await redis.incrby(key, qty);
}
```

### 4. The Checkout Service

This service orchestrates the stock reservation, payment simulation, and restoration.

```typescript
// src/services/checkout.service.ts
import { redis, tryReserveStock, releaseStock } from '../lib/redis';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export async function processCheckout(productId: string, sku: string, quantity: number) {
  // 1. Atomically decrement stock in Redis
  const reserved = await tryReserveStock(sku, quantity);

  if (!reserved) {
    throw new Error('INSUFFICIENT_STOCK');
  }

  try {
    // 2. Simulate Payment Process
    // In production, this calls Stripe/PayPal
    await simulatePayment();

    // 3. Create Order in DB
    const order = await prisma.order.create({
      data: {
        productId,
        quantity,
        status: 'COMPLETED',
      },
    });

    // 4. (Optional) Sync DB stock asynchronously
    // In a high-traffic app, you'd queue a job to update Postgres later
    return order;

  } catch (error) {
    // 5. CRITICAL: Restoration
    // If payment fails or DB write fails, put stock back in Redis immediately
    await releaseStock(sku, quantity);

    console.error(`Stock restored for ${sku} due to error: ${error.message}`);
    throw error;
  }
}

async function simulatePayment() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      // 20% chance of payment failure for testing
      Math.random() > 0.8 ? reject(new Error('PAYMENT_FAILED')) : resolve(true);
    }, 100);
  });
}
```

