### 3. High-Concurrency Redis Logic (`src/lib/redis.ts`)
Standard Redis `DECR` is not enough because we need to check if stock is sufficient *before* decrementing. We use a **Lua script** to ensure this check-and-set operation is atomic.

```typescript
import Redis from 'ioredis';

export const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

// Lua script: Returns 1 on success, -1 if insufficient stock
const DECREMENT_STOCK_LUA = `
  local current_stock = tonumber(redis.call('get', KEYS[1]) or "0")
  local requested_qty = tonumber(ARGV[1])

  if current_stock >= requested_qty then
    return redis.call('decrby', KEYS[1], requested_qty)
  else
    return -1
  end
`;

export async function reserveStock(productId: string, qty: number): Promise<boolean> {
  const result = await redis.eval(
    DECREMENT_STOCK_LUA,
    1,
    `product:stock:${productId}`,
    qty
  );
  return (result as number) >= 0;
}

export async function releaseStock(productId: string, qty: number): Promise<void> {
  await redis.incrby(`product:stock:${productId}`, qty);
}
```

### 4. The Checkout Service (`src/services/checkout.ts`)
This is where we manage the lifecycle and handle failures.

```typescript
import { db } from '../lib/db';
import { reserveStock, releaseStock } from '../lib/redis';
import { processPayment } from './payment';

export async function checkout(productId: string, quantity: number) {
  // 1. Atomically decrement stock in Redis (Hot Path)
  const isReserved = await reserveStock(productId, quantity);

  if (!isReserved) {
    throw new Error('OUT_OF_STOCK');
  }

  let order;
  try {
    // 2. Create a PENDING order in DB
    order = await db.order.create({
      data: { productId, quantity, status: 'PENDING' }
    });

    // 3. Process External Payment
    const paymentSuccess = await processPayment(order.id);

    if (!paymentSuccess) {
      throw new Error('PAYMENT_FAILED');
    }

    // 4. Update DB and final stock (Asynchronous or inside transaction)
    await db.$transaction([
      db.order.update({
        where: { id: order.id },
        data: { status: 'COMPLETED' }
      }),
      db.product.update({
        where: { id: productId },
        data: { stock: { decrement: quantity } }
      })
    ]);

    return { success: true, orderId: order.id };

  } catch (error) {
    // 5. THE RESTORATION: If anything fails, put stock back in Redis instantly
    await releaseStock(productId, quantity);

    if (order) {
      await db.order.update({
        where: { id: order.id },
        data: { status: 'FAILED' }
      });
    }

    throw error;
  }
}
```

