### 4. Product Service (`src/services/product.service.ts`)

This handles the business logic, including fetching products from sub-categories.

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class ProductService {
  static async createProduct(data: any) {
    return prisma.product.create({ data });
  }

  static async getProducts(filters: { categorySlug?: string; minPrice?: number; maxPrice?: number }) {
    const where: any = {};

    if (filters.categorySlug) {
      // Find category and all its children IDs to include products in subcategories
      const category = await prisma.category.findUnique({
        where: { slug: filters.categorySlug },
        include: { children: true }
      });

      if (category) {
        const categoryIds = [category.id, ...category.children.map(c => c.id)];
        where.categoryId = { in: categoryIds };
      }
    }

    if (filters.minPrice || filters.maxPrice) {
      where.price = {
        gte: filters.minPrice,
        lte: filters.maxPrice,
      };
    }

    return prisma.product.findMany({
      where,
      include: { category: true },
    });
  }

  static async getProductsByAttribute(key: string, value: any) {
    // Advanced PostgreSQL JSONB query using Prisma raw or path query
    return prisma.product.findMany({
      where: {
        attributes: {
          path: [key],
          equals: value,
        },
      },
    });
  }
}
```

