### 4. The Hybrid Search Service
This is the core logic. It performs two queries: one for exact keywords and one for semantic meaning, then combines them.

```typescript
// services/search.service.ts
import { PrismaClient } from '@prisma/client';
import { getEmbedding } from '../lib/ml';

const prisma = new PrismaClient();

export async function hybridSearch(query: string, limit = 10) {
  const queryEmbedding = await getEmbedding(query);
  const vectorString = `[${queryEmbedding.join(',')}]`;

  // We use a Raw Query to access pgvector and Full Text Search features
  return await prisma.$queryRaw`
    SELECT 
      id, 
      url, 
      description,
      -- Calculate Semantic Similarity (Cosine Distance)
      (1 - (embedding <=> ${vectorString}::vector)) as semantic_score,
      -- Calculate Keyword Match Score (Postgres Text Search)
      ts_rank_cd(to_tsvector('english', description), plainto_tsquery('english', ${query})) as keyword_score
    FROM "ImageMetadata"
    WHERE 
      (1 - (embedding <=> ${vectorString}::vector)) > 0.3 -- Minimum semantic threshold
      OR to_tsvector('english', description) @@ plainto_tsquery('english', ${query})
    ORDER BY (
      -- Hybrid Ranking: Weights can be adjusted based on preference
      (0.7 * (1 - (embedding <=> ${vectorString}::vector))) + 
      (0.3 * ts_rank_cd(to_tsvector('english', description), plainto_tsquery('english', ${query})))
    ) DESC
    LIMIT ${limit};
  `;
}
```

