### 5. API Endpoint
Create a simple Express route to handle search requests.

```typescript
// server.ts
import express from 'express';
import { hybridSearch } from './services/search.service';

const app = express();
app.use(express.json());

app.get('/search', async (req, res) => {
  const { q } = req.query;
  if (!q) return res.status(400).json({ error: "Query required" });

  try {
    const results = await hybridSearch(q as string);
    res.json(results);
  } catch (err) {
    res.status(500).json({ error: "Search failed" });
  }
});

// Helper to seed data
app.post('/images', async (req, res) => {
  const { url, description } = req.body;
  const embedding = await getEmbedding(description);

  // Manual insert due to pgvector Prisma limitations
  await prisma.$executeRaw`
    INSERT INTO "ImageMetadata" (id, url, description, embedding)
    VALUES (gen_random_uuid(), ${url}, ${description}, ${embedding}::vector)
  `;

  res.status(201).send();
});

app.listen(3000, () => console.log("Server running on port 3000"));
```

