### 1. Database Schema & Security (SQL)

Run this in your Supabase SQL Editor. This setup creates the tables and enforces the "Isolation Principle."

```sql
-- 1. Create Patients Table
CREATE TABLE patients (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  doctor_id UUID REFERENCES auth.users(id) NOT NULL,
  full_name TEXT NOT NULL,
  email TEXT,
  phone TEXT,
  date_of_birth DATE,
  medical_history TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- 2. Create Appointments Table
CREATE TABLE appointments (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  doctor_id UUID REFERENCES auth.users(id) NOT NULL,
  patient_id UUID REFERENCES patients(id) ON DELETE CASCADE NOT NULL,
  appointment_date TIMESTAMPTZ NOT NULL,
  reason TEXT,
  status TEXT DEFAULT 'scheduled' CHECK (status IN ('scheduled', 'completed', 'cancelled')),
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- 3. Enable Row Level Security (CRITICAL)
ALTER TABLE patients ENABLE ROW LEVEL SECURITY;
ALTER TABLE appointments ENABLE ROW LEVEL SECURITY;

-- 4. Create Isolation Policies
-- This policy ensures a doctor can only SEE and MODIFY patients where doctor_id matches their Auth ID
CREATE POLICY "Doctors can only access their own patients" 
ON patients FOR ALL 
USING (auth.uid() = doctor_id);

CREATE POLICY "Doctors can only access their own appointments" 
ON appointments FOR ALL 
USING (auth.uid() = doctor_id);
```

