### 2. Frontend Implementation (Next.js)

#### Patient Management Hook (`hooks/use-patients.ts`)
We use React Query to manage the state. Notice we don't need to pass a "Doctor ID" in the filter; the RLS policy automatically filters the results based on the logged-in user's session.

```typescript
import { createClient } from '@/utils/supabase/client';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';

export function usePatients() {
  const supabase = createClient();
  const queryClient = useQueryClient();

  const { data: patients, isLoading } = useQuery({
    queryKey: ['patients'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('patients')
        .select('*')
        .order('last_name', { ascending: true });
      if (error) throw error;
      return data;
    },
  });

  const addPatient = useMutation({
    mutationFn: async (newPatient: any) => {
      const { error } = await supabase.from('patients').insert(newPatient);
      if (error) throw error;
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['patients'] }),
  });

  return { patients, isLoading, addPatient };
}
```

