### 1. Database Schema (`prisma/schema.prisma`)

This schema handles the hierarchy: District -> Schools -> Forms -> Submissions.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum Role {
  DISTRICT_ADMIN
  SCHOOL_STAFF
}

model District {
  id      String   @id @default(cuid())
  name    String
  schools School[]
  users   User[]
}

model School {
  id         String   @id @default(cuid())
  name       String
  districtId String
  district   District @relation(fields: [districtId], references: [id])
  forms      Form[]
  users      User[]
}

model User {
  id         String   @id @default(cuid())
  email      String   @unique
  role       Role     @default(SCHOOL_STAFF)
  districtId String
  district   District @relation(fields: [districtId], references: [id])
  schoolId   String?  // Null if District Admin
  school     School?  @relation(fields: [schoolId], references: [id])
}

model Form {
  id          String       @id @default(cuid())
  title       String
  description String?
  published   Boolean      @default(false)
  schoolId    String
  school      School       @relation(fields: [schoolId], references: [id])

  // JSON structure defining the questions: { type: 'text' | 'select', label: string, required: boolean }[]
  fields      Json

  submissions Submission[]
  createdAt   DateTime     @default(now())
}

model Submission {
  id        String   @id @default(cuid())
  formId    String
  form      Form     @relation(fields: [formId], references: [id])
  // JSON structure containing the answers: { [fieldLabel]: value }
  data      Json
  createdAt DateTime @default(now())
}
```

