This component allows school staff to add questions dynamically.

```tsx
// components/forms/FormBuilder.tsx
"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { FormField, FieldType } from "@/types/form";
import { PlusCircle, Trash2 } from "lucide-react";

export function FormBuilder({ onSave }: { onSave: (fields: FormField[]) => void }) {
  const [fields, setFields] = useState<FormField[]>([]);

  const addField = (type: FieldType) => {
    const newField: FormField = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      label: `New ${type} Question`,
      required: false,
    };
    setFields([...fields, newField]);
  };

  const updateField = (id: string, updates: Partial<FormField>) => {
    setFields(fields.map(f => f.id === id ? { ...f, ...updates } : f));
  };

  return (
    <div className="space-y-6 p-4 border rounded-lg bg-slate-50">
      <div className="flex gap-2 mb-4 overflow-x-auto pb-2">
        <Button variant="outline" size="sm" onClick={() => addField('TEXT')}>+ Short Answer</Button>
        <Button variant="outline" size="sm" onClick={() => addField('EMAIL')}>+ Email</Button>
        <Button variant="outline" size="sm" onClick={() => addField('SELECT')}>+ Dropdown</Button>
      </div>

      {fields.map((field, index) => (
        <div key={field.id} className="bg-white p-4 border rounded shadow-sm flex flex-col gap-3">
          <div className="flex items-center justify-between">
            <span className="text-xs font-bold text-slate-400 uppercase">{field.type}</span>
            <Button variant="ghost" size="sm" onClick={() => setFields(fields.filter(f => f.id !== field.id))}>
              <Trash2 className="w-4 h-4 text-red-500" />
            </Button>
          </div>

          <Input 
            placeholder="Question Label" 
            value={field.label}
            onChange={(e) => updateField(field.id, { label: e.target.value })}
          />

          {field.type === 'SELECT' && (
            <Input 
              placeholder="Options (comma separated)" 
              onChange={(e) => updateField(field.id, { options: e.target.value.split(',') })}
            />
          )}
        </div>
      ))}

      <Button className="w-full" onClick={() => onSave(fields)}>
