### 1. The Database Schema (Prisma)

This schema ensures data isolation while allowing the district to aggregate data easily.

```prisma
// prisma/schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model District {
  id        String   @id @default(cuid())
  name      String
  slug      String   @unique
  schools   School[]
  users     User[]
  createdAt DateTime @default(now())
}

model School {
  id          String   @id @default(cuid())
  name        String
  districtId  String
  district    District @relation(fields: [districtId], references: [id])
  forms       Form[]
  submissions Submission[]
  createdAt   DateTime @default(now())
}

model User {
  id         String   @id @default(cuid())
  email      String   @unique
  role       Role     @default(SCHOOL_ADMIN)
  districtId String
  district   District @relation(fields: [districtId], references: [id])
  schoolId   String?  // Null if District Admin
  createdAt  DateTime @default(now())
}

enum Role {
  DISTRICT_ADMIN
  SCHOOL_ADMIN
}

model Form {
  id          String   @id @default(cuid())
  title       String
  description String?
  schoolId    String
  school      School   @relation(fields: [schoolId], references: [id])
  // This stores the structure: [{label: "Child Name", type: "text", required: true}]
  schema      Json     
  submissions Submission[]
  isActive    Boolean  @default(true)
  createdAt   DateTime @default(now())
}

model Submission {
  id        String   @id @default(cuid())
  formId    String
  form      Form     @relation(fields: [formId], references: [id])
  schoolId  String
  school    School   @relation(fields: [schoolId], references: [id])
  // Stores response: {"Child Name": "John Doe", "Attending": true}
  data      Json     
  submittedAt DateTime @default(now())
}
