### 2. Dynamic Form Builder Component

This component allows school admins to "build" their forms.

```tsx
// components/forms/FormBuilder.tsx
"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Plus, Trash2 } from "lucide-react";

export type FormField = {
  id: string;
  label: string;
  type: "text" | "number" | "checkbox" | "date";
  required: boolean;
};

export function FormBuilder({ onSave }: { onSave: (fields: FormField[]) => void }) {
  const [fields, setFields] = useState<FormField[]>([]);

  const addField = () => {
    const newField: FormField = {
      id: Math.random().toString(36).substr(2, 9),
      label: "New Question",
      type: "text",
      required: false,
    };
    setFields([...fields, newField]);
  };

  const updateField = (id: string, updates: Partial<FormField>) => {
    setFields(fields.map(f => f.id === id ? { ...f, ...updates } : f));
  };

  return (
    <div className="space-y-4 p-6 border rounded-xl bg-white shadow-sm">
      <h3 className="text-lg font-bold">Build Your Form</h3>
      {fields.map((field, index) => (
        <div key={field.id} className="flex gap-4 items-end border-b pb-4">
          <div className="flex-1 space-y-2">
            <label className="text-xs font-medium uppercase text-gray-500">Label</label>
            <Input 
              value={field.label} 
              onChange={(e) => updateField(field.id, { label: e.target.value })} 
            />
          </div>
          <div className="w-32 space-y-2">
            <label className="text-xs font-medium uppercase text-gray-500">Type</label>
            <select 
              className="w-full h-10 border rounded-md px-2"
              value={field.type}
              onChange={(e) => updateField(field.id, { type: e.target.value as any })}
            >
              <option value="text">Short Answer</option>
              <option value="date">Date</option>
              <option value="checkbox">Checkbox</option>
            </select>
          </div>
          <Button variant="ghost" size="icon" onClick={() => setFields(fields.filter(f => f.id !== field.id))}>
            <Trash2 className="w-4 h-4 text-red-500" />
          </Button>
        </div>
      ))}
      <div className="flex justify-between">
        <Button variant="outline" onClick={addField}>
          <Plus className="w-4 h-4 mr-2" /> Add Field
        </Button>
        <Button onClick={() => onSave(fields)}>Save Form</Button>
      </div>
    </div>
  );
}
```

