#### `app/register/page.tsx` (Sign Up + Company Creation)
This page handles the "Onboarding" where a user creates both their account and their company.

```tsx
'use client';
import { useState } from 'react';
import { supabase } from '@/lib/supabase';

export default function Register() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [companyName, setCompanyName] = useState('');

  const handleSignUp = async (e: React.FormEvent) => {
    e.preventDefault();

    // 1. Sign up the user
    const { data: authData, error: authError } = await supabase.auth.signUp({
      email, password
    });

    if (authError || !authData.user) return alert(authError?.message);

    // 2. Create the Company
    const { data: companyData } = await supabase
      .from('companies')
      .insert([{ name: companyName }])
      .select()
      .single();

    // 3. Create the Profile linked to the company
    await supabase.from('profiles').insert([{
      id: authData.user.id,
      company_id: companyData.id,
      full_name: 'Admin User',
      role: 'admin'
    }]);

    window.location.href = '/dashboard';
  };

  return (
    <div className="max-w-md mx-auto mt-20 p-6 border rounded-xl shadow">
      <h1 className="text-2xl font-bold mb-4">Register your Company</h1>
      <form onSubmit={handleSignUp} className="flex flex-col gap-4">
        <input className="border p-2" type="text" placeholder="Company Name" onChange={e => setCompanyName(e.target.value)} />
        <input className="border p-2" type="email" placeholder="Email" onChange={e => setEmail(e.target.value)} />
        <input className="border p-2" type="password" placeholder="Password" onChange={e => setPassword(e.target.value)} />
        <button className="bg-blue-600 text-white p-2 rounded">Create Account</button>
      </form>
    </div>
  );
}
```

#### `app/dashboard/tools/page.tsx` (Tool Management)
Because of the RLS policies we wrote earlier, `supabase.from('tools').select('*')` will **automatically** only return tools belonging to the user's company.

```tsx
import { createServerComponentClient } from '@supabase/auth-helpers-nextjs';
import { cookies } from 'next/headers';

export default async function ToolsPage() {
  const supabase = createServerComponentClient({ cookies });

  // RLS ensures this query is scoped to the user's company_id automatically
  const { data: tools } = await supabase.from('tools').select(`
    *,
    assigned_to ( full_name )
  `);

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold">Equipment Inventory</h1>
        <button className="bg-green-600 text-white px-4 py-2 rounded">Add Tool</button>
      </div>

      <div className="grid gap-4">
        {tools?.map((tool) => (
          <div key={tool.id} className="border p-4 rounded-lg flex justify-between bg-white shadow-sm">
            <div>
              <p className="font-semibold text-lg">{tool.name}</p>
              <p className="text-sm text-gray-500">SN: {tool.serial_number}</p>
            </div>
            <div className="text-right">
              <span className={`px-2 py-1 rounded text-xs ${
                tool.status === 'available' ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
              }`}>
                {tool.status.toUpperCase()}
              </span>
              <p className="text-sm mt-1">Assigned to: {tool.assigned_to?.full_name || 'Unassigned'}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
```

