### The Quiz Engine
This component handles the interactive part of the lesson.

```tsx
// components/QuizEngine.tsx
"use client";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";

interface Question {
  question: string;
  options: string[];
  correctAnswer: number;
}

export default function QuizEngine({ questions }: { questions: Question[] }) {
  const [currentStep, setCurrentStep] = useState(0);
  const [score, setScore] = useState(0);
  const [completed, setCompleted] = useState(false);

  const handleAnswer = (index: number) => {
    if (index === questions[currentStep].correctAnswer) {
      setScore(score + 1);
    }

    if (currentStep + 1 < questions.length) {
      setCurrentStep(currentStep + 1);
    } else {
      setCompleted(true);
    }
  };

  if (completed) {
    return (
      <Card className="p-6 text-center">
        <h2 className="text-2xl font-bold">Quiz Complete!</h2>
        <p className="text-xl mt-2">You scored {score} / {questions.length}</p>
        <Button onClick={() => window.location.reload()} className="mt-4">Retry</Button>
      </Card>
    );
  }

  return (
    <Card className="p-6">
      <div className="mb-4 text-sm text-muted-foreground">
        Question {currentStep + 1} of {questions.length}
      </div>
      <h3 className="text-xl font-semibold mb-4">{questions[currentStep].question}</h3>
      <div className="grid gap-3">
        {questions[currentStep].options.map((option, idx) => (
          <Button 
            key={idx} 
            variant="outline" 
            className="justify-start h-auto py-3 text-left"
            onClick={() => handleAnswer(idx)}
          >
            {option}
          </Button>
        ))}
      </div>
    </Card>
  );
}
```

