```tsx
// app/dashboard/create-lesson/page.tsx
"use client";
import { useForm, useFieldArray } from "react-hook-form";
import { supabase } from "@/lib/supabase";

export default function CreateLesson() {
  const { register, control, handleSubmit } = useForm({
    defaultValues: {
      title: "",
      video: null,
      questions: [{ question: "", options: ["", "", ""], correctAnswer: 0 }]
    }
  });

  const { fields, append } = useFieldArray({ control, name: "questions" });

  const onSubmit = async (data: any) => {
    // 1. Upload Video to Supabase Storage
    const videoFile = data.video[0];
    const { data: uploadData } = await supabase.storage
      .from('lessons')
      .upload(`videos/${Date.now()}`, videoFile);

    // 2. Save Lesson
    const { data: lesson } = await supabase.from('lessons').insert({
      title: data.title,
      video_url: uploadData?.path,
      // ... content
    }).select().single();

    // 3. Save Quiz
    await supabase.from('quizzes').insert({
      lesson_id: lesson.id,
      questions: data.questions
    });
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="max-w-4xl mx-auto p-8 space-y-6">
      <h1 className="text-3xl font-bold">Create New Lesson</h1>
      <input {...register("title")} placeholder="Lesson Title" className="w-full p-2 border" />

      <div className="space-y-4">
        <h2 className="text-xl font-semibold">Interactive Quiz</h2>
        {fields.map((field, index) => (
          <div key={field.id} className="p-4 border rounded bg-slate-50">
            <input {...register(`questions.${index}.question`)} placeholder="Question" className="w-full mb-2 p-2" />
            {/* Options mapping here... */}
          </div>
        ))}
        <Button type="button" onClick={() => append({ question: "", options: ["", ""], correctAnswer: 0 })}>
          Add Question
        </Button>
      </div>

      <Button type="submit" className="w-full">Publish Lesson</Button>
    </form>
  );
}
