### 1. Database Schema (`prisma/schema.prisma`)

We need a relational structure to handle lessons, nested modules (video/text/quizzes), and reviews.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum UserRole {
  STUDENT
  TEACHER
}

model User {
  id            String    @id @default(cuid())
  email         String    @unique
  name          String?
  role          UserRole  @default(STUDENT)
  lessons       Lesson[]  @relation("TeacherLessons") // Lessons created by teacher
  reviews       Review[]
}

model Lesson {
  id          String    @id @default(cuid())
  title       String
  description String
  thumbnail   String?
  teacherId   String
  teacher     User      @relation("TeacherLessons", fields: [teacherId], references: [id])
  modules     Module[]
  reviews     Review[]
  createdAt   DateTime  @default(now())
}

enum ModuleType {
  VIDEO
  TEXT
  QUIZ
}

model Module {
  id          String      @id @default(cuid())
  lessonId    String
  lesson      Lesson      @relation(fields: [lessonId], references: [id], onDelete: Cascade)
  type        ModuleType
  title       String
  content     String?     // For Text or Video URLs
  order       Int
  questions   Question[]  // For Quiz type
}

model Question {
  id            String   @id @default(cuid())
  moduleId      String
  module        Module   @relation(fields: [moduleId], references: [id], onDelete: Cascade)
  questionText  String
  options       String[] // JSON string array
  correctAnswer Int      // Index of options
}

model Review {
  id        String   @id @default(cuid())
  rating    Int      // 1-5
  comment   String
  studentId String
  student   User     @relation(fields: [studentId], references: [id])
  lessonId  String
  lesson    Lesson   @relation(fields: [lessonId], references: [id])
  createdAt DateTime @default(now())
}
```

