### 2. The Interactive Quiz Component

This component handles the logic for students taking quizzes within a lesson.

```tsx
// components/QuizModule.tsx
"use client";
import { useState } from "react";
import { Button } from "@/components/ui/button";

interface Question {
  id: string;
  questionText: string;
  options: string[];
  correctAnswer: number;
}

export default function QuizModule({ questions }: { questions: Question[] }) {
  const [currentStep, setCurrentStep] = useState(0);
  const [score, setScore] = useState(0);
  const [showResult, setShowResult] = useState(false);

  const handleAnswer = (index: number) => {
    if (index === questions[currentStep].correctAnswer) {
      setScore(score + 1);
    }

    if (currentStep < questions.length - 1) {
      setCurrentStep(currentStep + 1);
    } else {
      setShowResult(true);
    }
  };

  if (showResult) {
    return (
      <div className="p-6 bg-white rounded-lg shadow text-center">
        <h2 className="text-2xl font-bold mb-4">Quiz Complete!</h2>
        <p className="text-lg">Your Score: {score} / {questions.length}</p>
        <Button onClick={() => window.location.reload()} className="mt-4">Retry</Button>
      </div>
    );
  }

  return (
    <div className="p-6 bg-slate-50 rounded-xl border">
      <h3 className="text-xl font-semibold mb-4">
        Question {currentStep + 1} of {questions.length}
      </h3>
      <p className="mb-6 text-lg">{questions[currentStep].questionText}</p>
      <div className="grid gap-3">
        {questions[currentStep].options.map((option, idx) => (
          <button
            key={idx}
            onClick={() => handleAnswer(idx)}
            className="w-full text-left p-4 rounded-lg border bg-white hover:bg-blue-50 hover:border-blue-500 transition-all"
          >
            {option}
          </button>
        ))}
      </div>
    </div>
  );
}
```

