## 2. Server Actions (`lib/actions.ts`)

These handle the business logic for creating lessons and submitting reviews.

```typescript
"use server"

import { db } from "@/lib/db";
import { auth, currentUser } from "@clerk/nextjs/server";
import { revalidatePath } from "next/cache";

export async function createLesson(formData: any) {
  const { userId } = auth();
  const user = await currentUser();

  if (!userId) throw new Error("Unauthorized");

  const lesson = await db.lesson.create({
    data: {
      title: formData.title,
      description: formData.description,
      videoUrl: formData.videoUrl,
      textContent: formData.textContent,
      teacherId: userId,
      teacherName: user?.firstName || "Teacher",
      quizzes: {
        create: formData.quizzes, // Array of { question, options, correctAnswer }
      },
    },
  });

  revalidatePath("/");
  return lesson;
}

export async function submitReview(lessonId: string, rating: number, comment: string) {
  const { userId } = auth();
  const user = await currentUser();

  if (!userId) throw new Error("Unauthorized");

  await db.review.create({
    data: {
      lessonId,
      studentId: userId,
      studentName: user?.firstName || "Student",
      rating,
      comment,
    },
  });

  revalidatePath(`/lessons/${lessonId}`);
}
