## 3. The Interactive Quiz Component (`components/QuizModule.tsx`)

This client component handles the interactive state of the lesson quizzes.

```tsx
"use client"

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { CheckCircle2, XCircle } from "lucide-react";

export function QuizModule({ quizzes }: { quizzes: any[] }) {
  const [currentStep, setCurrentStep] = useState(0);
  const [selected, setSelected] = useState<number | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [score, setScore] = useState(0);

  const handleCheck = (index: number) => {
    setSelected(index);
    const correct = index === quizzes[currentStep].correctAnswer;
    setIsCorrect(correct);
    if (correct) setScore(score + 1);
  };

  const nextQuestion = () => {
    setSelected(null);
    setIsCorrect(null);
    setCurrentStep(currentStep + 1);
  };

  if (currentStep >= quizzes.length) {
    return (
      <Card className="p-6 text-center">
        <h3 className="text-2xl font-bold">Quiz Complete!</h3>
        <p className="text-lg mt-2">You scored {score} out of {quizzes.length}</p>
        <Button className="mt-4" onClick={() => setCurrentStep(0)}>Restart</Button>
      </Card>
    );
  }

  const quiz = quizzes[currentStep];

  return (
    <Card className="p-6">
      <h3 className="text-xl font-semibold mb-4">Question {currentStep + 1}: {quiz.question}</h3>
      <div className="space-y-3">
        {quiz.options.map((option: string, i: number) => (
          <Button
            key={i}
            variant={selected === i ? (isCorrect ? "default" : "destructive") : "outline"}
            className="w-full justify-start text-left"
            onClick={() => handleCheck(i)}
            disabled={selected !== null}
          >
            {option}
          </Button>
        ))}
      </div>
      {isCorrect !== null && (
        <div className="mt-4 flex items-center gap-2">
          {isCorrect ? <CheckCircle2 className="text-green-500" /> : <XCircle className="text-red-500" />}
          <span>{isCorrect ? "Correct!" : "Try again in the next round!"}</span>
          <Button className="ml-auto" onClick={nextQuestion}>Next</Button>
        </div>
      )}
    </Card>
  );
}
```

