### 2. The Countdown Component
A reusable timer that handles the "Next Piece of Content" logic.

```tsx
// components/Countdown.tsx
'use client';
import { useState, useEffect } from 'react';

interface TimeLeft {
  days: number; hours: number; minutes: number; seconds: number;
}

export default function Countdown({ targetDate, title }: { targetDate: string; title: string }) {
  const [timeLeft, setTimeLeft] = useState<TimeLeft | null>(null);

  useEffect(() => {
    const timer = setInterval(() => {
      const difference = +new Date(targetDate) - +new Date();
      if (difference > 0) {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
          minutes: Math.floor((difference / 1000 / 60) % 60),
          seconds: Math.floor((difference / 1000) % 60),
        });
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [targetDate]);

  if (!timeLeft) return null;

  return (
    <div className="bg-gradient-to-r from-purple-600 to-pink-600 p-6 rounded-2xl text-white shadow-xl">
      <h3 className="text-sm font-bold uppercase tracking-widest mb-4">{title}</h3>
      <div className="flex gap-4 text-center">
        {Object.entries(timeLeft).map(([unit, value]) => (
          <div key={unit} className="flex flex-col">
            <span className="text-3xl font-black">{value.toString().padStart(2, '0')}</span>
            <span className="text-[10px] uppercase opacity-80">{unit}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
```

