### 2. The Countdown Component

This component handles the "Next Concert/Content" requirement with a live ticker.

```tsx
// components/Countdown.tsx
'use client';

import { useState, useEffect } from 'react';

export default function Countdown({ targetDate, label }: { targetDate: Date, label: string }) {
  const [timeLeft, setTimeLeft] = useState({ days: 0, hours: 0, minutes: 0, seconds: 0 });

  useEffect(() => {
    const timer = setInterval(() => {
      const difference = +new Date(targetDate) - +new Date();
      if (difference > 0) {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
          minutes: Math.floor((difference / 1000 / 60) % 60),
          seconds: Math.floor((difference / 1000) % 60),
        });
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [targetDate]);

  return (
    <div className="bg-gradient-to-r from-purple-600 to-blue-600 p-6 rounded-2xl text-white shadow-xl">
      <h3 className="text-sm uppercase tracking-widest font-bold mb-4">{label}</h3>
      <div className="flex gap-4 text-center">
        {Object.entries(timeLeft).map(([unit, value]) => (
          <div key={unit} className="flex flex-col">
            <span className="text-3xl font-black">{value.toString().padStart(2, '0')}</span>
            <span className="text-[10px] uppercase">{unit}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
```

