### 3. Nested Comment System

This is a recursive component that handles "comments on comments."

```tsx
// components/comments/CommentThread.tsx
import { useState } from 'react';
import { formatDistanceToNow } from 'date-fns';

interface CommentProps {
  comment: any; // Ideally typed from Prisma
  onReply: (parentId: string, content: string) => void;
}

export function CommentItem({ comment, onReply }: CommentProps) {
  const [isReplying, setIsReplying] = useState(false);
  const [replyText, setReplyText] = useState('');

  return (
    <div className="mt-4 border-l-2 border-gray-100 pl-4">
      <div className="flex items-start gap-3">
        <div className="w-8 h-8 rounded-full bg-gray-200" />
        <div>
          <p className="text-sm font-semibold">User Name</p>
          <p className="text-gray-700 text-sm">{comment.content}</p>
          <div className="flex gap-3 mt-1 text-xs text-gray-500">
            <span>{formatDistanceToNow(new Date(comment.createdAt))} ago</span>
            <button 
              onClick={() => setIsReplying(!isReplying)}
              className="hover:text-purple-600 font-medium"
            >
              Reply
            </button>
          </div>
        </div>
      </div>

      {isReplying && (
        <div className="mt-3 flex gap-2">
          <input 
            className="flex-1 border rounded-lg px-3 py-1 text-sm"
            placeholder="Write a reply..."
            value={replyText}
            onChange={(e) => setReplyText(e.target.value)}
          />
          <button 
            onClick={() => {
              onReply(comment.id, replyText);
              setIsReplying(false);
              setReplyText('');
            }}
            className="bg-purple-600 text-white px-3 py-1 rounded-lg text-sm"
          >
            Post
          </button>
        </div>
      )}

      {/* RECURSION HAPPENS HERE */}
      {comment.replies?.map((reply: any) => (
        <CommentItem key={reply.id} comment={reply} onReply={onReply} />
      ))}
    </div>
  );
}
