### 4. Gated Content Feed (Server Component)

This component decides what to show based on the user's subscription status.

```tsx
// app/feed/page.tsx
import { createServerComponentClient } from '@supabase/auth-helpers-nextjs';
import { cookies } from 'next/headers';
import PostCard from '@/components/PostCard';
import SubscriptionWall from '@/components/SubscriptionWall';

export default async function ArtistFeed() {
  const supabase = createServerComponentClient({ cookies });

  // 1. Get Session
  const { data: { session } } = await supabase.auth.getSession();

  // 2. Check Subscription Status
  const { data: subscription } = await supabase
    .from('subscriptions')
    .select('status')
    .eq('fanId', session?.user.id)
    .single();

  const isSubscribed = subscription?.status === 'active';

  // 3. Fetch Posts
  const { data: posts } = await supabase
    .from('posts')
    .select('*, artist:profiles(*)')
    .order('createdAt', { ascending: false });

  return (
    <main className="max-w-2xl mx-auto py-10 px-4">
      <h1 className="text-3xl font-bold mb-8">Artist Updates</h1>

      <div className="space-y-8">
        {posts?.map((post) => {
          if (post.isPremium && !isSubscribed) {
            return <SubscriptionWall key={post.id} artistName={post.artist.full_name} />;
          }

          return (
            <PostCard 
              key={post.id} 
              post={post} 
              isPremium={post.isPremium} 
            />
          );
        })}
      </div>
    </main>
  );
}
```

