### 3. Server Actions (`lib/actions.ts`)
This handles the logic for creating books, tags, and reviews in a single transaction.

```typescript
"use server"

import { prisma } from "@/lib/db";
import { revalidatePath } from "next/cache";

export async function createReview(formData: FormData) {
  const title = formData.get("title") as string;
  const author = formData.get("author") as string;
  const content = formData.get("content") as string;
  const rating = parseInt(formData.get("rating") as string);
  const clubId = formData.get("clubId") as string;
  const tagsString = formData.get("tags") as string; // Comma separated

  const tagNames = tagsString.split(",").map(t => t.trim().toLowerCase()).filter(t => t !== "");

  // 1. Create or find the book
  const book = await prisma.book.upsert({
    where: { id: title + author }, // Simple composite key for demo
    update: {},
    create: { title, author, id: title + author }
  });

  // 2. Upsert Review with Tags
  await prisma.review.upsert({
    where: { bookId_clubId: { bookId: book.id, clubId } },
    update: { content, rating },
    create: {
      content,
      rating,
      bookId: book.id,
      clubId,
      tags: {
        connectOrCreate: tagNames.map(name => ({
          where: { name },
          create: { name }
        }))
      }
    }
  });

  revalidatePath(`/club/${clubId}`);
}
```

