### 3. Review Submission Form
This form handles the "Long Review", "Star Rating", and "Tags".

```tsx
// components/ReviewForm.tsx
"use client"
import { useState } from "react";
import { useRouter } from "next/navigation";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import * as z from "zod";
import { StarRating } from "./star-rating";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Input } from "@/components/ui/input";

const formSchema = z.object({
  title: z.string().min(2),
  author: z.string().min(2),
  content: z.string().min(50, "Reviews must be at least 50 characters long."),
  rating: z.number().min(1).max(5),
  tags: z.string(), // Comma separated for simplicity in this example
});

export default function ReviewForm({ clubId }: { clubId: string }) {
  const [rating, setRating] = useState(0);
  const router = useRouter();

  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: { rating: 0, content: "" }
  });

  async function onSubmit(values: z.infer<typeof formSchema>) {
    // In a real app, use a Server Action here
    const response = await fetch('/api/reviews', {
      method: 'POST',
      body: JSON.stringify({ ...values, clubId, rating }),
    });

    if (response.ok) {
      router.refresh();
      form.reset();
    }
  }

  return (
    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6 bg-card p-6 rounded-lg border">
      <div className="grid grid-cols-2 gap-4">
        <Input {...form.register("title")} placeholder="Book Title" />
        <Input {...form.register("author")} placeholder="Author" />
      </div>

      <div>
        <label className="block text-sm font-medium mb-2">Rating</label>
        <StarRating rating={rating} setRating={setRating} />
      </div>

      <Textarea 
        {...form.register("content")} 
        placeholder="Write your long-form review here... What did the club think?" 
        className="min-h-[200px]"
      />

      <Input 
        {...form.register("tags")} 
        placeholder="Tags (e.g. spooky, inspirational, tear-jerker)" 
      />

      <Button type="submit" className="w-full">Post Review to Club Bookshelf</Button>
    </form>
  );
}
```

