            return (
              <div key={i} className="aspect-video rounded-2xl overflow-hidden shadow-2xl">
                <iframe 
                  src={block.url.replace('watch?v=', 'embed/')} 
                  className="w-full h-full"
                  allowFullScreen
                />
              </div>
            );
          }
          // Render Images
          if (block._type === 'image') {
            return <img key={i} src={urlFor(block).url()} className="rounded-2xl w-full" />;
          }
          // Render Blog Text
          return (
            <div key={i} className="prose prose-lg max-w-none">
              <PortableText value={[block]} />
            </div>
          );
        })}
      </div>
    </article>
  );
}
