## 1. Database Schema (PostgreSQL)

You will need to run this in your Supabase SQL Editor to set up the tables:

```sql
-- Profiles table linked to Auth
create table profiles (
  id uuid references auth.users on delete cascade primary key,
  username text unique,
  avatar_url text
);

-- Events table
create table events (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  creator_id uuid references profiles(id),
  title text not null,
  description text,
  status text default 'voting', -- voting, confirmed, completed
  final_time timestamp with time zone,
  final_location text
);

-- Voting options (Time/Place)
create table event_options (
  id uuid default gen_random_uuid() primary key,
  event_id uuid references events(id) on delete cascade,
  type text check (type in ('time', 'location')),
  value text not null, -- Stores either a ISO string date or a string address
  votes_count int default 0
);

-- User Votes
create table votes (
  id uuid default gen_random_uuid() primary key,
  user_id uuid references profiles(id),
  option_id uuid references event_options(id) on delete cascade,
  unique(user_id, option_id)
);

-- Real-time Chat
create table messages (
  id uuid default gen_random_uuid() primary key,
  event_id uuid references events(id) on delete cascade,
  user_id uuid references profiles(id),
  content text not null,
  created_at timestamp with time zone default timezone('utc'::text, now())
);

-- Shared Photos
create table photos (
  id uuid default gen_random_uuid() primary key,
  event_id uuid references events(id) on delete cascade,
  user_id uuid references profiles(id),
  storage_path text not null,
  created_at timestamp with time zone default timezone('utc'::text, now())
);
```

