## 3. Real-time Chat Component

This component uses Supabase's real-time subscriptions so friends can chat instantly.

### `components/event/ChatRoom.tsx`

```tsx
import { useEffect, useState, useRef } from 'react';
import { createClient } from '@/lib/supabase/client';

export default function ChatRoom({ eventId }: { eventId: string }) {
  const [messages, setMessages] = useState<any[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const supabase = createClient();
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // 1. Load existing messages
    const fetchMessages = async () => {
      const { data } = await supabase
        .from('messages')
        .select('*, profiles(username)')
        .eq('event_id', eventId)
        .order('created_at', { ascending: true });
      if (data) setMessages(data);
    };

    fetchMessages();

    // 2. Subscribe to new messages
    const channel = supabase
      .channel(`event_chat:${eventId}`)
      .on('postgres_changes', { 
        event: 'INSERT', 
        schema: 'public', 
        table: 'messages',
        filter: `event_id=eq.${eventId}` 
      }, (payload) => {
        setMessages((prev) => [...prev, payload.new]);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [eventId]);

  const sendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user || !newMessage.trim()) return;

    await supabase.from('messages').insert({
      event_id: eventId,
      user_id: user.id,
      content: newMessage
    });
    setNewMessage('');
  };

  return (
    <div className="flex flex-col h-[500px] border rounded-lg bg-card">
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((m) => (
          <div key={m.id} className="flex flex-col">
            <span className="text-xs font-bold text-primary">{m.profiles?.username || 'User'}</span>
            <span className="bg-muted p-2 rounded-md max-w-xs">{m.content}</span>
          </div>
        ))}
        <div ref={scrollRef} />
      </div>
      <form onSubmit={sendMessage} className="p-4 border-t flex gap-2">
        <input 
          value={newMessage}
          onChange={(e) => setNewMessage(e.target.value)}
          className="flex-1 bg-background border rounded px-3 py-2 outline-none"
          placeholder="Say something..."
        />
        <button className="bg-primary text-primary-foreground px-4 py-2 rounded">Send</button>
      </form>
    </div>
  );
}
```

