## 4. Shared Photo Album

This component handles file uploads to Supabase Storage and displays the grid.

### `components/event/PhotoAlbum.tsx`

```tsx
import { useState, useEffect } from 'react';
import { createClient } from '@/lib/supabase/client';
import { Camera, Upload } from 'lucide-react';

export default function PhotoAlbum({ eventId }: { eventId: string }) {
  const [photos, setPhotos] = useState<any[]>([]);
  const [uploading, setUploading] = useState(false);
  const supabase = createClient();

  const fetchPhotos = async () => {
    const { data } = await supabase
      .from('photos')
      .select('*')
      .eq('event_id', eventId);
    setPhotos(data || []);
  };

  useEffect(() => { fetchPhotos(); }, [eventId]);

  const uploadPhoto = async (e: React.ChangeEvent<HTMLInputElement>) => {
    try {
      setUploading(true);
      const file = e.target.files?.[0];
      if (!file) return;

      const { data: { user } } = await supabase.auth.getUser();
      const filePath = `${eventId}/${user?.id}-${Date.now()}.jpg`;

      // 1. Upload to Storage
      const { error: uploadError } = await supabase.storage
        .from('event-photos')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      // 2. Save to DB
      await supabase.from('photos').insert({
        event_id: eventId,
        user_id: user?.id,
        storage_path: filePath
      });

      fetchPhotos();
    } catch (err) {
      console.error(err);
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-semibold">Shared Memories</h2>
        <label className="cursor-pointer bg-primary text-white px-4 py-2 rounded flex items-center gap-2">
          {uploading ? "Uploading..." : <><Camera size={18} /> Add Photo</>}
          <input type="file" hidden onChange={uploadPhoto} disabled={uploading} />
        </label>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
        {photos.map((photo) => (
          <div key={photo.id} className="aspect-square relative rounded-lg overflow-hidden border">
            <img 
              src={`${process.env.NEXT_PUBLIC_SUPABASE_URL}/storage/v1/object/public/event-photos/${photo.storage_path}`}
              alt="Event memory"
              className="object-cover w-full h-full hover:scale-105 transition-transform"
            />
          </div>
        ))}
      </div>
    </div>
  );
}
```

