import { ThumbsUp, MapPin, Clock } from 'lucide-react';

export default function VotingSystem({ eventId, userId }: { eventId: string, userId: string }) {
  const [options, setOptions] = useState<any[]>([]);
  const [newOption, setNewOption] = useState('');
  const [type, setType] = useState<'time' | 'location'>('location');

  useEffect(() => {
    fetchOptions();
    const subscription = supabase
      .channel('voting')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'votes' }, fetchOptions)
      .subscribe();
    return () => { supabase.removeChannel(subscription) };
  }, [eventId]);

  async function fetchOptions() {
    const { data } = await supabase
      .from('event_options')
      .select('*, votes(user_id)')
      .eq('event_id', eventId);
    if (data) setOptions(data);
  }

  async function addOption() {
    if (!newOption) return;
    await supabase.from('event_options').insert([{ event_id: eventId, type, value: newOption }]);
    setNewOption('');
    fetchOptions();
  }

  async function toggleVote(optionId: string, hasVoted: boolean) {
    if (hasVoted) {
      await supabase.from('votes').delete().eq('option_id', optionId).eq('user_id', userId);
    } else {
      await supabase.from('votes').insert([{ option_id: optionId, user_id: userId }]);
    }
    fetchOptions();
  }

  return (
    <div className="space-y-6 bg-white p-6 rounded-xl shadow-sm">
      <h2 className="text-xl font-bold">Cast Your Vote</h2>

      <div className="flex gap-2">
        <select value={type} onChange={(e: any) => setType(e.target.value)} className="border p-2 rounded">
          <option value="location">Place</option>
          <option value="time">Time</option>
        </select>
        <input 
          className="flex-1 border p-2 rounded" 
          placeholder="Suggest something..."
          value={newOption}
          onChange={(e) => setNewOption(e.target.value)}
        />
        <button onClick={addOption} className="bg-indigo-600 text-white px-4 py-2 rounded">Add</button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {options.map((opt) => {
          const hasVoted = opt.votes?.some((v: any) => v.user_id === userId);
          return (
            <div key={opt.id} className={`p-4 border rounded-lg flex justify-between items-center ${hasVoted ? 'border-indigo-500 bg-indigo-50' : ''}`}>
              <div>
                <span className="flex items-center gap-2 text-sm text-gray-500 uppercase">
                  {opt.type === 'location' ? <MapPin size={14}/> : <Clock size={14}/>} {opt.type}
                </span>
                <p className="font-semibold text-lg">{opt.value}</p>
                <p className="text-sm text-gray-500">{opt.votes?.length || 0} votes</p>
              </div>
              <button 
                onClick={() => toggleVote(opt.id, hasVoted)}
                className={`p-3 rounded-full ${hasVoted ? 'bg-indigo-600 text-white' : 'bg-gray-100'}`}
              >
                <ThumbsUp size={20} />
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );
}
