#### `src/components/PhotoAlbum.tsx`
Handles image uploads to Supabase Storage.

```tsx
import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { Camera, Image as ImageIcon } from 'lucide-react';

export default function PhotoAlbum({ eventId, userId }: { eventId: string, userId: string }) {
  const [photos, setPhotos] = useState<any[]>([]);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    fetchPhotos();
  }, [eventId]);

  async function fetchPhotos() {
    const { data } = await supabase.from('photos').select('*').eq('event_id', eventId);
    if (data) setPhotos(data);
  }

  async function uploadPhoto(e: React.ChangeEvent<HTMLInputElement>) {
    try {
      setUploading(true);
      const file = e.target.files?.[0];
      if (!file) return;

      const fileExt = file.name.split('.').pop();
      const fileName = `${Math.random()}.${fileExt}`;
      const filePath = `${eventId}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('event-photos')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage.from('event-photos').getPublicUrl(filePath);

      await supabase.from('photos').insert([
        { event_id: eventId, user_id: userId, storage_url: publicUrl }
      ]);

      fetchPhotos();
    } catch (error) {
      console.error('Error uploading:', error);
    } finally {
      setUploading(false);
    }
  }

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold flex items-center gap-2">
          <ImageIcon size={20} /> Event Gallery
        </h2>
        <label className="cursor-pointer bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2">
          <Camera size={18} />
          {uploading ? 'Uploading...' : 'Add Photo'}
          <input type="file" className="hidden" accept="image/*" onChange={uploadPhoto} disabled={uploading} />
        </label>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2">
        {photos.map((photo) => (
          <div key={photo.id} className="aspect-square rounded-lg overflow-hidden bg-gray-200">
            <img src={photo.storage_url} className="w-full h-full object-cover hover:scale-105 transition" />
          </div>
        ))}
      </div>
    </div>
  );
}
