### 1. Database Schema (Supabase/PostgreSQL)

You need to enable the **PostGIS** extension in Supabase to handle "spherical" math (calculating distances between GPS coordinates).

Run this SQL in your Supabase SQL Editor:

```sql
-- Enable PostGIS extension
create extension if not exists postgis;

-- Create Pins table
create table pins (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default now(),
  creator_id uuid references auth.users(id),
  message text,
  image_url text,
  -- geography(Point) allows for accurate distance queries
  location geography(Point, 4326) not null
);

-- Create Comments table
create table pin_comments (
  id uuid default gen_random_uuid() primary key,
  pin_id uuid references pins(id) on delete cascade,
  user_id uuid references auth.users(id),
  content text not null,
  created_at timestamp with time zone default now()
);

-- Create Likes table
create table pin_likes (
  pin_id uuid references pins(id) on delete cascade,
  user_id uuid references auth.users(id),
  primary key (pin_id, user_id)
);

-- Spatial function to find pins within X meters of a user
create or replace function get_nearby_pins(lat float, long float, radius_meters float)
returns setof pins as $$
begin
  return query
  select *
  from pins
  where st_dwithin(
    location,
    st_setsrid(st_makepoint(long, lat), 4326)::geography,
    radius_meters
  );
end;
$$ language plpgsql;
```

