#### The Main Map View (`App.js`)

This component handles fetching the user's location and rendering pins nearby.

```javascript
import React, { useState, useEffect } from 'react';
import { StyleSheet, View, Text, TouchableOpacity, Modal, TextInput } from 'react-native';
import MapView, { Marker, Circle } from 'react-native-maps';
import * as Location from 'expo-location';
import { createClient } from '@supabase/supabase-js';
import { Plus, MessageCircle, ThumbsUp } from 'lucide-react-native';

const supabase = createClient('YOUR_SUPABASE_URL', 'YOUR_SUPABASE_ANON_KEY');

export default function App() {
  const [location, setLocation] = useState(null);
  const [pins, setPins] = useState([]);
  const [modalVisible, setModalVisible] = useState(false);
  const [message, setMessage] = useState('');

  useEffect(() => {
    (async () => {
      // 1. Request Permission
      let { status } = await Location.requestForegroundPermissionsAsync();
      if (status !== 'granted') return;

      // 2. Get Current Location
      let loc = await Location.getCurrentPositionAsync({});
      setLocation(loc.coords);

      // 3. Initial Pin Load
      fetchNearbyPins(loc.coords.latitude, loc.coords.longitude);
    })();
  }, []);

  const fetchNearbyPins = async (lat, lng) => {
    // Calling our custom Postgres function
    const { data, error } = await supabase.rpc('get_nearby_pins', {
      lat: lat,
      long: lng,
      radius_meters: 1000 // 1km radius
    });
    if (data) setPins(data);
  };

  const dropPin = async () => {
    const { data: { user } } = await supabase.auth.getUser();

    // Convert Lat/Lng to PostGIS Point format
    const point = `POINT(${location.longitude} ${location.latitude})`;

    const { error } = await supabase
      .from('pins')
      .insert([
        { 
          creator_id: user.id, 
          message, 
          location: point 
        }
      ]);

    if (!error) {
      setModalVisible(false);
      setMessage('');
      fetchNearbyPins(location.latitude, location.longitude);
    }
  };

  return (
    <View style={styles.container}>
      {location && (
        <MapView
          style={styles.map}
          initialRegion={{
            latitude: location.latitude,
            longitude: location.longitude,
            latitudeDelta: 0.01,
            longitudeDelta: 0.01,
          }}
          showsUserLocation={true}
        >
          {pins.map((pin) => (
            <Marker
              key={pin.id}
              coordinate={{
                // Supabase returns Point as "POINT(long lat)"
                latitude: extractCoord(pin.location, 1),
                longitude: extractCoord(pin.location, 0),
              }}
              title={pin.message}
            >
