  iconAnchor: [12, 41],
});

export default function GeoMap() {
  const [position, setPosition] = useState<[number, number] | null>(null);
  const [pins, setPins] = useState<any[]>([]);
  const [isNearPin, setIsNearPin] = useState(false);

  useEffect(() => {
    // 1. Get User Location
    if ("geolocation" in navigator) {
      navigator.geolocation.watchPosition((pos) => {
        const { latitude, longitude } = pos.coords;
        setPosition([latitude, longitude]);
        fetchNearbyPins(latitude, longitude);
      });
    }
  }, []);

  async function fetchNearbyPins(lat: number, lng: number) {
    const { data, error } = await supabase.rpc('get_nearby_pins', {
      lat,
      lng,
      radius_meters: 100 // Only show pins within 100m
    });
    if (data) setPins(data);
  }

  const handleDropPin = async () => {
    if (!position) return;

    const message = prompt("Leave a message at this spot?");
    if (!message) return;

    const { error } = await supabase.from('pins').insert({
      message,
      location: `POINT(${position[1]} ${position[0]})`, // Longitude first for PostGIS
      creator_id: (await supabase.auth.getUser()).data.user?.id
    });

    if (!error) fetchNearbyPins(position[0], position[1]);
  };

  if (!position) return <div className="h-screen flex items-center justify-center">Locating...</div>;

  return (
    <div className="relative h-screen w-full">
      <MapContainer center={position} zoom={18} className="h-full w-full">
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

        {/* User Current Location Indicator */}
        <Circle center={position} radius={10} pathOptions={{ color: 'blue' }} />

        {/* Nearby Pins */}
        {pins.map((pin) => (
          <Marker 
            key={pin.id} 
            position={[pin.location.coordinates[1], pin.location.coordinates[0]]}
            icon={markerIcon}
          >
            <Popup>
              <div className="p-2">
                <p className="font-bold">{pin.message}</p>
                <div className="mt-2 flex gap-2">
                  <button className="text-xs bg-gray-100 p-1 rounded">👍 Like</button>
                  <button className="text-xs bg-gray-100 p-1 rounded">💬 Comment</button>
                </div>
              </div>
            </Popup>
          </Marker>
        ))}
      </MapContainer>

      {/* UI Overlay */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-[1000]">
        <button 
          onClick={handleDropPin}
          className="bg-blue-600 text-white px-6 py-3 rounded-full shadow-lg font-bold active:scale-95 transition-transform"
        >
