### 1. The Database Schema (`prisma/schema.prisma`)
This schema handles the relationship between users, their registries, and the gift items.

```prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model User {
  id         String     @id @default(cuid())
  email      String     @unique
  name       String?
  registries Registry[]
}

model Registry {
  id           String     @id @default(cuid())
  title        String
  description  String?
  personalNote String?    // Owner's message to guests
  eventDate    DateTime?
  slug         String     @unique // For public URLs
  userId       String
  user         User       @relation(fields: [userId], references: [id])
  items        GiftItem[]
  createdAt    DateTime   @default(now())
}

model GiftItem {
  id                String  @id @default(cuid())
  registryId        String
  registry          Registry @relation(fields: [registryId], references: [id], onDelete: Cascade)
  title             String
  description       String?
  url               String?
  price             Float?
  quantityRequested Int     @default(1)
  quantityClaimed   Int     @default(0)
  isFullyClaimed    Boolean @default(false)
}
```

