### 2. Registry Management Actions (`lib/actions.ts`)
Server actions for creating registries and claiming items.

```typescript
"use server"

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";

export async function createRegistry(formData: FormData, userId: string) {
  const title = formData.get("title") as string;
  const note = formData.get("personalNote") as string;
  const slug = title.toLowerCase().replace(/ /g, "-") + "-" + Math.random().toString(36).substring(2, 7);

  await prisma.registry.create({
    data: {
      title,
      personalNote: note,
      slug,
      userId,
    },
  });

  revalidatePath("/dashboard");
}

export async function claimGiftItem(itemId: string, quantityToClaim: number) {
  const item = await prisma.giftItem.findUnique({ where: { id: itemId } });

  if (!item) throw new Error("Item not found");

  const newClaimedCount = item.quantityClaimed + quantityToClaim;

  if (newClaimedCount > item.quantityRequested) {
    throw new Error("Cannot claim more than requested");
  }

  await prisma.giftItem.update({
    where: { id: itemId },
    data: {
      quantityClaimed: newClaimedCount,
      isFullyClaimed: newClaimedCount === item.quantityRequested,
    },
  });

  revalidatePath(`/registry/${item.registryId}`);
}
```

