### 4. Partial Claim Component (`components/ClaimDialog.tsx`)
A client-side component to handle how many items a guest wants to claim.

```tsx
"use client"

import { useState } from "react";
import { claimGiftItem } from "@/lib/actions";
import { Button } from "@/components/ui/button";
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogTrigger 
} from "@/components/ui/dialog";

export default function ClaimDialog({ item }: { item: any }) {
  const [quantity, setQuantity] = useState(1);
  const remaining = item.quantityRequested - item.quantityClaimed;

  return (
    <Dialog>
      <DialogTrigger asChild>
        <Button variant="default">Claim this gift</Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Claim {item.title}</DialogTitle>
        </DialogHeader>
        <div className="py-4 space-y-4">
          <p>How many would you like to contribute?</p>
          <div className="flex items-center gap-4">
            <input 
              type="number" 
              min="1" 
              max={remaining}
              value={quantity}
              onChange={(e) => setQuantity(parseInt(e.target.value))}
              className="border p-2 rounded w-20"
            />
            <span className="text-muted-foreground">out of {remaining} available</span>
          </div>
          <Button 
            className="w-full" 
            onClick={async () => {
              await claimGiftItem(item.id, quantity);
              alert("Thank you for your gift!");
            }}
          >
            Confirm Contribution
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}
```

