### 1. Database Schema (`prisma/schema.prisma`)
We need a relational structure to handle Users, Registries, Items, and Claims.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model User {
  id            String     @id @default(cuid())
  email         String     @unique
  name          String?
  registries    Registry[]
}

model Registry {
  id          String   @id @default(cuid())
  title       String
  description String?
  ownerNote   String?  @db.Text
  eventDate   DateTime?
  userId      String
  user        User     @relation(fields: [userId], references: [id], onDelete: Cascade)
  items       Item[]
  createdAt   DateTime @default(now())
}

model Item {
  id           String   @id @default(cuid())
  name         String
  description  String?
  url          String?
  price        Float?
  requestedQty Int      @default(1)
  claimedQty   Int      @default(0)
  registryId   String
  registry     Registry @relation(fields: [registryId], references: [id], onDelete: Cascade)
  claims       Claim[]
}

model Claim {
  id             String   @id @default(cuid())
  itemId         String
  item           Item     @relation(fields: [itemId], references: [id], onDelete: Cascade)
  claimerName    String
  quantityTaken  Int
  message        String?
  createdAt      DateTime @default(now())
}
```

