### 2. Server Actions (`lib/actions.ts`)
Handling the business logic for creating registries and claiming items.

```typescript
"use server";

import { prisma } from "@/lib/db";
import { revalidatePath } from "next/cache";

export async function createRegistry(formData: FormData, userId: string) {
  const title = formData.get("title") as string;
  const description = formData.get("description") as string;
  const ownerNote = formData.get("ownerNote") as string;

  const registry = await prisma.registry.create({
    data: { title, description, ownerNote, userId },
  });

  revalidatePath("/dashboard");
  return registry;
}

export async function addItem(registryId: string, formData: FormData) {
  const name = formData.get("name") as string;
  const requestedQty = parseInt(formData.get("qty") as string);
  const url = formData.get("url") as string;

  await prisma.item.create({
    data: { name, requestedQty, url, registryId },
  });

  revalidatePath(`/registry/${registryId}`);
}

export async function claimItem(itemId: string, quantity: number, claimerName: string) {
  const item = await prisma.item.findUnique({ where: { id: itemId } });
  if (!item) throw new Error("Item not found");

  const remaining = item.requestedQty - item.claimedQty;
  if (quantity > remaining) throw new Error("Not enough items left to claim");

  await prisma.$transaction([
    prisma.claim.create({
      data: { itemId, quantityTaken: quantity, claimerName },
    }),
    prisma.item.update({
      where: { id: itemId },
      data: { claimedQty: { increment: quantity } },
    }),
  ]);

  revalidatePath(`/registry/${item.registryId}`);
}
```

