### 4. Claim Item Dialog (`components/ClaimDialog.tsx`)
A client-side component to handle the partial claim logic.

```tsx
"use client";

import { useState } from "react";
import { claimItem } from "@/lib/actions";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";

export default function ClaimDialog({ item }: { item: any }) {
  const [open, setOpen] = useState(false);
  const remaining = item.requestedQty - item.claimedQty;

  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const qty = parseInt(formData.get("quantity") as string);
    const name = formData.get("name") as string;

    await claimItem(item.id, qty, name);
    setOpen(false);
  }

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="default">Claim Item</Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Claim {item.name}</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="text-sm">Your Name</label>
            <Input name="name" required placeholder="John Doe" />
          </div>
          <div>
            <label className="text-sm">Quantity (Max {remaining})</label>
            <Input 
              name="quantity" 
              type="number" 
              min="1" 
              max={remaining} 
              defaultValue="1" 
              required 
            />
          </div>
          <Button type="submit" className="w-full">Confirm Claim</Button>
        </form>
      </DialogContent>
    </Dialog>
  );
}
