### 2. Core Server Action: Claiming Items

This logic handles the "partial claim" requirement.

```typescript
// app/actions/registry-actions.ts
"use server"

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";

export async function claimItem(itemId: string, quantityToClaim: number) {
  const item = await prisma.item.findUnique({
    where: { id: itemId }
  });

  if (!item) throw new Error("Item not found");

  const remaining = item.quantityRequested - item.quantityClaimed;

  if (quantityToClaim > remaining) {
    throw new Error(`Only ${remaining} items left to claim.`);
  }

  await prisma.item.update({
    where: { id: itemId },
    data: {
      quantityClaimed: {
        increment: quantityToClaim
      }
    }
  });

  revalidatePath(`/registry/[slug]`, 'page');
}
```

