#### `src/store/useCartStore.ts`
The heart of the application. It handles the business logic and session persistence.

```typescript
import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { CartItem, Product, PromoCode } from '../types';

interface CartState {
  items: CartItem[];
  appliedPromo: PromoCode | null;

  // Actions
  addItem: (product: Product) => void;
  removeItem: (id: number) => void;
  updateQuantity: (id: number, delta: number) => void;
  applyPromo: (promo: PromoCode | null) => void;
  clearCart: () => void;

  // Computed
  getTotals: () => { subtotal: number; discount: number; total: number };
}

export const useCartStore = create<CartState>()(
  persist(
    (set, get) => ({
      items: [],
      appliedPromo: null,

      addItem: (product) => set((state) => {
        const existing = state.items.find(i => i.id === product.id);
        if (existing) {
          return {
            items: state.items.map(i => i.id === product.id 
              ? { ...i, quantity: i.quantity + 1 } 
              : i)
          };
        }
        return { items: [...state.items, { ...product, quantity: 1 }] };
      }),

      removeItem: (id) => set((state) => ({
        items: state.items.filter(i => i.id !== id)
      })),

      updateQuantity: (id, delta) => set((state) => ({
        items: state.items.map(i => {
          if (i.id === id) {
            const newQty = Math.max(1, i.quantity + delta);
            return { ...i, quantity: newQty };
          }
          return i;
        })
      })),

      applyPromo: (promo) => set({ appliedPromo: promo }),

      clearCart: () => set({ items: [], appliedPromo: null }),

      getTotals: () => {
        const { items, appliedPromo } = get();
        let subtotal = 0;
        let discount = 0;

        items.forEach(item => {
          const itemTotal = item.price * item.quantity;
          subtotal += itemTotal;

          // Promo Logic: Specific Category or Global
          if (appliedPromo) {
            if (!appliedPromo.targetCategory || appliedPromo.targetCategory === item.category) {
              discount += itemTotal * appliedPromo.discount;
            }
          }
        });

        return { subtotal, discount, total: subtotal - discount };
      }
    }),
    { name: 'shopping-cart-storage' } // This key persists to localStorage
  )
);
```

