### 3. The State Manager (Zustand + Persistence)
Zustand is chosen for its simplicity and built-in support for persistence.

```typescript
// store/useCartStore.ts
import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { CartItem, Product, PromoCode } from '@/types';

interface CartState {
  items: CartItem[];
  appliedPromo: PromoCode | null;
  addItem: (product: Product) => void;
  removeItem: (productId: string) => void;
  updateQuantity: (productId: string, delta: number) => void;
  applyPromo: (promo: PromoCode | null) => void;
  clearCart: () => void;
}

export const useCartStore = create<CartState>()(
  persist(
    (set) => ({
      items: [],
      appliedPromo: null,

      addItem: (product) => set((state) => {
        const existing = state.items.find((i) => i.id === product.id);
        if (existing) {
          return {
            items: state.items.map((i) =>
              i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i
            ),
          };
        }
        return { items: [...state.items, { ...product, quantity: 1 }] };
      }),

      removeItem: (productId) => set((state) => ({
        items: state.items.filter((i) => i.id !== productId),
      })),

      updateQuantity: (productId, delta) => set((state) => ({
        items: state.items
          .map((i) => (i.id === productId ? { ...i, quantity: i.quantity + delta } : i))
          .filter((i) => i.quantity > 0),
      })),

      applyPromo: (promo) => set({ appliedPromo: promo }),

      clearCart: () => set({ items: [], appliedPromo: null }),
    }),
    { name: 'shopping-cart-storage' } // LocalStorage key
  )
);
```

