### 5. Cart Logic & Calculations
This hook calculates the total, applying promo codes only to specific items if a `targetCategory` is defined.

```typescript
// hooks/useCartTotals.ts
import { useCartStore } from '@/store/useCartStore';

export const useCartTotals = () => {
  const { items, appliedPromo } = useCartStore();

  const subtotal = items.reduce((acc, item) => acc + item.price * item.quantity, 0);

  let discount = 0;

  if (appliedPromo) {
    if (appliedPromo.targetCategory) {
      // Apply discount only to specific category
      const eligibleItems = items.filter(i => i.category === appliedPromo.targetCategory);
      const eligibleTotal = eligibleItems.reduce((acc, item) => acc + item.price * item.quantity, 0);

      discount = appliedPromo.discountType === 'percent' 
        ? eligibleTotal * (appliedPromo.value / 100)
        : Math.min(appliedPromo.value, eligibleTotal);
    } else {
      // Apply global discount
      discount = appliedPromo.discountType === 'percent'
        ? subtotal * (appliedPromo.value / 100)
        : appliedPromo.value;
    }
  }

  return {
    subtotal,
    discount,
    total: Math.max(0, subtotal - discount),
    itemCount: items.reduce((acc, item) => acc + item.quantity, 0)
  };
};
```

