#### The Engine (`src/context/CartContext.tsx`)
This handles the logic for adding items and calculating discounts.

```tsx
import React, { createContext, useContext, useReducer, useEffect } from 'react';
import { Product, PromoCode, PROMO_CODES } from '../data/products';

interface CartItem extends Product {
  quantity: number;
}

interface CartState {
  items: CartItem[];
  appliedPromo: PromoCode | null;
}

type CartAction =
  | { type: 'ADD_TO_CART'; payload: Product }
  | { type: 'REMOVE_FROM_CART'; payload: number }
  | { type: 'UPDATE_QUANTITY'; payload: { id: number; qty: number } }
  | { type: 'APPLY_PROMO'; payload: string }
  | { type: 'REMOVE_PROMO' };

const CartContext = createContext<{
  state: CartState;
  dispatch: React.Dispatch<CartAction>;
  totals: { subtotal: number; discount: number; total: number };
} | undefined>(undefined);

const cartReducer = (state: CartState, action: CartAction): CartState => {
  switch (action.type) {
    case 'ADD_TO_CART':
      const existing = state.items.find(i => i.id === action.payload.id);
      if (existing) {
        return {
          ...state,
          items: state.items.map(i => i.id === action.payload.id ? { ...i, quantity: i.quantity + 1 } : i)
        };
      }
      return { ...state, items: [...state.items, { ...action.payload, quantity: 1 }] };

    case 'REMOVE_FROM_CART':
      return { ...state, items: state.items.filter(i => i.id !== action.payload) };

    case 'UPDATE_QUANTITY':
      return {
        ...state,
        items: state.items.map(i => i.id === action.payload.id ? { ...i, quantity: Math.max(1, action.payload.qty) } : i)
      };

    case 'APPLY_PROMO':
      const promo = PROMO_CODES.find(p => p.code === action.payload.toUpperCase());
      return { ...state, appliedPromo: promo || null };

    case 'REMOVE_PROMO':
      return { ...state, appliedPromo: null };

    default:
      return state;
  }
};

export const CartProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, dispatch] = useReducer(cartReducer, { items: [], appliedPromo: null }, (initial) => {
    const saved = localStorage.getItem('cart_session');
    return saved ? JSON.parse(saved) : initial;
  });

  useEffect(() => {
    localStorage.setItem('cart_session', JSON.stringify(state));
  }, [state]);

  const totals = React.useMemo(() => {
    const subtotal = state.items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    let discount = 0;

    if (state.appliedPromo) {
      const p = state.appliedPromo;
      // Filter items the promo applies to
      const targetItems = p.applicableCategory 
        ? state.items.filter(i => i.category === p.applicableCategory)
        : state.items;

      const targetSum = targetItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);

      if (p.discountType === 'percentage') {
        discount = targetSum * (p.value / 100);
      } else {
        discount = Math.min(targetSum, p.value);
      }
    }

    return { subtotal, discount, total: subtotal - discount };
  }, [state]);

  return (
    <CartContext.Provider value={{ state, dispatch, totals }}>
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => {
  const context = useContext(CartContext);
  if (!context) throw new Error('useCart must be used within CartProvider');
  return context;
};
```

