                        onClick={() => dispatch({ type: 'UPDATE_QUANTITY', payload: { id: item.id, qty: item.quantity - 1 }})}
                        className="p-1 hover:bg-gray-100 rounded"><Minus size={14} /></button>
                      <span className="text-sm w-4 text-center">{item.quantity}</span>
                      <button 
                        onClick={() => dispatch({ type: 'UPDATE_QUANTITY', payload: { id: item.id, qty: item.quantity + 1 }})}
                        className="p-1 hover:bg-gray-100 rounded"><Plus size={14} /></button>
                    </div>
                    <button 
                      onClick={() => dispatch({ type: 'REMOVE_FROM_CART', payload: item.id })}
                      className="text-red-500 hover:text-red-700"><Trash2 size={18} /></button>
                  </div>
                ))}
              </div>
            )}

            <div className="border-t pt-4">
              <form onSubmit={handleApplyPromo} className="mb-4">
                <label className="text-xs font-bold text-gray-500 uppercase block mb-2">Promo Code</label>
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={promoInput}
                    onChange={(e) => setPromoInput(e.target.value)}
                    placeholder="e.g. TECH20"
                    className="flex-1 border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                  <button className="bg-gray-800 text-white px-4 py-2 rounded-lg text-sm font-medium">Apply</button>
                </div>
                {state.appliedPromo && (
                  <div className="mt-2 flex items-center justify-between bg-green-50 px-3 py-2 rounded-lg border border-green-100">
                    <div className="flex items-center gap-2 text-green-700 text-xs font-bold">
                      <CheckCircle2 size={14} />
                      {state.appliedPromo.code} APPLIED
                    </div>
                    <button 
                      type="button"
                      onClick={() => dispatch({ type: 'REMOVE_PROMO' })}
                      className="text-green-800 text-xs underline">Remove</button>
                  </div>
                )}
              </form>

              <div className="space-y-2 text-sm">
                <div className="flex justify-between text-gray-600">
                  <span>Subtotal</span>
                  <span>${totals.subtotal.toFixed(2)}</span>
                </div>
                {totals.discount > 0 && (
                  <div className="flex justify-between text-green-600 font-medium">
                    <span>Discount</span>
                    <span>-${totals.discount.toFixed(2)}</span>
                  </div>
                )}
                <div className="flex justify-between text-xl font-bold border-t pt-2 mt-2">
                  <span>Total</span>
                  <span>${totals.total.toFixed(2)}</span>
                </div>
              </div>

              <button className="w-full bg-black text-white py-3 rounded-xl mt-6 font-bold hover:bg-gray-900 transition-transform active:scale-95">
                Checkout
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
```

