```tsx
'use client';

import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';
import { Order } from '@/types/order';
import OrderStatusBadge from '@/components/OrderStatusBadge';
import { Package, Clock, ChevronRight } from 'lucide-react';

export default function OrderHistory() {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchOrders();

    // REAL-TIME SUBSCRIPTION
    const channel = supabase
      .channel('order-status-updates')
      .on(
        'postgres_changes',
        { event: 'UPDATE', schema: 'public', table: 'orders' },
        (payload) => {
          setOrders((currentOrders) =>
            currentOrders.map((order) =>
              order.id === payload.new.id 
                ? { ...order, status: payload.new.status } 
                : order
            )
          );
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  async function fetchOrders() {
    const { data, error } = await supabase
      .from('orders')
      .select(`
        *,
        order_items (*)
      `)
      .order('created_at', { ascending: false });

    if (!error) setOrders(data);
    setLoading(false);
  }

  if (loading) return <div className="p-8 text-center">Loading your orders...</div>;

  return (
    <div className="max-w-4xl mx-auto p-6">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 text-left">Your Order History</h1>
        <p className="text-gray-500">View and track your purchases in real-time.</p>
      </header>

      <div className="space-y-4">
        {orders.map((order) => (
          <div key={order.id} className="bg-white border rounded-xl shadow-sm overflow-hidden transition-all hover:shadow-md">
            <div className="p-6">
              <div className="flex flex-wrap justify-between items-start gap-4 mb-4">
                <div>
                  <div className="flex items-center gap-2 mb-1">
                    <Package className="w-5 h-5 text-blue-600" />
                    <span className="font-semibold text-lg">Order #{order.id.slice(0, 8)}</span>
                  </div>
                  <div className="flex items-center gap-4 text-sm text-gray-500">
                    <span className="flex items-center gap-1">
                      <Clock className="w-4 h-4" />
                      {new Date(order.created_at).toLocaleDateString()}
                    </span>
                    <span>{order.order_items.length} items</span>
                  </div>
                </div>
                <div className="flex flex-col items-end">
                  <OrderStatusBadge status={order.status} />
                  <span className="mt-2 font-bold text-xl">${order.total_amount}</span>
                </div>
              </div>

              {/* Item Details Log */}
              <div className="border-t pt-4">
                <h3 className="text-sm font-semibold text-gray-700 mb-3">Items Purchased</h3>
                <ul className="space-y-2">
                  {order.order_items.map((item) => (
                    <li key={item.id} className="flex justify-between text-sm py-1 border-b border-gray-50 last:border-0">
                      <span className="text-gray-600">
                        <span className="font-medium text-gray-900">{item.quantity}x</span> {item.product_name}
                      </span>
