```tsx
// app/orders/[id]/page.tsx
'use client';

import { useEffect, useState } from 'react';
import { createClient } from '@/utils/supabase/client';
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Package, Truck, CheckCircle, Clock } from "lucide-react";

export default function OrderDetails({ params }: { params: { id: string } }) {
  const [order, setOrder] = useState<any>(null);
  const [items, setItems] = useState<any[]>([]);
  const supabase = createClient();

  useEffect(() => {
    // 1. Initial Fetch
    const fetchOrderData = async () => {
      const { data: orderData } = await supabase
        .from('orders')
        .select('*')
        .eq('id', params.id)
        .single();

      const { data: itemData } = await supabase
        .from('order_items')
        .select('*')
        .eq('order_id', params.id);

      setOrder(orderData);
      setItems(itemData || []);
    };

    fetchOrderData();

    // 2. Subscribe to Real-time updates
    const channel = supabase
      .channel('order-status-updates')
      .on(
        'postgres_changes',
        { event: 'UPDATE', schema: 'public', table: 'orders', filter: `id=eq.${params.id}` },
        (payload) => {
          setOrder(payload.new);
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [params.id]);

  if (!order) return <div className="p-8 text-center">Loading order...</div>;

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'Processing': return <Clock className="text-blue-500" />;
      case 'Shipped': return <Truck className="text-orange-500" />;
      case 'Delivered': return <CheckCircle className="text-green-500" />;
      default: return <Package className="text-gray-500" />;
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-6">
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-3xl font-bold">Order #{order.id.slice(0, 8)}</h1>
        <Badge className="text-lg px-4 py-1" variant="outline">
          {getStatusIcon(order.status)}
          <span className="ml-2">{order.status}</span>
        </Badge>
      </div>

      <Card className="mb-6">
        <CardHeader><CardTitle>Order Items</CardTitle></CardHeader>
        <CardContent>
          <div className="space-y-4">
            {items.map((item) => (
              <div key={item.id} className="flex justify-between border-b pb-2">
                <div>
                  <p className="font-medium">{item.product_name}</p>
                  <p className="text-sm text-muted-foreground">Qty: {item.quantity}</p>
                </div>
                <p className="font-semibold">${(item.unit_price * item.quantity).toFixed(2)}</p>
              </div>
            ))}
            <div className="flex justify-between pt-4 text-xl font-bold">
              <span>Total</span>
              <span>${order.total_amount}</span>
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="bg-blue-50 p-4 rounded-lg border border-blue-200">
        <p className="text-blue-800 text-sm">
          💡 <strong>Real-time Update:</strong> This page will update automatically when your order moves to the next stage.
        </p>
      </div>
    </div>
  );
}
