```jsx
import React, { useEffect, useState } from 'react';
import { supabase } from '../lib/supabase';
import { Package, Clock, CheckCircle, Truck, ChevronRight } from 'lucide-react';

export default function OrderHistory({ userId }) {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchOrders();

    // REAL-TIME SUBSCRIPTION: Listen for status changes
    const subscription = supabase
      .channel('order-updates')
      .on('postgres_changes', { 
          event: 'UPDATE', 
          schema: 'public', 
          table: 'orders',
          filter: `customer_id=eq.${userId}` 
        }, 
        (payload) => {
          setOrders(current => 
            current.map(order => order.id === payload.new.id ? { ...order, ...payload.new } : order)
          );
        }
      )
      .subscribe();

    return () => supabase.removeChannel(subscription);
  }, [userId]);

  const fetchOrders = async () => {
    const { data, error } = await supabase
      .from('orders')
      .select(`
