### 1. Database Schema (Supabase SQL)
Run this in your Supabase SQL Editor. It enables the vector extension and sets up the table and a similarity search function.

```sql
-- Enable the pgvector extension
create extension if not exists vector;

-- Create the memories table
create table memories (
  id uuid primary key default gen_random_uuid(),
  user_id uuid references auth.users not null,
  content text not null,
  title text,
  url text,
  type text check (type in ('text', 'link', 'video')),
  embedding vector(1536), -- 1536 is the dimension for OpenAI embeddings
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- Enable Row Level Security
alter table memories enable row level security;

-- Search function for similarity
create or replace function match_memories (
  query_embedding vector(1536),
  match_threshold float,
  match_count int
)
returns table (
  id uuid,
  content text,
  title text,
  url text,
  type text,
  similarity float
)
language plpgsql
as $$
begin
  return query
  select
    memories.id,
    memories.content,
    memories.title,
    memories.url,
    memories.type,
    1 - (memories.embedding <=> query_embedding) as similarity
  from memories
  where 1 - (memories.embedding <=> query_embedding) > match_threshold
  order by memories.embedding <=> query_embedding
  limit match_count;
end;
$$;
```

