### 2. The Logic Layer (API Route)
Create an API route `app/api/memories/route.ts` to handle saving and finding related content.

```typescript
import { createClient } from '@supabase/supabase-js';
import { OpenAI } from 'openai';
import { NextResponse } from 'next/server';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

export async function POST(req: Request) {
  const { content, title, url, type, userId } = await req.json();

  // 1. Generate Embedding for the new content
  const embeddingResponse = await openai.embeddings.create({
    model: "text-embedding-3-small",
    input: `${title}: ${content}`,
  });
  const [{ embedding }] = embeddingResponse.data;

  // 2. Save the memory to Supabase
  const { data: memory, error: saveError } = await supabase
    .from('memories')
    .insert({
      content,
      title,
      url,
      type,
      user_id: userId,
      embedding
    })
    .select()
    .single();

  if (saveError) return NextResponse.json({ error: saveError.message }, { status: 500 });

  // 3. Find related memories (semantic search)
  const { data: related, error: searchError } = await supabase.rpc('match_memories', {
    query_embedding: embedding,
    match_threshold: 0.5, // Adjust for strictness (0 to 1)
    match_count: 5,
  });

  // Filter out the one we just saved
  const filteredRelated = related?.filter((item: any) => item.id !== memory.id);

  return NextResponse.json({ memory, related: filteredRelated });
}
```

