#### B. The Core Action (`app/actions.ts`)
This is where the magic happens: saving the item and finding relatives.

```typescript
import { generateEmbedding } from "@/lib/ai";
import { supabase } from "@/lib/supabase"; // Using Supabase for pgvector access

export async function saveAndRelate(content: string, type: 'text' | 'link') {
  const embedding = await generateEmbedding(content);

  // 1. Save the new item
  const { data: newItem, error: saveError } = await supabase
    .from('BrainItem')
    .insert({
      content,
      type,
      embedding,
      user_id: 'current-user-id' // Replace with Auth
    })
    .select()
    .single();

  // 2. Find related items using Cosine Similarity
  // We look for items where the distance is small (close to 1)
  const { data: relatedItems } = await supabase.rpc('match_brain_items', {
    query_embedding: embedding,
    match_threshold: 0.5, // Adjust for strictness
    match_count: 5,
    exclude_id: newItem.id
  });

  return { newItem, relatedItems };
}
```

#### C. SQL Function for Similarity Search
You need to run this in your database to allow the `rpc` call above to work.

```sql
create or replace function match_brain_items (
  query_embedding vector(1536),
  match_threshold float,
  match_count int,
  exclude_id uuid
) returns setof "BrainItem"
language plpgsql
as $$
begin
  return query
  select *
  from "BrainItem"
  where "BrainItem".id != exclude_id
  and 1 - ("BrainItem".embedding <=> query_embedding) > match_threshold
  order by "BrainItem".embedding <=> query_embedding
  limit match_count;
end;
$$;
```

