### 3. The Core Logic (Server Action)
Create a file `app/actions.ts`. This handles the AI logic and database interaction.

```typescript
"use server"

import { createClient } from '@supabase/supabase-js'
import OpenAI from 'openai'

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY })
const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY! // Use service role for backend
)

export async function saveMemory(content: string, metadata: any) {
  // 1. Generate Embedding from OpenAI
  const embeddingResponse = await openai.embeddings.create({
    model: "text-embedding-3-small",
    input: content,
  });
  const embedding = embeddingResponse.data[0].embedding;

  // 2. Save to Supabase
  const { data, error } = await supabase
    .from('memories')
    .insert({
      content,
      metadata,
      embedding
    })
    .select()

  if (error) throw error;

  // 3. Find related items immediately
  const related = await findRelated(embedding, data[0].id);

  return { saved: data[0], related };
}

export async function findRelated(embedding: number[], excludeId?: string) {
  const { data, error } = await supabase.rpc('match_memories', {
    query_embedding: embedding,
    match_threshold: 0.3, // Adjust for strictness
    match_count: 5,
  });

  if (error) throw error;
  return data.filter(item => item.id !== excludeId);
}
```

