### 3. Server Actions (`app/actions.ts`)

These handle the backend logic for creating sessions and fetching history.

```typescript
"use server"

import { prisma } from "@/lib/prisma"
import { OpenAI } from "openai"

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY })

export async function createSession() {
  const session = await prisma.chatSession.create({
    data: { title: "New Chat" }
  })
  return session.id
}

export async function getSessions(search?: string) {
  return await prisma.chatSession.findMany({
    where: search ? { title: { contains: search } } : {},
    orderBy: { updatedAt: 'desc' }
  })
}

export async function getMessages(sessionId: string) {
  return await prisma.message.findMany({
    where: { sessionId },
    orderBy: { createdAt: 'asc' }
  })
}

export async function sendMessage(sessionId: string, content: string) {
  // 1. Save User Message
  await prisma.message.create({
    data: { content, role: 'user', sessionId }
  })

  // 2. Get AI Response
  const response = await openai.chat.completions.create({
    model: "gpt-3.5-turbo",
    messages: [{ role: "user", content }],
  })

  const aiContent = response.choices[0].message.content || "Error: No response"

  // 3. Save AI Message
  const aiMessage = await prisma.message.create({
    data: { content: aiContent, role: 'assistant', sessionId }
  })

  // 4. Update session title if it's the first message
  const count = await prisma.message.count({ where: { sessionId } })
  if (count <= 2) {
    const titleRes = await openai.chat.completions.create({
      model: "gpt-3.5-turbo",
      messages: [{ role: "user", content: `Summarize this chat in 3-5 words: ${content}` }],
    })
    await prisma.chatSession.update({
      where: { id: sessionId },
      data: { title: titleRes.choices[0].message.content?.replace(/"/g, '') || "New Chat" }
    })
  }

  return aiMessage
}
```

