### 6. Chat Interaction Component (`components/ChatInterface.tsx`)

```tsx
"use client"
import { useState, useRef, useEffect } from "react"
import { sendMessage } from "@/app/actions"
import { Send } from "lucide-react"

export default function ChatInterface({ sessionId, initialMessages }: any) {
  const [messages, setMessages] = useState(initialMessages)
  const [input, setInput] = useState("")
  const [loading, setLoading] = useState(false)
  const scrollRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [messages])

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!input.trim() || loading) return

    const userMsg = { role: "user", content: input }
    setMessages((prev: any) => [...prev, userMsg])
    setInput("")
    setLoading(true)

    try {
      const aiMsg = await sendMessage(sessionId, input)
      setMessages((prev: any) => [...prev, aiMsg])
    } catch (error) {
      console.error(error)
    } finally {
      setLoading(false)
    }
  }

  return (
    <>
      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {messages.map((m: any, i: number) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-4 rounded-2xl ${
              m.role === 'user' 
                ? 'bg-blue-600 text-white rounded-br-none' 
                : 'bg-slate-100 text-slate-800 rounded-bl-none'
            }`}>
              {m.content}
            </div>
          </div>
        ))}
        {loading && <div className="text-slate-400 text-sm animate-pulse">Assistant is thinking...</div>}
        <div ref={scrollRef} />
      </div>

      <form onSubmit={handleSubmit} className="p-4 border-t border-slate-200 bg-white">
        <div className="max-w-4xl mx-auto flex gap-4">
          <input
            className="flex-1 border border-slate-300 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500"
            placeholder="Type your message..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button 
            disabled={loading}
            className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 disabled:opacity-50"
          >
            <Send size={20} />
          </button>
        </div>
      </form>
    </>
  )
}
