#### Create/List Sessions
`app/api/sessions/route.ts`
```typescript
import { prisma } from "@/lib/prisma";
import { NextResponse } from "next/server";

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const query = searchParams.get("q") || "";

  const sessions = await prisma.session.findMany({
    where: {
      OR: [
        { title: { contains: query } },
        { messages: { some: { content: { contains: query } } } }
      ]
    },
    orderBy: { updatedAt: "desc" },
    include: { _count: { select: { messages: true } } }
  });
  return NextResponse.json(sessions);
}

export async function POST() {
  const session = await prisma.session.create({
    data: { title: "New Chat" }
  });
  return NextResponse.json(session);
}
```

#### Handle Messages
`app/api/sessions/[id]/messages/route.ts`
```typescript
import { prisma } from "@/lib/prisma";
import { NextResponse } from "next/server";

export async function GET(req: Request, { params }: { params: { id: string } }) {
  const messages = await prisma.message.findMany({
    where: { sessionId: params.id },
    orderBy: { createdAt: "asc" }
  });
  return NextResponse.json(messages);
}

export async function POST(req: Request, { params }: { params: { id: string } }) {
  const { content } = await req.json();

  // 1. Save User Message
  const userMessage = await prisma.message.create({
    data: { role: "user", content, sessionId: params.id }
  });

  // 2. Mock AI Logic (Replace with OpenAI API call)
  const aiContent = `I received your message: "${content}". This is a persistent session response.`;

  const assistantMessage = await prisma.message.create({
    data: { role: "assistant", content: aiContent, sessionId: params.id }
  });

  // 3. Update session title if it's the first message
  const count = await prisma.message.count({ where: { sessionId: params.id } });
  if (count <= 2) {
    await prisma.session.update({
      where: { id: params.id },
      data: { title: content.substring(0, 30) }
    });
  }

  return NextResponse.json(assistantMessage);
}
