`app/api/chat/route.ts`:

```typescript
import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function POST(req: Request) {
  const { prompt, sessionId } = await req.json();

  let session;

  if (sessionId) {
    session = await prisma.session.findUnique({ where: { id: sessionId } });
  }

  // Create new session if it doesn't exist
  if (!session) {
    session = await prisma.session.create({
      data: {
        title: prompt.substring(0, 30) + (prompt.length > 30 ? "..." : ""),
      },
    });
  }

  // Save User Message
  await prisma.message.create({
    data: {
      content: prompt,
      role: 'user',
      sessionId: session.id,
    },
  });

  // Simulate AI Response (In production, call OpenAI here)
  const aiResponse = `I received your message: "${prompt}". This is a persistent response stored in session ${session.id}.`;

  const assistantMessage = await prisma.message.create({
    data: {
      content: aiResponse,
      role: 'assistant',
      sessionId: session.id,
    },
  });

  return NextResponse.json({ 
    message: assistantMessage, 
    sessionId: session.id,
    sessionTitle: session.title 
  });
}
