### 1. Database Schema (Supabase SQL)
Run this in your Supabase SQL Editor to set up the vector extension and tables.

```sql
-- Enable the pgvector extension
create extension if not exists vector;

-- 1. Table for PDF metadata
create table documents (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  storage_path text not null,
  user_id uuid references auth.users(id) on delete cascade,
  created_at timestamp with time zone default now()
);

-- 2. Table for text chunks and their embeddings
create table document_sections (
  id uuid primary key default gen_random_uuid(),
  document_id uuid references documents(id) on delete cascade,
  content text not null,
  embedding vector(1536) -- For OpenAI text-embedding-3-small
);

-- 3. Table for Chat Sessions
create table chats (
  id uuid primary key default gen_random_uuid(),
  user_id uuid references auth.users(id) on delete cascade,
  title text default 'New Research Chat',
  created_at timestamp with time zone default now()
);

-- 4. Table for Messages (History)
create table messages (
  id uuid primary key default gen_random_uuid(),
  chat_id uuid references chats(id) on delete cascade,
  role text check (role in ('user', 'assistant')),
  content text not null,
  created_at timestamp with time zone default now()
);

-- Vector Search Function
create or replace function match_document_sections (
  query_embedding vector(1536),
  match_threshold float,
  match_count int,
  p_document_id uuid
) returns table (
  id uuid,
  content text,
  similarity float
) language plpgsql as $$
begin
  return query
  select
    document_sections.id,
    document_sections.content,
    1 - (document_sections.embedding <=> query_embedding) as similarity
  from document_sections
  where document_sections.document_id = p_document_id
    and 1 - (document_sections.embedding <=> query_embedding) > match_threshold
  order by similarity desc
  limit match_count;
end;
$$;
```

