### 2. Core PDF Processing Logic
This utility handles file reading, chunking, and embedding.

`lib/process-pdf.ts`
```typescript
import { PDFLoader } from "langchain/document_loaders/fs/pdf";
import { RecursiveCharacterTextSplitter } from "langchain/text_splitter";
import { OpenAIEmbeddings } from "@langchain/openai";
import { createClient } from "@supabase/supabase-js";

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY! // Use service role for backend
);

const embeddings = new OpenAIEmbeddings({
  openAIApiKey: process.env.OPENAI_API_KEY,
  modelName: "text-embedding-3-small",
});

export async function processAndStorePDF(file: Blob, fileName: string, userId: string) {
  // 1. Load PDF
  const loader = new PDFLoader(file);
  const docs = await loader.load();

  // 2. Split into chunks
  const splitter = new RecursiveCharacterTextSplitter({
    chunkSize: 1000,
    chunkOverlap: 200,
  });
  const chunks = await splitter.splitDocuments(docs);

  // 3. Save PDF entry to DB
  const { data: docRecord, error: docError } = await supabase
    .from("documents")
    .insert({ name: fileName, user_id: userId, storage_path: `pdfs/${userId}/${Date.now()}.pdf` })
    .select()
    .single();

  if (docError) throw docError;

  // 4. Generate embeddings and save chunks
  const batchSize = 100;
  for (let i = 0; i < chunks.length; i += batchSize) {
    const batch = chunks.slice(i, i + batchSize);
    const embeddingResults = await embeddings.embedDocuments(
      batch.map((c) => c.pageContent.replace(/\n/g, " "))
    );

    const rows = batch.map((chunk, idx) => ({
      document_id: docRecord.id,
      content: chunk.pageContent,
      embedding: embeddingResults[idx],
    }));

    await supabase.from("document_sections").insert(rows);
  }

  return docRecord;
}
```

