### 3. Chat API Route (RAG Implementation)
`app/api/chat/route.ts` handles the context-aware retrieval and streaming response.

```typescript
import { OpenAIStream, StreamingTextResponse } from 'ai';
import { Configuration, OpenAIApi } from 'openai-edge';
import { createClient } from '@supabase/supabase-js';
import { OpenAIEmbeddings } from "@langchain/openai";

const config = new Configuration({ apiKey: process.env.OPENAI_API_KEY });
const openai = new OpenAIApi(config);

export async function POST(req: Request) {
  const { messages, chatId, documentId } = await req.json();
  const lastMessage = messages[messages.length - 1].content;

  // 1. Embed the user's question
  const embeddings = new OpenAIEmbeddings({ modelName: "text-embedding-3-small" });
  const [queryEmbedding] = await embeddings.embedDocuments([lastMessage]);

  // 2. Query Supabase for relevant chunks
  const supabase = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!);
  const { data: contextChunks } = await supabase.rpc('match_document_sections', {
    query_embedding: queryEmbedding,
    match_threshold: 0.5,
    match_count: 5,
    p_document_id: documentId
  });

  const contextText = contextChunks?.map((c: any) => c.content).join("\n\n") || "";

  // 3. Build the prompt
  const systemPrompt = `You are a helpful Research Assistant. Use the following PDF context to answer the user's question. If the answer isn't in the context, say you don't know based on the document.

  CONTEXT:
  ${contextText}`;

  // 4. Stream response
  const response = await openai.createChatCompletion({
    model: 'gpt-4o',
    stream: true,
    messages: [
      { role: 'system', content: systemPrompt },
      ...messages
    ],
  });

  const stream = OpenAIStream(response, {
    onCompletion: async (completion) => {
      // Save full Q&A to history
      await supabase.from('messages').insert([
        { chat_id: chatId, role: 'user', content: lastMessage },
        { chat_id: chatId, role: 'assistant', content: completion }
      ]);
    }
  });

  return new StreamingTextResponse(stream);
}
```

