### 4. Implementation: The Upload & Embedding Logic
Install dependencies: `npm install @supabase/supabase-js openai pdf-parse langchain`

**`app/api/upload/route.ts`**
This handles reading the PDF, splitting it into chunks, and storing vectors.

```typescript
import { createRouteHandlerClient } from '@supabase/auth-helpers-nextjs';
import { cookies } from 'next/headers';
import { NextResponse } from 'next/server';
import OpenAI from 'openai';
import pdf from 'pdf-parse';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

export async function POST(req: Request) {
  const supabase = createRouteHandlerClient({ cookies });
  const formData = await req.formData();
  const file = formData.get('file') as File;

  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return new Response('Unauthorized', { status: 401 });

  // 1. Upload to Supabase Storage
  const { data: storageData, error: uploadError } = await supabase.storage
    .from('pdfs')
    .upload(`${user.id}/${Date.now()}-${file.name}`, file);

  if (uploadError) return NextResponse.json({ error: uploadError.message });

  // 2. Parse PDF Text
  const buffer = Buffer.from(await file.arrayBuffer());
  const pdfData = await pdf(buffer);
  const text = pdfData.text;

  // 3. Save Document Record
  const { data: doc } = await supabase.from('documents').insert({
    name: file.name,
    storage_path: storageData.path,
    user_id: user.id
  }).select().single();

  // 4. Chunk text and Generate Embeddings
  // Simple chunking (In production, use LangChain RecursiveCharacterTextSplitter)
  const chunks = text.match(/[\s\S]{1,1000}/g) || []; 

  for (const chunk of chunks) {
    const embeddingResponse = await openai.embeddings.create({
      model: "text-embedding-3-small",
      input: chunk,
    });

    const embedding = embeddingResponse.data[0].embedding;

    await supabase.from('document_sections').insert({
      document_id: doc.id,
      content: chunk,
      embedding: embedding
    });
  }

  return NextResponse.json({ success: true, documentId: doc.id });
}
```

