```typescript
import { OpenAIStream, StreamingTextResponse } from 'ai';
import OpenAI from 'openai';
import { createRouteHandlerClient } from '@supabase/auth-helpers-nextjs';
import { cookies } from 'next/headers';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

export async function POST(req: Request) {
  const { messages, chatId } = await req.json();
  const lastMessage = messages[messages.length - 1].content;
  const supabase = createRouteHandlerClient({ cookies });

  // 1. Create embedding for the user's question
  const embedRes = await openai.embeddings.create({
    model: "text-embedding-3-small",
    input: lastMessage,
  });
  const [{ embedding }] = embedRes.data;

  // 2. Vector search for context
  const { data: chunks } = await supabase.rpc('match_document_sections', {
    query_embedding: embedding,
    match_threshold: 0.5,
    match_count: 5,
  });

  const context = chunks?.map((c: any) => c.content).join("\n\n") ?? "";

  // 3. Prompt GPT with context
  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    stream: true,
    messages: [
      { role: 'system', content: `You are a research assistant. Use the following context to answer: ${context}` },
      ...messages
    ],
  });

  // 4. Stream and Save to DB (Simplified for brevity)
  const stream = OpenAIStream(response, {
    onCompletion: async (completion) => {
      // Save user message and assistant response to 'messages' table here
      await supabase.from('messages').insert([
        { chat_id: chatId, role: 'user', content: lastMessage },
        { chat_id: chatId, role: 'assistant', content: completion }
      ]);
    }
  });

  return new StreamingTextResponse(stream);
}
```

