### 2. PDF Processing & Vectorization (`lib/vector-store.ts`)
When a user uploads a PDF, we must: 
1. Extract text.
2. Split text into chunks.
3. Convert chunks into vectors (embeddings).
4. Store them in the database.

```typescript
import { OpenAIEmbeddings } from "@langchain/openai";
import { SupabaseVectorStore } from "@langchain/community/vectorstores/supabase";
import { createClient } from "@supabase/supabase-js";

const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;
const supabaseUrl = process.env.SUPABASE_URL!;

export const supabaseClient = createClient(supabaseUrl, supabaseKey);

export async function embedAndStorePDF(chunks: string[], documentId: string) {
  const embeddings = new OpenAIEmbeddings({
    openAIApiKey: process.env.OPENAI_API_KEY,
  });

  // Each chunk is stored with its associated documentId as metadata
  await SupabaseVectorStore.fromTexts(
    chunks,
    chunks.map(() => ({ documentId })),
    embeddings,
    {
      client: supabaseClient,
      tableName: "documents_embeddings",
      queryName: "match_documents",
    }
  );
}
```

