### 3. The Chat Logic (`app/api/chat/route.ts`)
This is the core "Brain". It retrieves relevant context and asks OpenAI for the answer.

```typescript
import { OpenAIEmbeddings, ChatOpenAI } from "@langchain/openai";
import { SupabaseVectorStore } from "@langchain/community/vectorstores/supabase";
import { PrismaClient } from "@prisma/client";
import { createClient } from "@supabase/supabase-js";

const prisma = new PrismaClient();

export async function POST(req: Request) {
  const { message, documentId, userId } = await req.json();

  // 1. Initialize Vector Store
  const client = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!);
  const vectorStore = new SupabaseVectorStore(new OpenAIEmbeddings(), {
    client,
    tableName: "documents_embeddings",
    queryName: "match_documents",
  });

  // 2. Search for relevant context in the specific document
  const results = await vectorStore.similaritySearch(message, 4, {
    documentId: documentId,
  });

  const context = results.map((r) => r.pageContent).join("\n");

  // 3. Call OpenAI with Context
  const model = new ChatOpenAI({ modelName: "gpt-4o" });
  const response = await model.invoke([
    ["system", `You are a helpful research assistant. Use the following context to answer the user: ${context}`],
    ["human", message],
  ]);

  const answer = response.content as string;

  // 4. Save to History
  await prisma.message.createMany({
    data: [
      { documentId, role: "user", content: message },
      { documentId, role: "assistant", content: answer },
    ],
  });

  return Response.json({ answer });
}
```

