### 3. The Persistence Layer (`src/persistence.ts`)

This service manages saving binary Yjs updates to the database. Instead of saving every keystroke, we batch updates to prevent DB bottlenecks.

```typescript
import * as Y from 'yjs';
import { Pool } from 'pg';

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

export const persistence = {
  // Retrieve the full document state from DB
  getYDoc: async (docName: string): Promise<Y.Doc> => {
    const ydoc = new Y.Doc();

    // 1. Get the latest snapshot
    const snapshot = await pool.query(
      'SELECT snapshot_data FROM document_snapshots WHERE doc_id = $1',
      [docName]
    );

    if (snapshot.rows.length > 0) {
      Y.applyUpdate(ydoc, snapshot.rows[0].snapshot_data);
    }

    // 2. Apply updates occurred after the snapshot
    const updates = await pool.query(
      'SELECT update_data FROM document_updates WHERE doc_id = $1 ORDER BY id ASC',
      [docName]
    );

    updates.rows.forEach(row => {
      Y.applyUpdate(ydoc, row.update_data);
    });

    return ydoc;
  },

  // Save a new update
  storeUpdate: async (docName: string, update: Uint8Array) => {
    await pool.query(
      'INSERT INTO document_updates (doc_id, update_data) VALUES ($1, $2)',
      [docName, Buffer.from(update)]
    );
  },

  // Periodically "Squash" updates into a single snapshot to keep loading fast
  flushDocument: async (docName: string, ydoc: Y.Doc) => {
    const snapshot = Y.encodeStateAsUpdate(ydoc);
    await pool.query('BEGIN');
    try {
      await pool.query(
        `INSERT INTO document_snapshots (doc_id, snapshot_data, version_count) 
         VALUES ($1, $2, 0) 
         ON CONFLICT (doc_id) DO UPDATE SET snapshot_data = $2`,
        [docName, Buffer.from(snapshot)]
      );
      await pool.query('DELETE FROM document_updates WHERE doc_id = $1', [docName]);
      await pool.query('COMMIT');
    } catch (e) {
      await pool.query('ROLLBACK');
      throw e;
    }
  }
};
```

