### 4. WebSocket & Collaboration Server (`src/server.ts`)

We extend the `y-websocket` utility to integrate our database persistence.

```typescript
import Fastify from 'fastify';
import fastifyWebsocket from '@fastify/websocket';
import { setupWSConnection, setPersistence } from 'y-websocket/bin/utils';
import * as Y from 'yjs';
import { persistence } from './persistence';

const app = Fastify();
app.register(fastifyWebsocket);

// Link Yjs to our Postgres Persistence
setPersistence({
  bindState: async (docName, ydoc) => {
    // Load existing data from DB
    const persistedDoc = await persistence.getYDoc(docName);
    const newUpdate = Y.encodeStateAsUpdate(persistedDoc);
    Y.applyUpdate(ydoc, newUpdate);

    // Watch for new changes and save them
    ydoc.on('update', async (update) => {
      await persistence.storeUpdate(docName, update);
    });
  },
  writeState: async (docName, ydoc) => {
    // Periodic full save (snapshot)
    return persistence.flushDocument(docName, ydoc);
  }
});

app.register(async (fastify) => {
  fastify.get('/collaboration/:docId', { websocket: true }, (connection, req) => {
    const docId = (req.params as any).docId;

    // y-websocket's internal handler manages the sync protocol
    setupWSConnection(connection.socket, req.raw, {
      docName: docId,
      gc: true // Garbage collection on CRDT nodes
    });
  });
});

// REST API for basic doc management
app.post('/documents', async (req, reply) => {
    // Create doc logic...
});

const start = async () => {
  try {
    await app.listen({ port: 3000, host: '0.0.0.0' });
    console.log('Server running on http://localhost:3000');
  } catch (err) {
    app.log.error(err);
    process.exit(1);
  }
};
start();
```

