### 3. The Backend Implementation

We will use **Hocuspocus**. It handles the WebSocket handshake, document awareness (presence), and CRDT syncing automatically.

```typescript
// src/server.ts
import { Hocuspocus } from "@hocuspocus/server";
import { PrismaClient } from "@prisma/client";
import * as Y from "yjs";

const prisma = new PrismaClient();

const server = new Hocuspocus({
  port: 1234,

  // 1. Authentication
  async onAuthenticate(data) {
    const { token } = data;
    // In a real app, verify a JWT here
    if (token !== "secret-token") {
      throw new Error("Not authorized");
    }
  },

  // 2. Load Document from Database
  async onLoadDocument(data) {
    const doc = await prisma.document.findUnique({
      where: { id: data.documentName },
    });

    if (doc) {
      // Apply the persisted binary update to the Yjs document
      Y.applyUpdate(data.document, doc.data);
    } else {
      // Create new document if it doesn't exist
      await prisma.document.create({
        data: {
          id: data.documentName,
          name: "Untitled Document",
          data: Buffer.from(Y.encodeStateAsUpdate(data.document)),
        },
      });
    }

    return data.document;
  },

  // 3. Persist Changes (Debounced by Hocuspocus)
  async onStoreDocument(data) {
    const state = Y.encodeStateAsUpdate(data.document);

    await prisma.document.update({
      where: { id: data.documentName },
      data: { data: Buffer.from(state) },
    });
  },

  // 4. Versioning Logic
  async onStateless({ payload, documentName }) {
    const parsed = JSON.parse(payload);

    if (parsed.type === "SAVE_VERSION") {
      const doc = await prisma.document.findUnique({ where: { id: documentName } });
      if (doc) {
        await prisma.version.create({
          data: {
            documentId: documentName,
            snapshot: doc.data,
            label: parsed.label || `Revision ${new Date().toISOString()}`,
          },
        });
      }
    }
  },
});

server.listen();
console.log("Collaborative Backend running on ws://localhost:1234");
```

