### 2. The Persistence Layer (`src/persistence.ts`)
In CRDTs, a document is a collection of "updates" (binary blobs). We store these updates in a database.

```typescript
import * as Y from 'yjs';
import { Pool } from 'pg'; // Assuming PostgreSQL

// Simulated Database Connection
const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
});

export const persistence = {
  /**
   * Loads the document from the database.
   * We fetch all binary updates and apply them to a fresh Y.Doc
   */
  bindState: async (docName: string, ydoc: Y.Doc) => {
    const result = await pool.query(
      'SELECT update_blob FROM doc_updates WHERE doc_name = $1 ORDER BY id ASC',
      [docName]
    );

    if (result.rows.length > 0) {
      Y.applyUpdate(ydoc, Y.mergeUpdates(result.rows.map(r => r.update_blob)));
    }

    // Listen for changes on the Y.Doc to save new updates to the DB
    ydoc.on('update', async (update: Uint8Array) => {
      await pool.query(
        'INSERT INTO doc_updates (doc_name, update_blob) VALUES ($1, $2)',
        [docName, Buffer.from(update)]
      );
    });
  },

  /**
   * Periodic snapshots to prevent the update list from growing infinitely
   */
  createSnapshot: async (docName: string, ydoc: Y.Doc) => {
    const state = Y.encodeStateAsUpdate(ydoc);
    await pool.query('BEGIN');
    await pool.query('DELETE FROM doc_updates WHERE doc_name = $1', [docName]);
    await pool.query(
      'INSERT INTO doc_updates (doc_name, update_blob) VALUES ($1, $2)',
      [docName, Buffer.from(state)]
    );
    await pool.query('COMMIT');
  }
};
```

### 3. The WebSocket Server (`src/server.ts`)
We use the `y-websocket` utility but customize it to integrate with our persistence layer.

```typescript
import http from 'http';
import WebSocket from 'ws';
import express from 'express';
import * as Y from 'yjs';
import { setupWSConnection, setPersistence } from 'y-websocket/bin/utils';
import { persistence } from './persistence';

const app = express();
const server = http.createServer(app);
const wss = new WebSocket.Server({ server });

const port = process.env.PORT || 1234;

// 1. Configure Yjs Persistence
setPersistence({
  bindState: async (docName, ydoc) => {
    // Load from DB when the first user connects to a document
    await persistence.bindState(docName, ydoc);
  },
  writeState: async (docName, ydoc) => {
    // This is called periodically by y-websocket or on document close
    return new Promise((resolve) => {
      persistence.createSnapshot(docName, ydoc).then(() => resolve(true));
    });
  }
});

// 2. Handle WebSocket Connections
wss.on('connection', (ws: WebSocket, req: http.IncomingMessage) => {
  // Extract document name from URL (e.g., /my-document)
  const docName = req.url?.slice(1) || 'default-doc';

  // setupWSConnection handles:
  // - Syncing state between clients
  // - Awareness (cursors, who is online)
  // - Heartbeats
  setupWSConnection(ws, req, { docName, gc: true });

  console.log(`User joined document: ${docName}`);
});

server.listen(port, () => {
  console.log(`Collaboration server running on port ${port}`);
});
```

