### 1. The Data Model (Prisma Schema)

The core of an IMS is the schema. We need to separate the **Product** (general info) from the **Variant** (specific SKU) and track **Inventory** levels per warehouse.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Warehouse {
  id        String      @id @default(cuid())
  name      String
  location  String
  inventory Inventory[]
  createdAt DateTime    @default(now())
}

model Product {
  id          String           @id @default(cuid())
  name        String
  description String?
  category    String
  variants    ProductVariant[]
  createdAt   DateTime         @default(now())
}

model ProductVariant {
  id        String      @id @default(cuid())
  sku       String      @unique
  name      String // e.g., "Blue / XL"
  price     Decimal     @db.Decimal(10, 2)
  productId String
  product   Product     @relation(fields: [productId], references: [id])
  inventory Inventory[]
  movements StockMovement[]
}

model Inventory {
  id         String         @id @default(cuid())
  variantId  String
  variant    ProductVariant @relation(fields: [variantId], references: [id])
  warehouseId String
  warehouse  Warehouse      @relation(fields: [warehouseId], references: [id])
  quantity   Int            @default(0)

  @@unique([variantId, warehouseId]) // One record per variant per warehouse
}

enum MovementType {
  INBOUND  // Receiving stock
  OUTBOUND // Sales
  TRANSFER // Between warehouses
  ADJUSTMENT // Manual correction
}

model StockMovement {
  id              String         @id @default(cuid())
  variantId       String
  variant         ProductVariant @relation(fields: [variantId], references: [id])
  type            MovementType
  quantity        Int
  fromWarehouseId String?
  toWarehouseId   String?
  reason          String?
  createdAt       DateTime       @default(now())
}
```

