### 2. The Business Logic (Inventory Service)

When moving stock, we must use **Database Transactions**. If the subtraction from Warehouse A fails, the addition to Warehouse B must not occur.

```typescript
// lib/inventory-service.ts
import { prisma } from "./prisma";

export async function transferStock(
  variantId: string,
  fromWarehouseId: string,
  toWarehouseId: string,
  quantity: number
) {
  return await prisma.$transaction(async (tx) => {
    // 1. Check and decrement source
    const sourceStock = await tx.inventory.update({
      where: {
        variantId_warehouseId: { variantId, warehouseId: fromWarehouseId },
      },
      data: {
        quantity: { decrement: quantity },
      },
    });

    if (sourceStock.quantity < 0) {
      throw new Error("Insufficient stock for transfer");
    }

    // 2. Increment destination (upsert handles first-time arrival)
    await tx.inventory.upsert({
      where: {
        variantId_warehouseId: { variantId, warehouseId: toWarehouseId },
      },
      update: {
        quantity: { increment: quantity },
      },
      create: {
        variantId,
        warehouseId: toWarehouseId,
        quantity,
      },
    });

    // 3. Log the movement for audit
    await tx.stockMovement.create({
      data: {
        variantId,
        type: "TRANSFER",
        quantity,
        fromWarehouseId,
        toWarehouseId,
        reason: "Inter-warehouse transfer",
      },
    });
  });
}
```

