### 2. Backend Logic: Stock Transfer Service

This core logic ensures that moving 50 units from Warehouse A to Warehouse B is an atomic operation.

```typescript
// src/services/inventory.service.ts
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export const transferStock = async (
  variantId: string,
  fromWarehouseId: string,
  toWarehouseId: string,
  quantity: number
) => {
  return await prisma.$transaction(async (tx) => {
    // 1. Check & Deduct from source
    const sourceStock = await tx.inventory.update({
      where: { variantId_warehouseId: { variantId, warehouseId: fromWarehouseId } },
      data: { quantity: { decrement: quantity } },
    });

    if (sourceStock.quantity < 0) {
      throw new Error("Insufficient stock in source warehouse");
    }

    // 2. Add to destination (Upsert logic)
    await tx.inventory.upsert({
      where: { variantId_warehouseId: { variantId, warehouseId: toWarehouseId } },
      update: { quantity: { increment: quantity } },
      create: { variantId, warehouseId: toWarehouseId, quantity },
    });

    // 3. Log Movement
    await tx.stockMovement.create({
      data: {
        variantId,
        fromWarehouseId,
        toWarehouseId,
        quantity,
        type: 'TRANSFER',
        reason: 'Internal replenishment',
      },
    });

    return { success: true };
  });
};
```

