### 2. Backend Logic: The Inventory Service

The most critical part is the **Transfer** logic. It must be atomic: if the deduction from Warehouse A fails, the addition to Warehouse B must not happen.

```typescript
// apps/api/src/inventory/inventory.service.ts

import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../prisma.service';

@Injectable()
export class InventoryService {
  constructor(private prisma: PrismaService) {}

  async transferStock(dto: {
    variantId: string;
    fromWarehouseId: string;
    toWarehouseId: string;
    quantity: number;
  }) {
    return this.prisma.$transaction(async (tx) => {
      // 1. Check source stock
      const sourceStock = await tx.stockLevel.findUnique({
        where: {
          variantId_warehouseId: {
            variantId: dto.variantId,
            warehouseId: dto.fromWarehouseId,
          },
        },
      });

      if (!sourceStock || sourceStock.quantity < dto.quantity) {
        throw new BadRequestException('Insufficient stock in source warehouse');
      }

      // 2. Deduct from source
      await tx.stockLevel.update({
        where: { id: sourceStock.id },
        data: { quantity: { decrement: dto.quantity } },
      });

      // 3. Add to destination (Upsert)
      await tx.stockLevel.upsert({
        where: {
          variantId_warehouseId: {
            variantId: dto.variantId,
            warehouseId: dto.toWarehouseId,
          },
        },
        update: { quantity: { increment: dto.quantity } },
        create: {
          variantId: dto.variantId,
          warehouseId: dto.toWarehouseId,
          quantity: dto.quantity,
        },
      });

      // 4. Record movement for audit trail
      return tx.stockMovement.create({
        data: {
          variantId: dto.variantId,
          type: 'TRANSFER',
          quantity: dto.quantity,
          sourceWarehouseId: dto.fromWarehouseId,
          destWarehouseId: dto.toWarehouseId,
          reason: 'Internal Transfer',
        },
      });
    });
  }
}
```

