### 3. Backend Implementation (Express + TypeScript)

We'll create a dynamic endpoint that validates incoming data against the specialty's template.

```typescript
// src/routes/records.ts
import { Router } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';

const prisma = new PrismaClient();
const router = Router();

router.post('/records', async (req, res) => {
  try {
    const { patientId, specialtyId, data, notes } = req.body;

    // 1. Fetch the specialty template
    const specialty = await prisma.specialty.findUnique({
      where: { id: specialtyId }
    });

    if (!specialty) return res.status(404).send("Specialty not found");

    // 2. Data Persistence
    // In a production app, you would add a JSON-schema validator here 
    // to ensure 'data' matches 'specialty.fieldTemplate'
    const record = await prisma.record.create({
      data: {
        patientId,
        specialtyId,
        data, // The variable fields
        notes
      }
    });

    res.json(record);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

export default router;
```

