// pages/api/records/index.ts
import { NextApiRequest, NextApiResponse } from 'next';
import { prisma } from '@/lib/prisma';

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  if (req.method === 'POST') {
    const { patientId, specialtyId, clinicalData, doctorName } = req.body;

    try {
      // 1. Fetch the specialty template to validate
      const specialty = await prisma.specialty.findUnique({
        where: { id: specialtyId }
      });

      if (!specialty) return res.status(404).json({ error: "Specialty not found" });

      // 2. Simple validation (In production, use Zod to validate clinicalData 
      // matches specialty.uiSchema)

      const record = await prisma.record.create({
        data: {
          patientId,
          specialtyId,
          doctorName,
          clinicalData, // PostgreSQL stores this as JSONB
        }
      });

      return res.status(201).json(record);
    } catch (error) {
      return res.status(500).json({ error: "Internal Server Error" });
    }
  }
}
