### 1. The Database Schema (`prisma/schema.prisma`)

We define `SpecialtyTemplate` to manage what fields each specialty requires, and `PatientRecord` to store the actual data.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Patient {
  id            String          @id @default(cuid())
  firstName     String
  lastName      String
  dateOfBirth   DateTime
  records       PatientRecord[]
  createdAt     DateTime        @default(now())
}

model Specialty {
  id        String              @id @default(cuid())
  name      String              @unique // e.g., "Cardiology"
  templates SpecialtyTemplate[]
}

model SpecialtyTemplate {
  id          String    @id @default(cuid())
  specialtyId String
  specialty   Specialty @relation(fields: [specialtyId], references: [id])

  // Defines the structure: e.g., [{ name: "bp_systolic", type: "number", label: "Systolic BP" }]
  fields      Json      
  isActive    Boolean   @default(true)
  version     Int       @default(1)
  records     PatientRecord[]
}

model PatientRecord {
  id                String            @id @default(cuid())
  patientId         String
  patient           Patient           @relation(fields: [patientId], references: [id])
  templateId        String
  template          SpecialtyTemplate @relation(fields: [templateId], references: [id])

  // The actual variable data stored as JSON
  // e.g., { "bp_systolic": 120, "heart_rate": 80 }
  data              Json              

  notes             String?           @db.Text
  createdAt         DateTime          @default(now())
  providerName      String            // The doctor who created the record
}
```

