### 4. API Route for Data Integrity

When saving a record, we must validate that the submitted JSON matches the template's requirements.

```typescript
// app/api/records/route.ts
import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { SpecialtyField } from "@/types/specialty";

export async function POST(req: Request) {
  try {
    const body = await req.json();
    const { patientId, templateId, data, providerName } = body;

    // 1. Fetch the template to validate against
    const template = await prisma.specialtyTemplate.findUnique({
      where: { id: templateId }
    });

    if (!template) return NextResponse.json({ error: "Template not found" }, { status: 404 });

    const fields = template.fields as unknown as SpecialtyField[];

    // 2. Strict Validation: Ensure all required fields in template exist in payload
    for (const field of fields) {
      if (field.required && (data[field.name] === undefined || data[field.name] === "")) {
        return NextResponse.json({ error: `Missing required field: ${field.label}` }, { status: 400 });
      }
    }

    // 3. Persist to PostgreSQL
    const record = await prisma.patientRecord.create({
      data: {
        patientId,
        templateId,
        data, // Saved as JSONB
        providerName
      }
    });

    return NextResponse.json(record);
  } catch (error) {
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}
```

