### 3. Dynamic Validation (Zod)
Since each property type has different requirements, we define specific schemas for the `attributes` field.

```typescript
// src/schemas/property.schema.ts
import { z } from 'zod';
import { PropertyType } from '@prisma/client';

// Attributes for Apartments
const ApartmentAttributes = z.object({
  rooms: z.number().int().positive(),
  floor: z.number().int(),
  hasElevator: z.boolean(),
  balconyArea: z.number().optional(),
});

// Attributes for Land
const LandAttributes = z.object({
  zoningType: z.enum(['RESIDENTIAL', 'COMMERCIAL', 'AGRICULTURAL']),
  isCleared: z.boolean(),
  lotSizeSqFt: z.number(),
});

export const CreatePropertySchema = z.object({
  body: z.object({
    title: z.string().min(5),
    type: z.nativeEnum(PropertyType),
    price: z.number().positive(),
    address: z.string(),
    city: z.string(),
    state: z.string(),
    zipCode: z.string(),
    // Validate attributes based on the type
    attributes: z.record(z.any()), 
  }).refine((data) => {
    // Custom refinement to validate specific attribute sets
    if (data.type === PropertyType.APARTMENT) {
      return ApartmentAttributes.safeParse(data.attributes).success;
    }
    if (data.type === PropertyType.LAND) {
      return LandAttributes.safeParse(data.attributes).success;
    }
    return true;
  }, {
    message: "Attributes do not match the property type requirements",
    path: ["attributes"]
  }),
});
```

