### 3. Domain Validation (Zod)
Since the `attributes` field is flexible in the database, we must enforce its structure in the application layer based on the `PropertyType`.

```typescript
// src/schemas/property.schema.ts
import { z } from 'zod';

const ApartmentAttributes = z.object({
  bedrooms: z.number().int().positive(),
  bathrooms: z.number().positive(),
  floorNumber: z.number().int(),
  hasElevator: z.boolean(),
});

const LandAttributes = z.object({
  areaSqFt: z.number().positive(),
  zoningType: z.enum(['Residential', 'Commercial', 'Industrial', 'Agricultural']),
  isLevel: z.boolean(),
});

// Discriminated Union: Validates 'attributes' based on 'type'
export const CreatePropertySchema = z.discriminatedUnion('type', [
  z.object({
    type: z.literal('APARTMENT'),
    title: z.string().min(5),
    price: z.number().positive(),
    address: z.string(),
    city: z.string(),
    state: z.string(),
    zipCode: z.string(),
    attributes: ApartmentAttributes,
  }),
  z.object({
    type: z.literal('LAND'),
    title: z.string().min(5),
    price: z.number().positive(),
    address: z.string(),
    city: z.string(),
    state: z.string(),
    zipCode: z.string(),
    attributes: LandAttributes,
  }),
  // Add HOUSE and COMMERCIAL similarly...
]);

export type CreatePropertyInput = z.infer<typeof CreatePropertySchema>;
```

