### 3. Core Service Logic (`src/services/social.service.ts`)

This is where the complex social logic lives, such as generating a feed of posts from people you follow.

```typescript
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export const SocialService = {
  // Follow a user
  async followUser(followerId: string, followingId: string) {
    if (followerId === followingId) throw new Error("Cannot follow yourself");

    return await prisma.follows.create({
      data: { followerId, followingId }
    });
  },

  // Get News Feed (Posts from users I follow)
  async getHomeFeed(userId: string, limit = 20, cursor?: string) {
    return await prisma.post.findMany({
      where: {
        author: {
          followers: {
            some: { followerId: userId }
          }
        }
      },
      take: limit,
      skip: cursor ? 1 : 0,
      cursor: cursor ? { id: cursor } : undefined,
      orderBy: { createdAt: 'desc' },
      include: {
        author: { select: { username: true } },
        _count: { select: { likes: true, comments: true } }
      }
    });
  },

  // Like a post
  async toggleLike(userId: string, postId: string) {
    const existing = await prisma.like.findUnique({
      where: { userId_postId: { userId, postId } }
    });

    if (existing) {
      return await prisma.like.delete({
        where: { userId_postId: { userId, postId } }
      });
    }

    return await prisma.like.create({
      data: { userId, postId }
    });
  }
};
