### 2. Implementation: The Engagement Service (Go)

Go is chosen for its superior concurrency model (goroutines) and low memory footprint.

#### Redis Schema Strategy:
*   `engagement:leaderboard:{hour_key}`: A Sorted Set containing `post_id` as member and `score` as value.
*   `engagement:events:stream`: A stream for the Notification and DB sync workers.

#### Core Logic: High-Velocity Ingestor

```go
package main

import (
	"context"
	"fmt"
	"github.com/go-redis/redis/v8"
	"time"
)

var ctx = context.Background()

type EngagementType string

const (
	Like    EngagementType = "LIKE"
	Share   EngagementType = "SHARE"
	Comment EngagementType = "COMMENT"
)

// Weights for trending algorithm
var weights = map[EngagementType]float64{
	Like:    1.0,
	Comment: 3.0,
	Share:   5.0,
}

type EngagementStore struct {
	rdb *redis.Client
}

func (s *EngagementStore) RecordEngagement(postID string, engType EngagementType) error {
	// 1. Calculate Score based on weight
	score := weights[engType]

	// 2. Generate a key based on the current hour to maintain the window
	hourKey := fmt.Sprintf("leaderboard:%d", time.Now().Unix()/3600)

	// 3. Atomically update the Leaderboard
	// ZINCRBY increments the score or creates it if it doesn't exist
	pipe := s.rdb.Pipeline()
	pipe.ZIncrBy(ctx, hourKey, score, postID)
	pipe.Expire(ctx, hourKey, 2*time.Hour) // Auto-cleanup old hours

	// 4. Push to Stream for Notification & DB persistence
	// This decouples the "count" from the "process"
	event := map[string]interface{}{
		"post_id": postID,
		"type":    string(engType),
		"ts":      time.Now().UnixNano(),
	}
	pipe.XAdd(ctx, &redis.XAddArgs{
		Stream: "engagement_stream",
		Values: event,
		MaxLen: 100000, // Cap stream size to prevent OOM
		Approx: true,
	})

	_, err := pipe.Exec(ctx)
	return err
}

// GetTopTrending fetches the top 100 posts
func (s *EngagementStore) GetTopTrending() ([]redis.Z, error) {
	hourKey := fmt.Sprintf("leaderboard:%d", time.Now().Unix()/3600)
	return s.rdb.ZRevRangeWithScores(ctx, hourKey, 0, 99).Result()
}
```

---

### 3. Solving Write Contention (The "Viral Post" Problem)

If 1 million people "Like" a post in 10 seconds, writing to PostgreSQL 1 million times will lock the row. 

**Solution: The Buffered Syncer.**
This background worker reads from the Redis Stream, aggregates counts in memory, and performs a single `UPSERT` every 5 seconds.

```go
func (s *EngagementStore) StartDBSyncWorker() {
	ticker := time.NewTicker(5 * time.Second)
	// Local buffer: post_id -> count
	buffer := make(map[string]int)

	for {
		select {
		case <-ticker.C:
			s.flushToDB(buffer)
			buffer = make(map[string]int) // Clear buffer
		default:
			// Read from Redis Stream (XREAD)
			messages, _ := s.rdb.XRead(ctx, &redis.XReadArgs{
				Streams: []string{"engagement_stream", "$"},
				Count:   100,
				Block:   0,
			}).Result()

			for _, msg := range messages {
				for _, m := range msg.Messages {
					pid := m.Values["post_id"].(string)
					buffer[pid]++
				}
			}
		}
	}
}

func (s *EngagementStore) flushToDB(buffer map[string]int) {
	if len(buffer) == 0 { return }
	// Perform Batch UPSERT:
	// INSERT INTO posts (id, likes) VALUES ($1, $2) 
	// ON CONFLICT (id) DO UPDATE SET likes = posts.likes + EXCLUDED.likes
	fmt.Printf("Flushing %d updates to PostgreSQL...\n", len(buffer))
}
```

