// components/SafeSettings.tsx
import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabaseClient';

export default function SafeSettings({ userId }: { userId: string }) {
  const [keyword, setKeyword] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  useEffect(() => {
    fetchKeywords();
  }, []);

  async function fetchKeywords() {
    const { data } = await supabase
      .from('blocked_keywords')
      .select('keyword')
      .eq('user_id', userId);
    if (data) setKeywords(data.map(k => k.keyword));
  }

  async function addKeyword() {
    if (!keyword) return;
    await supabase
      .from('blocked_keywords')
      .insert({ user_id: userId, keyword: keyword.toLowerCase().trim() });
    setKeyword('');
    fetchKeywords();
  }

  async function removeKeyword(word: string) {
    await supabase
      .from('blocked_keywords')
      .delete()
      .eq('user_id', userId)
      .eq('keyword', word);
    fetchKeywords();
  }

  return (
    <div className="p-6 bg-white rounded-lg shadow-md">
      <h2 className="text-xl font-bold mb-4">Content Safety Settings</h2>

      <div className="flex gap-2 mb-4">
        <input 
          className="border p-2 flex-grow rounded"
          placeholder="Enter blocked keyword..."
          value={keyword}
          onChange={(e) => setKeyword(e.target.value)}
        />
        <button onClick={addKeyword} className="bg-red-500 text-white px-4 py-2 rounded">
          Block
        </button>
      </div>

      <div className="flex flex-wrap gap-2">
        {keywords.map(word => (
          <span key={word} className="bg-gray-100 px-3 py-1 rounded-full flex items-center gap-2">
            {word}
            <button onClick={() => removeKeyword(word)} className="text-red-500 font-bold">×</button>
          </span>
        ))}
