### 2. The Core Logic: The Safe Feed Service

This is the "brain" of the feature. It fetches posts while applying exclusions.

```typescript
// lib/feed-service.ts
import { db } from "./db"; // Your database instance

export async function getSafeFeed(currentUserId: string) {
  // 1. Get the user's preferences
  const userPrefs = await db.user.findUnique({
    where: { id: currentUserId },
    include: {
      mutedUsers: { select: { mutedId: true } },
      blockedKeywords: { select: { word: true } },
    },
  });

  if (!userPrefs) throw new Error("User not found");

  const mutedUserIds = userPrefs.mutedUsers.map((m) => m.mutedId);
  const keywords = userPrefs.blockedKeywords.map((k) => k.word.toLowerCase());

  // 2. Fetch posts excluding muted users
  // Note: We filter keywords in the query for performance
  const posts = await db.post.findMany({
    where: {
      authorId: { notIn: mutedUserIds },
      AND: keywords.map((word) => ({
        content: {
          not: { contains: word, mode: 'insensitive' },
        },
      })),
    },
    include: { author: true },
    orderBy: { createdAt: "desc" },
  });

  return posts;
}
```

