### 1. The Core Logic (TypeScript)
First, we define our data structures and the filtering utility.

```typescript
// types.ts
export interface Post {
  id: string;
  authorId: string;
  authorName: string;
  content: string;
  timestamp: Date;
}

export interface UserSettings {
  mutedUserIds: string[];
  blockedKeywords: string[];
}

/**
 * The Filter Engine
 * Can be used on the frontend or backend.
 */
export const filterPosts = (posts: Post[], settings: UserSettings): Post[] => {
  const { mutedUserIds, blockedKeywords } = settings;

  return posts.filter((post) => {
    // 1. Check if user is muted
    const isAuthorMuted = mutedUserIds.includes(post.authorId);
    if (isAuthorMuted) return false;

    // 2. Check for blocked keywords (case-insensitive)
    const containsBlockedKeyword = blockedKeywords.some((keyword) => {
      const normalizedContent = post.content.toLowerCase();
      const normalizedKeyword = keyword.toLowerCase().trim();
      return normalizedKeyword !== "" && normalizedContent.includes(normalizedKeyword);
    });

    if (containsBlockedKeyword) return false;

    return true;
  });
};
```

