import React, { useState } from 'react';
import { evaluate } from 'mathjs';
import { Save, Delete, Percent, Divide, X, Minus, Plus, Equal, Trash2 } from 'lucide-react';

const Calculator = ({ onSave }) => {
  const [display, setDisplay] = useState('');
  const [serverName, setServerName] = useState('');
  const [result, setResult] = useState(null);

  const handleAction = (val) => {
    if (val === 'AC') {
      setDisplay('');
      setResult(null);
      setServerName('');
    } else if (val === '=') {
      try {
        const res = evaluate(display);
        setResult(res);
      } catch (err) {
        setResult('Error');
      }
    } else {
      setDisplay((prev) => prev + val);
    }
  };

  const handleSave = () => {
    if (result === null || result === 'Error') return;
    onSave({
      id: Date.now(),
      expression: display,
