  useEffect(() => {
    localStorage.setItem('calc_history', JSON.stringify(history));
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history]);

  const handleCalculate = (e) => {
    e?.preventDefault();
    if (!input) return;

    try {
      const calculatedResult = evaluate(input).toString();
      setResult(calculatedResult);

      const newEntry = {
        id: Date.now(),
        timestamp: new Date().toLocaleString(),
        expression: input,
        result: calculatedResult,
        server: serverName || 'Default Server'
      };

      setHistory(prev => [newEntry, ...prev]);
    } catch (err) {
      setResult('Error');
    }
  };

  const clearHistory = () => {
    if (window.confirm('Clear all calculation history?')) {
      setHistory([]);
    }
  };

  const copyToClipboard = (text, id) => {
    navigator.clipboard.writeText(text);
    setCopyFeedback(id);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  const appendInput = (val) => setInput(prev => prev + val);
  const backspace = () => setInput(prev => prev.slice(0, -1));
  const clearAll = () => {
    setInput('');
    setResult('');
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-4 md:p-8 font-sans">
      <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* LEFT: Calculator Engine */}
        <div className="lg:col-span-7 bg-slate-800 rounded-3xl p-6 shadow-2xl border border-slate-700">
          <div className="mb-6">
            <label className="flex items-center gap-2 text-sm font-medium text-slate-400 mb-2">
              <Server size={16} /> Server / Reference Name
            </label>
            <input 
              type="text"
              value={serverName}
              onChange={(e) => setServerName(e.target.value)}
              placeholder="e.g. Production-Cluster-01"
              className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>

          <div className="bg-slate-900 rounded-2xl p-6 mb-6 text-right shadow-inner border border-slate-700">
            <div className="text-slate-500 text-lg h-8 overflow-hidden font-mono">{input || '0'}</div>
            <div className="text-4xl font-bold text-blue-400 mt-2 truncate">
              {result ? `= ${result}` : '...'}
            </div>
          </div>

          {/* Keypad */}
          <div className="grid grid-cols-4 gap-3">
            {['7', '8', '9', '/'].map(btn => (
              <button key={btn} onClick={() => appendInput(btn)} className="btn-calc">{btn}</button>
            ))}
            {['4', '5', '6', '*'].map(btn => (
              <button key={btn} onClick={() => appendInput(btn)} className="btn-calc">{btn}</button>
            ))}
            {['1', '2', '3', '-'].map(btn => (
              <button key={btn} onClick={() => appendInput(btn)} className="btn-calc">{btn}</button>
            ))}
            <button onClick={() => appendInput('0')} className="btn-calc">0</button>
            <button onClick={() => appendInput('.')} className="btn-calc">.</button>
            <button onClick={backspace} className="btn-calc text-orange-400"><Delete size={20} /></button>
            <button onClick={() => appendInput('+')} className="btn-calc">+</button>

            <button onClick={clearAll} className="col-span-2 btn-calc text-red-400">CLEAR</button>
            <button 
              onClick={handleCalculate} 
              className="col-span-2 bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-xl shadow-lg transition-transform active:scale-95"
            >
              EXECUTE
            </button>
          </div>
        </div>

        {/* RIGHT: History & Server Logs */}
        <div className="lg:col-span-5 bg-slate-800 rounded-3xl p-6 border border-slate-700 flex flex-col h-[600px] lg:h-auto">
          <div className="flex items-center justify-between mb-6">
