#### The Calculator Logic (`components/Calculator.jsx`)

```jsx
import React, { useState } from 'react';

const Calculator = ({ onCalculate, activeServer }) => {
  const [display, setDisplay] = useState('0');
  const [equation, setEquation] = useState('');

  const buttons = [
    'C', 'DEL', '%', '/',
    '7', '8', '9', '*',
    '4', '5', '6', '-',
    '1', '2', '3', '+',
    '0', '.', '=',
  ];

  const handleAction = (value) => {
    if (value === 'C') {
      setDisplay('0');
      setEquation('');
    } else if (value === 'DEL') {
      setDisplay(display.length > 1 ? display.slice(0, -1) : '0');
    } else if (value === '=') {
      try {
        // Using Function() here for a simple demo; for heavy production, use 'mathjs'
        const result = Function(`"use strict"; return (${equation + display})`)();
        const formattedResult = Number(result.toFixed(4)).toString();

        onCalculate({
          expression: `${equation} ${display}`,
          result: formattedResult
        });

        setDisplay(formattedResult);
        setEquation('');
      } catch (e) {
        setDisplay('Error');
      }
    } else if (['+', '-', '*', '/', '%'].includes(value)) {
      setEquation(`${display} ${value} `);
      setDisplay('0');
    } else {
      setDisplay(display === '0' ? value : display + value);
    }
  };

  return (
    <div className="bg-slate-800 p-6 rounded-3xl border border-slate-700 shadow-2xl">
      <div className="mb-4 text-right overflow-hidden">
        <div className="text-slate-500 text-sm h-6 truncate">{equation}</div>
        <div className="text-4xl font-mono font-bold truncate text-blue-100">{display}</div>
        <div className="mt-2 text-[10px] uppercase tracking-widest text-blue-500 font-bold">
          Tag: {activeServer}
        </div>
      </div>

      <div className="grid grid-cols-4 gap-2">
        {buttons.map((btn) => (
          <button
            key={btn}
            onClick={() => handleAction(btn)}
            className={`p-4 text-lg font-medium rounded-xl transition-all active:scale-95
              ${btn === '=' ? 'bg-blue-600 hover:bg-blue-500 col-span-2' : 
                ['+', '-', '*', '/', 'C', 'DEL', '%'].includes(btn) ? 'bg-slate-700 hover:bg-slate-600 text-blue-400' : 
                'bg-slate-700/50 hover:bg-slate-700 text-slate-200'}
            `}
          >
            {btn}
          </button>
        ))}
      </div>
    </div>
  );
};

export default Calculator;
```

