// app/page.tsx
import { ProductGrid } from "@/components/ProductGrid";
import { FilterSidebar } from "@/components/FilterSidebar";
import { SearchInput } from "@/components/SearchInput";
import { products } from "@/lib/data"; // Mock data file

export default function StoreFront({
  searchParams,
}: {
  searchParams: { [key: string]: string | string[] | undefined };
}) {
  const query = typeof searchParams.q === "string" ? searchParams.q : "";
  const colorFilter = typeof searchParams.color === "string" ? searchParams.color : "";
  const categoryFilter = typeof searchParams.category === "string" ? searchParams.category : "";

  // Filtering Logic
  const filteredProducts = products.filter((product) => {
    const matchesQuery = product.name.toLowerCase().includes(query.toLowerCase());
    const matchesCategory = categoryFilter ? product.category === categoryFilter : true;
    const matchesColor = colorFilter 
      ? product.variants.some(v => v.color.toLowerCase() === colorFilter.toLowerCase()) 
      : true;

    return matchesQuery && matchesCategory && matchesColor;
  });

  return (
    <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
