### 5. How to add "Sizes/Colors" Filtering
Add this to your `FilterSidebar.tsx`. It works by appending `?color=blue` or `?category=Tops` to the URL.

```tsx
// components/FilterSidebar.tsx
"use client";
import { useRouter, useSearchParams } from "next/navigation";

const CATEGORIES = ["Tops", "Bottoms", "Accessories"];
const COLORS = ["Black", "White", "Indigo", "Red"];

export function FilterSidebar() {
  const router = useRouter();
  const searchParams = useSearchParams();

  const updateFilter = (key: string, value: string) => {
    const params = new URLSearchParams(searchParams);
    if (params.get(key) === value) params.delete(key); // Toggle off
    else params.set(key, value);
    router.push(`/?${params.toString()}`);
  };

  return (
    <aside className="w-full lg:w-64 flex-shrink-0 space-y-8 mb-8 lg:mb-0">
      <div>
        <h3 className="font-semibold mb-4">Categories</h3>
        <div className="space-y-2">
          {CATEGORIES.map((cat) => (
            <label key={cat} className="flex items-center gap-2 cursor-pointer">
              <input
                type="checkbox"
                checked={searchParams.get("category") === cat}
                onChange={() => updateFilter("category", cat)}
                className="rounded text-black focus:ring-black"
              />
              <span className="text-sm text-gray-600">{cat}</span>
            </label>
          ))}
        </div>
      </div>

      <div>
        <h3 className="font-semibold mb-4">Colors</h3>
        <div className="flex flex-wrap gap-2">
          {COLORS.map((color) => (
            <button
              key={color}
              onClick={() => updateFilter("color", color)}
              className={`px-3 py-1 text-xs rounded-full border transition-colors ${
                searchParams.get("color") === color 
                ? "bg-black text-white" 
                : "bg-white text-gray-600 hover:border-gray-400"
              }`}
            >
              {color}
            </button>
          ))}
        </div>
      </div>
    </aside>
  );
}
```

