#### Step 2: The Search and Filter Logic
We use a custom hook to handle filtering logic. This allows users to bookmark or share a specific search result because the state is stored in the URL.

```tsx
// components/StoreFront.tsx (Client Component)
'use client'

import { useState, useMemo } from 'react';
import { PRODUCTS } from '@/lib/data';
import ProductCard from './ProductCard';
import FilterSidebar from './FilterSidebar';
import SearchBar from './SearchBar';

export default function StoreFront() {
  const [search, setSearch] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [selectedSize, setSelectedSize] = useState<string>('All');

  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter((product) => {
      const matchesSearch = product.name.toLowerCase().includes(search.toLowerCase());
      const matchesCategory = selectedCategory === 'All' || product.category === selectedCategory;
      const matchesSize = selectedSize === 'All' || 
        product.variants.some(v => v.size === selectedSize);

      return matchesSearch && matchesCategory && matchesSize;
    });
  }, [search, selectedCategory, selectedSize]);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="flex flex-col md:flex-row gap-8">
        {/* Sidebar */}
        <aside className="w-full md:w-64 space-y-6">
          <SearchBar value={search} onChange={setSearch} />
          <FilterSidebar 
            selectedCategory={selectedCategory} 
            onCategoryChange={setSelectedCategory}
            selectedSize={selectedSize}
            onSizeChange={setSelectedSize}
          />
        </aside>

        {/* Main Content */}
        <main className="flex-1">
          <div className="mb-6 flex justify-between items-center">
            <h2 className="text-xl font-semibold">
              Products ({filteredProducts.length})
            </h2>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredProducts.map(product => (
              <ProductCard key={product.id} product={product} />
            ))}
          </div>

          {filteredProducts.length === 0 && (
            <div className="text-center py-20 bg-gray-50 rounded-lg">
              <p className="text-gray-500 text-lg">No products found matching your filters.</p>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}
