### 1. Security Core (`src/lib/crypto.ts`)

This module handles the heavy lifting of encryption and blind indexing.

```typescript
import crypto from 'crypto';

const ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 16;
const SALT_LENGTH = 64;
const AUTH_TAG_LENGTH = 16;

// In production, these would come from AWS KMS or HashiCorp Vault
const MASTER_KEY = Buffer.from(process.env.MASTER_KEY!, 'hex'); // 32 bytes
const SEARCH_PEPPER = process.env.SEARCH_PEPPER!; 

export interface EncryptedData {
  ciphertext: string;
  iv: string;
  tag: string;
}

/**
 * High-security encryption (Randomized)
 * Prevents frequency analysis because the same input results in different output
 */
export function encrypt(plaintext: string): EncryptedData {
  const iv = crypto.randomBytes(IV_LENGTH);
  const cipher = crypto.createCipheriv(ALGORITHM, MASTER_KEY, iv);

  let encrypted = cipher.update(plaintext, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  return {
    ciphertext: encrypted,
    iv: iv.toString('hex'),
    tag: cipher.getAuthTag().toString('hex'),
  };
}

export function decrypt(data: EncryptedData): string {
  const decipher = crypto.createDecipheriv(
    ALGORITHM, 
    MASTER_KEY, 
    Buffer.from(data.iv, 'hex')
  );
  decipher.setAuthTag(Buffer.from(data.tag, 'hex'));

  let decrypted = decipher.update(data.ciphertext, 'hex', 'utf8');
  decrypted += decipher.final('utf8');
  return decrypted;
}

/**
 * Blind Index (Deterministic)
 * Allows searching for PII without decrypting.
 */
export function generateBlindIndex(plaintext: string): string {
  return crypto
    .createHmac('sha256', SEARCH_PEPPER)
    .update(plaintext.toLowerCase().trim())
    .digest('hex');
}
```

