import { encrypt, decrypt, generateBlindIndex, EncryptedData } from '../lib/crypto';

export interface PatientPII {
  ssn: string;
  email: string;
  full_name: string;
}

export class VaultService {
  static protect(data: PatientPII) {
    return {
      // Storage: Randomized Encryption
      ssn_encrypted: encrypt(data.ssn),
      email_encrypted: encrypt(data.email),
      name_encrypted: encrypt(data.full_name),

      // Search: Blind Indexes
      ssn_index: generateBlindIndex(data.ssn),
      email_index: generateBlindIndex(data.email),
