### 3. The Vault Engine (Core Logic)
This service handles the heavy lifting of encryption and indexing.

```typescript
// src/services/vault.service.ts
import crypto from 'crypto';

const ALGORITHM = 'aes-256-gcm';
const KEY = Buffer.from(process.env.ENCRYPTION_KEY!, 'hex');
const SALT = process.env.SEARCH_INDEX_SALT!;

export class VaultService {
  /**
   * Encrypts plaintext and returns a formatted string: iv:authTag:ciphertext
   */
  static encrypt(plaintext: string): string {
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv(ALGORITHM, KEY, iv);

    let encrypted = cipher.update(plaintext, 'utf8', 'hex');
    encrypted += cipher.final('hex');

    const authTag = cipher.getAuthTag().toString('hex');
    return `${iv.toString('hex')}:${authTag}:${encrypted}`;
  }

  /**
   * Decrypts the formatted string back to plaintext
   */
  static decrypt(cipherText: string): string {
    const [ivHex, authTagHex, encryptedHex] = cipherText.split(':');

    const decipher = crypto.createDecipheriv(ALGORITHM, KEY, Buffer.from(ivHex, 'hex'));
    decipher.setAuthTag(Buffer.from(authTagHex, 'hex'));

    let decrypted = decipher.update(encryptedHex, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }

  /**
   * Creates a deterministic hash for searching. 
   * This is the "Blind Index".
   */
  static generateBlindIndex(plaintext: string): string {
    return crypto
      .createHmac('sha256', SALT)
      .update(plaintext.toLowerCase().trim()) // Normalize for consistent searching
      .digest('hex');
  }
}
```

