```typescript
// src/controllers/patient.controller.ts
import { Request, Response } from 'express';
import { Patient } from '../models/patient.model';
import { VaultService } from '../services/vault.service';

export const createPatient = async (req: Request, res: Response) => {
  try {
    const { name, ssn, providerId } = req.body;

    const newPatient = new Patient({
      providerId,
      // Encrypt for storage
      name_enc: VaultService.encrypt(name),
      ssn_enc: VaultService.encrypt(ssn),
      // Hash for searching
      name_bindex: VaultService.generateBlindIndex(name),
      ssn_bindex: VaultService.generateBlindIndex(ssn),
    });

    await newPatient.save();
    res.status(201).json({ message: "Patient record secured", id: newPatient._id });
  } catch (err) {
    res.status(500).json({ error: (err as Error).message });
  }
};

export const findPatientBySSN = async (req: Request, res: Response) => {
  try {
    const { ssn } = req.body;

    // Step 1: Hash the search term exactly like we did during storage
    const searchHash = VaultService.generateBlindIndex(ssn);

    // Step 2: Query the DB using the index (High performance)
    const patient = await Patient.findOne({ ssn_bindex: searchHash });

    if (!patient) return res.status(404).json({ message: "Not found" });

    // Step 3: Decrypt for the authorized response
    res.json({
      id: patient._id,
      name: VaultService.decrypt(patient.name_enc),
      ssn: VaultService.decrypt(patient.ssn_enc),
      providerId: patient.providerId
    });
  } catch (err) {
    res.status(500).json({ error: (err as Error).message });
  }
};
```

### Why this is production-ready:

1.  **Searchable without Decryption:** In the `findPatientBySSN` method, we do not perform a "table scan" or decrypt every row to find a match. We use a hashed lookup, which is $O(1)$ or $O(log n)$ depending on the DB index.
2.  **Authenticated Encryption (AES-GCM):** Unlike standard AES-CBC, AES-GCM includes an "Authentication Tag." This prevents "Bit-flipping attacks" where an attacker modifies the ciphertext in the database. If even 1 bit is changed in the DB, decryption will fail.
3.  **Resistance to Frequency Analysis:** Because we use a random `IV` for every encryption, two patients named "John Doe" will have completely different `name_enc` strings in the database.
4.  **Audit-Log Ready:** The `name_bindex` can be used in your audit logs to link activities to a specific person without ever logging their actual name in plaintext.

### Security Note: Key Rotation
In a real production healthcare environment, you should implement **Envelop Encryption**. 
1.  Generate a "Data Encryption Key" (DEK) for every patient record.
2.  Encrypt the patient's data with the DEK.
3.  Encrypt the DEK with a "Key Encryption Key" (KEK) from a service like AWS KMS.
4.  Store the encrypted DEK alongside the patient record. 

This allows you to rotate your master keys (KEK) without re-encrypting millions of database rows.

To build a high-performance feature that finds users sharing at least three specific hobby tags, we need a robust database schema and an efficient query strategy.

I will use **Node.js (TypeScript)**, **Express**, and **PostgreSQL** with **Prisma ORM**. PostgreSQL is ideal here because of its powerful relational querying capabilities and indexing.

### 1. The Database Schema

The core of this feature lies in a many-to-many relationship between `Users` and `Hobbies`.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model User {
  id        String   @id @default(uuid())
  username  String   @unique
  hobbies   UserHobby[]
}

model Hobby {
  id    String   @id @default(uuid())
  slug  String   @unique // e.g., "rock-climbing", "chess"
  name  String
  users UserHobby[]
}

model UserHobby {
  userId  String
  hobbyId String
  user    User  @relation(fields: [userId], references: [id])
  hobby   Hobby @relation(fields: [hobbyId], references: [id])

  @@id([userId, hobbyId])
  @@index([hobbyId]) // Crucial for performance
}
```

### 2. The Logic: "The Intersection Query"

Finding users with at least $N$ matches is an "Intersection" problem. 
1. Get the current user's hobby IDs.
2. Search the `UserHobby` table for other users who have those IDs.
3. Group the results by `userId`.
4. Filter for groups where the count is $\ge 3$.

### 3. Implementation (The Service Layer)

This service uses a raw SQL query via Prisma. While Prisma's API is great, for complex aggregations like `HAVING COUNT(*) >= 3`, raw SQL is more performant and readable.

```typescript
// src/services/match.service.ts
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class MatchService {
  /**
   * Finds users sharing at least 3 hobbies with the target user
   */
  static async findHobbyMatches(userId: string, limit: number = 10) {
    // 1. Get current user's hobbies first
    const currentUserHobbies = await prisma.userHobby.findMany({
      where: { userId },
      select: { hobbyId: true }
    });

    const hobbyIds = currentUserHobbies.map(h => h.hobbyId);

    if (hobbyIds.length < 3) {
      return []; // Cannot have 3 matches if user doesn't have 3 hobbies
    }

    /**
     * SQL Explanation:
     * 1. Select the userId and count how many hobbies match
     * 2. Join with the User table to get profile details
     * 3. Filter only for hobbies the current user has
     * 4. Exclude the current user themselves
     * 5. Group by user to count their specific matches
     * 6. HAVING filters for the "At least 3" logic
     * 7. Order by the most matches first
     */
    const matches = await prisma.$queryRaw`
      SELECT 
        u.id, 
        u.username, 
        COUNT(uh."hobbyId") as "sharedCount"
      FROM "UserHobby" uh
      JOIN "User" u ON uh."userId" = u.id
      WHERE uh."hobbyId" = ANY(${hobbyIds})
        AND uh."userId" != ${userId}
      GROUP BY u.id
      HAVING COUNT(uh."hobbyId") >= 3
      ORDER BY "sharedCount" DESC
      LIMIT ${limit}
    `;

    return matches;
  }
}
```

