### 3. The Implementation logic

The core logic uses a specialized SQL query. We want to:
1.  Identify the Hobby IDs belonging to the current user.
2.  Search the join table for other users who have those same Hobby IDs.
3.  Group the results by `userId`.
4.  Filter groups where the count is $\ge 3$.

#### `hobby.service.ts`

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export const findCompatibleUsers = async (userId: number) => {
  // 1. Get the current user's hobby IDs
  const currentUser = await prisma.user.findUnique({
    where: { id: userId },
    include: { hobbies: { select: { id: true } } }
  });

  if (!currentUser || currentUser.hobbies.length < 3) {
    return []; // Cannot match if user has fewer than 3 hobbies
  }

  const hobbyIds = currentUser.hobbies.map(h => h.id);

  /**
   * 2. Execute Raw SQL for performance.
   * We want users who share at least 3 IDs from our hobbyIds array.
   */
  const matches = await prisma.$queryRaw<{ userId: number; shared_count: number }[]>`
    SELECT "A" as "userId", COUNT(*) as "shared_count"
    FROM "_UserHobbies"
    WHERE "B" IN (${hobbyIds.join(',')}) -- "B" is HobbyId in Prisma's implicit join table
    AND "A" != ${userId}                -- Don't match the user with themselves
    GROUP BY "A"
    HAVING COUNT(*) >= 3
    ORDER BY "shared_count" DESC
    LIMIT 20;
  `;

  if (matches.length === 0) return [];

  // 3. Fetch full user profiles for the matches
  const matchIds = matches.map(m => m.userId);
  return prisma.user.findMany({
    where: { id: { in: matchIds } },
    include: { hobbies: true }
  });
};
```

