### 2. Core Logic: Content Validation Service

Because content types are dynamic, we need a service to validate that a `ContentEntry` matches the `ContentModel` definition.

```typescript
// src/content/content-validator.service.ts
import { Injectable, BadRequestException } from '@nestjs/common';

@Injectable()
export class ContentValidatorService {
  validate(schema: any[], data: any) {
    for (const field of schema) {
      const value = data[field.name];

      if (field.required && (value === undefined || value === null)) {
        throw new BadRequestException(`Field ${field.name} is required`);
      }

      if (value !== undefined) {
        this.validateType(field.name, value, field.type);
      }
    }
  }

  private validateType(name: string, value: any, type: string) {
    switch (type) {
      case 'string':
        if (typeof value !== 'string') throw new BadRequestException(`${name} must be a string`);
        break;
      case 'number':
        if (typeof value !== 'number') throw new BadRequestException(`${name} must be a number`);
        break;
      case 'rich-text':
        // Expecting HTML or JSON (Lexical/Slate)
        if (typeof value !== 'string' && typeof value !== 'object') 
            throw new BadRequestException(`${name} must be valid rich text`);
        break;
      case 'asset':
        if (typeof value !== 'string') throw new BadRequestException(`${name} must be an Asset UUID`);
        break;
    }
  }
}
```

