export class EntriesController {
  constructor(
    private prisma: PrismaService,
    private validator: ContentValidatorService
  ) {}

  @Post(':modelSlug')
  @UseGuards(JwtAuthGuard)
  async create(
    @Param('modelSlug') slug: string,
    @Body() body: any,
    @Request() req
  ) {
    const model = await this.prisma.contentModel.findUnique({
      where: { slug }
    });

    if (!model) throw new NotFoundException('Content model not found');

    // Validate dynamic content against the model's field definitions
    this.validator.validate(model.fields as any[], body);

    return this.prisma.contentEntry.create({
      data: {
        modelId: model.id,
        content: body,
        authorId: req.user.id,
      },
    });
  }

  @Get(':modelSlug')
  async findAll(@Param('modelSlug') slug: string) {
    return this.prisma.contentEntry.findMany({
      where: { model: { slug }, status: 'PUBLISHED' },
      include: { model: true }
    });
  }
}
