### 4. Dynamic Content Logic (`content.service.ts`)

This service handles the validation of dynamic data against the defined model.

```typescript
import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class ContentService {
  constructor(private prisma: PrismaService) {}

  async createEntry(modelSlug: string, data: any) {
    const model = await this.prisma.contentModel.findUnique({
      where: { slug: modelSlug },
    });

    if (!model) throw new BadRequestException('Content model not found');

    // Dynamic Validation Logic
    this.validateSchema(model.fields, data);

    return this.prisma.contentEntry.create({
      data: {
        contentModelId: model.id,
        data: data,
        authorId: 'system-user', // Replace with dynamic user id
      },
    });
  }

  private validateSchema(fields: any, data: any) {
    const schemaFields = fields as Array<{ name: string; type: string; required: boolean }>;

    for (const field of schemaFields) {
      const value = data[field.name];

      if (field.required && (value === undefined || value === null)) {
        throw new BadRequestException(`Field ${field.name} is required`);
      }

      if (value !== undefined) {
        // Basic type checking
        if (field.type === 'NUMBER' && typeof value !== 'number') {
          throw new BadRequestException(`${field.name} must be a number`);
        }
        // Add more complex validations for MEDIA, DATE, etc.
      }
    }
  }
}
