### 2. The Content Model (Dynamic Schema Definition)

The `ContentModel` defines what fields a content type has (e.g., a "Post" has a "Title" of type `string`).

```typescript
// src/modules/content-models/content-model.schema.ts
import { Prop, Schema, SchemaFactory } from '@nestjs/mongoose';
import { Document } from 'mongoose';

export enum FieldType {
  STRING = 'string',
  NUMBER = 'number',
  RICH_TEXT = 'rich_text',
  MEDIA = 'media',
  REFERENCE = 'reference'
}

@Schema()
export class ContentField {
  @Prop({ required: true })
  name: string; // e.g., "title"

  @Prop({ required: true, enum: FieldType })
  type: FieldType;

  @Prop({ default: false })
  required: boolean;
}

@Schema({ timestamps: true })
export class ContentModel extends Document {
  @Prop({ required: true, unique: true })
  name: string; // e.g., "Blog Post"

  @Prop({ required: true, unique: true })
  slug: string; // e.g., "blog-post"

  @Prop([ContentField])
  fields: ContentField[];
}

export const ContentModelSchema = SchemaFactory.createForClass(ContentModel);
```

