### 5. Dynamic Validation Logic

When a user tries to save an entry, we must validate it against the `ContentModel` fields.

```typescript
// src/modules/entries/entries.service.ts
import { Injectable, BadRequestException } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { Entry } from './entry.schema';
import { ContentModel } from '../content-models/content-model.schema';

@Injectable()
export class EntriesService {
  constructor(
    @InjectModel(Entry.name) private entryModel: Model<Entry>,
    @InjectModel(ContentModel.name) private modelDef: Model<ContentModel>,
  ) {}

  async createEntry(modelSlug: string, data: any) {
    const definition = await this.modelDef.findOne({ slug: modelSlug });
    if (!definition) throw new BadRequestException('Invalid Content Type');

    // Simple Dynamic Validation
    for (const field of definition.fields) {
      if (field.required && !data[field.name]) {
        throw new BadRequestException(`Field ${field.name} is required`);
      }
      // You can add more complex AJV validation here based on field.type
    }

    const entry = new this.entryModel({
      modelId: definition._id,
      data,
    });
    return entry.save();
  }
}
```

