### 2. The Interaction Model (with Native TTL)
This model defines the interaction and tells MongoDB to automatically delete the document 30 days after `createdAt`.

```javascript
// src/models/Interaction.js
const mongoose = require('mongoose');

const InteractionSchema = new mongoose.Schema({
  userId: { type: String, required: true, index: true },
  prompt: { type: String, required: true },
  response: { type: String, required: true },
  metadata: {
    modelUsed: String,
    tokens: Number
  },
  createdAt: { 
    type: Date, 
    default: Date.now,
    // Native MongoDB TTL: automatically deletes 2592000 seconds (30 days) after createdAt
    expires: 2592000 
  }
});

// Manual index for performance on custom queries
InteractionSchema.index({ createdAt: 1 });

module.exports = mongoose.model('Interaction', InteractionSchema);
```

### 3. The Purge Service (Application Layer)
While the DB handles TTL, we want a service that we can trigger manually or via cron for auditing purposes.

```javascript
// src/services/purgeService.js
const Interaction = require('../models/Interaction');
const cron = require('node-cron');

const purgeOldInteractions = async () => {
  const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

  try {
    const result = await Interaction.deleteMany({
      createdAt: { $lt: thirtyDaysAgo }
    });
    console.log(`[Purge Service] Cleanup successful. Removed ${result.deletedCount} old interactions.`);
  } catch (error) {
    console.error('[Purge Service] Error during cleanup:', error);
  }
};

// Schedule to run every night at midnight
const initCronJobs = () => {
  cron.schedule('0 0 * * *', () => {
    console.log('Running scheduled data purge...');
    purgeOldInteractions();
  });
};

module.exports = { purgeOldInteractions, initCronJobs };
```

